-- Poems batch 93
INSERT OR IGNORE INTO poems (id,title,author,dynasty,collection,collection_id,rhythmic,tags,excerpt,length,source_path,paragraphs) VALUES
('35be79e9-f784-4b0c-b46d-a1c00e38cc96','題化龍坊酒樓壁','馮觀國','宋','宋诗','song-poetry','','[]','若問先生歸去來，此行直是到天台。',32,'全唐诗/poet.song.111000.json','["若問先生歸去來，此行直是到天台。", "碧桃瑶草紫芝熟，到日須容醉玉杯。"]'),
('5ba1181d-bfa0-4ecb-ace7-98b08a8ae925','偈四首  其一','釋法恭','宋','宋诗','song-poetry','','[]','春風楊柳眉，春禽弄百舌。',96,'全唐诗/poet.song.111000.json','["春風楊柳眉，春禽弄百舌。", "一片祖師心，兩處俱漏泄。", "不動步還家，習漏頓消滅。", "暗投玉線芒，曉貫金針穴。", "深固實幽遠，無人孰辨別。", "慚愧可憐生，頭頭皆合轍。", "不念阿彌陀，南無乾屎橛。", "無智癡人前，第一不得說。"]'),
('c5eae147-6eda-44ca-98ba-5052f6bd7c7a','偈四首  其二','釋法恭','宋','宋诗','song-poetry','','[]','頭祖纔始陞堂，百丈卷席歸去。',28,'全唐诗/poet.song.112000.json','["頭祖纔始陞堂，百丈卷席歸去。", "不是拾得寒山，有理也無雪處。"]'),
('e3475324-9a59-4f67-a9ad-8bb953f72d4d','偈四首  其三','釋法恭','宋','宋诗','song-poetry','','[]','見得徹，用時親，相逢盡是箇中人。',48,'全唐诗/poet.song.112000.json','["見得徹，用時親，相逢盡是箇中人。", "望空雨寶休誇富，無地容錐未是貧。", "踏著秤磓硬似鐵，八兩元來是半斤。"]'),
('b7e891e9-9b0e-4e88-b1b0-2c00e06be4b4','偈四首  其四','釋法恭','宋','宋诗','song-poetry','','[]','五天一隻蓬蒿箭，攪動支那百萬兵。',32,'全唐诗/poet.song.112000.json','["五天一隻蓬蒿箭，攪動支那百萬兵。", "不得雲門行正令，幾乎錯認定盤星。"]'),
('b40bc149-efd2-4efc-b574-55c98496c905','頌古','釋法恭','宋','宋诗','song-poetry','','[]','臘月燒山，對面熱謾。',36,'全唐诗/poet.song.112000.json','["臘月燒山，對面熱謾。", "瞥然悟去，身在長安。", "咄哉無限未歸客，沙裏求油實可憐。"]'),
('262068eb-b308-4a02-bad1-7b63576a6815','偈六首  其一','釋法智','宋','宋诗','song-poetry','','[]','真空不空，寥寥無影樹頭月。',92,'全唐诗/poet.song.112000.json','["真空不空，寥寥無影樹頭月。", "真色非色，隠隠不萌枝上花。", "威音路外芬芳，鳳無依倚。", "空劫已前照耀，鶴不停機。", "更須一色功圓，便得同中有異。", "同中異，直下承當休擬議。", "夜來明月照蘆花，鶴鷺並頭踏雪睡。"]'),
('43a78c60-ff04-4259-925e-30211ecf1259','偈六首  其二','釋法智','宋','宋诗','song-poetry','','[]','辨不辨，昏不昏，打破盆子只論盆。',46,'全唐诗/poet.song.112000.json','["辨不辨，昏不昏，打破盆子只論盆。", "千里遠山烟樹，數家沙鳥漁村。", "夜深月與湖光渾，天水茫茫絕點痕。"]'),
('a347db76-9ffa-42b3-b572-4f2be394d0ee','偈六首  其三','釋法智','宋','宋诗','song-poetry','','[]','深夜虛堂露氣佳，冰霜著月沒痕瑕。',32,'全唐诗/poet.song.112000.json','["深夜虛堂露氣佳，冰霜著月沒痕瑕。", "木人打破琉璃碗，走過新羅始到家。"]'),
('f5f2e0af-6bfe-43bb-9a3d-7d62c5ed5d1a','偈六首  其四','釋法智','宋','宋诗','song-poetry','','[]','一不成，二不是，火雲堆裏秋風起。',56,'全唐诗/poet.song.112000.json','["一不成，二不是，火雲堆裏秋風起。", "堪笑耘田車水翁，手脚忙亂同兒戲。", "同兒戲，有巴鼻。", "但得豐年賀太平，四海五湖皇化裏。"]'),
('9e2d833b-a64b-41aa-b3be-c4785cbebc5e','偈六首  其五','釋法智','宋','宋诗','song-poetry','','[]','動時常寂寂，靜處活鱍鱍。',76,'全唐诗/poet.song.112000.json','["動時常寂寂，靜處活鱍鱍。", "動靜兩俱忘，佛祖何處著。", "驀地夢回頭，長天飛一鶚。", "春風有時好，春風有時惡。", "不得春風花不開，花開又被風吹落。", "錯錯錯，蒸餠元來是麵作。"]'),
('a39a0c97-2ff6-4ff5-b778-010470d76b61','偈六首  其六','釋法智','宋','宋诗','song-poetry','','[]','幽鳥語如篁，柳垂金線長。',24,'全唐诗/poet.song.112000.json','["幽鳥語如篁，柳垂金線長。", "雲收山谷靜，風送杏花香。"]'),
('39e5e3a0-e2ea-4c48-9ee7-ced65ff7b0b5','贊天童覺和尚','釋法智','宋','宋诗','song-poetry','','[]','烏頂雪眉，雲蹤鶴態。',50,'全唐诗/poet.song.112000.json','["烏頂雪眉，雲蹤鶴態。", "貌出正偏，見非向背。", "芙蓉月照兮太白峰高，丹鳳翔空兮瓊林玉碎。", "覿面分明，兩彩一賽。"]'),
('0830e637-122f-473b-a284-394711825bf5','偈二首  其一','釋法智','宋','宋诗','song-poetry','','[]','明月高懸未照前，雪眉人憑玉欄干。',32,'全唐诗/poet.song.112000.json','["明月高懸未照前，雪眉人憑玉欄干。", "夜深雨過風雷息，客散雲樓酒碗乾。"]'),
('b4eac27a-1848-4393-9f29-d67701e4ea2d','偈二首  其二','釋法智','宋','宋诗','song-poetry','','[]','三界無法，何處求心。',36,'全唐诗/poet.song.112000.json','["三界無法，何處求心。", "驚蛇入草，飛鳥出林。", "雨過山堂秋夜靜，市聲終不到孤岑。"]'),
('07592494-f680-456c-938b-fd5eb47d7174','偈','釋悟','宋','宋诗','song-poetry','','[]','一切聲，是佛聲，簷前雨滴響泠泠。',48,'全唐诗/poet.song.112000.json','["一切聲，是佛聲，簷前雨滴響泠泠。", "一切色，是佛色，覿面相呈諱不得。", "便恁麽，若爲明，碧天雲外月華清。"]'),
('1c6b36b4-7a3e-44e7-8641-517e6fc2a6d6','偈','釋慧深','宋','宋诗','song-poetry','','[]','未得入頭應切切，入頭已得須教徹。',32,'全唐诗/poet.song.112000.json','["未得入頭應切切，入頭已得須教徹。", "雖然得入本無無，莫守無無無間歇。"]'),
('fcd34519-dce3-457d-8e95-8872a2d1e1e6','偈','釋思徹','宋','宋诗','song-poetry','','[]','羊頭車子推明月，沒底船兒載曉風。',32,'全唐诗/poet.song.112000.json','["羊頭車子推明月，沒底船兒載曉風。", "一句頓超情量外，道無南北與西東。"]'),
('78760cfe-31f4-466b-aabd-7c3802b839fc','偈','釋通理','宋','宋诗','song-poetry','','[]','峰頭駕鐵船，三更日輪杲。',40,'全唐诗/poet.song.112000.json','["峰頭駕鐵船，三更日輪杲。", "心閑不自明，落葉知誰掃。", "等閑摘箇鄭州梨，放手元是青州棗。"]'),
('a5efb5f9-7491-489b-a761-d2f578fbf11c','偈','釋元實','宋','宋诗','song-poetry','','[]','一位纔彰五位分，君臣叶處紫雲屯。',32,'全唐诗/poet.song.112000.json','["一位纔彰五位分，君臣叶處紫雲屯。", "夜明簾卷無私照，金殿重重顯至尊。"]'),
('de9e0765-fc9e-46be-9360-f75ef9bfb531','偈','釋普紹','宋','宋诗','song-poetry','','[]','靈雲悟桃花，玄沙傍不肯。',48,'全唐诗/poet.song.112000.json','["靈雲悟桃花，玄沙傍不肯。", "多少癡禪和，擔雪去填井。", "今春花又開，此意誰能領。", "端的少人知，花落春風靜。"]'),
('a2eea687-6215-4fbf-9c08-814de72c78bf','偈','隆禪師','宋','宋诗','song-poetry','','[]','一不成，二不是。',46,'全唐诗/poet.song.112000.json','["一不成，二不是。", "口喫飯，鼻出氣。", "休云北斗藏身，說甚南山鼈鼻。", "家財運出任交關，勸君莫競錐頭利。"]'),
('201f90bd-2bcf-4d25-b678-e03a7bf9fd90','偈','釋了心','宋','宋诗','song-poetry','','[]','佛之一字孰云無，木馬泥牛滿道途。',32,'全唐诗/poet.song.112000.json','["佛之一字孰云無，木馬泥牛滿道途。", "倚遍欄干春色晚，海風吹斷碧珊瑚。"]'),
('526eb4d3-1b79-470a-bf24-c53e7d7004a0','堠','李道','宋','宋诗','song-poetry','','[]','過客煩瞻視，當途獨有名。',48,'全唐诗/poet.song.112000.json','["過客煩瞻視，當途獨有名。", "幾人行大道，用爾算前程。", "土石儀形久，山河里數明。", "從茲知正路，捷徑謾縱橫。"]'),
('931aeee8-cab6-4eb2-8eba-260806cce0cb','月桂','李道','宋','宋诗','song-poetry','','[]','月窟孀娥不惜栽，和風分付天下來。',32,'全唐诗/poet.song.112000.json','["月窟孀娥不惜栽，和風分付天下來。", "欲知仙艷無窮處，不隔人間朔望開。"]'),
('b914d506-b5fd-429c-94ab-43d2f3e00e41','句','陳桷','宋','宋诗','song-poetry','','[]','神仙多是大羅客，我比大羅超一格。',16,'全唐诗/poet.song.112000.json','["神仙多是大羅客，我比大羅超一格。"]'),
('f79d2c78-bdb4-4ee3-b7b5-55c75d267c2b','句','周林','宋','宋诗','song-poetry','','[]','殷紅片片點蒼苔。',8,'全唐诗/poet.song.112000.json','["殷紅片片點蒼苔。"]'),
('fdf27a9f-45fc-43bf-9ced-ade591903071','句','李如箎','宋','宋诗','song-poetry','','[]','繅車籬落桑陰盡，土鼓鄉亭稻葉青。',16,'全唐诗/poet.song.112000.json','["繅車籬落桑陰盡，土鼓鄉亭稻葉青。"]'),
('ca41d262-f3f5-48ed-bc37-08e9d638e44a','明福觀','王傅','宋','宋诗','song-poetry','','[]','泉源山下延平曠，路入松關起清爽。',64,'全唐诗/poet.song.112000.json','["泉源山下延平曠，路入松關起清爽。", "飛雲西峙積翠臺，突兀三千六百丈。", "杏花片片舖金壇，天風吹桂香漫山。", "遊人盡去蘿月上，覺我身世非人間。"]'),
('59edf69d-3f11-4bcb-b532-ec32e823d685','題蔡潤畫','李耕','宋','宋诗','song-poetry','','[]','雨過天如沐，回山濃翠侵。',72,'全唐诗/poet.song.112000.json','["雨過天如沐，回山濃翠侵。", "平橋带野水，涓涓繞竹林。", "茅屋闃無人，案上橫素琴。", "白鷺正熟睡，杳無羨魚心。", "維舟欲渡誰，柳岸烟沉沉。", "長嘯在何處，惆悵隔雲岑。"]'),
('0ceec793-11a9-462a-9490-ff598acff36b','題管聖浩蒲川歸隠','王鞏','宋','宋诗','song-poetry','','[]','卜築蒲川上，翛然遠市廛。',48,'全唐诗/poet.song.112000.json','["卜築蒲川上，翛然遠市廛。", "潮聲書屋外，月影釣舟前。", "地僻紅塵浄，沙平白鳥眠。", "此中幽適趣，不必問斜川。"]'),
('49c80016-7e10-4be1-8afe-a84301cd74f4','出舍在浙江亭得父書開示題詩於亭','張牧','宋','宋诗','song-poetry','','[]','結束青山向日還，得書南望意悠然。',64,'全唐诗/poet.song.112000.json','["結束青山向日還，得書南望意悠然。", "少寬二老庭幃念，粗了生平燈火緣。", "去路雖遥心已近，短篇欲就意難圓。", "不妨靜洗笙歌耳，穩接江濤到枕邊。"]'),
('e708e92d-7410-4a46-a2a2-b3c085c3361f','韶州秩滿至清源道中聞子庠姪磻俱登第又題客邸','張牧','宋','宋诗','song-poetry','','[]','道路已三月，山川猶昔年。',48,'全唐诗/poet.song.112000.json','["道路已三月，山川猶昔年。", "繡花紅委地，刺水綠平田。", "生計付身外，兒曹慰眼前。", "愈知貧有味，無夢到愁邊。"]'),
('ecd2677e-48f0-430a-97c6-43ac69c519e6','句','張洙','宋','宋诗','song-poetry','','[]','漫道玉爲堂，玉堂今夜長。',12,'全唐诗/poet.song.112000.json','["漫道玉爲堂，玉堂今夜長。"]'),
('306d2668-ecca-4b94-aad9-dad948fa0d34','錢塘感興','孫雄飛','宋','宋诗','song-poetry','','[]','百年承襲地，和氣媚芳塵。',48,'全唐诗/poet.song.112000.json','["百年承襲地，和氣媚芳塵。", "車馬當吳會，山川與楚鄰。", "酒樓絃管暮，花市綺羅春。", "風俗真佳麗，多應笑魯民。"]'),
('91682e52-0e3c-4822-8727-4bbe22afb6ca','靈隠蓮峰堂','孫雄飛','宋','宋诗','song-poetry','','[]','堂開金色界，梵客爲鉤簾。',48,'全唐诗/poet.song.112000.json','["堂開金色界，梵客爲鉤簾。", "山影碧侵座，水聲清繞簷。", "粉雲埋石脚，珠露泣松髯。", "終擬携孤笛，憑欄喚玉蟾。"]'),
('6ca92b6c-1cda-4799-aa90-35d79159d9d3','上天竺','孫雄飛','宋','宋诗','song-poetry','','[]','行窮湖上徑，迤邐到林巒。',48,'全唐诗/poet.song.112000.json','["行窮湖上徑，迤邐到林巒。", "地瘦馬蹄澀，水清山骨寒。", "樓臺棲樹杪，鐘磬閙雲端。", "自笑利名役，未能來挂冠。"]'),
('5ef88973-474b-41a8-9a03-0f4b28a75e13','句','任盡言','宋','宋诗','song-poetry','','[]','切勿填河漢，須留洗甲兵。',12,'全唐诗/poet.song.112000.json','["切勿填河漢，須留洗甲兵。"]'),
('9cde91f5-ebf1-4032-b4cc-23c64e6f5052','早起偶成','仲并','宋','宋诗','song-poetry','','[]','晨光起天末，微風動林杪。',72,'全唐诗/poet.song.112000.json','["晨光起天末，微風動林杪。", "披衣初夢回，捲書倦清曉。", "隠几欲無寐，百念自憂悄。", "簞瓢舊獨樂，樂意今亦少。", "豈但感時節，政欲避煩擾。", "我非斯人徒，區區務自了。"]'),
('249a2708-2817-4473-bdc3-fd21fc31f41e','寒食日歸吳興寄魯山','仲并','宋','宋诗','song-poetry','','[]','風雲雖不定，日雨亦易乾。',60,'全唐诗/poet.song.112000.json','["風雲雖不定，日雨亦易乾。", "殘春猶凜凜，助我朝食寒。", "想見芳野田，士女游班班。", "去者日以疏，更爲來者歡。", "青紅間車馬，日暮醉墦間。"]'),
('e3b5650c-db2e-415a-a59b-fdcb01aaa888','題大明寺','仲并','宋','宋诗','song-poetry','','[]','招提隠松桂，遠在城一隅。',132,'全唐诗/poet.song.112000.json','["招提隠松桂，遠在城一隅。", "我來歲云暮，天寒氣象殊。", "寓目得佳趣，百念如滌除。", "及此齋時鐘，簞瓢慰吾臞。", "丈室曦未來，香篆沈熏爐。", "聊施濟勝具，未暇學跏趺。", "緩步大明寺，山光佳有餘。", "郊原自春色，物意如相娛。", "習公四海士，豪氣編虎鬚。", "邂逅偶傾蓋，清遊邀我俱。", "相從得二謝，笑語寄歌呼。"]'),
('5c62e154-36db-4738-b33e-fec4c99350f0','送大理金少卿赴闕以老成耆德重于典刑爲韵兼寄呈刑曹徐侍郎  其一','仲并','宋','宋诗','song-poetry','','[]','霜餘日初杲，遮留人擁道。',48,'全唐诗/poet.song.112000.json','["霜餘日初杲，遮留人擁道。", "公來春向闌，公去秋垂老。", "公當侍丹墀，正人國之寶。", "行行那得留，仍視玉堂草。"]'),
('19ba7fda-d7d8-47de-a744-ae2e27ed592f','送大理金少卿赴闕以老成耆德重于典刑爲韵兼寄呈刑曹徐侍郎  其二','仲并','宋','宋诗','song-poetry','','[]','憶昔游成均，千言談笑成。',48,'全唐诗/poet.song.112000.json','["憶昔游成均，千言談笑成。", "傑立羣雋上，少日騰英聲。", "大當持荷橐，小當登蓬瀛。", "戢翼久不振，一旦朝陽鳴。"]'),
('7140170d-69fd-48d5-9334-e85c740fd646','送大理金少卿赴闕以老成耆德重于典刑爲韵兼寄呈刑曹徐侍郎  其三','仲并','宋','宋诗','song-poetry','','[]','全璧公之歸，有識爲嗟咨。',48,'全唐诗/poet.song.112000.json','["全璧公之歸，有識爲嗟咨。", "外祠三拜命，歷歲艾且耆。", "乘流與遇坎，道在他何知。", "汪汪波萬頃，未許兒輩窺。"]'),
('745bdbb1-3355-4079-a330-050f9a39976a','送大理金少卿赴闕以老成耆德重于典刑爲韵兼寄呈刑曹徐侍郎  其四','仲并','宋','宋诗','song-poetry','','[]','高山列松柏，歲寒寧動色。',48,'全唐诗/poet.song.112000.json','["高山列松柏，歲寒寧動色。", "顔巷一簞瓢，掩關養吾直。", "紛紛聲利場，時勝時奔北。", "袖手了不關，昂然見全德。"]'),
('cfa04eeb-6348-494f-b82b-fd65328cbfe6','送大理金少卿赴闕以老成耆德重于典刑爲韵兼寄呈刑曹徐侍郎  其五','仲并','宋','宋诗','song-poetry','','[]','九重聖端拱，慨念人材重。',48,'全唐诗/poet.song.112000.json','["九重聖端拱，慨念人材重。", "澄清鴛鷺行，拔尤鋤猥茸。", "輔郡與畿甸，連歲拜殊寵。", "付君天下平，民寃自無壅。"]'),
('88f0ed48-1c6e-4e99-9654-4a678ce0ed87','送大理金少卿赴闕以老成耆德重于典刑爲韵兼寄呈刑曹徐侍郎  其六','仲并','宋','宋诗','song-poetry','','[]','疇昔公何如，盡讀天下書。',48,'全唐诗/poet.song.112000.json','["疇昔公何如，盡讀天下書。", "公今復何似，未如張與于。", "皋陶當日語，一一皆世模。", "但令犴獄空，安用高吾閭。"]'),
('b955083c-75c1-46f7-b870-ec42de96f42f','送大理金少卿赴闕以老成耆德重于典刑爲韵兼寄呈刑曹徐侍郎  其七','仲并','宋','宋诗','song-poetry','','[]','澆風昔未殄，向隅或不免。',48,'全唐诗/poet.song.112000.json','["澆風昔未殄，向隅或不免。", "上心天地心，哀矜用中典。", "卿聯慎所付，遂極天下選。", "議讞聊小試，經綸期一展。"]'),
('82e84af0-535a-460c-b45d-b85c000cfdb1','送大理金少卿赴闕以老成耆德重于典刑爲韵兼寄呈刑曹徐侍郎  其八','仲并','宋','宋诗','song-poetry','','[]','指日公旋登，政席仍樞庭。',48,'全唐诗/poet.song.112000.json','["指日公旋登，政席仍樞庭。", "坐令貧病士，少慰身飄零。", "問訊徐夫子，起處秋安寧。", "兩翁廟堂具，那得長司刑。"]'),
('4038eb5d-1aa0-4d26-9653-37e5e7ac606b','錢檢法及代期以詩告別因次其韵','仲并','宋','宋诗','song-poetry','','[]','昔年兩岸柳，逢春正依依。',288,'全唐诗/poet.song.112000.json','["昔年兩岸柳，逢春正依依。", "扁舟轉河曲，風光隨處宜。", "彈指歲云何，秋風橘柚垂。", "折腰得斗粟，未救臣朔饑。", "儒宮一何有，惜哉壯觀隳。", "采采池中芹，亂葑迷漣漪。", "蕭條住槐市，庭空蔓草滋。", "丹雘墮煨燼，草木含瘡痍。", "永懷千古人，雜佩思報之。", "我乃但便腹，未免兒輩嗤。", "斯辰况多艱，每懷廢晨炊。", "疇昔請長纓，唾手平龜茲。", "西畧收咸京，北伐空鮮卑。", "坐令王室尊，國風無黍離。", "力微不辦此，千愁鎖修眉。", "承惠謝微官，一室投荒陂。", "吳山險可攀，吳水清可窺。", "勝概苦邀予，投紱今去遲。", "王孫定偉器，尺璧無纖疵。", "枯棋屢賈勇，佳篇仍致師。", "一日不會面，悠悠勤我思。", "大軸插牙籤，細字攻毛錐。", "朝廷羅羣公，如君滄海遺。", "勿學貧賤交，自比山林姿。"]'),
('c1eb748f-9c5f-4f21-b8ed-04dc18e0f66f','七月二十日過王村幾到岸遇和中襲明舟回相拉宿於陳氏庵中蚊甚盛達旦不能寢','仲并','宋','宋诗','song-poetry','','[]','畏暑肩暫息，初凉戒我行。',168,'全唐诗/poet.song.112000.json','["畏暑肩暫息，初凉戒我行。", "王村去城市，捷帆片時程。", "到岸纔咫尺，兩君笑相迎。", "回棹不自由，劇談底裏傾。", "却泊紅蓮渚，支筇叩禪扃。", "闤闠未有此，一見心眼清。", "日暮山蕭然，風來竹有聲。", "危亭仍解衣，坐久太清生。", "携枕共席地，醉言强作醒。", "蚊聲喧不寐，談餘已窗明。", "他鄉各蓬轉，易散難合并。", "共居雖一溪，相望南北城。", "勝處偶同踐，輕去寧無情。", "慇懃拂素壁，留詩當題名。"]'),
('b6806cdb-5113-4480-965b-788c4cf225a8','奉和陳德召遊惠山見寄三十韵','仲并','宋','宋诗','song-poetry','','[]','飛埃喜污人，餘事忌掛眼。',288,'全唐诗/poet.song.112000.json','["飛埃喜污人，餘事忌掛眼。", "酒浪綠可親，山光翠相挽。", "折腰素非願，被面有餘赧。", "從來萬事空，此去百念滿。", "恰憶茲山遊，判作經年款。", "駕言隨所如，歌笑爲君莞。", "洗耳聽潺湲，緩步踏𡾰嵼。", "褰裳跨風磴，捫蘿度雲棧。", "禾黍豈離離，棗下初纂纂。", "川原供遐矚，筍蕨中去莧。", "桃李傾城姿，松杉萬金産。", "雪浪逗冰泉，乳花浮玉碗。", "相望一牛鳴，不憚四牡痯。", "層閣神所宅，敗簷我將館。", "心求千佛印，手罷七年板。", "勝槩何時無，羈懷自悲潸。", "小院昔徜徉，東風未暄暖。", "夜語聯僧榻，晨炊共華饌。", "羊腸一分襟，雁背幾折簡。", "於今懷舉桉，過公倦開琖。", "早知玉樹摧，不如春思短。", "塵容久難贖，樂事貧益罕。", "佳篇分錦繡，和氣回絃管。", "差肩招隠些，下視廣陵散。"]'),
('d335931f-a50b-4fc9-b102-67cfbfde63ff','祝子權以詩見招勉繼其韵','仲并','宋','宋诗','song-poetry','','[]','總角嗜學問，於心期可收。',204,'全唐诗/poet.song.112000.json','["總角嗜學問，於心期可收。", "歲月如逝水，倏忽二十秋。", "紛紛何所得，俗士難與謀。", "夫子四海士，不數韓荆州。", "摳衣一嘗會，頗輕萬戶侯。", "祝子晚傾蓋，緩急仍同舟。", "偉哉廊廟器，價高自難酬。", "相從半周星，會別嗟何稠。", "班荆此話舊，落落志益修。", "嗟我聞道晚，僅脫兒女憂。", "一斑幸時窺，稍知辨薰蕕。", "執經濫同席，得子真良儔。", "安得身爲雲，相陪汗漫遊。", "茫茫水東注，百川皆亂流。", "駑駘飽束芻，市者常易售。", "借問諸夫子，爲功忌中休。", "此語期同踐，此外復何求。"]'),
('86273252-8e38-4817-9819-4759564c780d','送周元特侍郎守宣城','仲并','宋','宋诗','song-poetry','','[]','西風迎公來，東風送公去。',288,'全唐诗/poet.song.112000.json','["西風迎公來，東風送公去。", "尚欲留朱轓，公行不可住。", "無酒對公傾，有懷爲公賦。", "夫子文武資，亦復廊廟具。", "剛方仰術業，坦夷見襟度。", "青衫試州縣，機鋒微已露。", "吾意有不可，萬夫挽不顧。", "翱翔諸公間，籍甚當時譽。", "峩冠上烏臺，直諫汲長孺。", "風雲千載合，冕旒一言寤。", "凜凜議論餘，可使淮南懼。", "天威瞻咫尺，政塗去跬步。", "興逸頓言歸，解佩苕溪路。", "湖山聊寄懷，詩書尚溫故。", "中外豈不殊，進退自餘裕。", "宣城唇齒邦，望公來何暮。", "我饑我顰呻，公飯公覆護。", "舉首望旌戟，指期詠襦袴。", "平生觸邪手，不難鋤弊蠹。", "雙溪疊嶂間，按堵百無慮。", "坐席豈容溫，當饋意久注。", "獻納念伏蒲，謀謨懷借箸。", "行矣股肱良，歸作腹心助。", "要觀今周公，聲名三吐哺。"]'),
('35291fa8-8f89-42be-b1f7-e714abf2233c','和何樞密題楚頌亭韵','仲并','宋','宋诗','song-poetry','','[]','山林與鐘鼎，各了一世緣。',204,'全唐诗/poet.song.112000.json','["山林與鐘鼎，各了一世緣。", "千年眉山翁，生氣猶凜然。", "菟裘視陽羨，賣劒將老焉。", "此志空泉扃，禾黍荒故園。", "尚餘種橘帖，會有異世賢。", "西清廣川公，文翰鬰雙全。", "新篇來西樞，句句清可絃。", "廊廟須公歸，寧容一壑專。", "九重最深眷，每轉從諫圜。", "絕唱今寡和，惜哉坡已仙。", "回視楚臣些，並馳爭孰先。", "况復黄絹碑，光耀荆溪邊。", "此亭會不磨，名與兩公傳。", "幾株羅瀟湘，便覺饒風烟。", "不比濯錦江，榿木須三年。", "行矣凉飈起，霜滿千崖巔。", "香霧噴四坐，滿引杯垂蓮。"]'),
('ba443a6d-ad5a-4386-b39c-a42a7b9bc80b','同祝子權遊虎邱','仲并','宋','宋诗','song-poetry','','[]','出門迎朝暾，入門餞夕陽。',180,'全唐诗/poet.song.112000.json','["出門迎朝暾，入門餞夕陽。", "豈願從吾駟，聲名跨楚梁。", "明日聊與君，褰裳陟危岡。", "方舟轉河曲，薰風度微凉。", "細看槐柳暗，稍覺薝萄香。", "天高散霞綺，雲浄呈天光。", "梵宮占地勝，古木參天長。", "禽鳥亦自得，嗚呼聲激昂。", "緩步信携筇，清流足飛觴。", "乃知聲利役，脫去非無方。", "所憐雄麗地，千年隴樹荒。", "石頑尚莓苔，劍逝寧光芒。", "自今一瞬息，江山幾興亡。", "我衰漸落寞，樂極淚淋浪。", "寄謝同心人，無驚鬢毛黄。"]'),
('7eee00a4-2a99-4e9b-9945-503028599dde','志師自通州訪我於儀真因携之至長蘆留語數日及其歸也作詩以送之','仲并','宋','宋诗','song-poetry','','[]','通州瞿曇師，多於雁鶩行。',96,'全唐诗/poet.song.112000.json','["通州瞿曇師，多於雁鶩行。", "吾常愛志僧，謂之一鳳凰。", "不見十五載，訪我大江傍。", "留之固未遣，載以荆州航。", "相從三日遊，山晚松風長。", "爾我豈其夢，嗒然堯桀忘。", "凌晨洗一鉢，束衣還故鄉。", "爲子植梧桐，何時復來翔。"]'),
('dc858c0a-5a56-47ff-bb87-c382d275822e','舟過仁王寺因口占一首','仲并','宋','宋诗','song-poetry','','[]','平野綠遠近，晴山翠縱橫。',144,'全唐诗/poet.song.112000.json','["平野綠遠近，晴山翠縱橫。", "西風今日凉，天意濟此行。", "居士十日病，快意身已輕。", "逢寺聊少憩，山僧苦相迎。", "豈爲餘事來，泉石鍾吾情。", "風生本何意，松篁得之清。", "向來城市口，無此笙竽聲。", "坐久百念歇，一雨秋意生。", "所恨二三子，無懷可同傾。", "少日戒客氣，四十猶未平。", "一事一錯誤，百年幾折肱。", "不如謝公等，窮山掩柴扃。"]'),
('ab3d424e-1095-43dd-a481-8dd66ca2543e','鄭漕生辰代幾先作','仲并','宋','宋诗','song-poetry','','[]','至公無轍跡，萬變歸諸正。',144,'全唐诗/poet.song.112000.json','["至公無轍跡，萬變歸諸正。", "誰云學則然，要在成以性。", "我公鍾間氣，異稟剛且勁。", "一毫不容私，心境自澄映。", "超然是非表，燭物眼常浄。", "還將溟渤量，一了百川競。", "由來仁者壽，茲理天所命。", "欲知椿齡永，視此寬平政。", "桂華弄小春，晚香適再盛。", "年年幾望月，影泛杯中聖。", "尚書心如水，遠裔有餘慶。", "何以繼清風，家聲南北鄭。"]'),
('bba2bddc-2f77-4b40-a476-a5ffd8917a45','戲李彥平李德邵','仲并','宋','宋诗','song-poetry','','[]','人生貴適意，自苦良亦癡。',252,'全唐诗/poet.song.112000.json','["人生貴適意，自苦良亦癡。", "百年同夢幻，富貴安所施。", "我生世緣薄，疲弱不可支。", "紛華豈不佳，自覺心已辭。", "歸來時自笑，撫手長嗟咨。", "人生行樂耳，勳業知何時。", "兩李近豪放，高懷不少卑。", "謫仙已云歿，流風宛在茲。", "平子韵絕俗，豪逸真吾師。", "萬事一粲然，不復論成虧。", "邵公蘗菴下，操心常苦危。", "易象魯春秋，憂樂常相隨。", "端居談利害，羌夷可鞭笞。", "近亦能稍稍，笑語隨兒嬉。", "平居如二子，廊廟真所宜。", "人豈不自省，何必求蓍龜。", "漫遊恐未免，慎勿差毫釐。", "世事足反覆，紛紛盡如斯。", "錯固不足道，誼也亦爲之。", "請復銘座右，政可爲吾規。", "前言戲之耳，未來容可追。"]'),
('114c0149-491e-4302-9ee9-989819e77c41','元宵微雨十六夜雨止見月','仲并','宋','宋诗','song-poetry','','[]','燈火千門競是日，出戶黄昏雲抹漆。',64,'全唐诗/poet.song.112000.json','["燈火千門競是日，出戶黄昏雲抹漆。", "夜光乘闇何處投，冷淡行人悵如失。", "明朝風清天動色，雲陰初若龜兆坼。", "須臾白盤升天東，相如歸來更全璧。"]'),
('e916a5fb-5c5e-4b3e-bb54-89a5fae11dcf','舟行用前韵懷祝子權','仲并','宋','宋诗','song-poetry','','[]','楊枝巧作腰支弱，不分小桃紅入萼。',128,'全唐诗/poet.song.112000.json','["楊枝巧作腰支弱，不分小桃紅入萼。", "風光向人但嫵媚，客子那知行路惡。", "短篷蕩漾晴波裏，取次茶深酒薄薄。", "所思故人殊未來，悲風爲我生絕壑。", "塵沙隔年不相見，結鄰空記他時約。", "相看一字不寄將，剩有新知豈云樂。", "眼前俗士敗意耳，憶君歲歲空牢落。", "炯炯眉目端可思，月照西廊暮雲廓。"]'),
('3a10ea3f-4be3-490e-b74d-07e45254f61c','建昌守楊吉老得居湖州山間作亭於上名曰弁輝爲長句以記之','仲并','宋','宋诗','song-poetry','','[]','白首苕溪幾我鄉，青眼弁山如故友。',320,'全唐诗/poet.song.112000.json','["白首苕溪幾我鄉，青眼弁山如故友。", "誅茅晚歲合巖棲，漂梗一生嗟浪走。", "往往每來每太息，去去一步一回首。", "簷楹之雄誰氏室，基堂宜爲後人有。", "榮華謬作長久計，蕩盈要以仁誼守。", "室空無人人不問，天固遺公公信否。", "輪奐雅宜鳳池人，權輿本自鳳池手。", "付之勳閥可無憾，會與令名俱不朽。", "雅懷卜鄰非卜居，囂塵可暫不可久。", "新亭巀嵲城之巔，佳致回環天所就。", "與山似有他年約，相嚮每爲長者壽。", "碧鮮蒼潤被草木，煖翠晴光排戶牖。", "時復一觴澆磊磈，下視羣峰皆培塿。", "乃知韞玉山有輝，更覺看山公不負。", "向來曾試西垣策，只今聊綰南豐綬。", "胸中水鑑極涇渭，筆下瑰辭粲瓊玖。", "傾蓋視我平生交，曳裾陪公衆客後。", "喜見成都宅一區，恨無負郭田數畝。", "去住還當慚二老，窮獨已復成一叟。", "門前剝啄非他人，我來問字不載酒。"]'),
('ec9fcac5-9f04-4dd0-9810-08c3c382ffd9','陳行之得之因震澤舊居闢小閣面列洞庭山客有名以尊經者江都仲某爲長句以紀之','仲并','宋','宋诗','song-poetry','','["\u6d1e\u5ead\u6e56"]','洞庭之野排千巖，陳子卷簾非愛山。',256,'全唐诗/poet.song.112000.json','["洞庭之野排千巖，陳子卷簾非愛山。", "震澤之流清沒底，陳子憑欄不觀水。", "傑閣橫空一事無，終年傳習唯父書。", "乃翁平時束五傳，絕人偉論驚諸儒。", "至寶不受久埋沒，近者私記刊吳都。", "搢紳駢肩快先睹，一言價重百車渠。", "正派源流要有自，二難秀發名家駒。", "少小辛勤門戶計，皇天有知子不孤。", "於今三十五經立，亹亹雄辯來起予。", "不但家法傳羣紀，經學當與心法俱。", "溪山相對無浪語，寶此一編時卷舒。", "自憐早歲已漂泊，乃翁邀我來僧廬。", "於今壎篪弦誦地，當時從容談笑餘。", "契闊死生三十載，萍浮蓬轉常崎嶇。", "子能箕裘萬事足，其他得喪爭錙銖。", "凜凜清氛端可想，神遊彷彿歸來歟。"]'),
('35015cd5-3069-4fcb-8bdb-95ee3b5304f9','避暑報恩觀','仲并','宋','宋诗','song-poetry','','[]','萬家九陌車塵中，丹甍碧瓦真人宮。',96,'全唐诗/poet.song.112000.json','["萬家九陌車塵中，丹甍碧瓦真人宮。", "回廊小院畧具體，清風爽氣無能同。", "殿簷密有杉松護，炎蒸縱酷來無從。", "偶因謁客凌晨入，歸逕往往侵昏鐘。", "道人坐穩知樂否，我生半世猶飄蓬。", "茅簷與此異寒暑，分毫不透東南風。"]'),
('f818ff06-515c-43d1-a22d-3f59028ad49b','外舅莊子尚生辰','仲并','宋','宋诗','song-poetry','','[]','荆溪之山環千峰，摩空巉絕相爭雄。',192,'全唐诗/poet.song.112000.json','["荆溪之山環千峰，摩空巉絕相爭雄。", "與公萬仞俱壁立，祇有爽氣蟠胸中。", "荆溪之流碧滿野，寒光秀色兼天瀉。", "與公雅量相對清，更覺波瀾來筆下。", "高門懸弧此日生，少年揮毫敵兩京。", "當時紫宸初射策，玉色臨軒知姓名。", "一旦橫經向儒苑，鳳掖鑾坡去非遠。", "如今高卧尚琳宮，主父嚴徐見何晚。", "向來皂蓋先一州，龔黄已往無此流。", "旰食我皇收士急，未容獨樂林泉幽。", "華堂宴笑春風裏，水綠山青助公喜。", "三槐功就却歸來，壽如此山如此水。"]'),
('56281645-6195-4438-80f8-dac6eb3676f7','代人上師垣生辰三首  其一','仲并','宋','宋诗','song-poetry','','[]','玉带金魚衮繡光，維垣一旦侍君王。',160,'全唐诗/poet.song.112000.json','["玉带金魚衮繡光，維垣一旦侍君王。", "垂紳廟堂調玉燭，能使天公時雨暘。", "疇昔干戈歲屢歉，於今萬室盈倉箱。", "天心人意若相語，問公何以迴穹蒼。", "天惡人心二三德，公惟一德妙贊襄。", "夜半熟視璿霄象，紫微列宿相熒煌。", "甘露醴泉不足瑞，但欲歲歲占農祥。", "物阜人嬉了無事，斯民擊壤君垂裳。", "時時公亦憩傑閣，萬物欣欣春晝長。", "當時尹躬似今日，但欠昭回雲漢章。"]'),
('542df72b-2f22-4604-87ea-bf88acbfca01','代人上師垣生辰三首  其二','仲并','宋','宋诗','song-poetry','','[]','天寒歲律今崢嶸，御街鐘鼓天初明。',160,'全唐诗/poet.song.112000.json','["天寒歲律今崢嶸，御街鐘鼓天初明。", "近臣日報君顔喜，問寢慈寧聖主情。", "萬年洩洩融融樂，此事無與凡公卿。", "父老問某何臻此，天子用孝公用誠。", "向來瞻雲一萬里，雁書不到江南城。", "初决和戎蓋公策，來歸騶馭人歡迎。", "九重日奉天下養，禁苑蟠桃春自生。", "當時若用他人說，至今未見風塵清。", "前代功臣豈不有，未有彷彿公勳名。", "封人考叔陋籌策，區區但捨君之羹。"]'),
('608c5a94-7e92-4f3a-b269-fdf000839ee3','代人上師垣生辰三首  其三','仲并','宋','宋诗','song-poetry','','[]','化工作意辦春來，斗柄明朝後日回。',144,'全唐诗/poet.song.112000.json','["化工作意辦春來，斗柄明朝後日回。", "東風先到江南岸，江山濯濯無塵埃。", "靈光葱葱隨處有，夜半兩兩明三台。", "天遣異人爲時出，要作霖雨澤九垓。", "明堂藉此一柱壯，他山之木皆凡材。", "如今國勢盤泰華，向來天步屯雲雷。", "歲歲年年競是日，人人爭欲持壽杯。", "天知調羹付公手，江梅不爲他人開。", "長生唯在一清浄，別無方丈并蓬萊。"]'),
('9da2d8c1-384d-4038-8fe5-009f0d0b70a3','沈正卿得男以詩慶之','仲并','宋','宋诗','song-poetry','','[]','乃翁壁立千仞餘，乃翁摛章錦不如。',224,'全唐诗/poet.song.112000.json','["乃翁壁立千仞餘，乃翁摛章錦不如。", "英風雅韵來無盡，川媚還復生明珠。", "華堂寧無侍巾櫛，娉婷試問誰家姝。", "嬋娟深鎖人不見，忽驚清曉懸門弧。", "聞是高秋生驥子，充閭喜氣相縈紆。", "大父大母顧之笑，乃翁再拜爲親娛。", "公家餘慶得英物，渥洼自有名家駒。", "摩頂尚記前生誤，墮地舉手一笑俱。", "夙習如斯定夙寤，少小便應傳父書。", "公卿衮衮自今始，行矣家慶端可圖。", "佳辰清樽來賓友，母愛子抱集坐隅。", "臭味芝蘭席上客，爲公贊喜容歌呼。", "我衰我倦毋多酌，老矣醉倒須人扶。", "留取明年會湯餠，要看徐卿第二雛。"]'),
('cdab252d-a62f-422a-9edc-94df98f8b9a3','詠竹','仲并','宋','宋诗','song-poetry','','[]','自結高人伴，雅無俗士緣。',48,'全唐诗/poet.song.112000.json','["自結高人伴，雅無俗士緣。", "驅之傍城市，勁節非所便。", "未論傲霜雪，試欲藏風煙。", "願留舊青眼，歲晚相周旋。"]'),
('27c75dd0-4f59-4f4b-b0c2-06a1f8792da5','遊靈巖詩  其一','仲并','宋','宋诗','song-poetry','','[]','古寺青楓外，平湖暮靄西。',48,'全唐诗/poet.song.112000.json','["古寺青楓外，平湖暮靄西。", "亂花經雨薄，冷蝶趁人低。", "俯檻留連語，聽禽自在啼。", "風光兼客恨，樽遊故須携。"]'),
('80a9c5ca-4e11-457b-b4b9-9df75d153e8f','遊靈巖詩  其二','仲并','宋','宋诗','song-poetry','','[]','移舟晨鼓閙，泊渚暮鴉盤。',48,'全唐诗/poet.song.112000.json','["移舟晨鼓閙，泊渚暮鴉盤。", "夾岸柳渾暗，橫軒梅半殘。", "最憐春日薄，猶動客衣寒。", "樓外西風急，雲湖看湧瀾。"]'),
('66303bed-9a24-4ff6-92f2-a84479c92651','舟行再用前韵  其一','仲并','宋','宋诗','song-poetry','','[]','一棹苕溪去，千門榆火新。',48,'全唐诗/poet.song.112000.json','["一棹苕溪去，千門榆火新。", "老來猶是客，病起怯逢春。", "儒館妙人物，吟毫泣鬼神。", "平生經濟業，勉矣正逢辰。"]'),
('273e51a3-1bea-4036-bf67-3959d5947df5','舟行再用前韵  其二','仲并','宋','宋诗','song-poetry','','[]','行藏那用卜，皺面不重紅。',48,'全唐诗/poet.song.112000.json','["行藏那用卜，皺面不重紅。", "又作都城別，長懷國士風。", "折巾從有道，斗酒對無功。", "一夢何時續，南窗笑語中。"]'),
('f42e91e8-3103-4025-8a78-1d8c0600680b','覺華山居三首  其一','仲并','宋','宋诗','song-poetry','','[]','竟日人聲斷，空山一二家。',48,'全唐诗/poet.song.112000.json','["竟日人聲斷，空山一二家。", "猶憐中夜雨，不礙曉來花。", "健飯蔬如肉，衝寒酒當茶。", "飛潛各有性，貧樂付天涯。"]'),
('75621131-e819-473f-a493-61747ffdb4b5','覺華山居三首  其二','仲并','宋','宋诗','song-poetry','','[]','舊雨無人到，非緣今不來。',48,'全唐诗/poet.song.112000.json','["舊雨無人到，非緣今不來。", "蔬盤春後足，經卷粥前開。", "燕語緣人去，禽聲逐夢回。", "勤披頻得句，隨量日持杯。"]'),
('607a55ae-d548-4bbf-aef6-8d55941e7263','覺華山居三首  其三','仲并','宋','宋诗','song-poetry','','[]','倏起郊扉念，亟回朝市轅。',48,'全唐诗/poet.song.112000.json','["倏起郊扉念，亟回朝市轅。", "君恩如父母，山迥亦乾坤。", "援筆醉醒語，携筇前後村。", "是非襟度外，客至總休論。"]'),
('60ddf807-a312-4f52-91bb-819db31a0144','歲晚泊姑蘇用呂居仁舍人韵二首寄孟信安  其一','仲并','宋','宋诗','song-poetry','','[]','斷岸留孤棹，層臺聳近城。',48,'全唐诗/poet.song.112000.json','["斷岸留孤棹，層臺聳近城。", "雁傳他邑信，鷗背去年盟。", "幾片雪多思，一枝梅有情。", "何人在樓上，吹笛暮寒生。"]'),
('0a3836c1-5759-468f-8384-0dc5748bfb11','歲晚泊姑蘇用呂居仁舍人韵二首寄孟信安  其二','仲并','宋','宋诗','song-poetry','','[]','睡穩窗遲曉，愁多鬢易秋。',48,'全唐诗/poet.song.112000.json','["睡穩窗遲曉，愁多鬢易秋。", "祇堪浮小艇，不擬上西樓。", "無盡江山景，須陪杖屨游。", "一區何日辦，孰爲我公留。"]'),
('401f85ef-6c48-42c0-bde2-a3b69d49fe17','泰興道本上人少時頗留意詩律已而遍歷諸方卒無終歲之寧今垂五十矣自淮鄉過余於吳興翌日來辭曰道本欲自越趨天童或自溫趨江心問道於覺了二士願聞一言爲書五字詩以送之','仲并','宋','宋诗','song-poetry','','[]','芒鞋亦良苦，歧路不曾休。',48,'全唐诗/poet.song.112000.json','["芒鞋亦良苦，歧路不曾休。", "句律可青眼，宗風已白頭。", "舌端頻自味，心外更何求。", "欲寄明年信，溫州定越州。"]'),
('d4f940c2-ab42-4441-b9be-0e52613ee8b7','韓侍郎  其一','仲并','宋','宋诗','song-poetry','','[]','带礪元勳後，熊羆吉夢初。',48,'全唐诗/poet.song.112000.json','["带礪元勳後，熊羆吉夢初。", "祥煙輝戶牖，喜色動門閭。", "丙魏功行致，韋平慶有餘。", "願言椿算遠，二十考中書。"]'),
('e2cf3693-0aaa-4835-bcb7-d18ff536dca0','韓侍郎  其二','仲并','宋','宋诗','song-poetry','','[]','社稷中興際，朝廷憶老成。',48,'全唐诗/poet.song.112000.json','["社稷中興際，朝廷憶老成。", "我公傳祖烈，美譽冠時評。", "相業光三世，官聯且貳卿。", "宸心方眷倚，行慶秉鈞衡。"]'),
('1316afae-6352-4b3f-8a9f-3922f1de6476','送致政節推朱子發歸無錫二首  其一','仲并','宋','宋诗','song-poetry','','[]','白髮倦場屋，一官初自娛。',48,'全唐诗/poet.song.112000.json','["白髮倦場屋，一官初自娛。", "幡然掛章紱，遽作卧江湖。", "耆舊添佳傳，都門續故圖。", "會當垂不朽，名與惠山俱。"]'),
('6b34a7d5-d6fa-4438-a7cb-a07719ef29b4','送致政節推朱子發歸無錫二首  其二','仲并','宋','宋诗','song-poetry','','[]','雞栖朱伯厚，來葉尚多賢。',48,'全唐诗/poet.song.112000.json','["雞栖朱伯厚，來葉尚多賢。", "吏案儘紛若，心田正坦然。", "林泉誰共樂，衣鉢子能傳。", "會有蒲輪到，朝煙夕靄邊。"]'),
('e605b33f-d5e8-44c2-90ca-585611781bd2','送泉州周尚書  其一','仲并','宋','宋诗','song-poetry','','[]','閭里推耆德，門庭只故居。',48,'全唐诗/poet.song.112000.json','["閭里推耆德，門庭只故居。", "綺羅看富室，丹碧衒新廬。", "潤屋寶非璧，滿車家有書。", "功名宜歲晚，带玉綴金魚。"]'),
('4c53ead3-190b-4be0-81e2-4eca51192fab','送泉州周尚書  其二','仲并','宋','宋诗','song-poetry','','[]','常若侍君側，寧論去幾程。',48,'全唐诗/poet.song.112000.json','["常若侍君側，寧論去幾程。", "政須懷宿望，寧得殿名城。", "執手欲何語，諛公恐不情。", "斯民艱食甚，第一勸春耕。"]'),
('6ec8bfc7-aa5a-4960-9fb2-8b4895ab76f1','送泉州周尚書  其三','仲并','宋','宋诗','song-poetry','','[]','得譽今銓筦，飛聲自諫垣。',48,'全唐诗/poet.song.112000.json','["得譽今銓筦，飛聲自諫垣。", "久知蒙帝可，不敢喪吾存。", "切切道涂喜，勤勤指顧言。", "我公今氣貌，猶是舊攀轅。"]'),
('64313707-92d1-46ff-81b4-ba996a78a236','送泉州周尚書  其四','仲并','宋','宋诗','song-poetry','','[]','別公今夜月，恰可一庭方。',48,'全唐诗/poet.song.112000.json','["別公今夜月，恰可一庭方。", "勇往先過建，徐行不到漳。", "同時三郡樂，指日四時康。", "勝地豈云遠，吾當騑乘黄。"]'),
('47999090-b06a-472f-b39a-44eabe2f4f13','送泉州周尚書  其五','仲并','宋','宋诗','song-poetry','','[]','身外從紛若，胸中固卓然。',48,'全唐诗/poet.song.112000.json','["身外從紛若，胸中固卓然。", "險夷唯故步，舒卷只遺編。", "錦繡文千段，珠璣詩幾聯。", "我公今愈健，筆力敵中年。"]'),
('e2bcd15c-f7a6-4223-ac12-abba08f8add2','送張持國省幹歸山陰三首  其一','仲并','宋','宋诗','song-poetry','','[]','臭味張公子，生涯類我貧。',48,'全唐诗/poet.song.112000.json','["臭味張公子，生涯類我貧。", "又爲兩鄉夢，看即一朝紳。", "洗眼千巖秀，抽身肥馬塵。", "他年乘夜雪，從子剡溪濱。"]'),
('436468d4-074b-41c3-8152-9fe2e8da281a','送張持國省幹歸山陰三首  其二','仲并','宋','宋诗','song-poetry','','[]','稠衆相從地，無言意已傾。',48,'全唐诗/poet.song.112000.json','["稠衆相從地，無言意已傾。", "余方厭藜藿，子肯扣柴荆。", "短棹起歸暮，長亭如別情。", "回頭聽羌管，拍拍喚愁生。"]'),
('77528568-97c8-4140-982b-9a05709ef6d7','送張持國省幹歸山陰三首  其三','仲并','宋','宋诗','song-poetry','','[]','埋輪賢使者，重席老先生。',48,'全唐诗/poet.song.112000.json','["埋輪賢使者，重席老先生。", "一別遽多歲，相望無幾程。", "到家乘暇日，爲我話深情。", "欲冩相思語，昏花字不成。"]'),
('8e94059d-77a8-4be7-a242-e138d14321ca','送劉大諫赴漳州四首兼寄建州太守趙左司  其一','仲并','宋','宋诗','song-poetry','','[]','海內聲名滿，溪頭且寓居。',48,'全唐诗/poet.song.112000.json','["海內聲名滿，溪頭且寓居。", "曾來非俗客，亦愛是吾廬。", "遠道勤爲問，平時懶作書。", "郡樓閒極目，細看北來魚。"]'),
('a9bafd16-2abe-4490-b531-e576dff837f4','送劉大諫赴漳州四首兼寄建州太守趙左司  其二','仲并','宋','宋诗','song-poetry','','[]','南國踰千里，西風幾十程。',48,'全唐诗/poet.song.112000.json','["南國踰千里，西風幾十程。", "凌寒初引道，投老試專城。", "貧賤荷公意，分携如此情。", "書來何處問，南浦寄深耕。"]'),
('3f777223-c074-4799-9a29-25deace39f87','送劉大諫赴漳州四首兼寄建州太守趙左司  其三','仲并','宋','宋诗','song-poetry','','[]','胄甲漢中壘，聲高昔諫垣。',48,'全唐诗/poet.song.112000.json','["胄甲漢中壘，聲高昔諫垣。", "幾年清議在，萬事此心存。", "臨遣再三意，褒嘉數十言。", "疾驅公未可，半路趣回轅。"]'),
('b644bab1-f2b1-4e9f-b8df-03f832b63bc3','送劉大諫赴漳州四首兼寄建州太守趙左司  其四','仲并','宋','宋诗','song-poetry','','[]','安穩甌閩路，介居天一方。',48,'全唐诗/poet.song.112000.json','["安穩甌閩路，介居天一方。", "雙旌誰出守，八郡莫如漳。", "日月中天近，風霜去路長。", "相知惟白首，端冕拜清光。"]'),
('80f9c152-c1da-41b8-a792-d7a06aef4589','代人上叔母張氏生辰三首  其一','仲并','宋','宋诗','song-poetry','','[]','雲漢良辰近，秋風一葉初。',48,'全唐诗/poet.song.112000.json','["雲漢良辰近，秋風一葉初。", "祥光連戶牖，喜色動門閭。", "蘋藻儀無間，芝蘭慶有餘。", "仁人宜上壽，不必問瀛居。"]'),
('77ffbf69-f132-4194-bb33-db0a89b9d5a9','代人上叔母張氏生辰三首  其二','仲并','宋','宋诗','song-poetry','','[]','仙閥流芳遠，吾門襲慶長。',48,'全唐诗/poet.song.112000.json','["仙閥流芳遠，吾門襲慶長。", "萱堂今壽考，樞府昔輝光。", "玉樹諸郎秀，金花寵命昌。", "欲知椿算久，辟穀有家方。"]'),
('0d97a2b3-4269-4483-a4db-c6d29c44cc9d','代人上叔母張氏生辰三首  其三','仲并','宋','宋诗','song-poetry','','[]','憶昔觀光際，溫顔獲屢親。',48,'全唐诗/poet.song.112000.json','["憶昔觀光際，溫顔獲屢親。", "奬提煩叔父，駑蹇負前人。", "幸會逢今日，飄颻愧此身。", "捧觴陪子姪，深覺仲容貧。"]'),
('8d470594-2746-4bd8-9ccd-a56d0b77b823','花前有感兼呈崔相公劉郎中','仲并','宋','宋诗','song-poetry','','[]','落花如雪鬢如霜，醉把花看益自傷。',64,'全唐诗/poet.song.112000.json','["落花如雪鬢如霜，醉把花看益自傷。", "少日爲名多檢束，長年無興可顛狂。", "四時輪轉春常少，百刻支分夜苦長。", "何事同生壬子歲，老於崔丈及劉郎。"]'),
('0d5bf950-c8d9-4b4b-8fae-aae4a10a9629','日暮繫舟','仲并','宋','宋诗','song-poetry','','[]','新晴不受短篷遮，繫纜持觴一太嗟。',64,'全唐诗/poet.song.112000.json','["新晴不受短篷遮，繫纜持觴一太嗟。", "柳岸蕭條難駐客，茅簷安穩不如家。", "百年有幾欲華髮，今日無多已暮鴉。", "五世鄉關澤未斬，欲歸心折雁行斜。"]'),
('4f09af79-89e8-488d-bd50-fcf23ea11e12','中秋不見月','仲并','宋','宋诗','song-poetry','','[]','照人明月故應圓，露冷風清八月天。',64,'全唐诗/poet.song.112000.json','["照人明月故應圓，露冷風清八月天。", "且看驚鸞呈妙舞，却愁落雁怯虛弦。", "裙裾老去真聊爾，色笑公當一粲然。", "小院不妨今夜雨，人間那有兩嬋娟。"]'),
('c6190d52-252c-498f-aeb8-fc6fa0087276','四老堂詩  其一','仲并','宋','宋诗','song-poetry','','[]','好上清班冠紫宸，抽身便作最閒身。',64,'全唐诗/poet.song.112000.json','["好上清班冠紫宸，抽身便作最閒身。", "疏梅茂竹幾多目，曲檻方池隨處春。", "兩兩脊令聽自好，重重華萼見長新。", "靈椿一樹婆娑甚，穩覆家庭四老人。"]'),
('bc5228fc-5a51-4854-a9e9-a43ad8c40e97','四老堂詩  其二','仲并','宋','宋诗','song-poetry','','[]','便勝從來三戟門，良金如友玉如昆。',64,'全唐诗/poet.song.112000.json','["便勝從來三戟門，良金如友玉如昆。", "天邊鴻雁空千里，堂上壎箎共一樽。", "自昔披榛扶社稷，幾人衣錦向邱園。", "商山曾爲留侯起，來作侯家異世孫。"]'),
('f1d16374-0857-4573-b446-a9e927b785e8','題趙有翼叢桂小山','仲并','宋','宋诗','song-poetry','','[]','剩引桂枝叢小山，鶩行姑去自餘閒。',64,'全唐诗/poet.song.112000.json','["剩引桂枝叢小山，鶩行姑去自餘閒。", "人懷崑玉未當價，花與萊衣相映斑。", "佳樹非烟曉葱鬰，幽泉不雨夜潺湲。", "頓移巖壑山陰道，競秀爭流一席間。"]'),
('b32d5915-5f08-4392-8e69-27a500ce35ef','題吳氏曠遠亭','仲并','宋','宋诗','song-poetry','','[]','高人心跡喜雙清，曠遠幽亭誰與名。',64,'全唐诗/poet.song.112000.json','["高人心跡喜雙清，曠遠幽亭誰與名。", "簷外落花仍落絮，坐中傾國與傾城。", "松聲傳壑風初急，帆影飄空浪未平。", "不盡樽中今日醉，匆匆輕去得無情。"]'),
('e88c028c-fa15-4233-aecd-3e35c6b29a94','後數年登曠遠亭用前韵再賦','仲并','宋','宋诗','song-poetry','','[]','坐客一時人物換，此山海內舊知名。',64,'全唐诗/poet.song.112000.json','["坐客一時人物換，此山海內舊知名。", "華筵爲我歌金縷，深院有人來石城。", "酒浪滿浮春浪碧，眉峰淺畫晚峰平。", "日斜柁轉各回首，松竹繞溪知此情。"]'),
('48fab041-11c5-445c-9bb4-af89e143807e','和馬丈遊劉園','仲并','宋','宋诗','song-poetry','','[]','槐柳參差覆地陰，薰風院落日沉沉。',64,'全唐诗/poet.song.112000.json','["槐柳參差覆地陰，薰風院落日沉沉。", "酒餘不覺愁何在，花底直疑春可尋。", "江水無情猶北渡，淮岑相對漫南音。", "憑高最動歸與念，卧聽疏蟬出晚林。"]'),
('cc5198e9-6c82-4b09-98d3-f1dcf603a654','李彥平寄題靜海吏隠堂二詩甚佳因賦一篇','仲并','宋','宋诗','song-poetry','','[]','黄綢被底衙聲罷，永日庭閒訟不譁。',64,'全唐诗/poet.song.112000.json','["黄綢被底衙聲罷，永日庭閒訟不譁。", "案上琴書延好客，江頭風月雜漁家。", "尚看葉令餘波在，正索騷人秀句誇。", "聞道芙蕖紅萬朵，遥知不減浣溪花。"]'),
('4e392f4c-affd-4756-93c4-49b3cb4883c8','題李德邵蘗庵  其一','仲并','宋','宋诗','song-poetry','','[]','綺繻不復尚驕奢，經始菟裘謝物華。',64,'全唐诗/poet.song.112000.json','["綺繻不復尚驕奢，經始菟裘謝物華。", "戶外韋衣真隠者，屏間孔雀尚豪家。", "幾年汗簡編檮杌，晚歲薰爐負辟邪。", "誰謂吾廬還有幸，卜鄰歸路不相賒。"]'),
('978380c4-346a-46dd-84b3-dad729f20cf0','題李德邵蘗庵  其二','仲并','宋','宋诗','song-poetry','','[]','懷抱如公政自嘉，衡門那復念京華。',64,'全唐诗/poet.song.112000.json','["懷抱如公政自嘉，衡門那復念京華。", "壯年底事已將老，作戲逢場新有家。", "此去車書應萬里，似聞廊廟屏羣邪。", "時平尤頼安戎策，未合幽棲去國賒。"]'),
('c900ef2e-8dce-429b-b034-ec319197d065','再呈德邵','仲并','宋','宋诗','song-poetry','','[]','草草茅簷儉異奢，坐觀物態盡空華。',64,'全唐诗/poet.song.112000.json','["草草茅簷儉異奢，坐觀物態盡空華。", "放懷近欲輕千戶，排難何當念兩家。", "壯歲我今成傳癖，清時君勿病官邪。", "他年政恐從名宦，回首菟裘恨太賒。"]'),
('d9bb1cfb-52b7-4cbf-a10c-f37145d64d4a','祝子權見寄時欲卜居合溪飛雲寺','仲并','宋','宋诗','song-poetry','','[]','環堤風漲雨溪深，半嶺雲飛一院陰。',64,'全唐诗/poet.song.112000.json','["環堤風漲雨溪深，半嶺雲飛一院陰。", "三徑定回俗士駕，百年今見故人心。", "時危天地烽塵滿，歲晚江湖客病侵。", "他日青雲各回首，向來黄閣子知音。"]'),
('0c816c68-7251-4821-a44a-cdd6188f1e3b','李孝叔趙有翼趙存中黄子登沈正卿曾同季有觀梅道場之約僕偶過西山不得陪六客之末歸讀衆作因繼韵','仲并','宋','宋诗','song-poetry','','[]','公皆車馬城南去，我向西郊漾小舟。',64,'全唐诗/poet.song.112000.json','["公皆車馬城南去，我向西郊漾小舟。", "人事好乖各回首，吾年如此喜乘流。", "金蘭六客稀時見，珠玉一篇無句酬。", "却數竹林猶少在，不妨著我伯倫劉。"]'),
('5d61c8be-542c-436c-8b64-801e3f50980f','和沈正卿諸公西湖賞梅','仲并','宋','宋诗','song-poetry','','["\u897f\u6e56"]','一笑相逢水一涯，近簷猶記舊相知。',64,'全唐诗/poet.song.112000.json','["一笑相逢水一涯，近簷猶記舊相知。", "似矜冰玉非凡骨，終倚雪霜開好枝。", "新綠成陰無幾日，微酸著子亦同時。", "諸公忍袖和羹手，空賦西湖處士詩。"]'),
('701ae513-4924-40b2-b437-7b27abf77111','和耿時舉梅雪二首  其一','仲并','宋','宋诗','song-poetry','','[]','百花看盡不如梅，故作凌寒殿後開。',64,'全唐诗/poet.song.112000.json','["百花看盡不如梅，故作凌寒殿後開。", "照水憐生勻粉處，隔簾抵死透香來。", "未令寄隴音塵斷，能覓巡簷句法回。", "羞殺漫山桃李樹，枉教春力費鎸裁。"]'),
('f98d37f1-ef30-423f-9bfc-2c0b6fc9c601','和耿時舉梅雪二首  其二','仲并','宋','宋诗','song-poetry','','[]','點酥嬌面試初芳，琢句真須琢玉郎。',64,'全唐诗/poet.song.112000.json','["點酥嬌面試初芳，琢句真須琢玉郎。", "聊與一枝論雅素，未須千葉間輕黄。", "斜簪髻畔隨人好，滿覆樽前借客香。", "誰引角聲人未寢，落梅聲裏看晨粧。"]'),
('2d26ec92-a166-4550-b9cd-b8b2a4bf3b90','舟過吳江謁臞庵翁少留爲賦二詩  其一','仲并','宋','宋诗','song-poetry','','[]','住家却學浮家樣，橫截江湖疊浪中。',64,'全唐诗/poet.song.112000.json','["住家却學浮家樣，橫截江湖疊浪中。", "漫說三高無起日，孰知千古可同風。", "長林蒙霧行平遠，層榭攀雲語半空。", "隄上繫舟何限意，匆匆著句未全工。"]'),
('8bd2743e-e540-403e-9a46-77c48aa057b7','舟過吳江謁臞庵翁少留爲賦二詩  其二','仲并','宋','宋诗','song-poetry','','[]','明明窗色極知晚，隔岸喧闐祇掩關。',64,'全唐诗/poet.song.112000.json','["明明窗色極知晚，隔岸喧闐祇掩關。", "上下亭臺烟雨外，參差花竹水雲間。", "從多莫剪東南柳，勝絕新增西北山。", "客路十年辛苦裏，也容一日及公閒。"]'),
('ff73b5a1-7be3-4792-8f0e-4b3f44fbb356','陪王樞密飯坐間示新詩因次其韵','仲并','宋','宋诗','song-poetry','','[]','相業兵韜材總堪，君王喜與阿戎談。',64,'全唐诗/poet.song.112000.json','["相業兵韜材總堪，君王喜與阿戎談。", "樞機旋轉斗垂北，殿閣邃清風自南。", "主聖端如乾用九，公歸當待漢登三。", "史家莫比唐房杜，大似商宗舊學甘。"]'),
('19ee19a3-3c9c-4079-9140-f28437cc103c','用前韵別寄耿時舉二首  其一','仲并','宋','宋诗','song-poetry','','[]','樹猶如此我何堪，頼有隨齋可劇談。',64,'全唐诗/poet.song.112000.json','["樹猶如此我何堪，頼有隨齋可劇談。", "少日聲稱滿中外，幾年詞采秀東南。", "詩壇欲借背城一，材館均蒙吐哺三。", "每見匆匆又分去，與公交淡不須甘。"]'),
('71a33b5d-474a-4449-a0c4-98a824df5e5d','用前韵別寄耿時舉二首  其二','仲并','宋','宋诗','song-poetry','','[]','方兄於我一無堪，閉戶休休口不談。',64,'全唐诗/poet.song.112000.json','["方兄於我一無堪，閉戶休休口不談。", "憶昔茅簷差傍北，望公花塢恰平南。", "高歌頻舉巨觥一，佳唱如聞小雅三。", "投分素深貧酷似，相期同苦亦同甘。"]'),
('178298fc-89ef-414f-9add-d9eac0ced088','沈國錄席上用趙監丞韵  其一','仲并','宋','宋诗','song-poetry','','[]','晚來無計障風饕，美酒十千價未高。',64,'全唐诗/poet.song.112000.json','["晚來無計障風饕，美酒十千價未高。", "成敗兩奩供夜戰，醉醒一斗付春醪。", "流杯指日重修禊，琢句如公可命騷。", "多謝故人樂賓客，清歡十倍勝綈袍。"]'),
('3375b7bb-cb90-4b2f-9004-d7d32b7f810b','沈國錄席上用趙監丞韵  其二','仲并','宋','宋诗','song-poetry','','[]','杯觴盡醉老仍饕，似覺胡床步步高。',64,'全唐诗/poet.song.112000.json','["杯觴盡醉老仍饕，似覺胡床步步高。", "深院清香非柏子，公家重醖勝松醪。", "不須捧斚歌吳曲，看即揮毫繼楚騷。", "未盡餘春早歸去，談經當復慰青袍。"]'),
('0561bf4e-eb4d-460a-9216-cf1a90f2e772','翌日早起再用昨夕韵呈二丈','仲并','宋','宋诗','song-poetry','','[]','柳州老去腹寧饕，但喜衡陽紙價高。',64,'全唐诗/poet.song.112000.json','["柳州老去腹寧饕，但喜衡陽紙價高。", "乍暖風光如撲絮，相歡人意似投醪。", "家留溪上久漂泊，信斷淮南非驛騷。", "風浴舞雩那可緩，春衣替盡禦寒袍。"]'),
('c2223f71-8ead-4d39-85e4-a262e165b079','對雪用曾丈韵呈徐丈','仲并','宋','宋诗','song-poetry','','[]','鶴氅偏宜鶴髮翁，戲挼筇杖與兒同。',64,'全唐诗/poet.song.112000.json','["鶴氅偏宜鶴髮翁，戲挼筇杖與兒同。", "梅梢弄影半窗玉，柳徑吹綿三月風。", "擁戶且眠窗未晚，泛舟何向水如空。", "陽春便逐新詩到，不待葭灰落嶰筒。"]'),
('e1187043-a0ec-4d0b-ab65-5f70ac3a2228','再用前韵答徐聖可  其一','仲并','宋','宋诗','song-poetry','','[]','廼翁儒學似文翁，韵句天然無異同。',64,'全唐诗/poet.song.112000.json','["廼翁儒學似文翁，韵句天然無異同。", "社稷堂堂推故相，家庭挺挺見遺風。", "詞場已擅千軍敵，詩律仍驚萬馬空。", "願報瓊瑶無好語，朝來渾欲達空筒。"]'),
('d497f7ba-3fdc-4796-8e01-82481cc4af6e','再用前韵答徐聖可  其二','仲并','宋','宋诗','song-poetry','','[]','公方綠髮我成翁，猶喜芝蘭臭味同。',64,'全唐诗/poet.song.112000.json','["公方綠髮我成翁，猶喜芝蘭臭味同。", "雅奏黄鍾仍大呂，曠懷明月與清風。", "共高卞璧連城價，肯使衡茅四壁空。", "所望苕溪分一曲，郵籤日日遡歸筒。"]'),
('b86c53eb-70c0-4324-ac63-62927aa2b627','繼韵耿時舉寄示往歲梅雪','仲并','宋','宋诗','song-poetry','','[]','舊詩新讀更精神，雪裏招回未到春。',64,'全唐诗/poet.song.112000.json','["舊詩新讀更精神，雪裏招回未到春。", "俗眼驟驚銀可粉，天心忍用玉如塵。", "漫空柳絮千家到，轉眼梅花一夜新。", "物象區區勞比擬，申嚴詩令負前人。"]'),
('afab08d7-d2aa-484d-9f37-f873560fac0d','懷沈文伯','仲并','宋','宋诗','song-poetry','','[]','春服初成屬暮春，舞雩那似霅溪濱。',64,'全唐诗/poet.song.112000.json','["春服初成屬暮春，舞雩那似霅溪濱。", "繞溪簫鼓誰家子，並塞風烟吾故人。", "好去定無爲客恨，臨分猶復念予貧。", "驅車躍馬平安否，雁斷無因消息真。"]'),
('a335bf3a-6f58-45e0-b4b3-a46125851c69','鄭倅德興平江官滿有詩見寄次韵以敘老懷惜別之意','仲并','宋','宋诗','song-poetry','','[]','不奈飛埃點素衣，驚霜鬚鬢落全稀。',64,'全唐诗/poet.song.112000.json','["不奈飛埃點素衣，驚霜鬚鬢落全稀。", "隔簾初聽黄鸝語，舉盞那催畫鷁歸。", "就使淵明頻日醉，能爭伯玉幾年非。", "持竿欲老長城去，分我臨流半坐磯。"]'),
('f94e1a66-1334-4c86-9f9a-bb27149bed41','劉乾耀紹原昔同里巷以貧見過愧無以副其意輒成四韵爲別','仲并','宋','宋诗','song-poetry','','[]','舊時阡陌荆榛底，十載縱橫豺虎羣。',64,'全唐诗/poet.song.112000.json','["舊時阡陌荆榛底，十載縱橫豺虎羣。", "絳帳並遊那更得，烏衣羣從斷相聞。", "尚傳是是非非語，翻坐奇奇怪怪文。", "諛墓平生吾豈敢，了無一物壽劉君。"]'),
('0084d5de-7c03-4e6b-a073-28ae1676c6d1','歸自江陰寄蔣知郡汪簽判','仲并','宋','宋诗','song-poetry','','[]','維舟江口未棲鴉，急趁飛觴一笑譁。',64,'全唐诗/poet.song.112000.json','["維舟江口未棲鴉，急趁飛觴一笑譁。", "旋喜使君傾皂蓋，儘從醉客墮烏紗。", "高城不記人分袂，短棹空隨月到家。", "尚欲趨陪連夜飲，東籬容有後開花。"]'),
('57fdded6-510a-476f-bac2-6aee7cbe6858','和孟嶠之諸公遊虎邱一首','仲并','宋','宋诗','song-poetry','','[]','憑高休惜舉觴頻，聊結華嚴數面親。',64,'全唐诗/poet.song.112000.json','["憑高休惜舉觴頻，聊結華嚴數面親。", "筇杖止堪扶倦客，蒲團仍得憩閒身。", "雪霜侵鬢叵禁老，梅柳迎人俱欲春。", "後日重來應更好，南山排立畫簷新。"]'),
('d124e9a5-ae24-4008-aae2-5da6629337ba','用前韵奉寄孟嶠之','仲并','宋','宋诗','song-poetry','','[]','剩喜今年琢句頻，仍聞燈火夜相親。',64,'全唐诗/poet.song.112000.json','["剩喜今年琢句頻，仍聞燈火夜相親。", "懸知聳壑昂霄日，不負腰金拖玉身。", "攻苦詩書如白屋，加鞭辭藻正青春。", "古來孟氏好兄弟，餘韵未忘今轉新。"]'),
('a32cbff3-2965-4a1a-9c49-50246c68423a','再用前韵呈陳得之諸公','仲并','宋','宋诗','song-poetry','','[]','勳業毋庸攬鏡頻，空餘白髮向人親。',64,'全唐诗/poet.song.112000.json','["勳業毋庸攬鏡頻，空餘白髮向人親。", "未論骨相無三甲，細數年華有六身。", "泉石相看應笑我，萍蓬不定幾經春。", "尚須勇往趁晴日，竹外疏梅應斬新。"]'),
('3d55f6a9-6209-4b13-93d7-963ed7853332','呈彥平','仲并','宋','宋诗','song-poetry','','[]','詩人老去倍傷秋，我亦秋來尚黑頭。',64,'全唐诗/poet.song.112000.json','["詩人老去倍傷秋，我亦秋來尚黑頭。", "世事可憐催晚景，皇天未許減羈愁。", "不堪敗菊愁彭澤，又見寒雲餞蓐收。", "旋解鸘裘沽一醉，紛紛談話任封侯。"]'),
('141d2c8a-1038-441c-b257-d1dbfb047c5f','用汪彥章內翰諸公韵二首呈信安  其一','仲并','宋','宋诗','song-poetry','','[]','勳業皋夔前後身，門從羅雀厭蹄輪。',64,'全唐诗/poet.song.112000.json','["勳業皋夔前後身，門從羅雀厭蹄輪。", "旌麾亟解江城守，邱壑苦留廊廟人。", "禪觀起侵千嶂曉，篇章分與萬家春。", "要將姓字誇今古，史筆何人似獲麟。"]'),
('601bbe7e-a0ad-47ae-bd87-e0a65d1c72e2','用汪彥章內翰諸公韵二首呈信安  其二','仲并','宋','宋诗','song-poetry','','[]','王門一歲幾經過，客裏承顔未厭多。',64,'全唐诗/poet.song.112000.json','["王門一歲幾經過，客裏承顔未厭多。", "詩卷心胸傾錦繡，珍庖盤釜薦麟駝。", "自慚淮海可憐客，每費江湖無盡波。", "玉樹芝蘭爲公喜，庭空千丈影婆娑。"]'),
('2307b21b-083e-4c3a-8a8d-ff4e5318e23a','用方叔韵寄蘗庵老人','仲并','宋','宋诗','song-poetry','','[]','三徑蕭然欲就荒，已將身世兩兼忘。',64,'全唐诗/poet.song.112000.json','["三徑蕭然欲就荒，已將身世兩兼忘。", "紛紜勿用論榮辱，出處真須自弛張。", "憶昔少年親翰墨，與公長日付杯觴。", "如今事事俱無用，學道徒能笑子房。"]'),
('ffc0674a-6d57-4729-bcca-cbf40b132b1c','和臧陸二祕書','仲并','宋','宋诗','song-poetry','','[]','年來疏見驚人句，入手遽回如許春。',64,'全唐诗/poet.song.112000.json','["年來疏見驚人句，入手遽回如許春。", "幾日異科收異士，百年吾道付吾人。", "執鞭少也嘗求富，擊柝老來非爲貧。", "寄語子雲當自貴，儒風元不繫周秦。"]'),
('ef9329c7-163f-44ab-ac7c-6a8faa87c77c','送鄭公老少卿赴吉州三首  其一','仲并','宋','宋诗','song-poetry','','[]','千里能來兩鄭公，百年英烈尚遺風。',64,'全唐诗/poet.song.112000.json','["千里能來兩鄭公，百年英烈尚遺風。", "笙歌少讓他時勝，犴獄應從到日空。", "畫戟行程春色裏，郵亭離恨雨聲中。", "不辭遠爲宗風去，一瓣香緣六一翁。"]'),
('911f74bf-b574-4501-a90d-15158eb49e61','送鄭公老少卿赴吉州三首  其二','仲并','宋','宋诗','song-poetry','','[]','靜掩巖扉定幾年，蘭陵謠誦似新傳。',64,'全唐诗/poet.song.112000.json','["靜掩巖扉定幾年，蘭陵謠誦似新傳。", "文如此老仍千騎，恩與州人作二天。", "一室蕭然餘棐几，平生用處只蒲鞭。", "琵琶休抹三千指，公到家家自管絃。"]'),
('4c602b25-8500-43ca-a28a-0f7d6a0ce701','送鄭公老少卿赴吉州三首  其三','仲并','宋','宋诗','song-poetry','','[]','不記江城分袂初，幾年東北望門閭。',64,'全唐诗/poet.song.112000.json','["不記江城分袂初，幾年東北望門閭。", "寒溫一紙無非便，憂病千端自作疏。", "莫忘折梅尋勝事，懸知視草報初除。", "及茲郡舍多閒日，早著山中未了書。"]'),
('087c95a0-a3b7-4032-8a14-ac38f9fca2de','送高提幹暫過行在','仲并','宋','宋诗','song-poetry','','[]','老兼貧病怯離羣，細雨郵亭曉送君。',64,'全唐诗/poet.song.112000.json','["老兼貧病怯離羣，細雨郵亭曉送君。", "俗韵有誰歌白雪，高標真合致青雲。", "官居盡日勤篇翰，相業平時飽見聞。", "早晚薰風生茂苑，肯來樽酒細論文。"]'),
('6c26b939-5936-415c-b444-f819cc614fad','再和高提幹見寄','仲并','宋','宋诗','song-poetry','','[]','昂昂猶想立雞羣，三夜寒窗疊夢君。',64,'全唐诗/poet.song.112000.json','["昂昂猶想立雞羣，三夜寒窗疊夢君。", "人物芝蘭晉王謝，篇章黼黻漢卿雲。", "飄蓬賤跡誰能記，推轂高風今創聞。", "不敢馳書丞相府，何當收拾與斯文。"]'),
('72aeeb77-c6a2-4f08-9f79-e151eab32127','送平江守蔣宣卿奉祠歸宜興','仲并','宋','宋诗','song-poetry','','[]','二年環堵頼餘波，相和兒童襦袴歌。',64,'全唐诗/poet.song.112000.json','["二年環堵頼餘波，相和兒童襦袴歌。", "還復攀轅逢此日，敢忘推轂意如何。", "十行行矣重徵霸，三徑歸歟暫景坡。", "旦晚陪公畫橋路，共看天遠夕陽多。"]'),
('cf70b8ad-2d55-4f89-b6bc-7dd843f1d8bb','送智道者','仲并','宋','宋诗','song-poetry','','[]','胸中歷歷幾山川，竹杖芒鞋四十年。',64,'全唐诗/poet.song.112000.json','["胸中歷歷幾山川，竹杖芒鞋四十年。", "赤手旋爲新活計，白頭猶作舊因緣。", "如如妙境無多事，了了真心不礙禪。", "安坐高峰重點檢，未須枕石伴雲眠。"]'),
('67cf7b26-12a9-47c0-a550-88c0c2896af5','次韵答友人四首  其一','仲并','宋','宋诗','song-poetry','','[]','頗憶高人相與閒，扁舟誰與趣公還。',64,'全唐诗/poet.song.112000.json','["頗憶高人相與閒，扁舟誰與趣公還。", "杯行欵乃歌聲底，客坐參差帆影間。", "多病扶携新几杖，平生契好舊湖山。", "未容月轉各分手，醉語狂吟下碧灣。"]'),
('a9329fcb-6375-43ee-81fa-88f1fb6c5038','次韵答友人四首  其二','仲并','宋','宋诗','song-poetry','','[]','久矣忘情豈用閒，已看要起示無還。',64,'全唐诗/poet.song.112000.json','["久矣忘情豈用閒，已看要起示無還。", "自懷白髮蒼顔客，不墮黄花翠竹間。", "顧我分爲方外友，如公合上道家山。", "暇時及此頻相過，城北城南潯幾灣。"]'),
('e6c7642d-6ef1-4b95-b290-67d4b05ac5bf','次韵答友人四首  其三','仲并','宋','宋诗','song-poetry','','[]','晚矣吾身未乞閒，如公尺一合徵還。',64,'全唐诗/poet.song.112000.json','["晚矣吾身未乞閒，如公尺一合徵還。", "高標迥立風塵表，秀句喧傳字宙間。", "誰和陽春仍白雪，我知流水與高山。", "歸歟已熟他時路，直北龍溪一二灣。"]'),
('a5f18496-96e5-4f59-9070-7dd092c46c6d','次韵答友人四首  其四','仲并','宋','宋诗','song-poetry','','[]','百年未見一人閒，曾是興嗟唐已還。',64,'全唐诗/poet.song.112000.json','["百年未見一人閒，曾是興嗟唐已還。", "遺躅有誰高往古，清風元自振中間。", "我慚官薄當投紱，公比吾家已買山。", "待得有田歸已暮，何當分我一滄灣。"]'),
('10d82922-843f-424b-8f34-bfa32b623c6e','上孟郡王生辰三首  其一','仲并','宋','宋诗','song-poetry','','[]','霜餘晴日照堤沙，早晚天墀下白麻。',64,'全唐诗/poet.song.112000.json','["霜餘晴日照堤沙，早晚天墀下白麻。", "有吏當筵歌湛露，須公滿斚泛流霞。", "篇章况是萬人敵，閥閲相仍百乘家。", "落帽何須定重九，探先三日醉黄花。"]'),
('0acc4c3f-6009-45a9-a249-395ff90bb275','上孟郡王生辰三首  其二','仲并','宋','宋诗','song-poetry','','[]','先門勳業畫圖中，又見麒麟第一功。',64,'全唐诗/poet.song.112000.json','["先門勳業畫圖中，又見麒麟第一功。", "吹帽龍山前日事，還珠合浦昔人風。", "滿籝何有簡編足，薦牘無心天地公。", "誰說維熊契占夢，君王卜處本非熊。"]'),
('d1461cd8-eec4-417e-bfc9-61948e0a1338','上孟郡王生辰三首  其三','仲并','宋','宋诗','song-poetry','','[]','月挂微弦天未霜，初筵遽作十分凉。',64,'全唐诗/poet.song.112000.json','["月挂微弦天未霜，初筵遽作十分凉。", "飽參平日安心法，自是長年却老方。", "詔下龍墀思舊德，名標雁塔看諸郎。", "慇懃爲採瀼潭菊，滿泛西風歲歲觴。"]'),
('4bfbbac0-a32d-49a8-aee9-eff3cc113bf7','外舅莊子尚生辰  其一','仲并','宋','宋诗','song-poetry','','[]','祥光昨夜擁冰輪，南國初生瑞世人。',64,'全唐诗/poet.song.112000.json','["祥光昨夜擁冰輪，南國初生瑞世人。", "倚馬高文追異代，憩棠餘愛在斯民。", "吟毫剩借江山助，詔墨行頒雨露新。", "要識漆園非浪語，傳家重看八千春。"]'),
('f4931f54-5968-4269-8978-6610246fb3c8','外舅莊子尚生辰  其二','仲并','宋','宋诗','song-poetry','','[]','家聲久矣冠淮東，自喜升堂獲拜公。',64,'全唐诗/poet.song.112000.json','["家聲久矣冠淮東，自喜升堂獲拜公。", "每看雲烟生筆下，故應邱壑滿胸中。", "祠公此日家山樂，明府他時社稷功。", "早晚鋒車下吳會，西來猶想及春風。"]'),
('9b3a8527-f1bb-4920-84fd-eef38db10161','外舅莊子尚生辰  其三','仲并','宋','宋诗','song-poetry','','[]','兩州佳譽亞龔黄，琳館歸來道益光。',64,'全唐诗/poet.song.112000.json','["兩州佳譽亞龔黄，琳館歸來道益光。", "凜凜松筠非俗韵，詵詵蘭玉見餘芳。", "梅催寒萼春初破，月滿冰輪夜未央。", "景物漸新人不老，年年於此醉華觴。"]'),
('3dfd9e31-fb2d-4335-92f0-8cb4ae014f32','平江太守生辰二首  其一','仲并','宋','宋诗','song-poetry','','[]','畫戟從來瑞靄浮，頓回春意到南州。',64,'全唐诗/poet.song.112000.json','["畫戟從來瑞靄浮，頓回春意到南州。", "占熊饋鯉呈祥日，拖玉腰金得志秋。", "十載聲名天下最，滿懷韜畧古人求。", "壽觴頻舉公休惜，明日催歸侍邃旒。"]'),
('da6dd477-4da5-4e5e-a167-c59556fc1609','平江太守生辰二首  其二','仲并','宋','宋诗','song-poetry','','[]','玉笋初辭鵷鷺羣，一麾來此振餘芬。',64,'全唐诗/poet.song.112000.json','["玉笋初辭鵷鷺羣，一麾來此振餘芬。", "三槐事業他年看，五袴歌謠隨處聞。", "方丈可量閒日月，泰階還赴舊風雲。", "年年東注松江綠，渾欲朝來壽使君。"]'),
('3cda0903-2e3a-4831-ba99-eaaed0e7969d','上樞密生辰  其一','仲并','宋','宋诗','song-poetry','','[]','家住東南最上游，一從束髮侍宸旒。',64,'全唐诗/poet.song.112000.json','["家住東南最上游，一從束髮侍宸旒。", "文兼鍾阜古今秀，慶與秦淮日夜流。", "盛業行刊千琬琰，餘威坐折萬貔貅。", "竚看拜後恩榮異，槐鼎相聯魯與周。"]'),
('e745fbaf-26f5-4e8a-8aaa-d0c674a69c21','上樞密生辰  其二','仲并','宋','宋诗','song-poetry','','[]','謗焰讒波豈易然，功成方驗古無前。',64,'全唐诗/poet.song.112000.json','["謗焰讒波豈易然，功成方驗古無前。", "十年險阻忠償國，萬口紛紜誠格天。", "已遣烽消邊障火，行看貫朽大農錢。", "如今聞道持盈業，旦旦開陳黼扆邊。"]'),
('3739c72e-61b6-4560-9af6-015c7bb2ee46','上樞密生辰  其三','仲并','宋','宋诗','song-poetry','','[]','兒童猶解仰芬芳，合綴韓門弟子行。',64,'全唐诗/poet.song.112000.json','["兒童猶解仰芬芳，合綴韓門弟子行。", "久矣飄蓬疏望履，幸哉擁篲即升堂。", "夔龍會合時千載，鷗鷺留連天一方。", "遥願衮衣仍鶴髮，年年今日侍君王。"]'),
('32c2134a-d7e9-4085-a12f-709b04a16bad','胡樞密生辰  其一','仲并','宋','宋诗','song-poetry','','[]','秋山淡墨寫千峰，輝映門闌氣象中。',64,'全唐诗/poet.song.112000.json','["秋山淡墨寫千峰，輝映門闌氣象中。", "瑞靄亦知人意喜，華觴寧惜醉顔紅。", "莊椿此去幾千歲，漢閣他時第一功。", "試問溪頭閒草木，公來無日不春風。"]'),
('9b264a8f-30fa-4752-9cb3-32a789bec27f','胡樞密生辰  其二','仲并','宋','宋诗','song-poetry','','[]','借箸從容漢子房，平生書奏幾封囊。',64,'全唐诗/poet.song.112000.json','["借箸從容漢子房，平生書奏幾封囊。", "少辭天上風雲會，便覺壺中歲月長。", "調鼎望公非一日，草玄與我見諸郎。", "云何整頓乾坤手，漫隔三年鵷鷺行。"]'),
('7e773db0-e2ec-4ef2-acf4-cc909c0ca703','胡樞密生辰  其三','仲并','宋','宋诗','song-poetry','','[]','往歲聲馳淮海濱，曾歌紫綬照青春。',64,'全唐诗/poet.song.112000.json','["往歲聲馳淮海濱，曾歌紫綬照青春。", "光華萬里古無輩，獻納三朝國有人。", "剩約橫山供勝事，細憑芳醑壽斯辰。", "百年黄閤身猶健，重看歸來一幅巾。"]'),
('1aa47760-7c99-4bdf-a2f3-8384d8086c5c','上平江李侍郎生辰  其一','仲并','宋','宋诗','song-poetry','','[]','持橐朝端譽有光，垂弧門左晝初長。',64,'全唐诗/poet.song.112000.json','["持橐朝端譽有光，垂弧門左晝初長。", "功名唾手囊中物，藥石關心肘後方。", "公念承流當振廩，人歌難老競持觴。", "壽筵一舉松江淥，便趁追鋒侍帝旁。"]'),
('20a2ab82-0081-425d-9fca-15c33f172e75','上平江李侍郎生辰  其二','仲并','宋','宋诗','song-poetry','','[]','昔襦今袴雄藩守，佩玉峩冠近侍臣。',64,'全唐诗/poet.song.112000.json','["昔襦今袴雄藩守，佩玉峩冠近侍臣。", "十萬人家等蒙潤，三千風月政當仁。", "仙姿照坐桃如許，冷艷當簷梅一新。", "願比秦淮與鍾阜，鬰葱佳氣自長春。"]'),
('6902c10b-ec5e-40d9-80d3-3abe5f5c2635','代人上師垣生辰  其一','仲并','宋','宋诗','song-poetry','','[]','盛世還生瑞世人，東風屈指歲華新。',64,'全唐诗/poet.song.112000.json','["盛世還生瑞世人，東風屈指歲華新。", "祥烟不斷千山曉，愛日無邊萬國春。", "鳴玉珥貂扶紫極，櫜弓偃革轉洪鈞。", "我民非敢私爲壽，永作堂堂社稷臣。"]'),
('9e634932-a675-4d53-8fab-3ba2ebc8949d','代人上師垣生辰  其二','仲并','宋','宋诗','song-poetry','','[]','直把孤忠動帝聰，平生房杜不言功。',64,'全唐诗/poet.song.112000.json','["直把孤忠動帝聰，平生房杜不言功。", "沖霄鸞鳳謀謨合，遮道豺狼黨與空。", "韜畧暇時談笑裏，勳名他日畫圖中。", "中書未數汾陽考，萬有千年似魯公。"]'),
('e3b9c1a8-b4a6-455f-94ad-ab2df98deca9','代人上師垣生辰  其三','仲并','宋','宋诗','song-poetry','','[]','清風孤映紫宸班，平立伊周伯仲間。',64,'全唐诗/poet.song.112000.json','["清風孤映紫宸班，平立伊周伯仲間。", "幾歲苦心扶國步，今年喜色到天顔。", "羽書已靜淮西報，翟輅初從塞北還。", "式廓中原斷無事，從容廊廟有餘閒。"]'),
('b5854536-b536-4a8d-b74c-76d1567bdef5','代人上師垣生辰  其四','仲并','宋','宋诗','song-poetry','','[]','已聞鼙鼓靜邊陲，初見絲綸寵帝師。',64,'全唐诗/poet.song.112000.json','["已聞鼙鼓靜邊陲，初見絲綸寵帝師。", "寰宇一新周禮樂，廣庭重用漢威儀。", "江南江北無他事，春後春前更此時。", "舉盞上公千歲壽，賡歌永贊舜無爲。"]'),
('3fb12af3-4753-4ac1-ba1f-f3f2dd6ba5a8','代人上師垣生辰  其五','仲并','宋','宋诗','song-poetry','','[]','日日衣冠金馬門，有誰出力正乾坤。',64,'全唐诗/poet.song.112000.json','["日日衣冠金馬門，有誰出力正乾坤。", "來歸季子國人喜，終藉叔孫皇帝尊。", "鳳沼真成逢旦暮，龍樓今得問晨昏。", "欲知餘慶來何似，带礪山河永永存。"]'),
('dfc2ef4b-827a-465b-a10e-316fab5720cc','代人上師垣生辰  其六','仲并','宋','宋诗','song-poetry','','[]','冠豸英風傳至今，於時早已望商霖。',64,'全唐诗/poet.song.112000.json','["冠豸英風傳至今，於時早已望商霖。", "掛帆鯨浪朝天日，借箸龍墀許國心。", "帝渥洊頒廉陛遠，邊聲初斷塞垣深。", "不須更誦烝民句，處處兒童盡好音。"]'),
('dfc990b1-cd56-45bd-9445-058d5d3c5f00','代人上師垣生辰  其七','仲并','宋','宋诗','song-poetry','','[]','不用天河洗甲兵，只憑直道致昇平。',64,'全唐诗/poet.song.112000.json','["不用天河洗甲兵，只憑直道致昇平。", "三王事業賢臣主，一代師儒難弟兄。", "屢薄賦徭民鼓舞，盡除氛翳國清明。", "休將前古論今日，萬古無人敢抗衡。"]'),
('5f683303-089a-47a0-93dc-6b98ef935d13','廖成伯奉議生辰','仲并','宋','宋诗','song-poetry','','[]','曾聽尊前世綵歌，喜聞烟袖舞婆娑。',64,'全唐诗/poet.song.112000.json','["曾聽尊前世綵歌，喜聞烟袖舞婆娑。", "名駒汗血得夷路，老柏凌霜只舊柯。", "桃李盛時隨地有，芝蘭生處近人多。", "春風二月年年事，莫問靈椿歲幾何。"]'),
('180fcc69-33da-4fea-8995-b7cb373cd04c','提舉生辰','仲并','宋','宋诗','song-poetry','','[]','東井遥觀盾日升，南風猶入舜絃鳴。',64,'全唐诗/poet.song.112000.json','["東井遥觀盾日升，南風猶入舜絃鳴。", "鵬程九萬豈終息，椿歲八千方再榮。", "平世功名期鳳鳥，一時文采應長庚。", "浮瓜沉李年年事，稽首弧南一點明。"]'),
('ab35b9b7-f973-4dbf-8c97-6c3a4f66cab6','俞憲生辰代龐幾先作  其一','仲并','宋','宋诗','song-poetry','','[]','北固樓前萬頃秋，月明風定大江流。',64,'全唐诗/poet.song.112000.json','["北固樓前萬頃秋，月明風定大江流。", "從來此地多英傑，果有奇才副簡求。", "秀氣一天開夜色，威名千里駕潮頭。", "山川長在人難老，應抱文章入相周。"]'),
('6b389bc3-9e12-42e5-afe3-e4b5b99398d5','俞憲生辰代龐幾先作  其二','仲并','宋','宋诗','song-poetry','','[]','淮南持斧功成後，甌粵乘軺喜暫臨。',64,'全唐诗/poet.song.112000.json','["淮南持斧功成後，甌粵乘軺喜暫臨。", "使者英標衣蹙繡，近臣新渥带橫金。", "三山氣入中秋好，八郡香焚曉霧深。", "已爲黎元開壽域，可無椿歲慰人心。"]'),
('d568aae5-d661-4b47-bf7d-7f147660a961','白氏夫人生日二首  其一','仲并','宋','宋诗','song-poetry','','[]','相門苗裔正詵詵，長慶風流幾百春。',64,'全唐诗/poet.song.112000.json','["相門苗裔正詵詵，長慶風流幾百春。", "吉夢忽隨秋日曉，祥光常對月華新。", "翰林大筆高前古，玉樹諸郎靄後塵。", "何假捧觴勤頌祝，由來壽考屬仁人。"]'),
('56453467-c800-46f3-af10-d132d2882857','白氏夫人生日二首  其二','仲并','宋','宋诗','song-poetry','','[]','斷機久已傳家訓，采藻端然繼國風。',64,'全唐诗/poet.song.112000.json','["斷機久已傳家訓，采藻端然繼國風。", "庭院爐烟春藹藹，門闌瑞氣曉葱葱。", "遐齡願效三桃實，拜壽何辭百盞空。", "自幸晚爲門下士，餘波應許丐奇窮。"]'),
('041f7fa4-6db7-4d35-b79d-b17f25350b08','代同舍上黄相生辰三首  其一','仲并','宋','宋诗','song-poetry','','[]','列宿東南夜有輝，門弧此際誕英奇。',64,'全唐诗/poet.song.112000.json','["列宿東南夜有輝，門弧此際誕英奇。", "晏嬰儉德人皆仰，召虎中興日可期。", "名譽雅爲天下望，孤忠自結聖君知。", "大椿會見千年算，應許驚烏託一枝。"]'),
('9fe7c64d-2bef-4ff4-a197-6e1cd04f0f2d','代同舍上黄相生辰三首  其二','仲并','宋','宋诗','song-poetry','','[]','籍甚聲華振九州，龍名未許潁川優。',64,'全唐诗/poet.song.112000.json','["籍甚聲華振九州，龍名未許潁川優。", "兩年鈇鉞扶黄屋，一品星躔尚黑頭。", "烜赫朝班聯棣萼，張皇軍勢擁貔貅。", "自慚東閤叨甄錄，願向清時與國謀。"]'),
('0a8690d5-28e4-4d7d-8f38-e7cb486dafca','代同舍上黄相生辰三首  其三','仲并','宋','宋诗','song-poetry','','[]','五月天恩解網羅，四方舉首願時和。',64,'全唐诗/poet.song.112000.json','["五月天恩解網羅，四方舉首願時和。", "我公寰海甘霖望，今日門闌瑞氣多。", "已幸羈窮蒙庇頼，竚看談笑却干戈。", "汾陽二十中書考，他日遥知數倍過。"]'),
('16784192-e4df-40c8-ba5e-54b2bd9b34ac','用孫仲益尚書韵二首呈孟信安  其一','仲并','宋','宋诗','song-poetry','','[]','士仰韓門重，身高謝傅班。',72,'全唐诗/poet.song.112000.json','["士仰韓門重，身高謝傅班。", "文看輝北斗，人望起東山。", "絳灌庸奴爾，皋夔伯仲間。", "自天芝檢下，指日衮衣還。", "片語鳴丹鳳，羣爭息左蠻。", "時雖容下客，勝處一窺斑。"]'),
('8c433770-1fef-4d35-b134-aaae8c8c3d3f','用孫仲益尚書韵二首呈孟信安  其二','仲并','宋','宋诗','song-poetry','','[]','慷慨安周鼎，從容却郢兵。',72,'全唐诗/poet.song.112000.json','["慷慨安周鼎，從容却郢兵。", "馳心子牟闕，袖手闔閭城。", "前箸陳天陛，先聲震敵營。", "寰區望彌切，樞筦寄非輕。", "行有絲綸詔，寧終鷗鷺盟。", "一舒經世策，遐邇頌昇平。"]'),
('5f1eca53-9124-4528-921f-12ba373e131c','鄭漕生辰','仲并','宋','宋诗','song-poetry','','[]','象緯祥光動，門弧瑞氣盈。',120,'全唐诗/poet.song.112000.json','["象緯祥光動，門弧瑞氣盈。", "小陽春在序，幾望月偏明。", "他日三千牘，清時九萬程。", "名因使粵重，功自備吳成。", "偉量溟波闊，奇詞錦段呈。", "褒揚看唾玉，輕重倚提衡。", "松柏真難老，芝蘭足後生。", "筍班行趣召，金带已先橫。", "內史言何美，尚書心自清。", "祇應南北相，重振舊家聲。"]'),
('a2e8cbd9-ce80-4e2c-b7f2-d5008e728d5e','唐大夫生辰','仲并','宋','宋诗','song-poetry','','[]','氣轉初寒候，祥開既望辰。',96,'全唐诗/poet.song.112000.json','["氣轉初寒候，祥開既望辰。", "應時來鸑鷟，占夢獲麒麟。", "盛德圭無玷，高才竹有筠。", "胸襟藏巨壑，人物妙洪鈞。", "使者光華遠，朝廷寵數新。", "鵬程九萬里，椿幹八千春。", "鼎鼐虛前席，風雲即要津。", "黑頭紆衮繡，天意在斯民。"]'),
('2e8944ba-8f7e-46de-afcd-12783a4d607e','陳漕生辰代楊文作','仲并','宋','宋诗','song-poetry','','[]','六管陽初復，前宵月尚圓。',168,'全唐诗/poet.song.112000.json','["六管陽初復，前宵月尚圓。", "長庚俄夢李，崧岳故興宣。", "國使新恩數，忠臣夙眷偏。", "節龍開遠目，衣繡聳華年。", "日月聲名起，風雷號令傳。", "自應威動岳，曾是力回天。", "相國關中粟，尚書地上錢。", "委藏淹府庫，飛輓亂車船。", "南獠元歸地，西方正拓邊。", "定知新將飽，尤頼我公賢。", "赫赫蘭臺舊，飄飄鳳沼仙。", "終焉還魏闕，聊爾駐荆川。", "曲學聯珠履，非才汙彩牋。", "千秋期鶴壽，萬里附鵬鶱。"]'),
('e7109fda-93d4-4d9c-9cac-db07b7b6a83f','耿憲生辰','仲并','宋','宋诗','song-poetry','','[]','象緯祥光動，門弧瑞氣纏。',72,'全唐诗/poet.song.112000.json','["象緯祥光動，門弧瑞氣纏。", "秋來孤鶴健，霜近古松堅。", "鄰境兵戈盡，新恩雨露偏。", "軺車猶問俗，寶带獨優賢。", "投筆男兒志，封侯烈士年。", "老成端可恃，終冀勒燕然。"]'),
('727c08c7-63d6-4a8c-bf63-465c803408a5','對竹','仲并','宋','宋诗','song-poetry','','[]','嶔岑何處峯，來伴蕭疏竹。',24,'全唐诗/poet.song.112000.json','["嶔岑何處峯，來伴蕭疏竹。", "悠然方丈間，寄此千里目。"]'),
('9d96731f-8097-4be8-b2c1-d50db03ed8aa','假山','仲并','宋','宋诗','song-poetry','','[]','峯間碧琅玕，清風五月寒。',24,'全唐诗/poet.song.112000.json','["峯間碧琅玕，清風五月寒。", "欲題無好語，支枕卷簾看。"]'),
('e32e0f36-db1f-455d-8e99-98ee2b7bb472','官滿趨朝留滯吳門即事書懷十首  其一','仲并','宋','宋诗','song-poetry','','["\u897f\u6e56"]','十載錢塘雲漢間，江聲夢裏聽潺湲。',32,'全唐诗/poet.song.112000.json','["十載錢塘雲漢間，江聲夢裏聽潺湲。", "他山縱染千尋碧，不似西湖一带山。"]'),
('fe817df6-ad40-46fa-9a26-ce7b6c0fefe5','官滿趨朝留滯吳門即事書懷十首  其二','仲并','宋','宋诗','song-poetry','','[]','水邊梅柳倍精神，總趁晴天作好春。',32,'全唐诗/poet.song.112000.json','["水邊梅柳倍精神，總趁晴天作好春。", "多謝東君惜花意，不教風雨廢芳辰。"]'),
('802cda68-1654-4307-81f5-1ebc7b00b1aa','官滿趨朝留滯吳門即事書懷十首  其三','仲并','宋','宋诗','song-poetry','','[]','小樓嶻嶭亂山橫，獨倚朱欄度晚晴。',32,'全唐诗/poet.song.112000.json','["小樓嶻嶭亂山橫，獨倚朱欄度晚晴。", "忽聽如簧語音好，祗緣高處最宜鶑。"]'),
('9ce10dd1-9f5f-4fcc-8b60-ea26119a2f0d','官滿趨朝留滯吳門即事書懷十首  其四','仲并','宋','宋诗','song-poetry','','[]','枉費花工著意催，漫山桃李總非材。',32,'全唐诗/poet.song.112000.json','["枉費花工著意催，漫山桃李總非材。", "要令千古芬香在，能作和羹自有梅。"]'),
('418d1062-5028-44f7-8a77-57fe939e3cf8','官滿趨朝留滯吳門即事書懷十首  其五','仲并','宋','宋诗','song-poetry','','[]','花徑風來百樣香，捲簾春水綠池塘。',32,'全唐诗/poet.song.112000.json','["花徑風來百樣香，捲簾春水綠池塘。", "如今萬事銷磨盡，四卷楞伽味最長。"]'),
('7c0b60b2-5aea-448c-b1f6-84870dfce36b','官滿趨朝留滯吳門即事書懷十首  其六','仲并','宋','宋诗','song-poetry','','[]','春服何當詠舞雩，鳳池今是魯真儒。',32,'全唐诗/poet.song.112000.json','["春服何當詠舞雩，鳳池今是魯真儒。", "向令未解邊城戍，能對東風一笑無。"]'),
('79dcecd3-5451-4e68-89b0-a28e6c4b2aa1','官滿趨朝留滯吳門即事書懷十首  其七','仲并','宋','宋诗','song-poetry','','[]','錦带吳鈎輕薄兒，三三五五競花時。',32,'全唐诗/poet.song.112000.json','["錦带吳鈎輕薄兒，三三五五競花時。", "太平樂事從誰得，費盡經綸爾不知。"]'),
('ef59e591-139f-4a3b-9d08-1a82fb865a93','官滿趨朝留滯吳門即事書懷十首  其八','仲并','宋','宋诗','song-poetry','','[]','門外煙花看不厭，東風故爲客開簾。',32,'全唐诗/poet.song.112000.json','["門外煙花看不厭，東風故爲客開簾。", "如今樂極思疇昔，長是春深未解嚴。"]'),
('7e933e9b-815b-4514-98fe-1633a51bbafc','官滿趨朝留滯吳門即事書懷十首  其九','仲并','宋','宋诗','song-poetry','','[]','燕羽差池何處歸，銜恩春傍主人飛。',32,'全唐诗/poet.song.112000.json','["燕羽差池何處歸，銜恩春傍主人飛。", "定須借與一巢穩，十載飄零事事非。"]'),
('52f6e524-e00c-4c56-8721-4015e28102a8','官滿趨朝留滯吳門即事書懷十首  其一○','仲并','宋','宋诗','song-poetry','','[]','裁剪羣英荷化工，閒中無計答春風。',32,'全唐诗/poet.song.112000.json','["裁剪羣英荷化工，閒中無計答春風。", "自鋤花徑平如掌，要使荆榛一掃空。"]'),
('6c225277-0f8b-4c13-94ff-ef8bf9021e17','平江守禱晴即應時近元夕矣寄呈五絕句  其一','仲并','宋','宋诗','song-poetry','','[]','丹邱雨裏看春回，密霧濃雲撥不開。',32,'全唐诗/poet.song.112000.json','["丹邱雨裏看春回，密霧濃雲撥不開。", "怪底寒窗烘曉日，朱轓親禱梵宮來。"]'),
('d0995214-2879-44a4-9acb-db41a0efc1ef','平江守禱晴即應時近元夕矣寄呈五絕句  其二','仲并','宋','宋诗','song-poetry','','[]','投曉家家笑語聲，夜來風促雨如傾。',32,'全唐诗/poet.song.112000.json','["投曉家家笑語聲，夜來風促雨如傾。", "都緣默禱胸中久，一瓣香焚喚得晴。"]'),
('86edd5c0-cecc-44b5-8895-cadb23f44e44','平江守禱晴即應時近元夕矣寄呈五絕句  其三','仲并','宋','宋诗','song-poetry','','[]','梅經多雨玉飄零，就有殘枝困未醒。',32,'全唐诗/poet.song.112000.json','["梅經多雨玉飄零，就有殘枝困未醒。", "安得吳儂不歌舞，滿畦扶起麥青青。"]'),
('4e79889d-d147-430a-8ebb-47b5646be360','平江守禱晴即應時近元夕矣寄呈五絕句  其四','仲并','宋','宋诗','song-poetry','','[]','東風吹斷雨如繩，一夜仍開曲沼冰。',32,'全唐诗/poet.song.112000.json','["東風吹斷雨如繩，一夜仍開曲沼冰。", "便試元宵强半月，孰知天意欲催燈。"]'),
('255cab02-b0bf-40e7-ba47-b297050f8570','平江守禱晴即應時近元夕矣寄呈五絕句  其五','仲并','宋','宋诗','song-poetry','','[]','安排燈火作鰲頭，人樂公來再有秋。',32,'全唐诗/poet.song.112000.json','["安排燈火作鰲頭，人樂公來再有秋。", "轉雨作晴談笑事，他州誰得似吾州。"]'),
('f7d8dca8-53a2-418c-af77-41bcd47a5d07','夜抵德清縣偶題','仲并','宋','宋诗','song-poetry','','[]','溪山奪目壯哉縣，風露侵肌老矣身。',32,'全唐诗/poet.song.112000.json','["溪山奪目壯哉縣，風露侵肌老矣身。", "斷岸橫舟偏得月，小橋曳杖不逢人。"]'),
('1d8ff604-137f-4771-8621-f0d131697412','再過宜興舟中見芍藥數枝憶淮鄉此花之盛爲之悵然輒成三絕  其一','仲并','宋','宋诗','song-poetry','','[]','故眼相看未作疏，平生風味是吾廬。',32,'全唐诗/poet.song.112000.json','["故眼相看未作疏，平生風味是吾廬。", "娉娉裊裊誰家子，浪說傾城總不如。"]'),
('749118ac-33b0-4b73-a55d-359b4482b55f','再過宜興舟中見芍藥數枝憶淮鄉此花之盛爲之悵然輒成三絕  其二','仲并','宋','宋诗','song-poetry','','[]','少時暮暮復朝朝，一水相望恨未消。',32,'全唐诗/poet.song.112000.json','["少時暮暮復朝朝，一水相望恨未消。", "岸曲橫舟試回首，隔簾斜立數妖嬈。"]'),
('8cb4d334-2219-4eeb-aad0-2dae2d07dcda','再過宜興舟中見芍藥數枝憶淮鄉此花之盛爲之悵然輒成三絕  其三','仲并','宋','宋诗','song-poetry','','[]','却是溪頭消息真，故園十載漫風塵。',32,'全唐诗/poet.song.112000.json','["却是溪頭消息真，故園十載漫風塵。", "如今不問黄樓子，淺白輕紅自可人。"]'),
('b5497e82-1413-43bc-95ba-b85e7b89de1e','薄暮遊潘登仕園園有堂三間榜曰一枝蓋湖公樞密兩取莊周郄詵之語既以嘉潘亦以勉潘之二子因用其意各賦一絕  其一','仲并','宋','宋诗','song-poetry','','[]','斜窗短屋傍殘暉，宴坐蕭然老布衣。',32,'全唐诗/poet.song.112000.json','["斜窗短屋傍殘暉，宴坐蕭然老布衣。", "枯淡生涯一枝足，世間驚鵲誤南飛。"]'),
('87eb39bb-6a4e-4209-b4d8-e66642e2d7c8','薄暮遊潘登仕園園有堂三間榜曰一枝蓋湖公樞密兩取莊周郄詵之語既以嘉潘亦以勉潘之二子因用其意各賦一絕  其二','仲并','宋','宋诗','song-poetry','','[]','玉樹郎君兩白眉，照人英爽自兒時。',32,'全唐诗/poet.song.112000.json','["玉樹郎君兩白眉，照人英爽自兒時。", "乃翁可笑太多事，繞舍春風千萬枝。"]'),
('491ad57a-3f1d-4a0d-880c-ee49833a59cc','蕪城','仲并','宋','宋诗','song-poetry','','[]','鶑歌燕語戲晴暉，日暮行人緩緩歸。',32,'全唐诗/poet.song.112000.json','["鶑歌燕語戲晴暉，日暮行人緩緩歸。", "十里蕪城春色晚，回頭往事已全非。"]'),
('774f744c-3db6-4926-9a69-2571b840a802','有客來從陽羨聞元績離家已月餘由崑山過臨安桐廬計今合歸矣元績當不惜迂路一訪僕於苕霅間也戲爲一絕招之元績純孝人每在道念親殊切','仲并','宋','宋诗','song-poetry','','[]','風露侵人曷往哉，白雲飛處棹徘徊。',32,'全唐诗/poet.song.112000.json','["風露侵人曷往哉，白雲飛處棹徘徊。", "平時識面盡經過，莫爲茅簷偏不來。"]'),
('3d7a96d1-c1ec-45e3-bce5-9e808a710cb4','感時  其一','仲并','宋','宋诗','song-poetry','','[]','傷春那得易爲情，世味年來一一更。',32,'全唐诗/poet.song.112000.json','["傷春那得易爲情，世味年來一一更。", "馳馬彎弓今日事，儒冠深覺誤平生。"]'),
('a151d293-953d-4de4-b2dc-5b0557e6cce3','感時  其二','仲并','宋','宋诗','song-poetry','','[]','忽傳羣盜下淮瀕，又逐黄州韓使君。',32,'全唐诗/poet.song.112000.json','["忽傳羣盜下淮瀕，又逐黄州韓使君。", "却望長安在天上，愁看天際有孤雲。"]'),
('d118f9f2-24eb-48a2-aca7-8f5c6c07d004','晚坐和韵  其一','仲并','宋','宋诗','song-poetry','','[]','急雪逢春易作晴，窮閻猶復斷人行。',32,'全唐诗/poet.song.112000.json','["急雪逢春易作晴，窮閻猶復斷人行。", "公家何在欲乘月，夜半扁舟不隔城。"]'),
('ae9c1535-2594-41eb-bde3-530c5cdc7b02','晚坐和韵  其二','仲并','宋','宋诗','song-poetry','','[]','好月侵階已十分，太清不受一塵昏。',32,'全唐诗/poet.song.112000.json','["好月侵階已十分，太清不受一塵昏。", "今宵定自梅花發，踈影橫斜何處村。"]'),
('f24fc5fb-6fe2-40d7-b5a3-bcb217acd38b','晚坐和韵  其三','仲并','宋','宋诗','song-poetry','','[]','篇篇振玉妙玲瓏，字字春風和氣中。',32,'全唐诗/poet.song.112000.json','["篇篇振玉妙玲瓏，字字春風和氣中。", "安得居家無一事，搜吟日日與君同。"]'),
('3b92f1b7-3cba-4feb-a466-c74939bfe2de','晚坐和韵  其四','仲并','宋','宋诗','song-poetry','','[]','醉眼全醒病亦醒，虛齋危坐聽無聲。',32,'全唐诗/poet.song.112000.json','["醉眼全醒病亦醒，虛齋危坐聽無聲。", "錦囊欲報清新句，自笑常談只老生。"]'),
('ed7c23f9-bc4b-4706-b9ae-b7b282e1774e','晚坐和韵  其五','仲并','宋','宋诗','song-poetry','','[]','城東韓李城南趙，欲往從之道阻長。',32,'全唐诗/poet.song.112000.json','["城東韓李城南趙，欲往從之道阻長。", "與我詩盟煩借問，角弓永好願無忘。"]'),
('c22f9474-5112-4f36-9fd5-5640b4318245','次韵病起二首  其一','仲并','宋','宋诗','song-poetry','','[]','不妨佳句太頻頻，還得愁中眼漸明。',32,'全唐诗/poet.song.112000.json','["不妨佳句太頻頻，還得愁中眼漸明。", "好是維摩病初醒，又將口業起紛爭。"]'),
('76838508-e17e-4ba7-aff1-93cb39b3c1b2','次韵病起二首  其二','仲并','宋','宋诗','song-poetry','','[]','聞道車書未一家，平時苦苦念京華。',32,'全唐诗/poet.song.112000.json','["聞道車書未一家，平時苦苦念京華。", "新來忽得幽居味，竹屋茅簷政自嘉。"]'),
('2fded39b-b327-42d8-b9b9-2326bbf3878c','送閻少隠同其弟伯子宣子赴試淮南爲一月之別某以病起不及餞送爲三絕  其一','仲并','宋','宋诗','song-poetry','','[]','二難晚出材無敵，老將從來勇冠軍。',32,'全唐诗/poet.song.112000.json','["二難晚出材無敵，老將從來勇冠軍。", "一月望公三捷至，秋風不惜暫離羣。"]'),
('bfaef825-ceb1-4667-a07f-2d79832f31a5','送閻少隠同其弟伯子宣子赴試淮南爲一月之別某以病起不及餞送爲三絕  其二','仲并','宋','宋诗','song-poetry','','[]','街頭日夜催槐黄，去去歸帆如許忙。',32,'全唐诗/poet.song.112000.json','["街頭日夜催槐黄，去去歸帆如許忙。", "我病公行欠巵酒，少遲飲至共傳觴。"]'),
('b9aa3f3d-dc04-4cf3-aeac-ca83359fa436','送閻少隠同其弟伯子宣子赴試淮南爲一月之別某以病起不及餞送爲三絕  其三','仲并','宋','宋诗','song-poetry','','[]','扛鼎拔山誰長雄，八千號數誇江東。',32,'全唐诗/poet.song.112000.json','["扛鼎拔山誰長雄，八千號數誇江東。", "公家子弟又可用，要與父兄成大功。"]'),
('d04ffd9c-1ac3-461b-b9ab-3bc86bc7ef90','題章伯深臞怪圖  其一','仲并','宋','宋诗','song-poetry','','[]','竹戶茅簷一逕斜，清樽黄卷定生涯。',32,'全唐诗/poet.song.112000.json','["竹戶茅簷一逕斜，清樽黄卷定生涯。", "溪山勝處春長在，却放朱藤一半花。"]'),
('ef25315a-e5d9-45c4-9059-5b8d653d1e4e','題章伯深臞怪圖  其二','仲并','宋','宋诗','song-poetry','','[]','杖策山隈亦水濱，閒中未害飽經綸。',32,'全唐诗/poet.song.112000.json','["杖策山隈亦水濱，閒中未害飽經綸。", "何曾寂寞嵌巖裏，慣著風流廊廟人。"]'),
('df065615-337c-4fa7-9584-46f30bc6c997','畫枯木','仲并','宋','宋诗','song-poetry','','[]','乞與空齋伴我閒，風霜諳盡各蒼顔。',32,'全唐诗/poet.song.112000.json','["乞與空齋伴我閒，風霜諳盡各蒼顔。", "不妨黛色凌雲榦，蟠屈生綃尋尺間。"]'),
('17718f3a-6224-4154-b89b-2e9080edd9a7','次韵耿薦可催菊三首  其一','仲并','宋','宋诗','song-poetry','','[]','黄花應自惜離披，欲放清香故故遲。',32,'全唐诗/poet.song.112000.json','["黄花應自惜離披，欲放清香故故遲。", "病客高眠防不肯，剩裁好語報花知。"]'),
('a52bd665-aa52-4697-b11b-784e2b2117a9','次韵耿薦可催菊三首  其二','仲并','宋','宋诗','song-poetry','','[]','銜杯採菊久尋醫，白髮蒼顔漸可期。',32,'全唐诗/poet.song.112000.json','["銜杯採菊久尋醫，白髮蒼顔漸可期。", "準擬新來强作意，又從愁裏過花時。"]'),
('06324dfa-0894-4dc7-a6be-908b03ce3998','次韵耿薦可催菊三首  其三','仲并','宋','宋诗','song-poetry','','[]','年來花意亦難猜，陶令東籬獨未開。',32,'全唐诗/poet.song.112000.json','["年來花意亦難猜，陶令東籬獨未開。", "伴賦落英吾豈敢，狂言聊復爲君催。"]'),
('870b93da-55f1-4f04-8ae3-f31fe3c674ff','黄兵部生辰  其一','仲并','宋','宋诗','song-poetry','','[]','中朝人物競推先，富貴前塗看永年。',32,'全唐诗/poet.song.112000.json','["中朝人物競推先，富貴前塗看永年。", "九萬里程飛正遠，八千春幹久彌堅。"]'),
('46bd19f6-b750-42ca-8dbd-94500ee573bb','黄兵部生辰  其二','仲并','宋','宋诗','song-poetry','','[]','南國初持使節回，斑衣仍把錦新裁。',32,'全唐诗/poet.song.112000.json','["南國初持使節回，斑衣仍把錦新裁。", "大椿更向萱堂祝，長到春來共壽杯。"]'),
('404b5844-d97b-4efb-845c-c4899108fcb4','黄兵部生辰  其三','仲并','宋','宋诗','song-poetry','','[]','早歲蜚聲應宿郎，至今雞舌尚含香。',32,'全唐诗/poet.song.112000.json','["早歲蜚聲應宿郎，至今雞舌尚含香。", "未應駟馬誇流俗，只爲慈親樂故鄉。"]'),
('d3a78e70-5dff-4b4f-bb7b-f183c109a821','黄兵部生辰  其四','仲并','宋','宋诗','song-poetry','','[]','地上泉流府庫充，艱難天與歲時豐。',32,'全唐诗/poet.song.112000.json','["地上泉流府庫充，艱難天與歲時豐。", "他時若論關中漕，合數蕭何第一功。"]'),
('132e4b12-d4c9-4a81-82b4-5d1ad4d1aa33','奉陪舅丈祕書彥平主簿兄遊慧聚終日小飲上方待月再歷妙峰諸勝處用前人韵得二詩是日嘗微雨作  其一','仲并','宋','宋诗','song-poetry','','[]','憑高情不淺，盡日倚胡床。',48,'全唐诗/poet.song.112000.json','["憑高情不淺，盡日倚胡床。", "雲散他山雨，風來古殿香。", "一川橫晚照，重閣枕秋光。", "欲寫無窮意，詩凡不擅場。"]'),
('0a856e07-7b10-4136-b99d-ea054eb240a1','奉陪舅丈祕書彥平主簿兄遊慧聚終日小飲上方待月再歷妙峰諸勝處用前人韵得二詩是日嘗微雨作  其二','仲并','宋','宋诗','song-poetry','','[]','迎宵山吐月，不受寸雲吞。',48,'全唐诗/poet.song.112000.json','["迎宵山吐月，不受寸雲吞。", "看影篩林杪，移尊藉石根。", "參差明梵剎，一二數煙村。", "高處僧眠未，携筇試打門。"]'),
('e70e68bc-5f3d-4b4b-a6ff-cc534d49ca69','句','仲并','宋','宋诗','song-poetry','','[]','政恐崖州如有北，却應未肯受讒夫。',16,'全唐诗/poet.song.112000.json','["政恐崖州如有北，却應未肯受讒夫。"]'),
('69670f49-207f-408e-9e8a-3a689ab00580','遊青城山','白遜','宋','宋诗','song-poetry','','[]','青城山中雲茫茫，龍車問道來軒皇。',32,'全唐诗/poet.song.112000.json','["青城山中雲茫茫，龍車問道來軒皇。", "當封分爲五嶽長，天地截作神仙鄉。"]'),
('2fa8118a-a932-45e6-be9d-80ddacb1b730','句  其一','白遜','宋','宋诗','song-poetry','','[]','鹿隨採藥携家去，鶴恐飛仙佩箭歸。',16,'全唐诗/poet.song.112000.json','["鹿隨採藥携家去，鶴恐飛仙佩箭歸。"]'),
('75b18deb-8e61-4ef7-b120-1302404778c2','句  其二','白遜','宋','宋诗','song-poetry','','[]','上清宮殿與雲齊，六六峰朝萬嶺低。',16,'全唐诗/poet.song.112000.json','["上清宮殿與雲齊，六六峰朝萬嶺低。"]'),
('b20eadb4-177e-4e0e-a4cf-2ef0bdd8a2a7','星溪書院作','吳球','宋','宋诗','song-poetry','','[]','茅齋雨過竹雞啼，溪水涵空樹影低。',32,'全唐诗/poet.song.112000.json','["茅齋雨過竹雞啼，溪水涵空樹影低。", "愛煞夜廊風色靜，澄潭冷浸碧玻璃。"]'),
('594ee298-33a4-4183-abec-1d486e96a999','句','范彥輝','宋','宋诗','song-poetry','','[]','何當日月明，痛洗蒼生病。',12,'全唐诗/poet.song.112000.json','["何當日月明，痛洗蒼生病。"]'),
('eef22fd5-b57d-4ebc-9874-f0f429995d1e','歲久旱喜雨','薛靖','宋','宋诗','song-poetry','','[]','東南苦亢陽，吳越重罹厄。',120,'全唐诗/poet.song.112000.json','["東南苦亢陽，吳越重罹厄。", "流徙罄村墟，入夏地尚赤。", "詎無溝中人，矧乃急往役。", "頼茲天心慈，弗終閟膏澤。", "凱風將雨至，蓬蓬亙昕夕。", "水勢千澗呼，雲陰四郊積。", "祁祁沾灑均，歡聲遍南陌。", "秋秧布有種，萬一償春麥。", "相率理長鑱，幸可謀擔石。", "我亦歌豳風，憂心庶幾釋。"]'),
('ae4142a9-7b7c-443b-8a7f-f78898346bb6','望金山用唐人韵','薛靖','宋','宋诗','song-poetry','','[]','一柱支空立，濤聲春寺聞。',48,'全唐诗/poet.song.112000.json','["一柱支空立，濤聲春寺聞。", "消來巴地雪，飛到潤州雲。", "寂寞江山色，縱橫盜賊羣。", "不堪形勝裏，北望涕紛紜。"]'),
('3ac6b897-bb53-4206-88bc-143e3f8b0fc2','羅叢巖','陳中','宋','宋诗','song-poetry','','[]','矗矗山光映，團團樹影重。',24,'全唐诗/poet.song.112000.json','["矗矗山光映，團團樹影重。", "斷猿啼午夜，孤鶴唳秋風。"]'),
('fa4a178a-bb4b-42d0-be9e-c70e3f381575','壺公山','陳中','宋','宋诗','song-poetry','','[]','深澗無人草自斑，獨隨流水入深山。',64,'全唐诗/poet.song.112000.json','["深澗無人草自斑，獨隨流水入深山。", "隔林嵐氣青煙潤，滿地松陰白晝閑。", "野鳥聽經當戶入，洞龍带雨自天還。", "登高試望莆城景，一騎斜陽晚度關。"]'),
('85f0063c-689d-4b81-bd96-24961112d63d','定林寺','周燔','宋','宋诗','song-poetry','','[]','定巖坐聽松聲好，德水行穿竹影斜。',32,'全唐诗/poet.song.112000.json','["定巖坐聽松聲好，德水行穿竹影斜。", "無限世間幽絕處，天工分付與僧家。"]'),
('2a7050db-faab-46e6-a6ef-4cb5877b4c9a','夜游黄鶴樓遇道人','饒廷直','宋','宋诗','song-poetry','','[]','黄鶴樓前秋月寒，樓前江闊煙漫漫。',128,'全唐诗/poet.song.112000.json','["黄鶴樓前秋月寒，樓前江闊煙漫漫。", "夜深人散萬籟息，獨對清影憑闌干。", "一聲長嘯肅天宇，知是餐霞御風侶。", "多生曾結香火緣，邂逅相逢竟相語。", "翛然洗盡朝市忙，直疑身在無何鄉。", "回看往事一破甑，下視舉世俱亡羊。", "嗟予局促猶軒冕，知是盧敖遊未遠。", "他年有約願追隨，共看蓬萊水清淺。"]'),
('453c9ede-bd53-4b82-8245-61270e057d1f','巖桂花','鄭仲熊','宋','宋诗','song-poetry','','[]','天公憐我太岑寂，每歲殷勤兩度開。',32,'全唐诗/poet.song.112000.json','["天公憐我太岑寂，每歲殷勤兩度開。", "收拾落英將底用，博山香裏薦清杯。"]'),
('041a9d9b-6a38-4df2-834f-5e6a9e677b5e','句','鄒惇禮','宋','宋诗','song-poetry','','[]','疏直拙依附，清高無匹儔。',12,'全唐诗/poet.song.112000.json','["疏直拙依附，清高無匹儔。"]'),
('439ea399-9764-4e8c-9007-91c0ab918cf8','建炎丞相成國呂忠穆公退老堂  其一','范寅賓','宋','宋诗','song-poetry','','[]','忽辭端委侍巖廊，歸卧菟裘退老堂。',64,'全唐诗/poet.song.112000.json','["忽辭端委侍巖廊，歸卧菟裘退老堂。", "遠避勢家蕭相國，旁連永巷郭汾陽。", "江如渭水煙波碧，山似靈巖草木香。", "公向此閒留杖屨，寧知身在赤城傍。"]'),
('364f32ca-9c72-4051-84aa-16b5fee3c82c','建炎丞相成國呂忠穆公退老堂  其二','范寅賓','宋','宋诗','song-poetry','','[]','不令甲第起康莊，却向郊園草作堂。',64,'全唐诗/poet.song.112000.json','["不令甲第起康莊，却向郊園草作堂。", "廬阜規模臨嵽嵲，霅溪顔色俯滄浪。", "參旂井鉞聊遮戶，赤舄貂冠且挂牆。", "几浄窗明無俗事，願公時草乞言章。"]'),
('a1024950-94ca-4f01-beba-d51d260fb348','浯溪碑','蔡說','宋','宋诗','song-poetry','','[]','生非耀□欲爭雄，發見英華□自中。',64,'全唐诗/poet.song.112000.json','["生非耀□欲爭雄，發見英華□自中。", "□秉湘東千古筆，已思河北一時躬。", "忠肝義膽平□□，鐵畫銀鈎大紀功。", "尊主□□□子事，晞顔志節亦顔同。"]'),
('dd8276e0-66de-4405-be5d-9b53b58cc9c8','夏日過莊嚴寺僧索詩爲留三絕  其一','晁公武','宋','宋诗','song-poetry','','[]','松筠窈窕隠禪房，茗碗熏爐白晝長。',32,'全唐诗/poet.song.112000.json','["松筠窈窕隠禪房，茗碗熏爐白晝長。", "門外塵埃生熟惱，誰知林下自清凉。"]'),
('35881b15-ccc2-4215-bca9-a6289a77f1da','夏日過莊嚴寺僧索詩爲留三絕  其二','晁公武','宋','宋诗','song-poetry','','[]','笑脫塵衫撲軟紅，杖藜徙倚水光中。',32,'全唐诗/poet.song.112000.json','["笑脫塵衫撲軟紅，杖藜徙倚水光中。", "最憐林葉深深處，遮盡斜陽不礙風。"]'),
('b6369ddf-fa7c-40d6-ab44-a3a7481c5f4b','夏日過莊嚴寺僧索詩爲留三絕  其三','晁公武','宋','宋诗','song-poetry','','[]','出門散策烟棲樹，歸路扶輿月蛻痕。',32,'全唐诗/poet.song.112000.json','["出門散策烟棲樹，歸路扶輿月蛻痕。", "十里江村入圖畫，野橋沙路杳難分。"]'),
('3999073b-4c7c-404f-9d41-5fef52a021ff','荆州即事  其一','晁公武','宋','宋诗','song-poetry','','[]','戰船不見和州載，勝地惟餘避暑宮。',32,'全唐诗/poet.song.112000.json','["戰船不見和州載，勝地惟餘避暑宮。", "今日蒭蕘皆得往，大王風作庶人風。"]'),
('51c3de95-470c-4d3d-8c98-9c915b572eba','荆州即事  其二','晁公武','宋','宋诗','song-poetry','','[]','初上蓬籠竹笮船，始知身是劍南官。',32,'全唐诗/poet.song.112000.json','["初上蓬籠竹笮船，始知身是劍南官。", "沙頭沽酒市樓暖，靳步買薪江墅寒。"]'),
('a62fcacd-96c5-47db-963c-4e89a06bc4be','荷池','晁公武','宋','宋诗','song-poetry','','[]','平池積潦漲輕痕，宛若扁舟繫水濱。',64,'全唐诗/poet.song.112000.json','["平池積潦漲輕痕，宛若扁舟繫水濱。", "斷岸纔盈六七尺，低蓬恰受兩三人。", "巡簷悅目蒲蓮秀，隠几忘機雁鶩馴。", "坐閲江湖好風景，不愁濤瀨闊無津。"]'),
('74baf7c7-6a83-4697-a199-776bc207c048','南定樓','晁公武','宋','宋诗','song-poetry','','[]','水接荆門陸控秦，卧龍陳迹久尤新。',64,'全唐诗/poet.song.112000.json','["水接荆門陸控秦，卧龍陳迹久尤新。", "劍關驛外青山舊，錦里祠邊碧草春。", "更築飛樓瞰瀘水，擬將遺恨問洪鈞。", "南方已定雖饒富，北望中原正慘神。"]'),
('5c0768a7-3771-4c9e-a416-302c54fdc453','春日','晁公武','宋','宋诗','song-poetry','','[]','蝸牛廬畔舫齋前，春晚風光絕可憐。',32,'全唐诗/poet.song.112000.json','["蝸牛廬畔舫齋前，春晚風光絕可憐。", "雲補斷山尤秀拔，竹藏殘蕊尚嬋娟。"]'),
('68caba49-5dd5-47f9-b841-6a5188271d43','詩扇','晁公武','宋','宋诗','song-poetry','','[]','短蓬煙裏冷蕭蕭，兩岸梅花各見招。',32,'全唐诗/poet.song.112000.json','["短蓬煙裏冷蕭蕭，兩岸梅花各見招。", "吹散前村一杯酒，滿江風雨不相饒。"]'),
('306c3602-cd53-4d81-a0d9-f80bca4f010f','酆都觀','晁公武','宋','宋诗','song-poetry','','[]','勝絕平都觀，盤紆石磴長。',264,'全唐诗/poet.song.112000.json','["勝絕平都觀，盤紆石磴長。", "崇崗虎蹲踞，古柏雁分張。", "殿閣剛風外，軒墀灝氣旁。", "煙華迎碧瓦，雲葉覆雕牆。", "古有神仙術，能齊日月光。", "升騰繼黄老，烜赫數陰王。", "採藥巖巒秀，燒丹井竈香。", "綵雲生洞穴，白晝上穹蒼。", "陳迹今猶在，咸云實不亡。", "碑銘餘漢魏，像設自齊梁。", "仙騎霜毛潔，胎禽雪羽翔。", "豪商供香火，騷客鬭篇章。", "顧我趨行殿，尋真到靜坊。", "遺文觀翠琰，隠訣悟青囊。", "儻解交龍虎，終能翳鳳凰。", "定紆蒼玉佩，徑入白雲鄉。", "却憶求輕舉，相傳笑彼狂。", "李君煉丹石，韓子服硫黄。", "雅欲同南極，俄驚葬北邙。", "古今垂烱戒，服餌要周防。", "却老寧無策，怡神別有方。", "不須紈與素，但可舉清觴。"]'),
('25ae9c12-abaa-4c33-8ba9-9689e2d42f51','讀林罕小說','晁公武','宋','宋诗','song-poetry','','[]','倉頡鸛鳥跡，於是創文字。',252,'全唐诗/poet.song.112000.json','["倉頡鸛鳥跡，於是創文字。", "原其制作心，本以便記事。", "呼讀猶强名，况乃論位置。", "周人建小學，六書分義類。", "特令授童蒙，庶幾別同異。", "奈何中古後，穿鑿失倫次。", "蟲皿晉醫言，止戈楚人誌。", "宋更𩢍作騧，秦易辠爲罪。", "三刀自夢徵，兩日因讖記。", "山絲已怪妄，門草更茫昧。", "白水及緋衣，皆是表符瑞。", "解槐與說棗，抑又出譏戲。", "形聲罕復論，一切歸會義。", "咄哉許祭酒，著論窮巧慧。", "流俗喜不根，傳授滿當世。", "廷尉議三章，諸生談六藝。", "往往授其言，大抵皆附會。", "林生最晚出，紛亂尤自恣。", "何言斯亭上，刻石高贔屭。", "却思荆舒禍，對此頻雪涕。", "憑誰掩其惡，水火爲焚棄。"]'),
('ce1af56f-2951-4fa7-a3fb-7321f69040f0','登金山','晁公武','宋','宋诗','song-poetry','','[]','東游尋勝即登臨，浮玉知名冠古今。',64,'全唐诗/poet.song.112000.json','["東游尋勝即登臨，浮玉知名冠古今。", "萬壑波濤喧海口，千年巖岫據江心。", "雨篷烟棹征帆遠，曉磬昏鐘佛屋深。", "詩客分留風景在，憑君一爲發長吟。"]'),
('f10672d7-2c86-439b-9c4c-c2ceacd3b877','遊焦山','晁公武','宋','宋诗','song-poetry','','[]','江勢東傾劇建瓴，中流巖壑隠禪扃。',64,'全唐诗/poet.song.112000.json','["江勢東傾劇建瓴，中流巖壑隠禪扃。", "遊僧誰渡降龍鉢，過客爭摸瘞鶴銘。", "修竹捎雲凌北固，桃花吹浪漲南溟。", "上人勸賦斯山境，乞與微吟勒翠屏。"]'),
('cedd60e5-d3f9-4467-a9e6-240331dc4843','句  其一','晁公武','宋','宋诗','song-poetry','','[]','軒窗竹院臨流靜，燈火瓜洲隔岸深。',16,'全唐诗/poet.song.112000.json','["軒窗竹院臨流靜，燈火瓜洲隔岸深。"]'),
('4c57a701-8b90-4159-a905-24d7216b3ea0','句  其二','晁公武','宋','宋诗','song-poetry','','[]','只言天下少霖雨，不知隆中有卧龍。',16,'全唐诗/poet.song.112000.json','["只言天下少霖雨，不知隆中有卧龍。"]'),
('c9b9cd3f-0d39-470d-8bc7-265fdcd34671','句  其三','晁公武','宋','宋诗','song-poetry','','[]','峨眉古名山，長雄坤之維。',24,'全唐诗/poet.song.112000.json','["峨眉古名山，長雄坤之維。", "月峽爲表裏，雪嶺相蔽虧。"]'),
('d1f0104c-d509-4a7d-a7a6-92bd7a23e6a6','句  其四','晁公武','宋','宋诗','song-poetry','','[]','銅梁山昏嵐翠重，石鏡水落灘聲遲。',16,'全唐诗/poet.song.112000.json','["銅梁山昏嵐翠重，石鏡水落灘聲遲。"]'),
('ec410a77-8cc3-4175-8779-39c64b0e74ed','夔州歌簡晁子西','王從道','宋','宋诗','song-poetry','','[]','白帝夔州萬古城，全蜀東門下相控。',192,'全唐诗/poet.song.112000.json','["白帝夔州萬古城，全蜀東門下相控。", "瞿唐灧澦勢嶄絕，赤甲白鹽光澒洞。", "峽雨關雲朝莫征，煙葉水花洲渚共。", "少陵冥寞減光輝，山川草木今誰諷。", "明知風物待組織，可笑可笑浪嘲弄。", "逸亭野老泛舟來，迥立蒼茫遊覽縱。", "旋提燕拂呵物象，試吐清音激鸞鳳。", "江頭一見晁廣文，客裏倡酬無乃奉。", "天生之子映昭代，與我突出萬人衆。", "古來道合事襟期，有作正須行雅頌。", "下瞰一隅會萬景，豈無江靈爲供送。", "請君作詩如畫圖，收拾形容未宜空。"]'),
('64bb5562-00e5-4263-974c-856d33ba7f1a','寄范季隨','范季隨父','宋','宋诗','song-poetry','','[]','萬里投殊俗，餘生老一丘。',48,'全唐诗/poet.song.112000.json','["萬里投殊俗，餘生老一丘。", "常憐子之秀，能慰此生愁。", "只欲連牆住，胡爲下邑留。", "黄塵詩思盡，乞與四山秋。"]'),
('3c34fefd-c63e-4b72-a30a-36fb3c751225','句  其一','趙善晤','宋','宋诗','song-poetry','','[]','天約閑雲結嫩陰，苦無詩酒懶登臨。',16,'全唐诗/poet.song.112000.json','["天約閑雲結嫩陰，苦無詩酒懶登臨。"]'),
('c50a7b12-78e8-4390-ad05-6e80b6d6b990','句  其二','趙善晤','宋','宋诗','song-poetry','','[]','一聲鷄唱日初午，滿地花寒秋已深。',16,'全唐诗/poet.song.112000.json','["一聲鷄唱日初午，滿地花寒秋已深。"]'),
('07d13204-9b37-4234-b6ef-5dceae5b2fc1','貶朱崖行臨高道中買愁村古未有對馬上口占','胡銓','宋','宋诗','song-poetry','','[]','北往長思聞喜縣，南來怕入買愁村。',32,'全唐诗/poet.song.112000.json','["北往長思聞喜縣，南來怕入買愁村。", "區區萬里天涯路，野草荒烟正斷魂。"]'),
('0272e5d2-9c97-494b-bcc4-e4b0af552a26','次雷州和朱彧秀才韵時欲渡海','胡銓','宋','宋诗','song-poetry','','[]','何人著眼覷征驂，頼有新詩作指南。',64,'全唐诗/poet.song.112000.json','["何人著眼覷征驂，頼有新詩作指南。", "螺髻層層明晚照，蜃樓隠隠倚晴嵐。", "仲連蹈海齊虛語，魯叟乘槎亦謾談。", "爭似澹菴乘興往，銀山千疊酒微酣。"]'),
('0b70c86d-8f14-477a-b90f-4d20c3c580bc','題崖州洗兵亭','胡銓','宋','宋诗','song-poetry','','[]','一带清波六月凉，洗兵安用挽天潢。',64,'全唐诗/poet.song.112000.json','["一带清波六月凉，洗兵安用挽天潢。", "哥舒血蹴紅凝箭，子美苔欹綠卧槍。", "玉壘塵清閑擂鼓，玳筵風靜細流觴。", "澹菴臨水空惆悵，洛水凌波見未嘗。"]'),
('ccc13a0f-e8fa-4ab5-b86b-6b5ce98003fe','峽山','胡銓','宋','宋诗','song-poetry','','[]','山似牛頭峽，水如龍尾灣。',96,'全唐诗/poet.song.112000.json','["山似牛頭峽，水如龍尾灣。", "半生多罪垢，浣洗塵土顔。", "仙人舊聞名，一往何年還。", "岫幌煙爲鎖，玉扉誰與關。", "忽聞響答谷，恍若猿叫山。", "我欲紀末契，焉得茅三間。", "泉漏聽琴筑，風雨聞佩環。", "木杪青螺髻，得非雲霧鬟。"]'),
('a91ccd27-f18b-45f7-ae75-42c509cbdcd7','題鐵阬','胡銓','宋','宋诗','song-poetry','','[]','路入陽春境，杳然非世間。',48,'全唐诗/poet.song.112000.json','["路入陽春境，杳然非世間。", "初疑金菊嶺，原是鐵阬山。", "日薄嵐氣重，天寒酒力慳。", "人言茲地惡，我愛碧孱顔。"]'),
('db583a18-9d6d-4249-8a40-acc7565b8e67','銅石山','胡銓','宋','宋诗','song-poetry','','[]','是處山皆石，他山盡不如。',48,'全唐诗/poet.song.112000.json','["是處山皆石，他山盡不如。", "固非從地出，疑是補天餘。", "下隨一拳小，高凌千仞虛。", "奇章應未見，名不下中書。"]'),
('f44221f8-4ae3-49bb-92c9-3702ae53effa','和林和靖先生梅韵  其一','胡銓','宋','宋诗','song-poetry','','[]','感時湔淚幾時乾，顧影伶俜獨立難。',64,'全唐诗/poet.song.112000.json','["感時湔淚幾時乾，顧影伶俜獨立難。", "自恐節孤無與對，誰憐族冷不勝寒。", "未應一世供愁斷，長願三更秉燭看。", "雨過花邊行更好，猶嫌子美借銀鞍。"]'),
('7a84fbea-570b-4615-8dcc-224b33014cb9','和林和靖先生梅韵  其二','胡銓','宋','宋诗','song-poetry','','[]','風亭小立夢初殘，步步凌空對廣寒。',64,'全唐诗/poet.song.112000.json','["風亭小立夢初殘，步步凌空對廣寒。", "照眼雙明清可掬，閑情一味淡相看。", "曉縈瑞霧黏初潤，晴映高雲暴未乾。", "三嗅臨風思無限，蕊宮遥夜酒初闌。"]'),
('c3a722fb-e906-4f5e-9b0d-7e534c3dab4e','和林和靖先生梅韵  其三','胡銓','宋','宋诗','song-poetry','','[]','瘦吟幽玩有餘妍，更向高人獨樂園。',64,'全唐诗/poet.song.112000.json','["瘦吟幽玩有餘妍，更向高人獨樂園。", "無垢未應經露沐，不緇甯信受塵昏。", "春風自識明妃面，夜雨能清吏部魂。", "插向膽瓶看更好，凜如明月薦雷樽。"]'),
('8386926f-9324-426d-b112-fa94cd544758','和林和靖先生梅韵  其四','胡銓','宋','宋诗','song-poetry','','[]','一年佳處早梅時，鈎引清風巧釣詩。',64,'全唐诗/poet.song.112000.json','["一年佳處早梅時，鈎引清風巧釣詩。", "未分霜冷禁瘦朵，漸看春入奈愁枝。", "晚尤奇特憐無伴，夜更分明不可私。", "冷落更須憑酒煖，從今鄒律未消吹。"]'),
('2250a035-ae87-4fe8-82a7-45c4fa3bc625','和林和靖先生梅韵  其五','胡銓','宋','宋诗','song-poetry','','[]','紛紛紅紫勿相猜，自古騷人酷嗜梅。',64,'全唐诗/poet.song.112000.json','["紛紛紅紫勿相猜，自古騷人酷嗜梅。", "皂蓋折花憐老杜，黄梅時雨憶方回。", "一生耐凍天憐惜，滿世趨炎我獨來。", "桃李爭春身老大，急須吟醉莫停杯。"]'),
('0edb4d94-6659-4975-a119-cfec3d002e49','到瓊州和李參政','胡銓','宋','宋诗','song-poetry','','[]','落網從前一念斜，崖州前定復何嗟。',64,'全唐诗/poet.song.112000.json','["落網從前一念斜，崖州前定復何嗟。", "萬山行盡逢黎母，雙井渾疑似若邪。", "行止非人十年夢，廢興有命一浮家。", "此行所得誠多矣，更願從今泛北槎。"]'),
('120ab244-a954-40db-80ea-b113bbc3f85f','題自畫瀟湘夜雨圖','胡銓','宋','宋诗','song-poetry','','[]','一片瀟湘落筆端，騷人千古带愁看。',32,'全唐诗/poet.song.112000.json','["一片瀟湘落筆端，騷人千古带愁看。", "不堪秋著楓林港，雨闊煙深夜釣寒。"]'),
('47f67ff8-737c-4854-9e60-6a2026006297','題畫扇','胡銓','宋','宋诗','song-poetry','','[]','誰向生綃白團扇，畫將覊客據征鞍。',32,'全唐诗/poet.song.112000.json','["誰向生綃白團扇，畫將覊客據征鞍。", "南遷萬里知前定，壁上崖州莫怕看。"]'),
('912e5a19-7dcd-42e4-8dbe-bb4149f760ae','登南恩望海臺','胡銓','宋','宋诗','song-poetry','','[]','君恩寬逐客，萬里聽歸來。',48,'全唐诗/poet.song.112000.json','["君恩寬逐客，萬里聽歸來。", "未上凌煙閣，先登望海臺。", "山爲翠浪湧，湖拓碧天開。", "目斷飛雲處，終身愧老萊。"]'),
('09fdd47c-748d-46ee-bb70-083ef02660be','題岳忠武王廟','胡銓','宋','宋诗','song-poetry','','[]','匹馬吳江誰著鞭，惟公攘臂獨爭先。',64,'全唐诗/poet.song.112000.json','["匹馬吳江誰著鞭，惟公攘臂獨爭先。", "張皇貔虎三千士，支持乾坤十六年。", "堪恨臨淄功未就，不知鍾室事何緣。", "石頭城下聽輿議，萬姓顰眉亦可憐。"]'),
('da48dae7-e740-487b-b4f6-f43d453ca2c4','和張慶符題余作清江引圖  其一','胡銓','宋','宋诗','song-poetry','','[]','痛飲從來別有腸，酒酣落筆掃滄浪。',32,'全唐诗/poet.song.112000.json','["痛飲從來別有腸，酒酣落筆掃滄浪。", "如今却怕風波惡，莫畫清江畫醉鄉。"]'),
('2379800e-1064-4e8f-8c5a-61792e2e258b','和張慶符題余作清江引圖  其二','胡銓','宋','宋诗','song-poetry','','[]','何人半醉眼花昏，畫出江南煙雨村。',32,'全唐诗/poet.song.112000.json','["何人半醉眼花昏，畫出江南煙雨村。", "滿世庾塵遮不得，聊將醉墨洗乾坤。"]'),
('064dba4c-fbc4-4cfa-9db3-74b8304389ea','次張伯麟慶符','胡銓','宋','宋诗','song-poetry','','["\u897f\u6e56"]','往事渾如一夢中，回思吳越腋生風。',64,'全唐诗/poet.song.112000.json','["往事渾如一夢中，回思吳越腋生風。", "雲閒別嶺千層碧，日落西湖一抹紅。", "上竺留題陳跡在，孤山遊賞故人空。", "莫將句攪幽人意，我輩緣詩正坐窮。"]'),
('5348fee5-d75a-429c-aeff-0eb55f5ab0a4','答友人','胡銓','宋','宋诗','song-poetry','','[]','竹徑蕭疏杖履經，偕臨流水誦黄庭。',32,'全唐诗/poet.song.112000.json','["竹徑蕭疏杖履經，偕臨流水誦黄庭。", "秋風忽作世情冷，山色似慚君眼青。"]'),
('cdd97818-d94a-4f1f-b0b0-7860dfc85571','除夜次慶符','胡銓','宋','宋诗','song-poetry','','[]','白髮無端苦見尋，十年孤負醉花陰。',64,'全唐诗/poet.song.112000.json','["白髮無端苦見尋，十年孤負醉花陰。", "可憐獨鶴輕浮海，未及昏鴉日伴林。", "天末醉眠千嶺寂，江南夢繞五雲深。", "一杯遥祝慈闈壽，松柏長春共有心。"]'),
('83af7c7e-7615-4a57-a15e-04350c571d26','予戲作水墨四紙張慶符有詩因用其韵','胡銓','宋','宋诗','song-poetry','','[]','姑孰先生方遣化，饑食饞涎餐餠畫。',128,'全唐诗/poet.song.112000.json','["姑孰先生方遣化，饑食饞涎餐餠畫。", "信知詩必窮乃工，忍窮誰復如公者。", "崎嶇我已羈江湖，僂肩如我世恐無。", "從來畫亦窮乃妙，兩窮相值真堪吁。", "平生笑坡誇四板，祇愛丹青非道眼。", "豈如淡墨出天然，雪欲來時水雲晚。", "先生一見輒傾倒，回觀濁世秋毫小。", "不須更羨釣魚翁，已自超然遊漢表。"]'),
('6e3a325c-0c8d-4bbb-bde6-833ee91bfb93','乾道三年九月宴罷  其一','胡銓','宋','宋诗','song-poetry','','[]','晚年種德聽和鑾，露冷林深綻錦團。',64,'全唐诗/poet.song.112000.json','["晚年種德聽和鑾，露冷林深綻錦團。", "金鳳花殘秋欲半，木犀香遠晚初寒。", "擬將艾製候朝紱，愧把蘆芽易釣竿。", "早與君王乞歸去，仕途方險戰於鞍。"]'),
('7349b01c-3ae6-459f-9240-8a667e7abffc','乾道三年九月宴罷  其二','胡銓','宋','宋诗','song-poetry','','[]','萬古雲霄一鳳鸞，歸來蓬島月光團。',64,'全唐诗/poet.song.112000.json','["萬古雲霄一鳳鸞，歸來蓬島月光團。", "久將忠義私心許，要使奸雄怯膽寒。", "漏盡玉龍隨彩仗，赦銜金鳳下長竿。", "天家催賜黄花酒，笑指是翁能據鞍。"]'),
('4eaf6552-4664-4c46-8dd6-7e21c387859a','哭趙公鼎','胡銓','宋','宋诗','song-poetry','','[]','以身去國故求死，抗疏犯顔今獨難。',64,'全唐诗/poet.song.112000.json','["以身去國故求死，抗疏犯顔今獨難。", "閣下特書三姓在，海南惟見兩翁還。", "一坵孤塚寄瓊島，千古高名屹太山。", "天地祇因慳一老，中原何日復三關。"]'),
('22e0df84-f31e-4666-b27b-8d147e7fcd2e','辭朝','胡銓','宋','宋诗','song-poetry','','[]','不踏金堤新築沙，却尋寂寞紫雲家。',64,'全唐诗/poet.song.112000.json','["不踏金堤新築沙，却尋寂寞紫雲家。", "一春絃管花間鳥，半夜笙歌水底蛙。", "榮悴安時猶竹柏，行藏有待豈匏瓜。", "獨醒正渴杯中物，薄薄茅柴亦勝茶。"]'),
('b48d045d-6a01-4c1a-8656-1d5a3da84159','家訓','胡銓','宋','宋诗','song-poetry','','[]','悲哉爲儒者，力學不知疲。',288,'全唐诗/poet.song.112000.json','["悲哉爲儒者，力學不知疲。", "觀書眼欲暗，秉筆手生胝。", "無衣兒號寒，絕糧妻啼饑。", "文思苦冥搜，形容長枯羸。", "俯仰多迍邅，屢受胯下欺。", "十舉方一第，雙鬢已如絲。", "丈夫老且病，焉用富貴爲。", "可憐少壯日，適在貧賤時。", "沉沉朱門宅，中有乳臭兒。", "狀貌如婦人，光瑩膏粱肌。", "襁褓襲世爵，門承勳戚資。", "前庭列嬖僕，出入相追隨。", "千金辦月廩，萬錢供賞支。", "後堂擁姝姬，早夜同笑嬉。", "錯落開珠翠，艷輝沃膏脂。", "粧飾及鷹犬，繪綵至薔薇。", "青春付杯酒，白日消枰棋。", "守俸還酒債，堆金選娥眉。", "朝從博徒飲，暮赴娼樓期。", "逢人說門閥，樂性惟珍奇。", "絃歌恣娛燕，繒綺飾容儀。", "田園日脧削，戶門日傾隳。", "聲色遊戲外，無餘亦無知。", "帝王是何物，孔孟果爲誰。"]'),
('ea92315a-15b7-4282-b97d-725505da6ddb','劉仙巖','胡銓','宋','宋诗','song-poetry','','[]','縣崖怪石水潺潺，宜有神龍隠此間。',64,'全唐诗/poet.song.112000.json','["縣崖怪石水潺潺，宜有神龍隠此間。", "窮勝不妨歸險洞，尋春那止看羣山。", "攀龍行即天邊去，躍馬聊同野外還。", "好景良辰適相會，一樽好共水雲閒。"]'),
('64854553-a90e-4a2a-8d77-228722147977','永興觀','胡銓','宋','宋诗','song-poetry','','[]','連雲宿麥團碧浪，綴草落花成錦窠。',32,'全唐诗/poet.song.112000.json','["連雲宿麥團碧浪，綴草落花成錦窠。", "我來欲覓種桃者，獵獵空存庭下莎。"]'),
('e3288878-aac5-4645-b543-11888e229bf7','噴雪泉','胡銓','宋','宋诗','song-poetry','','[]','廬峯潄玉舊傳名，今見青原噴雪成。',32,'全唐诗/poet.song.112000.json','["廬峯潄玉舊傳名，今見青原噴雪成。", "兩處山川肯相下，洗除塵垢一時清。"]'),
('9f78b1ed-79ab-4712-a28f-67cd6a4bcbaa','寶氣亭','胡銓','宋','宋诗','song-poetry','','[]','塵容不逐江流浄，酒力都從雪壓消。',32,'全唐诗/poet.song.112000.json','["塵容不逐江流浄，酒力都從雪壓消。", "斗下祇今無劍氣，年來牛犢在人腰。"]'),
('058fb7fc-dca7-4dc2-8b27-f27c14104009','十二月二十四日問譚孔昭疾見庭下雨中花云木芙蓉也楚詞云搴芙蓉兮木末言芙蓉水花不在木末也','胡銓','宋','宋诗','song-poetry','','[]','幽花卧雨滋濺淚，秀色可人羞冶容。',32,'全唐诗/poet.song.112000.json','["幽花卧雨滋濺淚，秀色可人羞冶容。", "却笑楚人非博物，不知木末有芙蓉。"]'),
('1629d2d0-eb6e-497f-8ae1-b7d7de1eae3d','東池即事','胡銓','宋','宋诗','song-poetry','','[]','小園聊日涉，鷗鳥共忘機。',48,'全唐诗/poet.song.112000.json','["小園聊日涉，鷗鳥共忘機。", "笋長畦丁喜，春餘菜甲稀。", "幽花禁霧雨，翠篠澹風漪。", "步屧橫塘路，游魚覺昨非。"]'),
('c54dd218-e52d-4ae9-85cd-a1e28e56845a','泛舟東池坐客賦詩次其韵','胡銓','宋','宋诗','song-poetry','','[]','逐客生涯一釣篷，野塘幽絕小樓東。',64,'全唐诗/poet.song.112000.json','["逐客生涯一釣篷，野塘幽絕小樓東。", "柳邊新過清塵雨，水面徐來送月風。", "逸興似窮千里遠，勝遊還復五人同。", "子皮已結烟波社，白酒何妨日日中。"]'),
('c2f55a4d-c73d-4332-8328-b37b6ce96be8','復用前韵','胡銓','宋','宋诗','song-poetry','','[]','放逐歸來戶已篷，夢魂時到浙江東。',64,'全唐诗/poet.song.112000.json','["放逐歸來戶已篷，夢魂時到浙江東。", "心如止水偏陶月，身似虛舟但逐風。", "雲路自憐飛鳥倦，山盟誰與白鷗同。", "管城本乏封侯骨，人道中書却不中。"]'),
('0798efdc-aa9e-4b91-8cbe-cd50672331c1','公冶携酒見過與者溫元素康致美賦詩投壺再用前韵','胡銓','宋','宋诗','song-poetry','','[]','澹叟意簡古，終日巾不屋。',244,'全唐诗/poet.song.112000.json','["澹叟意簡古，終日巾不屋。", "彼美德星崔，憐我味蠹竹。", "挈榼破孤悶，聊欲觀醉玉。", "情殊饋盤餐，事等遺潘沐。", "古人感意重，飲水亦沙醁。", "一觴萬慮空，天宇覺隘促。", "自非薪突者，上客怕徐福。", "主人起揚觶，百歲風雹速。", "莫獻野人芹，但飽先生蓿。", "我亦起膝席，卒爵更三肅。", "溫伯况可人，康{巩/言}亦脫俗。", "共賦飣坐梅，句壓詩人谷。", "浩浩氣吐虹，盎盎春生腹。", "湘纍彼狷者，底事醒乃獨。", "日游無功鄉，生計豈不足。", "壺歌發笑電，雅劇不言肉。", "夜久拔銀燭，幽燼飄蔌蔌。", "我於腹無負，正恐腹自恧。", "姑置勿復科，茗碗瀹寒淥。", "舌出醉言歸，况我舌已木。"]'),
('0fab0c9d-0d41-4a71-9682-37d2aba05e74','小西湖  其一','胡銓','宋','宋诗','song-poetry','','["\u897f\u6e56"]','沙鷗無事作羣眠，亂荇縈風翠带牽。',32,'全唐诗/poet.song.112000.json','["沙鷗無事作羣眠，亂荇縈風翠带牽。", "波靜不憂無蒂樐，心清聊溉不毛田。"]'),
('b96016fb-2d39-4f8f-8ed1-582fed4c21c3','小西湖  其二','胡銓','宋','宋诗','song-poetry','','["\u897f\u6e56"]','湖邊日日枕流眠，却笑風波百丈牽。',32,'全唐诗/poet.song.112000.json','["湖邊日日枕流眠，却笑風波百丈牽。", "無限煙光堪我老，不須投表乞歸田。"]'),
('e50d94db-610f-4a4a-94d3-4d9a468b3770','北湖','胡銓','宋','宋诗','song-poetry','','[]','北湖境自舒，水迥山更碧。',24,'全唐诗/poet.song.112000.json','["北湖境自舒，水迥山更碧。", "雪衣故飛來，照影共清白。"]'),
('59964f59-eff1-4022-8c9d-405cfe3dedc3','中秋前一夕携家步至北湖藉縟草久之和東坡湖上聽琴韵','胡銓','宋','宋诗','song-poetry','','[]','臨水遲佳客，碧盡天邊雲。',96,'全唐诗/poet.song.112000.json','["臨水遲佳客，碧盡天邊雲。", "心期殊未來，且復偶細君。", "援琴松滿耳，添酒月入樽。", "水天靜秋光，不受世所醺。", "飲酣睡味美，風漪生簟紋。", "得來亦何有，理亂了不聞。", "兒童莫喚醒，不妨長醉昏。", "休論萬里情，我非宜城渾。"]'),
('50792a96-fff7-466c-bd12-bb8d7164e466','戲題陳晦叔經略秀齋','胡銓','宋','宋诗','song-poetry','','["\u897f\u6e56"]','天宇脩眉浮太華，晚晴濃綠新如畫。',128,'全唐诗/poet.song.112000.json','["天宇脩眉浮太華，晚晴濃綠新如畫。", "何似文君蹙遠山，秀色可餐清更雅。", "人知潑黛青孱顔，共喜眉宇脩彎環。", "不知是中石藴玉，遂能發彩驚塵寰。", "美人美人隔秋水，娟娟靜淑金閨裏。", "其人如玉德滿身，笑殺西湖比西子。", "杜陵破帽隨金鞍，心醉歸來空掩關。", "不須更問許玉斧，二十四山如髻鬟。"]'),
('57d96bce-eab7-40f2-ad01-d3c30b2e89f9','早梅','胡銓','宋','宋诗','song-poetry','','[]','千林閴無伴，獨秀益孤明。',48,'全唐诗/poet.song.112000.json','["千林閴無伴，獨秀益孤明。", "索笑延幽賞，聞香失宿酲。", "天教清到骨，我豈淡無情。", "睡起黄昏月，花邊洗破觥。"]'),
('bde89321-c5bd-4d61-92f7-ac441025d8d3','和山谷從張仲謀乞蠟梅韵寄吳明可','胡銓','宋','宋诗','song-poetry','','[]','玉壺佳處野梅發，未減後山襄樣黄。',32,'全唐诗/poet.song.112000.json','["玉壺佳處野梅發，未減後山襄樣黄。", "乞取一枝淮海去，不應春色占錢塘。"]'),
('0d92a5f8-d985-42c9-a3c9-e3797c27d72c','劉景仁畫墨梅扇上又畫梅影於扇陰求詩各題一絕  其一','胡銓','宋','宋诗','song-poetry','','[]','竹外梅花耿玉顔，凜然冰句落霜紈。',32,'全唐诗/poet.song.112000.json','["竹外梅花耿玉顔，凜然冰句落霜紈。", "莫將輕扇趨炎子，留作人間六月寒。"]'),
('575f7a43-17d2-4afd-b75c-f94d705f6d1e','劉景仁畫墨梅扇上又畫梅影於扇陰求詩各題一絕  其二','胡銓','宋','宋诗','song-poetry','','["\u897f\u6e56"]','踏月看梅不見花，只驚水底影橫斜。',32,'全唐诗/poet.song.112000.json','["踏月看梅不見花，只驚水底影橫斜。", "歸來掃向冰綃扇，袖有西湖處士家。"]'),
('48ced308-b895-4d23-8dfa-2a7b84a29a50','長卿見過賦美人插花用其韵','胡銓','宋','宋诗','song-poetry','','[]','花亦興不淺，美人頭上開。',48,'全唐诗/poet.song.112000.json','["花亦興不淺，美人頭上開。", "心事眼勾破，鬢香魂引來。", "笑春燭底影，濺淚風前杯。", "分韵得先字，客今誰可哉。"]'),
('80722293-61be-433a-b934-9bf1d8252154','落花','胡銓','宋','宋诗','song-poetry','','[]','未信花飛能減春，花飛只惱有情人。',32,'全唐诗/poet.song.112000.json','["未信花飛能減春，花飛只惱有情人。", "也知造物賈餘巧，要作醉眠紅錦裀。"]'),
('16b29253-8ef0-48f7-8cad-1c6a925113df','寄題王氏佚老堂','胡銓','宋','宋诗','song-poetry','','[]','大塊勞生亦可吁，解言佚我漆園癯。',64,'全唐诗/poet.song.112000.json','["大塊勞生亦可吁，解言佚我漆園癯。", "東家嘗記老吾老，西洛請師迂叟迂。", "于謹延年還可杖，孔光靈壽不須扶。", "勸君早作菟裘計，太半歸來雪滿鬚。"]'),
('86cda7e9-110f-4b8b-8085-2f09b46738b3','次李參政吏隠堂韵爲昌化守陳仲平題','胡銓','宋','宋诗','song-poetry','','[]','公餘詩老屢携將，物外高談味自長。',64,'全唐诗/poet.song.112000.json','["公餘詩老屢携將，物外高談味自長。", "省事清心追豹隠，批花判月瀉鵝黄。", "地偏不愧先生里，意野何如處士鄉。", "却笑商顔園與綺，苦矜巖穴事高皇。"]'),
('864ecf71-bab8-43c4-a683-6de313764d6f','吏隠堂','胡銓','宋','宋诗','song-poetry','','[]','微風稍披凍，芳萌亦吐林。',120,'全唐诗/poet.song.112000.json','["微風稍披凍，芳萌亦吐林。", "百鳥感春陽，鈎輈弄其音。", "振策遵城曲，逍遥寫煩襟。", "愛此堂下石，青潤挺琅琳。", "中坳貯清泉，測之不盈簪。", "纖鱗候暖戲，寂歷自浮沉。", "默視澹忘慮，白日爲移陰。", "人生本虛靜，垢濁無自侵。", "忽爲外物牽，至性不可尋。", "於焉得所監，一洗塵中心。"]'),
('889d7efb-833a-4995-80a0-294d8c94cacb','遠遊','胡銓','宋','宋诗','song-poetry','','[]','萍跡長泡轉，天崖到處家。',48,'全唐诗/poet.song.112000.json','["萍跡長泡轉，天崖到處家。", "芳菲雲過雨，聚散手摶沙。", "且喚陳驚坐，共尋留子嗟。", "酒狂從曠蕩，漢吏要無華。"]'),
('fc73f77a-f3d4-47ca-8b0d-6e2962c5f223','送王嘉叟侍郎使虜仍用其韵','胡銓','宋','宋诗','song-poetry','','[]','蘇張姓字炳如丹，遍歷遐荒覺世寬。',64,'全唐诗/poet.song.112000.json','["蘇張姓字炳如丹，遍歷遐荒覺世寬。", "龍勒殊勳標絕域，麟宮奇節障狂瀾。", "二千里外河源遠，十九年間海上寒。", "二子精忠君勉繼，歸來錦領萬人看。"]'),
('18f6795a-bcb9-455c-899d-3c4cbae2375a','次韵答陳立夫送酒  其一','胡銓','宋','宋诗','song-poetry','','[]','平生痛飲號專門，逸氣旋乾復轉坤。',32,'全唐诗/poet.song.112000.json','["平生痛飲號專門，逸氣旋乾復轉坤。", "孔坐年來客常滿，直須一日倒千樽。"]'),
('be8dd871-622a-4832-b8c5-f4c7f3c2ed0c','次韵答陳立夫送酒  其二','胡銓','宋','宋诗','song-poetry','','[]','公家家世舊崔嵬，驚坐先生日萬杯。',32,'全唐诗/poet.song.112000.json','["公家家世舊崔嵬，驚坐先生日萬杯。", "已辦槽床千日飲，便須乘月抱琴來。"]'),
('11a62b4f-5781-4f44-a66d-acef0fe07ff5','示公冶','胡銓','宋','宋诗','song-poetry','','[]','不妨我與魚傳素，只恐人言鴆作媒。',32,'全唐诗/poet.song.112000.json','["不妨我與魚傳素，只恐人言鴆作媒。", "莫笑東坡管閑事，細將紅葉寫將來。"]'),
('40727d03-f2e7-4df3-97b3-8790b6ad1753','過青潭鋪用杜少陵韵','胡銓','宋','宋诗','song-poetry','','[]','世路羊腸險，崎嶇不計層。',48,'全唐诗/poet.song.112000.json','["世路羊腸險，崎嶇不計層。", "附炎蛾並火，待暗鼠窺燈。", "國削臣心折，秋高虜勢增。", "魚蝦何足慮，回前顧鯨鵬。"]'),
('923b21c9-20e4-45ad-b1ca-e6ed2565c01f','宿陸便鋪用曹侍郎詠題柱韵','胡銓','宋','宋诗','song-poetry','','[]','襏襫但多于耜者，犀渠不見弄兵人。',32,'全唐诗/poet.song.112000.json','["襏襫但多于耜者，犀渠不見弄兵人。", "盈疇雲子歲不惡，父老却談今使君。"]'),
('edf497ee-39fc-4c84-806b-dc3d50745681','臨平道中用坡老雪中長韵答劉寺簿','胡銓','宋','宋诗','song-poetry','','[]','從來無逸爲元龜，艱難稼穡誠宜知。',320,'全唐诗/poet.song.112000.json','["從來無逸爲元龜，艱難稼穡誠宜知。", "奚爲三老凍且餒，不以仁政勤噓吹。", "澹菴野人錯料事，苦吟對雪空掀髭。", "蘇仙漫解賦曉浩，韓子亦徒歌晚澌。", "兩翁句法豈不好，祇欠鯁語書安危。", "先生忍寒蹋凜冽，著屐步步如爰絲。", "憂民未減胼胝叟，挾纊擁貂吾忍爲。", "斲水長哦壓郊島，令我玩味終朝持。", "肯同俠窟暖金帳，不說莊生姑射肌。", "平生浮雲睨卿相，往往羞談蔡克兒。", "向來編研國朝事，典刑一一裨明時。", "側聞玉音猶在耳，記錄姓名標殿帷。", "遄歸承明定不日，啟沃要領親鳳姿。", "莫將篇什助雪虐，好吐忠嘉淳俗漓。", "致君宜許堯相稷，活國未慚唐宰墀。", "嗟予三黜從此逝，已覺別袖風披披。", "扁舟却憶剡溪老，夢寐早逐心旌馳。", "古風永祕此囊錦，惡語勿笑吾言巵。", "行行自愛保明哲，咄咄賢業追規隨。", "况復君家有故事，元城先生劉器之。"]'),
('bdb9e0fe-cebc-48d1-919b-66344d027c8e','答單監簿','胡銓','宋','宋诗','song-poetry','','[]','賢哉洛城翁，塵甑每貸粟。',168,'全唐诗/poet.song.112000.json','["賢哉洛城翁，塵甑每貸粟。", "饑來睨書案，臭味清可掬。", "獨抱古遺經，凜凜一川玉。", "唯知耕寬閑，未暇井衍沃。", "蕭然跨騄駬，破漏數間屋。", "諫議真可人，著意向幽獨。", "贈之三百月，鼂采照鯨目。", "閉門予自煎，颯爽對修竹。", "先生如玉川，詩書實其腹。", "顧我亦何幸，此客良不俗。", "新篇忽入手，闊躡李杜躅。", "華衮褒雖榮，溢美論非篤。", "何時玉壺山，復得從所欲。", "三碗澆枯腸，勿賦飯不足。"]'),
('f13b0a1f-c883-4d49-b2f5-8b23f7d55e0f','上洪帥李伯紀丞相','胡銓','宋','宋诗','song-poetry','','[]','相印橫拖御案前，聖恩暫許帥藩宣。',64,'全唐诗/poet.song.112000.json','["相印橫拖御案前，聖恩暫許帥藩宣。", "舉幡北闕危三刖，抗疏南床忽十年。", "往事淒涼人墮甑，此身空潔鷺棲煙。", "當時坐榻生龍尾，猶望陳蕃一解懸。"]'),
('15306916-e990-40e3-965f-99d68ff88b69','夏旱至秋田家種蕎麥以補歲事','胡銓','宋','宋诗','song-poetry','','[]','千里還經赤地連，老農作苦也堪憐。',64,'全唐诗/poet.song.112000.json','["千里還經赤地連，老農作苦也堪憐。", "來牟不復歌豐歲，蕎麥猶能救歉年。", "山色淺深秋潑黛，田毛上下曉披綿。", "天公莫遣霜如雪，赤子嗷嗷要解懸。"]'),
('56ca478d-74b7-4bf0-9157-5c1eb4949eaa','乙未元夕坐上用東坡上元韵二首  其一','胡銓','宋','宋诗','song-poetry','','[]','勝遊寶籙記吾曾，五十年來一衲僧。',64,'全唐诗/poet.song.112000.json','["勝遊寶籙記吾曾，五十年來一衲僧。", "晝短莫吟千歲燭，年豐聊看九華燈。", "一毬未放寒星墜，萬炬渾驚烈日升。", "詩酒雖堪驅使在，照愁佳句愧坡能。"]'),
('01076561-a65a-4fcf-b1df-1329af840186','乙未元夕坐上用東坡上元韵二首  其二','胡銓','宋','宋诗','song-poetry','','[]','漫云學佛竟何曾，且伴西鄰正覺僧。',64,'全唐诗/poet.song.112000.json','["漫云學佛竟何曾，且伴西鄰正覺僧。", "莫笑酒狂剛止酒，且來燈下看傳燈。", "人言星近如堪摘，誰謂天高不可升。", "見說燧人初改火，固知將聖信多能。"]'),
('6391ecc3-a365-4a7f-baf9-5d0e30d5f2bc','元夕與監務宋皋飲罷踏月觀燈用坡老儋州上元韵','胡銓','宋','宋诗','song-poetry','','[]','賞心樂事巧相違，清坐持枚學數扉。',64,'全唐诗/poet.song.112000.json','["賞心樂事巧相違，清坐持枚學數扉。", "雁足不來空燕雀，鴒原何在歎蠨蝛。", "開懷對酒祛愁破，緩步看燈踏月歸。", "萬里投荒真細事，頻年不得戲萊衣。"]'),
('b4fe6166-a537-4cd8-b579-fe715523f252','司業口占絕句奇甚銓輒用韵和呈效吳體','胡銓','宋','宋诗','song-poetry','','[]','南山舊說王隠者，北斗今看韓退之。',32,'全唐诗/poet.song.112000.json','["南山舊說王隠者，北斗今看韓退之。", "不須覓句花照眼，行見調羹酸著枝。"]'),
('e6193bd4-73ed-4078-a209-9e8f316edfd3','銓携具賞石渠酴醾用坡韵呈同舍','胡銓','宋','宋诗','song-poetry','','[]','酴醾獨殿春，得路未爲晚。',96,'全唐诗/poet.song.112000.json','["酴醾獨殿春，得路未爲晚。", "露葉張翠傘，月蕊明玉幰。", "洗妝雨亦妍，暗麝風更遠。", "唐時真宰相，勁氣凌諫苑。", "危言工切劘，壁立萬仞巘。", "帝爲釀此花，以賞碩畫婉。", "清芬濯千古，天河豈須輓。", "不妨便醉死，聞香定魂返。"]'),
('c9920339-30d1-49c4-8742-b0b0bdf52d05','傳示銀杏兼簡林謙之','胡銓','宋','宋诗','song-poetry','','[]','頭白經筵思漫覃，駸駸末路我何堪。',64,'全唐诗/poet.song.112000.json','["頭白經筵思漫覃，駸駸末路我何堪。", "八年還作玉堂集，一笑真懷銀杏談。", "敢說麕書譏聶北，聊因麟趾詠周南。", "梅開更得珠園去，紅粟寒梢試一探。"]'),
('33e5941c-7fa0-4acb-9a56-2f04465832cb','和王民瞻送行詩  其一','胡銓','宋','宋诗','song-poetry','','[]','巖耕名已振京關，未信終身袖手閑。',64,'全唐诗/poet.song.112000.json','["巖耕名已振京關，未信終身袖手閑。", "萬卷不移顔氏樂，一生無愧伯夷班。", "致君自許唐虞上，待我誰能季孟間。", "兩社年來欠元老，蒼生拭目望公還。"]'),
('7342ff39-e7f0-45d5-bc87-85c155b7d237','和王民瞻送行詩  其二','胡銓','宋','宋诗','song-poetry','','[]','士氣從來弱不支，逢時言行欲俱危。',64,'全唐诗/poet.song.112000.json','["士氣從來弱不支，逢時言行欲俱危。", "不因湖外三年謫，安得江南一段奇。", "非我獨清緣世濁，此心誰識只天知。", "萬牛回首須公起，大厦將顛要力持。"]'),
('9ae12d66-ba8d-4a2e-bb87-4cb2c8294c9e','題小桃源圖','胡銓','宋','宋诗','song-poetry','','[]','閒愛鶴立木，靜嫌僧叩門。',48,'全唐诗/poet.song.112000.json','["閒愛鶴立木，靜嫌僧叩門。", "是非花莫笑，白黑手能言。", "心遠闊塵境，路幽迷水村。", "逢人不須說，自喚小桃源。"]'),
('7a990646-28f3-4a05-bcb1-9dc8447363de','游白龍洞','胡銓','宋','宋诗','song-poetry','','[]','懸崖怪石水潺潺，宜有神龍隠此間。',64,'全唐诗/poet.song.112000.json','["懸崖怪石水潺潺，宜有神龍隠此間。", "窮勝不妨歸險洞，尋春那止看羣山。", "攀龍行即天邊去，躍馬聊同野外還。", "好景良辰適相會，一樽聊共水雲閒。"]'),
('0b356b9b-ac3a-4215-a069-6b64f94ca3fd','與正覺長老同遊蔣山','胡銓','宋','宋诗','song-poetry','','[]','寶公何似贊公房，好句還追鐵鳳翔。',64,'全唐诗/poet.song.112000.json','["寶公何似贊公房，好句還追鐵鳳翔。", "金象妙高驚地勝，木犀清遠送天香。", "明年蠟屐誰猶健，昨日登樓我尚强。", "三老未應輸二老，茲游奇絕永難忘。"]'),
('f4137e5e-6efc-4d25-af70-7bf6833cb3ab','金陵書事','胡銓','宋','宋诗','song-poetry','','[]','六代風流最永嘉，鬰葱勝氣隠晴霞。',64,'全唐诗/poet.song.112000.json','["六代風流最永嘉，鬰葱勝氣隠晴霞。", "折衝樽俎神俱旺，表裏山河險莫誇。", "幾縷碧煙迷杏眼，半篙清漲減蒲芽。", "歌聲已得檀郎怨，四海而今再一家。"]'),
('cd596287-8e68-462c-b6bc-c95c20ed39e6','禁直賜果','胡銓','宋','宋诗','song-poetry','','[]','禁署裝成寶纓絡，冰盤翦出水晶鹽。',32,'全唐诗/poet.song.112000.json','["禁署裝成寶纓絡，冰盤翦出水晶鹽。", "傳呼天上好消息，玉果新頒出御匳。"]'),
('1d045a2b-0c23-4667-afc9-43cc0e9df9c2','玉津園餞魏王','胡銓','宋','宋诗','song-poetry','','[]','餞行朱邸帝城春，隨例顛忙宴玉津。',64,'全唐诗/poet.song.112000.json','["餞行朱邸帝城春，隨例顛忙宴玉津。", "報國獨勞千一慮，鈞天同聽十三人。", "金卮宣勸君恩重，花露湔愁醉夢真。", "却憶故山猿鶴在，便思投劾乞其身。"]'),
('d53c0ce3-28d3-4110-811c-62cee883b580','詩一首','胡銓','宋','宋诗','song-poetry','','[]','夜讀文公猛虎詩，云何虎死忽悲啼。',64,'全唐诗/poet.song.112000.json','["夜讀文公猛虎詩，云何虎死忽悲啼。", "人生未省向來事，虎死方羞前所爲。", "昨日猶能食熊豹，今朝無計奈狐狸。", "我曾道汝不了事，喚作癡兒果是癡。"]'),
('e768346b-575b-4651-99bd-785c44d87827','又用過鐵坑山韵','胡銓','宋','宋诗','song-poetry','','[]','縣古杉楓老，人居水竹間。',36,'全唐诗/poet.song.112000.json','["縣古杉楓老，人居水竹間。", "字民無獄訟，携客有江山。", "路遠旅愁積，病多詩思慳。"]'),
('4550c743-ed0b-43fd-ba42-72363031a74d','和新州端老','胡銓','宋','宋诗','song-poetry','','[]','平生不識澥渤島，入海要看蓬萊山。',32,'全唐诗/poet.song.112000.json','["平生不識澥渤島，入海要看蓬萊山。", "向來同是災荒客，今我海南君海北。"]'),
('8309985a-a0e0-4665-b4a3-3aee08f30f2b','和和靖八梅  其一','胡銓','宋','宋诗','song-poetry','','[]','暗裏尋香自不迷，照空焉用夜燃臍。',64,'全唐诗/poet.song.112000.json','["暗裏尋香自不迷，照空焉用夜燃臍。", "欲危疏朵風吹老，太瘦長條雨颭低。", "孤艷幾時同把盞，野香猶記助看題。", "唐人未識高標在，浪自紛紛說李蹊。"]'),
('1e71d2ea-8e00-4bdf-9943-228a36aadede','和和靖八梅  其二','胡銓','宋','宋诗','song-poetry','','[]','縞裙練帨照釵荆，霜竹寒松秀色並。',64,'全唐诗/poet.song.112000.json','["縞裙練帨照釵荆，霜竹寒松秀色並。", "八詠格高凌太白，千林地迥切西清。", "著枝有味知深意，欹屋無言似薄情。", "日暮水邊空悵望，渾如湘浦見皇英。"]'),
('6ef4e595-43c2-4b6f-8bb2-500922481a1b','和和靖八梅  其三','胡銓','宋','宋诗','song-poetry','','[]','當年曾見鳳城頭，入骨貪看興未休。',64,'全唐诗/poet.song.112000.json','["當年曾見鳳城頭，入骨貪看興未休。", "小摘欲論千種恨，微吟還喚一番愁。", "每嫌俗物薰心醉，長願清馨滿世留。", "穠李倚風梨带雨，比方應合面騂羞。"]'),
('914fb109-941e-4a74-8c90-46772f5d7408','追和東坡雪詩','胡銓','宋','宋诗','song-poetry','','[]','爲瑞應便種麥鴉，餘光猶得映書車。',64,'全唐诗/poet.song.112000.json','["爲瑞應便種麥鴉，餘光猶得映書車。", "也知一臘要三白，故作六霙先百花。", "授簡才慳慚賦客，披簑句好憶漁家。", "擬酤斗酒聽琴操，三百青銅落畫叉。"]'),
('14da68ca-f156-4e73-942a-9f0debc72fff','過三衢呈劉共父','胡銓','宋','宋诗','song-poetry','','[]','別離如許每引領，邂逅幾何還著鞭。',64,'全唐诗/poet.song.112000.json','["別離如許每引領，邂逅幾何還著鞭。", "微服過宋我何敢，大國賜秦公不然。", "衰鬢彫零已子後，高名崒嵂方丁年。", "即看手握天下砥，山中宰相從雲眠。"]'),
('311e1abf-e70d-4757-9b1e-75e9d39c9caf','次李參政送行韵答黄舜楊','胡銓','宋','宋诗','song-poetry','','[]','打成大錯一毫差，萬里去尋留子嗟。',64,'全唐诗/poet.song.112000.json','["打成大錯一毫差，萬里去尋留子嗟。", "微管閒思齊仲父，賜奴長價漢渾邪。", "道窮憐我空憂國，句好知君定作家。", "便欲相携趁帆飽，要觀子美賦靈槎。"]'),
('ce0dc933-0c7a-4c64-9458-18f9020a70f3','送周子上赴宜春','胡銓','宋','宋诗','song-poetry','','[]','憶昔昌黎伯，直諫氣凜然。',144,'全唐诗/poet.song.112000.json','["憶昔昌黎伯，直諫氣凜然。", "又聞贊皇公，直道薄雲天。", "堂堂兩宗工，蓋世勳無前。", "朅來著此邦，仰山同不騫。", "公今又繼往，相望三百年。", "風流雖已矣，遺跡儼弗愆。", "邦風雜未純，雕俗頑莫鎸。", "要須痛一洗，興氓作其賢。", "束吏縛猛虎，愛民烹小鮮。", "課爲天下最，名壓坐中先。", "鳳尾催歸詔，看看下小旃。", "踐槐知不晚，開旦促曹韉。"]'),
('038290c1-e900-4aac-8d14-d44751505547','送菊','胡銓','宋','宋诗','song-poetry','','["\u601d\u56fd", "\u83ca\u82b1"]','卧病高秋留海浦，明日重陽更風雨。',192,'全唐诗/poet.song.112000.json','["卧病高秋留海浦，明日重陽更風雨。", "杜門不出長蒼苔，令我天涯心獨苦。", "籬角黄花親手栽，近節如何獨未開。", "含芳閟采亮有以，使君昨暮徵詩來。", "凌晨試遣霜根送，畚玉雖微甚珍重。", "極知無意競秋光，往作橫窗歲寒供。", "憶我初客天子都，西垣植此常千株。", "結花年年應吹帽，始信南邦事盡殊。", "願得封培自今日，何間朱崖萬家室。", "秋香端不負乾坤，但願簫管亂疇匹。", "歸去來兮雖得歸，念歸政自莫輕違。", "他日采英林下酌，誰向清霜望翠微。"]'),
('55693cce-df12-45ea-bfcf-f7ed2a312d4f','逸賢峝','胡銓','宋','宋诗','song-poetry','','[]','好竹平生志頗堅，誰知島上有淇園。',64,'全唐诗/poet.song.112000.json','["好竹平生志頗堅，誰知島上有淇園。", "溪邊六逸李太白，林下七賢楊巨源。", "空翠有時穿犖确，圓機終日轉潺湲。", "從來到處安心地，肯認家山作本源。"]'),
('02144d32-23f7-4d9f-9e54-f12e9c6650c9','題陽江何氏挹翠軒','胡銓','宋','宋诗','song-poetry','','[]','人皆犯紅塵，君獨嗜空翠。',132,'全唐诗/poet.song.112000.json','["人皆犯紅塵，君獨嗜空翠。", "紅塵終有得，空翠了無味。", "自衆人以觀，君亦少良計。", "細問紅塵人，軒冕蔓倒敝。", "方寸萬斛埃，灰土常處袂。", "翻思對青山，一洗穢濁氣。", "始知空翠佳，千古餘爽思。", "何子亦何人，對此日隠几。", "明涵軒窗浄，影入林牖媚。", "眼界括窮碧，白鳥决歸眥。", "青山如高人，可挹不可致。"]'),
('9c493409-7435-489b-9b39-edec59f7c9e4','熙春亭','胡銓','宋','宋诗','song-poetry','','[]','井邑峯巒繞郡城，新臺高峙見南溟。',64,'全唐诗/poet.song.112000.json','["井邑峯巒繞郡城，新臺高峙見南溟。", "海瀾浩蕩連雲白，江漢朝宗徹底清。", "日月往來雙羽箭，乾坤今古一郵亭。", "年年不改長春景，遥想蓬山作畫屏。"]'),
('ebc91a9f-62b0-4999-a554-1bc10781e958','句  其一','胡銓','宋','宋诗','song-poetry','','[]','君側無讒人，發口不須婉。',12,'全唐诗/poet.song.112000.json','["君側無讒人，發口不須婉。"]'),
('fd11ee71-ba98-40ff-94dc-e33c19ea629f','句  其二','胡銓','宋','宋诗','song-poetry','','[]','盈尺子魚來丙穴，一瓶女酒敵新州。',16,'全唐诗/poet.song.112000.json','["盈尺子魚來丙穴，一瓶女酒敵新州。"]'),
('fb442b90-44a4-4968-b6c0-d1e2fc18915c','句  其三','胡銓','宋','宋诗','song-poetry','','[]','君恩許歸此一醉，傍有梨頰生微渦。',16,'全唐诗/poet.song.112000.json','["君恩許歸此一醉，傍有梨頰生微渦。"]'),
('07601bce-7917-4612-85f0-ff364782314b','句  其四','胡銓','宋','宋诗','song-poetry','','[]','萬古嗟無盡，千生笑有窮。',12,'全唐诗/poet.song.112000.json','["萬古嗟無盡，千生笑有窮。"]'),
('79e7789e-9827-473d-94b8-3ecbfc5098ea','句  其五','胡銓','宋','宋诗','song-poetry','','[]','兩山排闥來，周遭似環翠。',12,'全唐诗/poet.song.112000.json','["兩山排闥來，周遭似環翠。"]'),
('6c32bfd0-9e1f-464a-b2f0-8d70f3b88dcd','句  其六','胡銓','宋','宋诗','song-poetry','','[]','眼明漸見天涯驛，脚力將窮地盡州。',16,'全唐诗/poet.song.112000.json','["眼明漸見天涯驛，脚力將窮地盡州。"]'),
('e32f90d5-f0d0-4582-a45f-91b97f53208e','句  其七','胡銓','宋','宋诗','song-poetry','','[]','儋耳道中還可樂，東坡安用歎途窮。',16,'全唐诗/poet.song.112000.json','["儋耳道中還可樂，東坡安用歎途窮。"]'),
('66d4970f-884e-4cfe-9e96-1f9a852ce8fa','句  其八','胡銓','宋','宋诗','song-poetry','','[]','有水不栽蓮。',6,'全唐诗/poet.song.112000.json','["有水不栽蓮。"]'),
('eabd6e93-8185-4400-a862-9bd2621acb7c','句  其九','胡銓','宋','宋诗','song-poetry','','[]','當時號令君聽取，白戰無須带步叉。',16,'全唐诗/poet.song.112000.json','["當時號令君聽取，白戰無須带步叉。"]'),
('81d3d093-361b-4bba-9ec6-3cd12d63d75b','句  其一○','胡銓','宋','宋诗','song-poetry','','[]','啗氈使者莫思家。',8,'全唐诗/poet.song.112000.json','["啗氈使者莫思家。"]'),
('80567599-8dfd-4fa7-8a23-1dd7af1a0236','句  其一一','胡銓','宋','宋诗','song-poetry','','[]','梁園高會憶鄒巖，千里蒓羹未下鹽。',16,'全唐诗/poet.song.112000.json','["梁園高會憶鄒巖，千里蒓羹未下鹽。"]'),
('67790d1f-60e5-4bbf-9e3b-d506fba58fba','句  其一二','胡銓','宋','宋诗','song-poetry','','[]','中有羈孤濕帽尖。',8,'全唐诗/poet.song.112000.json','["中有羈孤濕帽尖。"]'),
('1da382ac-6a21-42d2-a736-0e9f3603b6ce','句  其一三','胡銓','宋','宋诗','song-poetry','','[]','夢入瓊崖身益壯，烟銷金塢臭空傳。',16,'全唐诗/poet.song.112000.json','["夢入瓊崖身益壯，烟銷金塢臭空傳。"]'),
('63272830-009a-4aac-8e64-bf562bdacdb8','句  其一四','胡銓','宋','宋诗','song-poetry','','[]','笑春燭底影，煎淚風前杯。',12,'全唐诗/poet.song.112000.json','["笑春燭底影，煎淚風前杯。"]'),
('910565e1-3d68-43f5-b479-63fdfc6c73c8','題翠巖寺','岳飛','宋','宋诗','song-poetry','','[]','秋風江上駐王師，暫向雲山躡翠微。',64,'全唐诗/poet.song.112000.json','["秋風江上駐王師，暫向雲山躡翠微。", "忠義必期清塞水，功名直欲鎮邊圻。", "山林嘯聚何勞取，沙漠羣凶定破機。", "行復三關迎二聖，金酋席卷盡擒歸。"]'),
('34816f06-ed24-4f06-8e72-aed43905ee0f','寄浮圖慧海','岳飛','宋','宋诗','song-poetry','','["\u5e90\u5c71", "\u957f\u6c5f"]','湓浦廬山幾度秋，長江萬折向東流。',64,'全唐诗/poet.song.112000.json','["湓浦廬山幾度秋，長江萬折向東流。", "男兒立志扶王室，聖主專師滅虜酋。", "功業要刊燕石上，歸休終伴赤松遊。", "丁寧寄語東林老，蓮社從此著力修。"]'),
('c9766c13-c333-447e-b867-726210ab6d6c','題青泥市蕭寺壁','岳飛','宋','宋诗','song-poetry','','[]','雄氣堂堂貫斗牛，誓將直節報君讎。',32,'全唐诗/poet.song.112000.json','["雄氣堂堂貫斗牛，誓將直節報君讎。", "斬除頑惡還車駕，不問登壇萬戶侯。"]'),
('6224c75c-6874-49c8-ad32-ad88d1e1cb47','送紫巖張先生北伐','岳飛','宋','宋诗','song-poetry','','["\u7231\u56fd", "\u9001\u522b", "\u8c6a\u8fc8"]','號令風霆迅，天聲動北陬。',48,'全唐诗/poet.song.112000.json','["號令風霆迅，天聲動北陬。", "長驅渡河洛，直擣向燕幽。", "馬蹀閼氏血，旗梟克汗頭。", "歸來報明主，恢復舊神州。"]'),
('9131a946-c363-417c-b1b2-665be93bbd90','池州翠微亭','岳飛','宋','宋诗','song-poetry','','["\u7eaa\u6e38", "\u53e4\u8bd7\u4e09\u767e\u9996", "\u70ed\u7231", "\u5199\u666f", "\u5b8b\u8bd7"]','經年塵土滿征衣，特特尋芳上翠微。',32,'全唐诗/poet.song.112000.json','["經年塵土滿征衣，特特尋芳上翠微。", "好山好水看不足，馬蹄催趁月明歸。"]'),
('9349a101-96d6-4c9f-a18a-63c3af5c2a93','遊嵬石山寺','岳飛','宋','宋诗','song-poetry','','[]','嵬石山前寺，林泉勝景幽。',48,'全唐诗/poet.song.112000.json','["嵬石山前寺，林泉勝景幽。", "紫金諸佛相，白雪老僧頭。", "潭水寒生月，松風夜带秋。", "我來屬龍語，爲雨濟民憂。"]'),
('d2d604e7-2809-4299-9de0-18e284e7b60e','過張溪贈張完','岳飛','宋','宋诗','song-poetry','','[]','無心買酒謁青春，對鏡空嗟白髮新。',32,'全唐诗/poet.song.112000.json','["無心買酒謁青春，對鏡空嗟白髮新。", "花下少年應笑我，垂垂羸馬訪高人。"]'),
('25b1d02d-2dc1-4650-a72a-ba16ffddbece','從駕遊內苑應制','岳飛','宋','宋诗','song-poetry','','[]','敕報遊西內，春光靄上林。',48,'全唐诗/poet.song.112000.json','["敕報遊西內，春光靄上林。", "花圍千朵錦，柳撚萬株金。", "燕繞龍旂舞，鶑隨鳳輦吟。", "君王多雨露，化育一人心。"]'),
('7cff3fbe-2ef7-4ea3-9c08-74828e8a383f','題驟馬岡','岳飛','宋','宋诗','song-poetry','','[]','立馬林岡豁戰眸，陣雲開處一溪流。',64,'全唐诗/poet.song.112000.json','["立馬林岡豁戰眸，陣雲開處一溪流。", "機舂水沚猶傳晉，黍秀宮庭孰憫周。", "南服只今殲小醜，北轅何日返神州。", "誓將七尺酬明聖，怒指天涯淚不收。"]'),
('cbaaafd0-0953-4365-93d6-94200fe6339a','題雩都華嚴寺','岳飛','宋','宋诗','song-poetry','','[]','手持竹節訪黄龍，舊穴空遺虎子蹤。',32,'全唐诗/poet.song.112000.json','["手持竹節訪黄龍，舊穴空遺虎子蹤。", "雲鎖斷崖無覓處，半山松竹撼秋風。"]'),
('e716e893-3ccc-4ef8-ad71-2f16382248fc','題池州翠光寺','岳飛','宋','宋诗','song-poetry','','[]','愛此倚欄桿，誰同寓目閒。',48,'全唐诗/poet.song.112000.json','["愛此倚欄桿，誰同寓目閒。", "輕陰弄晴日，秀色隠空山。", "島樹蕭疏外，征帆杳靄間。", "予雖江上老，心羨白雲還。"]'),
('d1e07d38-0744-4ced-ac41-a1de62f2f1d6','歸赴行在過上竺寺偶題','岳飛','宋','宋诗','song-poetry','','[]','强胡犯金闕，駐蹕大江南。',48,'全唐诗/poet.song.112000.json','["强胡犯金闕，駐蹕大江南。", "二帝雙魂杳，孤臣百戰酣。", "兵威空朔漠，法力仗瞿曇。", "恢復山河日，捐軀分亦甘。"]'),
('ccdd013c-7e20-4f78-95bb-0b88303e1ceb','送軫上人之廬山','岳飛','宋','宋诗','song-poetry','','["\u5e90\u5c71"]','何處高人雲路迷，相逢忽薦目前機。',64,'全唐诗/poet.song.112000.json','["何處高人雲路迷，相逢忽薦目前機。", "偶看菜葉隨流水，知有茅茨在翠微。", "瑣細夜談皆可聽，煙霏秋雨欲同歸。", "翛然又向諸方去，無數山供玉麈揮。"]'),
('b9e05ea4-fe8e-4d40-bf91-52108f7d4402','投岳侯','毛國英','宋','宋诗','song-poetry','','[]','鐵鎖沈沈截碧江，風旗獵獵駐危檣。',32,'全唐诗/poet.song.112000.json','["鐵鎖沈沈截碧江，風旗獵獵駐危檣。", "禹門縱使高千尺，放過蛟龍也不妨。"]'),
('2fcbf463-2d02-4df9-b942-3792b24f6a90','答岳鵬舉','張完','宋','宋诗','song-poetry','','[]','相別相逢不計春，眼前非舊亦非新。',32,'全唐诗/poet.song.112000.json','["相別相逢不計春，眼前非舊亦非新。", "聲求色相皆邪妄，莫認無疑是昔人。"]'),
('fc8b5578-eea5-4aab-add5-b4e99764937e','詩一首','掛笠道人','宋','宋诗','song-poetry','','[]','偶乘青帝出蓬萊，劍戟崢嶸遍九垓。',32,'全唐诗/poet.song.112000.json','["偶乘青帝出蓬萊，劍戟崢嶸遍九垓。", "我在目前人不識，爲留一笠莫沉埋。"]'),
('d58ac5fe-c8ed-482c-b2ae-bc999dc80fe4','夢中詩','許顗','宋','宋诗','song-poetry','','[]','閑花亂草春春有，秋鴻社燕年年歸。',32,'全唐诗/poet.song.112000.json','["閑花亂草春春有，秋鴻社燕年年歸。", "青天露下麥苗濕，古道月寒人迹稀。"]'),
('0fda04a3-7399-4850-9e56-263cd5225169','秋雨','許顗','宋','宋诗','song-poetry','','[]','零雨不出動隔旬，門前秋草長於人。',64,'全唐诗/poet.song.112000.json','["零雨不出動隔旬，門前秋草長於人。", "江湖浩渺欲無岸，錦石最小猶生雲。", "微陽片月何曾見，只有莓苔昏筆硯。", "田家黍穗未暇悲，茅屋且爲螢火飛。"]'),
('e917f1e5-9b9c-4767-93ea-f5ba4ea53420','紫騮馬','許顗','宋','宋诗','song-poetry','','[]','黄金絡頭玉爲觼，蜀錦障泥亂雲葉。',67,'全唐诗/poet.song.112000.json','["黄金絡頭玉爲觼，蜀錦障泥亂雲葉。", "花間顧影驕不行，萬里龍駒空汗血。", "露床秋粟飽不食，青蒭苜蓿無顔色。", "君不見東郊瘦馬百戰場，天寒日暮烏啄瘡。"]'),
('b481ed1d-fe9a-4141-b232-0d482af55798','遊石龍偶成寺僧通首坐飽歷叢林歸老此山故詩多及之','馮時行','宋','宋诗','song-poetry','','[]','飛泉撼琳球，羣山高崔嵬。',144,'全唐诗/poet.song.112000.json','["飛泉撼琳球，羣山高崔嵬。", "中有古道場，紫煙籠觀臺。", "石門不施關，榮辱自不來。", "霜鐘鳴萬壑，日出山霧開。", "老僧挈筠籃，上山拾羹材。", "歸煮南澗水，至味謝鹽梅。", "食飽不下床，法身充九垓。", "破衲一甲子，雲閒與徘徊。", "我欲吐情語，銘之古巖隈。", "雲切戒多事，勿聽龍作媒。", "爲雨非不佳，世間多塵埃。", "預恐爲雨罷，歸來污蒼苔。"]'),
('0f13140c-d2cb-4b7a-9bb9-9f0de57d91f5','友人惠酒殊佳用清光滑辣四字爲韵以謝  其一','馮時行','宋','宋诗','song-poetry','','[]','六府萃百感，攻愁須酒兵。',72,'全唐诗/poet.song.112000.json','["六府萃百感，攻愁須酒兵。", "故人如我知，侵月走雙甖。", "手裂絳泥封，瓦盆貯瑶瓊。", "我生百世後，見此聖之清。", "一飲肺腸潤，再飲毛骨輕。", "何必跨茅龍，超然欲遐征。"]'),
('2d0a1fd6-b394-47de-bc90-ab94f9c3769e','友人惠酒殊佳用清光滑辣四字爲韵以謝  其二','馮時行','宋','宋诗','song-poetry','','[]','先生飲至和，尺宅如鑑光。',72,'全唐诗/poet.song.112000.json','["先生飲至和，尺宅如鑑光。", "餘力暨酒醴，百甕春朝陽。", "洗我朱墨塵，凌風龜鶴腸。", "醉鄉更飽歷，歧路久已荒。", "休吏閉齋閣，三盞通真梁。", "到處百慮息，其俗如陶唐。"]'),
('215a664d-73e0-41b3-b6e5-fd7efc11b311','友人惠酒殊佳用清光滑辣四字爲韵以謝  其三','馮時行','宋','宋诗','song-poetry','','[]','苦懷茅屋底，夜歸船軋軋。',72,'全唐诗/poet.song.112000.json','["苦懷茅屋底，夜歸船軋軋。", "酒榼對魚籃，照路燃藁秸。", "及門呼弟昆，長少常七八。", "酣腸如有神，造化不管轄。", "朅來久欠此，君乃餉甘滑。", "大醉今復狂，醒來恐愁殺。"]'),
('c90073a7-ba48-433f-8318-c50a2a7d565f','友人惠酒殊佳用清光滑辣四字爲韵以謝  其四','馮時行','宋','宋诗','song-poetry','','[]','冠豸取能觸，佩劍取能割。',72,'全唐诗/poet.song.112000.json','["冠豸取能觸，佩劍取能割。", "飲酒移氣體，我亦嗜清辣。", "舉白欲下咽，丹腑已通達。", "溫溫坎離間，正氣自旋斡。", "於焉養真勇，險語犯天闥。", "千鍾建太平，豈徒爲消渴。"]'),
('2a67ea53-b4df-4f95-b91f-9f9959d4e45d','舍弟生子','馮時行','宋','宋诗','song-poetry','','[]','多女信無助，多男復何虞。',192,'全唐诗/poet.song.112000.json','["多女信無助，多男復何虞。", "我固喜二仲，輩出三丈夫。", "圓郎未解語，手欲學抹朱。", "閏郎好神氣，兩眼澄秋湖。", "復有新生兒，初探玄海珠。", "一一閲清俊，並是千里駒。", "胡爲集我家，足視種德符。", "昆弟若一體，在爾猶在吾。", "堂前有雙親，各已皓鬢鬚。", "抱弄想慰意，顔色朝愉愉。", "未問壯門戶，悅親良所須。", "况我藜藿腸，要當飽典謨。", "足以立家學，燦燦遺羣雛。", "爾後更五稔，汝等行不扶。", "我欲爲道肥，汝當爲書癯。", "富貴何足道，陸賈真洪儒。"]'),
('a5364628-69ee-4d64-8078-81a9c22c529c','龍鶴禱雨','馮時行','宋','宋诗','song-poetry','','[]','地靈丘壑邃，危路入紫煙。',168,'全唐诗/poet.song.112000.json','["地靈丘壑邃，危路入紫煙。", "藤蘿閟尺水，中有龍潛淵。", "青曦弄驕暉，紹興丙辰年。", "嗷嗷周餘民，生理諒難全。", "令尹謝不敏，來上天公牋。", "一念如絲芒，已斡造化權。", "夜半雷繞山，雨出山之巔。", "凌晨眺四郊，草木亦欣然。", "民戴神之休，次謂令尹賢。", "賢則吾豈敢，庶逭失職愆。", "甲兵久不洗，風霾漲塵寰。", "茲事非神助，誰其蕩腥羶。", "物極理必反，否泰如循環。", "神龍儻有意，速起飛九天。"]'),
('dc123337-2132-4146-b573-f28441eee500','斬雞栖木','馮時行','宋','宋诗','song-poetry','','[]','舍南開小圃，土平如沃肥。',180,'全唐诗/poet.song.112000.json','["舍南開小圃，土平如沃肥。", "去年種桃李，今年花離離。", "畦丁不解事，其傍樹雞栖。", "雨潤枝柯繁，風吹花葉披。", "頗乘風雨力，似欲桃李欺。", "桃李不自持，向人顔色低。", "客從何方來，指呼厲色辭。", "謂我同薰蕕，蒙昏其在茲。", "草木區以別，其猶異妍媸。", "再拜謝客意，黽勉事剪夷。", "桃李佳氣浮，欣欣如有知。", "老夫意猶惡，有悔不可追。", "大哉天地寬，含覆萬彙滋。", "美惡詎可齊，俱受一元施。", "援毫書其事，用貶小己私。"]'),
('9e7a6c73-6742-49cf-a506-107fc05b5a2c','偶成','馮時行','宋','宋诗','song-poetry','','[]','越羅與蜀錦，被體何其華。',84,'全唐诗/poet.song.112000.json','["越羅與蜀錦，被體何其華。", "豹胎與猩唇，適口良自佳。", "佳美未必得，飽暖不可賒。", "明通紙勝雪，樂昌墨如鴉。", "更招南浦石，四友相寵加。", "謾薰新寧香，時烹固陵茶。", "蕭然文字間，亦足爲生涯。"]'),
('02203e97-49bf-49d2-a7b6-70af2b433102','憶淵明二首  其一','馮時行','宋','宋诗','song-poetry','','[]','晨策東籬路，煌煌寒菊英。',48,'全唐诗/poet.song.112000.json','["晨策東籬路，煌煌寒菊英。", "我豈無他人，底事憶淵明。", "忘言會諸理，掃盡世俗情。", "悠然見南山，此意誰與評。"]'),
('4ac5f801-5690-4292-b998-e2c660769a7d','憶淵明二首  其二','馮時行','宋','宋诗','song-poetry','','[]','五音不害道，其如哇淫何。',48,'全唐诗/poet.song.112000.json','["五音不害道，其如哇淫何。", "聊以寫我心，素琴時按摩。", "澹泊有妙意，豈憂焚天和。", "賢哉等冥鴻，竟免嬰禍羅。"]'),
('5c11ccb4-ca0b-44a2-a89a-1558a023d761','題涪陵楊彥廣薰風亭','馮時行','宋','宋诗','song-poetry','','[]','身世如浮雲，百年一飄忽。',216,'全唐诗/poet.song.112000.json','["身世如浮雲，百年一飄忽。", "古人事業在，已腐蒿里骨。", "惜哉薰風亭，勁翰儼突兀。", "想當揮灑際，浩氣漲溟渤。", "迄茲變故後，同好亦泯沒。", "散帙落危睇，作亭煥新揭。", "超然盛德後，清芬念貽厥。", "亦聞爽塏地，山水皆秀發。", "曠蕩敞遐眺，葱蒨羅翠樾。", "勝遊集簪履，有酒備百罰。", "異時太真園，絳樹山硉矹。", "吾其解煩鞅，長風卧煙筏。", "問津鷗鳥外，亭上散白髮。", "飄飄揖薰風，解带脚不襪。", "咀嚼清冰圓，內洗肝肺渴。", "嗚呼蒼梧遠，瑶琴久衰歇。", "於焉慰永懷，森森來披拂。", "耿耿入疏襟，更欲遲華月。"]'),
('62b77066-8bf2-43b1-9638-a227113cf1d3','登洪雅明月樓與陳舜弼楊養源任道夫孫彥和探山水有清音韵賦詩得有字','馮時行','宋','宋诗','song-poetry','','[]','秋風吹征衣，我來亦何有。',276,'全唐诗/poet.song.112000.json','["秋風吹征衣，我來亦何有。", "長笑泉石間，邂逅得良友。", "飛屐凌長煙，相與濯世垢。", "浄宇閟寒藤，傑閣架層阜。", "登臨意象寬，軒豁擬高厚。", "江山來拱揖，似欲問安否。", "岌岌環翠屏，蜿蜿拖綠綬。", "欣然爲酬對，舉此一杯酒。", "憩心自瑩瑩，領要語不莠。", "浩歌激巖谷，朗暢孤月口。", "晴窗鏡萬類，憂樂隨所偶。", "向來事朱墨，伏案繭生肘。", "鬰鬰成底事，一腹負百醜。", "及茲謝塵紱，未及休五柳。", "暫與真賞愜，榮辱已芻狗。", "况復老煙霞，循寄日云久。", "頗聞葛稚川，芝朮幻衰朽。", "至今杖屨地，歷歷傳白叟。", "欲往從之遊，靜守一氣母。", "丹成跨明月，咫尺上南斗。", "頓首排天關，丐天解禍紐。", "日落寒雁哀，雲歸暮山黝。", "此意竟何如，乾坤一搔首。"]'),
('53e1ec21-737e-436b-8e56-bf4b8da9ceaf','隠甫聖可子儀同遊寶蓮分韵得郭字','馮時行','宋','宋诗','song-poetry','','[]','海縣一廛市，天地一郛郭。',288,'全唐诗/poet.song.112000.json','["海縣一廛市，天地一郛郭。", "跼蹐礙高厚，而况自羈絡。", "末俗競芒忽，訟紙霜葉落。", "平心作巨帚，一掃付清廓。", "無事我所得，超然解塵縛。", "天浄鏡磨垢，日炫眼刮膜。", "野水照曳杖，山煙薦飛屩。", "清朋璠璵姿，興寄相領畧。", "世間出世間，秋風古蘭若。", "翠巘拂觚稜，紫蘇濫關鑰。", "晨鐘隠町疃，香霧散林薄。", "竹密萬夫靜，樹迸蒼虯躍。", "黏壁篆乾蝸，簷絲下晴蠖。", "蒲團便熟倚，茗碗快自瀹。", "性與香火冷，身脫簿領虐。", "理窟深探討，迷津銳疏鑿。", "心期跨汗漫，知音付丘壑。", "俯仰三十秋，痛被造化謔。", "貧窮道味勝，老大世故約。", "妄念春朝冰，不作間市瘧。", "出據廊廟地，入分禽鳥樂。", "時來屈伸指，胸次何綽綽。", "一官弛負擔，五斗代菑穫。", "看山未害廉，塵迹詎可削。"]'),
('54dcb012-2b03-4cde-b527-accdfdae0eb3','紙帳','馮時行','宋','宋诗','song-poetry','','[]','野人抄谿苔，十幅圍秋風。',72,'全唐诗/poet.song.112000.json','["野人抄谿苔，十幅圍秋風。", "缺月窺我床，皎皎一室空。", "錦繡開華堂，坐挾不賞功。", "戮辱在其後，居然是樊籠。", "先生於此間，微吟和寒蛩。", "須臾寢不夢，覺來日升東。"]'),
('e5217cea-a318-4120-a09c-2a3018267749','布被','馮時行','宋','宋诗','song-poetry','','[]','天地一指耳，笑付杯中春。',72,'全唐诗/poet.song.112000.json','["天地一指耳，笑付杯中春。", "蒙頭布衾在，得失更勿論。", "前時曳竹杖，步過桑麻村。", "買費一千錢，十年度寒溫。", "恭儉德之基，福謙有鬼神。", "未能行於人，敢不施諸身。"]'),
('b95cf377-9234-4d3a-9bce-6f65af80968d','蒲團','馮時行','宋','宋诗','song-poetry','','[]','瘦骨何支離，老鶴驚晴霜。',72,'全唐诗/poet.song.112000.json','["瘦骨何支離，老鶴驚晴霜。", "軟苧聯溪蒲，一榻風月堂。", "四序自鱗次，跏趺貫炎凉。", "達官重錦茵，妙姬羅衣裳。", "寒士倚清秋，憂居涕浪浪。", "此君勿相留，我欲坐相忘。"]'),
('d61f2067-5813-4029-88ff-33a8b2f93ca0','瓦爐','馮時行','宋','宋诗','song-poetry','','[]','六籍聖賢心，歸來還下帷。',72,'全唐诗/poet.song.112000.json','["六籍聖賢心，歸來還下帷。", "老瓦燒柏子，冉冉度遊絲。", "侏儒飽欲死，靈均自長饑。", "塵言污人耳，夜來洗漣漪。", "更欲清鼻觀，引手時一披。", "知我其惟天，不須對愚溪。"]'),
('9f5d2c65-1b66-4ab9-b0a7-65425c7d628e','竹枕','馮時行','宋','宋诗','song-poetry','','[]','無節青琅玕，葛陂化龍餘。',72,'全唐诗/poet.song.112000.json','["無節青琅玕，葛陂化龍餘。", "可以奉君子，不憚捐其軀。", "幽人飽藜莧，總以飫膏腴。", "食罷掩關卧，鼻息谿雲敷。", "斗升乞西江，碌碌愧非夫。", "五友平生歡，相從歸故廬。"]'),
('70b5066f-59d4-4223-9cd6-64af84d313e9','見雪','馮時行','宋','宋诗','song-poetry','','[]','前日揮輕扇，今日御重衣。',192,'全唐诗/poet.song.112000.json','["前日揮輕扇，今日御重衣。", "重衣御則已，仍驚朝雪飛。", "數峯起天末，練練生光輝。", "有如老大臣，正色立玉墀。", "風自山椒來，凜凜折我髭。", "馬上久駐目，感此良慘悽。", "一昏復一曉，冉冉歲月移。", "憶昨大觀初，我始垂髫兒。", "倏忽一彈指，面目生權奇。", "今朝天上雪，宛作山中姿。", "豈免三十年，侵我兩鬢垂。", "况此甲馬動，憂端宿肝脾。", "何當撥百憂，采采山中芝。", "一洗稻粱氣，攝身凌霏微。", "春花與冬雪，俯視造化爲。", "去去宜努力，所幸今未衰。"]'),
('54ba3017-c502-4706-96f0-627fcbd14854','張明遠自持其所居萃勝亭記來求詩爲賦三篇  其一','馮時行','宋','宋诗','song-poetry','','[]','靜躁固異秉，出處良一途。',156,'全唐诗/poet.song.112000.json','["靜躁固異秉，出處良一途。", "巖前東來人，翻然應時須。", "赫赫帝者師，去與赤松俱。", "鐘鼎與林泉，天以私吾儒。", "窮達俛仰間，取捨亦須臾。", "曲士胸臆窘，屈伸自囚拘。", "長往信已隘，不休諒其愚。", "倚天霜崖姿，岱表張延符。", "桂棟辛荑楣，超然結雲廬。", "花草粲綺羅，清飈發笙竽。", "岡巒爲肺腑，煙霞相友于。", "逍遥以徜徉，聊可與爲娛。", "伏櫪萬里心，勿作山澤癯。"]'),
('fad5a8e5-b2ac-4628-b585-dd68c606b8d7','張明遠自持其所居萃勝亭記來求詩爲賦三篇  其二','馮時行','宋','宋诗','song-poetry','','[]','百城何岧嶢，儲清自太初。',156,'全唐诗/poet.song.112000.json','["百城何岧嶢，儲清自太初。", "靜境超人寰，羣仙之所居。", "清都閟寶籙，宮闕函丹書。", "真人拜玉庭，天帝手自除。", "寶蓋相參差，縹緲來空虛。", "我欲從之遊，茲山遂慵疏。", "朝霞以爲食，浮雲以爲車。", "此意靡堅决，西望空欷噓。", "君今定不凡，買山自菑畬。", "上方切層霄，伊蹊百步餘。", "瑶草破霧收，青精凌雨鋤。", "往往逢迎間，松喬曳雲裾。", "爲我語羨門，問訊今何如。"]'),
('9bb74d33-2216-444f-ac8d-8ebbdd98bb74','張明遠自持其所居萃勝亭記來求詩爲賦三篇  其三','馮時行','宋','宋诗','song-poetry','','[]','文章蓋代手，千載柳柳州。',156,'全唐诗/poet.song.112000.json','["文章蓋代手，千載柳柳州。", "落筆記山水，奇香撼琳球。", "開卷一再讀，宛若從之遊。", "歷歷爽心目，毛髮爲颼颼。", "若人嗜清曠，步履素得幽。", "攬勝得樞要，天地不可搜。", "巉巉華山孫，藤蘿護維陬。", "絕頂葺荷蓋，風月共夷猶。", "物色自飛動，與我相答酬。", "千里入睥睨，遠眼縱莫收。", "憑軒寫清絕，文與境趣侔。", "柳魂不可招，君幾紹前修。", "何當棄圭組，從君送清愁。"]'),
('f3712ae1-5817-408e-83ca-ad4f27be8173','重陽登翠圍亭亭廢十年竹柏蓊然殊蔽遠眼命寺僧芟除剪伐屏翳豁開林巒杳靄殆丹山之絕勝處也與同遊分韵賦詩以老杜開林出遠山爲韵得遠字','馮時行','宋','宋诗','song-poetry','','[]','林樾失洗沐，叢灌老偃蹇。',228,'全唐诗/poet.song.112000.json','["林樾失洗沐，叢灌老偃蹇。", "坐令軒豁地，雍穆成奧閫。", "千年李峨眉，孤調絕攀挽。", "徑欲剗君山，笑看湘水遠。", "我來此亭上，造化閲舒卷。", "何堪浩蕩意，鬰鬰仰若俛。", "蘭蕙生當門，尚爾付鍤畚。", "大材廊廟具，顧此何衮衮。", "石角礪霜斧，一斬三百本。", "圖事欲大快，不復計小損。", "天地英氣歸，川原勝魂返。", "鏡開水灧灧，龍轉山蜿蜿。", "卧虹踏歸市，融雲護春墾。", "晴光蕩芳酌，中筵舞蹲蹲。", "黄花壓客帽，胡床秋風穩。", "萬象競參揖，相見一何晚。", "通塞有時運，明晦理相反。", "干戈天地閉，撫事切深悃。", "痛澆磈磊胸，不復效老阮。"]'),
('1d57dfbe-f72f-4c2d-8453-8c520274e1ac','和鮮于晉伯游卧龍','馮時行','宋','宋诗','song-poetry','','["\u8861\u5c71"]','四十髮已白，百謀無一成。',264,'全唐诗/poet.song.112000.json','["四十髮已白，百謀無一成。", "林泉有夙志，芝朮寄晚程。", "人間好山水，往往盡經行。", "輒忌墮圭組，所至欲有營。", "卧龍勝蘭若，曩游愜平生。", "蒼茫紫翠間，藤蘿路回縈。", "上方攀躋迥，遐矚襟宇宏。", "風颯秋嶺瘦，雲護曉泉明。", "汲甘潄芳潤，擷香佩華英。", "境迷煙霞痼，道豁人鬼盲。", "是時駕言旋，濡毫記前楹。", "於今已八稔，愧負猿鶴盟。", "君今倚巖桂，泠然賦晨征。", "仙人餌白石，幽士飯青精。", "興託風塵表，咏味見高情。", "欲往從之遊，秋夢一羽輕。", "靜躁本異趣，出處諒欲誠。", "胸中一丘壑，敢以易功名。", "杖藜如可再，君爲寄先聲。", "南嶽寬嘲笑，北山緩譏評。", "行亦老菟裘，今姑隠市城。", "此心隨雲歸，與山日逢迎。"]'),
('86412af9-eb9d-4482-8ea1-fd07aaec126f','送開守解印','馮時行','宋','宋诗','song-poetry','','[]','窮冬自蕭疏，小壘玄雲開。',228,'全唐诗/poet.song.112000.json','["窮冬自蕭疏，小壘玄雲開。", "使君擲虎符，行矣何遽哉。", "父老相與言，未言心已哀。", "自云好使君，撫我如嬰孩。", "天不爲我旱，人不爲我災。", "使君今已行，力挽不可回。", "舉手向父老，聽我勿我猜。", "赤驥萬里足，瑶池倏往來。", "伏櫪方丈間，何其等駑駘。", "丹鳳隘寥廓，五湖看如杯。", "修羽落樊籠，安得一毰毸。", "驥非伏櫪姿，鳳當翔九垓。", "使君稟天秀，磊磊真長才。", "峽裏三家村，胡爲久徘徊。", "况與艱運偶，中州漲胡埃。", "天子急親賢，搜訪盡草萊。", "一麾諒其微，千里良需材。", "棄去自騰踏，爲國除禍胎。", "父老休嗟惜，功勳在雲臺。"]'),
('4f81f5f7-2e69-42c8-99eb-8de8bf2635ac','寄魏相之','馮時行','宋','宋诗','song-poetry','','[]','胡塵漲中州，大雅欲陵替。',288,'全唐诗/poet.song.112000.json','["胡塵漲中州，大雅欲陵替。", "遮眼惟甲兵，開口無丁字。", "君從何方來，落落清廟器。", "豈覓佳吏部，惠然枉輪駟。", "快語真起人，坐久益宏肆。", "復歸磨破瓦，自寫錦囊秘。", "敲門遣長鬚，恍若明星墜。", "意遠出寥廓，沈謝堪叔季。", "昔人重勳業，文章乃餘事。", "當其困湮淪，慷慨動幽思。", "舊筐儻好在，萬代作清吹。", "聽君發餘論，堂堂藴經濟。", "賈生求屬國，居然不自試。", "飄飄雲雨峽，風沙正憔悴。", "老聃柱下史，莊周漆園吏。", "鴻鵠千里心，蹭蹬戢遠翅。", "平生有筆硯，艱難不相棄。", "得失與憂樂，付此一游戲。", "舉手忽盈紙，不知老將至。", "達士要如此，何必苦酸鼻。", "凌江我二友，大非俗士比。", "與君共朝夕，可以忘世味。", "嗟我謀生拙，汩汩耗元氣。", "相逢思共載，羈紲但長喟。"]'),
('49b30e7c-87bc-4dc0-96ea-a61b15144fbe','和何子應夜讀書','馮時行','宋','宋诗','song-poetry','','[]','軒頊握元氣，堯舜法令疏。',144,'全唐诗/poet.song.112000.json','["軒頊握元氣，堯舜法令疏。", "三王備文物，古意漸欲無。", "周平一東轍，列國異車書。", "祖龍失雲雨，大漢天爲謨。", "後更十數姓，年歷幾千餘。", "滄海屢清淺，興亡如合符。", "生平笑書簏，遠覽資良圖。", "滑浄一棐几，萬代忽森如。", "佳處仍三復，此意良不虛。", "豈無太乙來，青藜夜相呼。", "挈我遊太初，天地如蝸廬。", "以思不如學，聖言豈欺予。"]'),
('dedf53f1-2445-48b4-9bb4-6e7acdb2c562','江行書事','馮時行','宋','宋诗','song-poetry','','[]','扁舟如竹葉，塊坐筋脈緩。',144,'全唐诗/poet.song.112000.json','["扁舟如竹葉，塊坐筋脈緩。", "起尋筇竹杖，散步午沙暖。", "石浄困還坐，江綠污仍盥。", "山轉孤渚沒，岸落細路斷。", "草色暝煙霧，花樹見村畔。", "物象總相愜，欲遣詩句管。", "詩成自吟哦，兩袖春風滿。", "皛皛日欲暮，我行亦已懶。", "聊復喚疏蓬，疊骨作小款。", "范蠡定何人，得遂老蕭散。", "我待功成後，此語正恐誕。", "徑欲具蓑笠，煙雨隨蠻蜑。"]'),
('5b4b99ad-17ff-407c-87a4-008756bbf65f','建炎庚戌中秋夜與同官相期於月下既爲具頑雲障空不可人意作詩以紀之得賞見二字  其一','馮時行','宋','宋诗','song-poetry','','[]','散懷誰與儔，風月茲吾賞。',156,'全唐诗/poet.song.112000.json','["散懷誰與儔，風月茲吾賞。", "好景會人心，宿約每不爽。", "蓐收濺明河，玉露洗穹壤。", "肅肅夜氣寂，皎皎素沆漭。", "飛出未半弓，已照天地廣。", "茲夕豈易得，久矣俟清賞。", "雲師誰爾忤，屏翳蔽虛敞。", "萬事不可必，變化如反掌。", "太清一滓穢，幽娥動懸想。", "誰爲披層霄，快哉心技癢。", "聞君洗瓦盞，倒遊有餘盎。", "何當數列炬，酣歌散清響。", "有月固來游，無月須一往。"]'),
('bc26bbb5-c362-4da8-8ab3-2fd701191bba','建炎庚戌中秋夜與同官相期於月下既爲具頑雲障空不可人意作詩以紀之得賞見二字  其二','馮時行','宋','宋诗','song-poetry','','[]','玉皇敕諸天，茲夕盡羣見。',156,'全唐诗/poet.song.112000.json','["玉皇敕諸天，茲夕盡羣見。", "驅雲收月光，反照玉京宴。", "老龍翻海窟，沓靄鬰萬變。", "天公有嚴令，遺隙無一線。", "蕭蕭寒桂影，可想不可見。", "生平謝惠連，與月有深眷。", "對影無清暉，把盞不下嚥。", "亦聞顧兔藥，天成非九轉。", "可使騎清風，飛入廣寒殿。", "安得一刀圭，扶我超宇縣。", "稽首分帝觴，飽以瓊爢薦。", "回首鄰清娥，相將以遊衍。", "人間滴與瀝，役役自卑賤。"]'),
('ffe91dfd-3e65-455f-9c7a-70c12cddbd8b','贈故人二首','馮時行','宋','宋诗','song-poetry','','[]','一日如三秋，屬君情所專。',252,'全唐诗/poet.song.112000.json','["一日如三秋，屬君情所專。", "晨風吹初春，繞屋鵲聲乾。", "得非造物意，憐我徒侶單。", "放晴速君歸，一笑不作難。", "起携化龍竹，消散枯體酸。", "矯首東山雲，行人爲我言。", "言君騎紫馬，近在十里間。", "溪邊古松隄，柳波梅飛殘。", "疾走落巾履，歡迎許平安。", "津津眉間黄，顧我一粲然。", "頗云萬貔虎，枕戈卧西關。", "元戎坐帷幄，花幕清晝閑。", "井絡天一涯，可以加飯餐。", "復出羣公詩，字字冰雪寒。", "窮探到冥窈，老語角險艱。", "一讀重驚歎，再讀醒昏頑。", "嗟我平生心，文陣亡左旃。", "遽拭涓滴眼，窺此瀛海寰。", "並驅吾豈敢，愧負百且千。", "尚能督租賦，用博酤酒錢。", "日日與君醉，高歌易長歎。"]'),
('3221b7e6-80f6-40d9-b966-d88bb436db24','再和','馮時行','宋','宋诗','song-poetry','','[]','煌煌六藝學，兀兀門亦專。',252,'全唐诗/poet.song.112000.json','["煌煌六藝學，兀兀門亦專。", "耕道宜有秋，而我適旱乾。", "疏鬢日月邁，破衣霜雪單。", "誰謂四海寬，已覺一飽難。", "失計墮簿領，署判手爲酸。", "皇家挈天綱，昨下如綸言。", "冷眼看匠手，雌黄英俊間。", "華堂玉塵動，繡簾香鴨殘。", "爲國得一人，可使天下安。", "當時呼畫師，我愧寧不然。", "策勳徑投筆，守志甘抱關。", "渥洼萬里心，束芻老廄閑。", "豈無苜蓿盤，可以羞晨餐。", "豈無芰荷衣，可以備祁寒。", "天地日莽蒼，逢辰諒多艱。", "世既不吾與，不去良亦頑。", "摇摇故山心，長風動旌旃。", "君今門下士，良莊滿人寰。", "與我各相去，何啻一小千。", "異時白雲邸，仰君分酒錢。", "富貴無相忘，勿徒况永歎。"]'),
('002f904a-8398-47c2-bd7e-8c02419536d9','西北有高樓','馮時行','宋','宋诗','song-poetry','','[]','西北有高樓，氛氳臨大路。',72,'全唐诗/poet.song.112000.json','["西北有高樓，氛氳臨大路。", "飛簷轉春風，綺窗瑣雲霧。", "姣服者誰子，傾城此容與。", "娟娟長眉青，不受脂澤污。", "娉婷惜不嫁，恐爲蕩子悞。", "寫心汎清瑟，獨不怨遲暮。"]'),
('302e7030-e851-4613-8469-1bc93f2206aa','東方有一士','馮時行','宋','宋诗','song-poetry','','[]','東方有一士，不見心忡忡。',60,'全唐诗/poet.song.112000.json','["東方有一士，不見心忡忡。", "尺璧未足多，夙好良所同。", "永懷不能寐，攬衣出房櫳。", "遥夜未渠央，取琴和秋蟲。", "豈無時世交，掣肘不相容。"]'),
('6c233b6c-bebf-4ebe-bdc5-34a3e4e050c7','題報恩方丈宋子展所作墨竹','馮時行','宋','宋诗','song-poetry','','[]','叢筠抱清節，茂若含幽翠。',72,'全唐诗/poet.song.112000.json','["叢筠抱清節，茂若含幽翠。", "孤樹老風霜，空枝少春意。", "其中有磐石，人莫知其器。", "堅頑如我心，脫盡榮枯累。", "畫不與詩謀，詩輒窮微理。", "何時逢畫郎，忘言笑相視。"]'),
('99c033be-b890-49e1-b914-7e8c642cd689','和楊拱辰見惠','馮時行','宋','宋诗','song-poetry','','[]','所操或異趣，竝席寧相親。',288,'全唐诗/poet.song.112000.json','["所操或異趣，竝席寧相親。", "臭味儻不殊，千里情猶伸。", "古今邪正間，何啻萬微塵。", "平生閲世眼，服膺無幾人。", "濟濟數君子，厖然氣深淳。", "南郭服仁義，轍跡世所循。", "楊侯墨池孫，清厲凌蒼旻。", "公幹抱奇藴，謦咳皆瑰珍。", "造物豈私我，惠我爲德鄰。", "賤子嬰禍羅，蹭蹬巴江垠。", "棄逐類秦客，憔悴如楚臣。", "九死不能悔，百煉未失真。", "敢希鳴玉侶，庶混擊壤民。", "飲水蠲煩燥，薰香懺貪嗔。", "朅來古安漢，息黥幸依仁。", "至道迷所適，避風時問津。", "昨者枉車蓋，正值霜雪辰。", "厨空無盛煙，坐冷乏軟茵。", "牆頭丐鄰翁，殽核粗且陳。", "公言我未暇，語竟即踆踆。", "挽袂不可止，滿坐顔色顰。", "公方遲騰踏，我已甘隠淪。", "我歸楚之夔，公家蜀之岷。", "感此會合難，時來笑脫巾。"]'),
('240ca31c-5934-47e0-aca9-2a49580051b2','再和','馮時行','宋','宋诗','song-poetry','','[]','人言不飲酒，神形不相親。',288,'全唐诗/poet.song.112000.json','["人言不飲酒，神形不相親。", "我云不遊山，足攣不可伸。", "徑須向泉石，抖擻人我塵。", "况復山林姿，豈類軒冕人。", "出門見四野，便有羲皇淳。", "昔遊頗有得，已事猶可循。", "異時春開陰，晴霽如秋旻。", "殽簌粗提携，不必皆奇珍。", "客居我貧者，尚能乞諸鄰。", "相與臨小軒，眼界浩無垠。", "水繞拖長带，山來趨小臣。", "軒前聳朱鳳，曾是棲羣真。", "飄遊邈何許，蹟可訪遺民。", "吾徒况健步，人扶必怒嗔。", "頻行當導引，能除體不仁。", "想當聞此約，喜見顔津津。", "必不類世俗，咫尺小參辰。", "鳥語聽妙轉，草軟藉芳茵。", "信宿得蘇李，良會如荀陳。", "翻思塵土中，旦暮走踆踆。", "有如對酸醯，未啜已深顰。", "放意寬衰颯，收機入混淪。", "尚欲挈妻子，終焉老西岷。", "或欲東入海，披髮謝冠巾。"]'),
('e5b11b29-f383-411c-a08d-d166a19af530','和嘉州通判賈元升見贈','馮時行','宋','宋诗','song-poetry','','[]','山城鳥鵲喜，佳句來春風。',192,'全唐诗/poet.song.112000.json','["山城鳥鵲喜，佳句來春風。", "浣手三過讀，散我磈磊胸。", "當年過秦論，千載猶爲雄。", "今觀妙好辭，蹀躞追前蹝。", "文章信有種，字字含徵宮。", "少城初識面，軟語開沖融。", "秋月耿高懷，春水瑩清衷。", "俱墮人事海，煩促難舂容。", "况乃燕雀卑，未易參鸞鴻。", "別來邛筰外，一笑誰與同。", "羨君對賢牧，快飲如渴虹。", "何當款齋閣，餘瀝借衰紅。", "所幸九河潤，密通千乘封。", "臭味譬草木，我輩情所鍾。", "夢隨沫若水，下與九頂通。", "更願洗老眼，見君攀翔龍。"]'),
('f70e3234-f1f0-4781-a39f-501db6c6ca32','題蘇慶嗣睡樂軒','馮時行','宋','宋诗','song-poetry','','[]','六鑿森劍戟，一枕寄華胥。',144,'全唐诗/poet.song.112000.json','["六鑿森劍戟，一枕寄華胥。", "睡覺既殊轍，睡兮真樂歟。", "達人藴大觀，方寸包太虛。", "憂樂兩不知，寤寐常如如。", "昔也蝶栩栩，今焉周蘧蘧。", "而今我法中，無欠亦無餘。", "以睡爲樂邪，不睡寧非渠。", "然則此軒名，無乃滯一隅。", "蘇子笑而應，斯豈真吾居。", "飄流閲世故，早覺心地初。", "今古一偃仰，天地一蘧廬。", "揭名聊爾爾，至言恐驚愚。"]'),
('c04fd270-3ea0-4daf-b829-c3a0c34d367c','出郊以江路野梅香爲韵得路字','馮時行','宋','宋诗','song-poetry','','[]','居然麋鹿性，疏散疾已痼。',132,'全唐诗/poet.song.112000.json','["居然麋鹿性，疏散疾已痼。", "杖策城東門，曠景引閒步。", "日正摇江影，春已暖沙路。", "疏梅忽相值，與我如有素。", "清芬煦嚴律，玉骨洗寒露。", "頗復動詩興，况乃有酒戶。", "與君嗅花飲，飲罷爲花賦。", "攬此冰雪姿，裁作山間句。", "更得雙南金，何遜似風度。", "夷融興未愜，短景不少駐。", "呼僮扶步歸，要折花無數。"]'),
('b40e78bc-7fd5-411a-a754-1faa6fb1c625','寄題何子應金華書院','馮時行','宋','宋诗','song-poetry','','[]','吾聞何月卿，逸氣欲傾瀉。',96,'全唐诗/poet.song.112000.json','["吾聞何月卿，逸氣欲傾瀉。", "詞源浩班揚，詩律薄風雅。", "想初讀書眼，坐閲燈幾炧。", "士生貴適性，安得計用舍。", "青鞋踏九疑，絲絇遠金馬。", "飄然瀟湘遊，采芷動盈把。", "吁嗟既憂患，猶得營萬瓦。", "我無茅一廬，劫劫思里社。"]'),
('76df2431-ab40-4921-930b-94154dd71d90','送馮獻道運使得岸字','馮時行','宋','宋诗','song-poetry','','[]','蜀江灧新肥，送客上霄漢。',144,'全唐诗/poet.song.112000.json','["蜀江灧新肥，送客上霄漢。", "別懷老易感，醉幘狂更岸。", "春暄鼓氣全，風軟帆力半。", "青雲隨步履，紫氣鬰几案。", "清明銷積陰，當陽盛熙旦。", "羣姦付嚴科，四海歸睿斷。", "君行此其時，國光炳大觀。", "况乃濟時須，礧砢真巨幹。", "舉杯酬柂尾，爲賦鹿鳴亂。", "雲從動巖穴，起我病痯痯。", "溝壑未填委，胡爲甘屏竄。", "日邊多故人，爲我致此段。"]'),
('b7dd6654-b8ec-4712-8a5e-e8be4e9b5469','題郭信可琴中趣軒','馮時行','宋','宋诗','song-poetry','','[]','泠泠接吾耳，塵爾非真精。',168,'全唐诗/poet.song.112000.json','["泠泠接吾耳，塵爾非真精。", "大音寂無響，瓦礫如雷鳴。", "古今滯迷妄，溜溜塵所縈。", "落葉隨水去，顛風吹殘英。", "道人了本源，超然契無生。", "銷鎔天所假，浩蕩還空明。", "視聽非耳目，况復求音聲。", "竹木閟漁社，衡茅落初營。", "杖藜候晚收，曳履看春耕。", "無爲萬物逝，不言四時行。", "情塵泯絕處，大地皆䪫韺。", "淵明出醉語，能與此理并。", "見之偶一笑，呼兒署南榮。", "莫作如是觀，吾軒本無名。"]'),
('6a8795f2-8721-472c-8929-2121661a61ef','題虎丘','馮時行','宋','宋诗','song-poetry','','["\u957f\u6c5f"]','海甸平無際，突阜如踞虎。',144,'全唐诗/poet.song.112000.json','["海甸平無際，突阜如踞虎。", "杉松閟巖壑，殿閣煥藻黼。", "老眼凌雲煙，吳會略可俯。", "昔遊恍如昨，歲月不勝數。", "老矣愜重來，病倦喜欲愈。", "况復偕賢彥，清罇侑歌舞。", "高談聞善謔，錦繡落英吐。", "籬菊粲佳節，山屐霽淫雨。", "蜀客萬里外，艱虞棘肺腑。", "摧頹已無氣，頼此作一鼓。", "却欲挽長江，快意洗天宇。", "且復置是事，秋風送歸櫓。"]'),
('a0f084c5-9747-4ba0-babc-88e6c88b59b9','中秋飲張仁甫家探韵得玉字','馮時行','宋','宋诗','song-poetry','','[]','數日及中秋，迎月試新醁。',60,'全唐诗/poet.song.112000.json','["數日及中秋，迎月試新醁。", "清暉困屏翳，頑陰費驅逐。", "廣座迷樽俎，高堂費燈燭。", "未用恤一眚，何妨縱百沃。", "見人如見月，張家呼小玉。"]'),
('8bcf2d1b-46b6-415f-933c-4aa0a11df9e4','同郭師聖司空仲容探韵得江字','馮時行','宋','宋诗','song-poetry','','[]','孤月流高天，分影遍千江。',168,'全唐诗/poet.song.112000.json','["孤月流高天，分影遍千江。", "我來無人境，亦復窺幽窗。", "好客如佳月，開門輒摐摐。", "月到客亦到，不隔山㟅谾。", "把手入茅廬，笑語鐘新撞。", "一鳴驚人友，更挾飛鳬雙。", "連璧光照眼，老我心所降。", "呼童洗瓦盞，竹葉傾山缸。", "清谿漱鳴玉，老樹森高幢。", "更招二三子，放懷山水邦。", "分題得佳句，一字鼎可扛。", "男兒樹勳德，出手便可樁。", "願移詩句力，挽俗還純厖。", "惟予心已灰，庶幾鹿門龐。"]'),
('04161bac-1ce9-44bf-841a-e7399edea9a2','與諸友同坐梅下月霧淒清風琴泠然不類人世各聯三二語醉歸卧南窗下明日徵所出語皆忘失不記因追賦古詩以補遺缺','馮時行','宋','宋诗','song-poetry','','[]','月冷逼疏影，梅孤泛清光。',204,'全唐诗/poet.song.112000.json','["月冷逼疏影，梅孤泛清光。", "兒曹竅孤竹，天風韵絲簧。", "相將二三子，中夜聊徜徉。", "泠泠白雪唱，灧灧碧霞觴。", "清絕非人境，浩蕩真醉鄉。", "飛花炯天星，墜葉嗚瓦霜。", "歌放滿空闊，神融接混茫。", "三山今何許，仙游諒荒唐。", "人間有逍遥，豈阻路且長。", "簪紱縻步武，得失煎肺腸。", "役役少至老，過問或未嘗。", "以愚息我機，以學鋤我荒。", "以文導我興，以酒發我狂。", "使與風月親，寧不荷彼蒼。", "夜久梅影偏，月亦鄰西岡。", "嚴風吹冠巾，白露霑衣裳。", "歸歟掩關卧，枕上從羲皇。"]'),
('b6a17592-424c-49f8-8ad2-8431238ccff6','遺夔門故舊','馮時行','宋','宋诗','song-poetry','','[]','蜀江迸出岷山來，翻濤鼓浪成風雷。',176,'全唐诗/poet.song.112000.json','["蜀江迸出岷山來，翻濤鼓浪成風雷。", "掀天斡地五千里，爭赴東海相喧豗。", "白鹽赤甲當道路，呀然拒之欲使回。", "大山大水相較力，究轉稍肯開東隈。", "山氣盛豪水氣怒，二氣停滀成胚胎。", "離騷兮作文章祖，始知孕秀鍾英才。", "曄曄令君出此地，得非千歲之根荄。", "願祝君如此山水，滔滔岌岌風雲起。", "人言富貴出長年，拭眼看君出奇偉。", "功名落落麒麟閣，公當不負山與水。", "如我頑鈍何爲者，剩買耕牛老東里。"]'),
('9e3da257-fa8a-4028-99e0-50d8e32d983f','安清洞夜坐有懷','馮時行','宋','宋诗','song-poetry','','[]','屋角錦樹風飛揚，陰岑夜色凝清霜。',144,'全唐诗/poet.song.112000.json','["屋角錦樹風飛揚，陰岑夜色凝清霜。", "結庵雲竇謝塵俗，危然搔首憂偏長。", "背燈顧影空寂閴，亦復自怪何昂藏。", "人生百慮已大瘦，顧我耿耿無他腸。", "年來戎馬暗河朔，宵旰十載煩吾皇。", "時將朝事問府主，藁街未見梟狼羊。", "我亦乾坤一窮士，癡心未肯老爲郎。", "浩歌慷慨擬投筆，門外太白空煌煌。", "願學北地傅介子，一節出斬樓蘭王。"]'),
('1ff32aae-9ba2-4afb-996b-710f4eb6e983','責睡魔','馮時行','宋','宋诗','song-poetry','','[]','綠陰滿門春已還，黄鸝門外猶綿蠻。',224,'全唐诗/poet.song.112000.json','["綠陰滿門春已還，黄鸝門外猶綿蠻。", "蕭蕭冷官無一事，高齋搔首兀癡頑。", "睡魔襲我意蕭散，直來眉睫揚神姦。", "須臾爽氣溷塵俗，雙眸瞑眩那能覸。", "彌明未斷口頭句，鼻息如寄雷車間。", "夢魂恍恍何所適，飄飄寥廓辭躋攀。", "松風拂足雲生腋，深窮月窟超人寰。", "更尋織女支機石，天河西戶聲潺湲。", "無何有客乘晚興，剝剝啄啄敲柴關。", "驚回清風枕簟冷，赤霞夾日崆峒山。", "一日廢書强舌本，萌生鄙吝勞清刪。", "謾學昌黎送窮術，揮毫加點文爛斑。", "睡魔憑物對我語，勸我停手開憤顔。", "自言宇宙若非我，人生俄頃無休閒。"]'),
('8d00b50a-ce08-47de-9867-8b18dfad9c05','謝素師惠二石','馮時行','宋','宋诗','song-poetry','','[]','素師爲我良古僻，野性乖疏無與適。',240,'全唐诗/poet.song.112000.json','["素師爲我良古僻，野性乖疏無與適。", "呼門投我清浄友，翻是巴江兩好石。", "一石形作巢蓮龜，近人團圓生素迹。", "皎如孤月流清空，光逐一星斜辟易。", "一石初似瓜色黄，年來應被天公劈。", "枯松說與連理心，參差再合如膠漆。", "兩石相逢已投分，何消引我爲儔敵。", "與君傾蓋便忘年，未害吾人縛禪寂。", "方今宰相真儒生，議割三關厭夷狄。", "祖宗土宇安生靈，幸以艱難念開闢。", "天畿要險壯中華，一日捐之良足惜。", "爭如推轂老將軍，遠煽天風驅退鷁。", "我雖孺子亦有知，不憚下圯傳履舄。", "嗟爾兩石如有神，尚父兵書欣所習。", "不應默默齋閣閑，相對人間夜寥閴。"]'),
('e4d3ac81-505a-4c8b-8b65-c080033368f2','和郭信可苦寒曲一首','馮時行','宋','宋诗','song-poetry','','[]','朔風吹沙邊雲黄，行人墮指鳥獸僵。',128,'全唐诗/poet.song.112000.json','["朔風吹沙邊雲黄，行人墮指鳥獸僵。", "鷫鸘裘弊醉何有，呼吸七氣成冰霜。", "畫堂繡幕圍絲管，馥馥麝煙紅吐煖。", "貧人尺布不可縫，夜長展轉牛衣短。", "將軍領戍山上山，勁弩折角刁斗寒。", "鐵衣照雪夜如水，哀雁一聲心欲死。", "年年官賜冬衣絹，婦女從軍身不遍。", "來歲忍寒須努力，農家饑死無人織。"]'),
('9c6a0fb0-f90e-4447-b480-a0e66a3621f8','關山月','馮時行','宋','宋诗','song-poetry','','[]','胡笳吹斷朔風起，霜結層冰斷遼水。',112,'全唐诗/poet.song.112000.json','["胡笳吹斷朔風起，霜結層冰斷遼水。", "殺氣橫空月上遲，草色蕭瑟邊風悲。", "萬里征夫齊悵望，操兵初入沙場廣。", "將軍樊噲勇敢兒，肉食萬里班超相。", "天兵乘障驅貔貅，寶劍欲斷單于頭。", "輕生百戰百勝罷，塞原積骨誰能收。", "至今唯有關山月，樂府聲中愁不絕。"]'),
('c8cf3106-901b-4325-b878-effe032403b6','陽春曲','馮時行','宋','宋诗','song-poetry','','[]','柳带抽春寒氣淺，風光曉引春樓怨。',64,'全唐诗/poet.song.112000.json','["柳带抽春寒氣淺，風光曉引春樓怨。", "關山行人久不歸，鸞瘦舞腰雙綬緩。", "錦書難寄北征鴻，歸飛海燕翻晴空。", "芳菲韶景伴愁老，蘭苑桃花落照紅。"]'),
('cca2ad32-ee68-4de4-9f3d-8c94e6ef83fa','自開江歸依山結茅以居偶成長句','馮時行','宋','宋诗','song-poetry','','[]','酒腐於爵肉腐俎，擔石之儲我何有。',128,'全唐诗/poet.song.112000.json','["酒腐於爵肉腐俎，擔石之儲我何有。", "陸居無屋江無船，誰人乞與買山錢。", "大梁千里森寒玉，瓊茅桂棟營山麓。", "雲涵雨霂謝天公，苦爲貧人養黄犢。", "秋衣更續谿芙蓉，蟬腹龜腸欲御風。", "戲遣冰懷搜老語，食無煙火更玲瓏。", "銅臭錢鳴總無惡，更換清貧終不諾。", "濁不能堪饑可忍，木强須撩天一哂。"]'),
('a5c7d8f7-41e0-4683-9a1e-42647302b18d','題楊氏清福亭','馮時行','宋','宋诗','song-poetry','','[]','幾年瀕江種松竹，鬰鬰葱葱蔽江曲。',144,'全唐诗/poet.song.112000.json','["幾年瀕江種松竹，鬰鬰葱葱蔽江曲。", "猶有楊侯舊子孫，更結高亭貯寒綠。", "東家殺賊印鑄金，西家言事腰胯玉。", "一樽徑醉我不知，不待招呼風月足。", "有客胸中抱經濟，才高正患功名促。", "閒爲清福非吾事，乞與此亭作佳目。", "主人再拜不敢讓，願作閒人老林麓。", "江平酒熟夜收釣，鴨肥稻香朝坦腹。", "此時寄語惡長官，勿遣追胥駭僮僕。"]'),
('a8f46235-f9d1-4d62-a2cc-5c06c10377b3','紹興六年十月六日同信可舜弼進道謁隠甫值渠曬畫於中庭遂得縱觀中間不無可人意獨范寬雪山八幅超然絕羣令人意象肅如真得脫身歸巖壑間者請賦詩以知君重毫素爲韵得君字','馮時行','宋','宋诗','song-poetry','','[]','畫山畫骨更畫魂，范寬此中高出羣。',192,'全唐诗/poet.song.112000.json','["畫山畫骨更畫魂，范寬此中高出羣。", "君家八幅老筆墨，百年古篋鋪香芸。", "我來日出掛東壁，蒼崖落雪飛紛紛。", "寒鳥不動空無塵，蕩蕩晴天開四垠。", "終南太華入霄漢，秀色千里填河汾。", "想當盤礴未畫時，天地開闢雲中君。", "長鯨吸川欲酣醺，疾起信手驅風雲。", "須臾却立萬嶺下，援筆往往齒沒齦。", "平生愛山在夢寐，行年四十老更文。", "摩挲巖壑重感歎，徑欲杖屨從麋麕。", "畫龍儻有真龍至，歸即到山非浪云。", "列仙之儒恐邂逅，煙霞芝朮應平分。"]'),
('4b8e4466-8ba4-47fe-8690-1c1c497172e6','策師南遊過三峽見予求施以詩會余憂悲苦惱無意賦詠姑借梅爲喻送行則無一字不著題此本分事不妨大親切也策將安取紹興十四年十二月一日','馮時行','宋','宋诗','song-poetry','','[]','策骨寒瘦枯梅枝，梅花開時徵我詩。',96,'全唐诗/poet.song.112000.json','["策骨寒瘦枯梅枝，梅花開時徵我詩。", "我詩悲瘁作無意，借梅代我陳其詞。", "梅云最先得春意，桃花亂攙作佛事。", "千年冷落空自知，今日相看合何似。", "迦葉眼睛誰不有，先覺我當爲上首。", "普令世界識春光，南枝待入瞿曇手。"]'),
('a81cacfe-aaba-4cb9-bb75-edd475cb06e0','僧有悟策者見予於珞磧江上誦程子山孫季辰李仁甫賦成都信相寺水月亭之什僕曩客成都朝夕過信相鑑公求此詩至再三余謂詩於佛法業成綺語每笑訶之不爲作今策誦二三公佳句起予追賦長句付策令寄鑑公','馮時行','宋','宋诗','song-poetry','','[]','天行明月地行水，水月相去八萬里。',96,'全唐诗/poet.song.112000.json','["天行明月地行水，水月相去八萬里。", "天公大力誰能移，月在水中天作底。", "我心與月明作兩，真月本在青天上。", "雖云佛說我別說，恐入衆生顛倒想。", "少城城隈佛宮闕，客哦水月僧饒舌。", "三峽水寒梅花時，起予對月賡此詩。"]'),
('f627b19b-3263-445e-86dd-a6f9a635825e','江月亭','馮時行','宋','宋诗','song-poetry','','[]','張家作亭跨江月，久欲題詩詩思竭。',128,'全唐诗/poet.song.112000.json','["張家作亭跨江月，久欲題詩詩思竭。", "今朝龍泉寶函來，豈亦索詩光貝闕。", "忽憶曩時醉亭上，笑倚長松清興發。", "波光浩渺蕩樽俎，夜色鮮明見毫髮。", "是時披襟揖灝氣，蠲滌肺肝洗塵骨。", "歸來至今忽想像，猶覺人寰可超越。", "會當月夕駕煙槳，吹笛呼龍出龍窟。", "蓬萊方丈儻可尋，借我長風泛溟渤。"]'),
('387f9ced-52c1-4814-b13e-37597d218962','題楊毅肅十馬圖','馮時行','宋','宋诗','song-poetry','','[]','平生仰聞毅肅公，南征北伐開駿功。',96,'全唐诗/poet.song.112000.json','["平生仰聞毅肅公，南征北伐開駿功。", "所乘十馬有圖畫，今觀逸氣猶追風。", "當時血戰冒飛矢，一中鈎膺一貫耳。", "功名富貴豈偶然，請看將軍出萬死。", "紹興壬戌之仲冬，李嚴城頭霜月空。", "夜深無寐開素軸，感時撫事三歎息。"]'),
('38c8a0a4-d902-40e6-84f1-defb5d5d4619','和楊偉明韵','馮時行','宋','宋诗','song-poetry','','[]','黄花不待我西歸，去載空吟九日詩。',128,'全唐诗/poet.song.112000.json','["黄花不待我西歸，去載空吟九日詩。", "今載擬招風月友，共醉黄花香滿枝。", "佳辰不許負佳客，我友南北如分岐。", "驕馬行嘶縉雲碧，楚狂使我無退之。", "把杯聲作噫吁嚱，傷予未遇空嗟咨。", "雄文自是送窮術，那憂窮鬼長相隨。", "牘中燦燦藍田玉，有誰懷寶遇明時。", "慷慨男兒當自料，少把閒愁愁所思。"]'),
('5cb0f3d3-9075-4b26-8e14-075cd0150c71','題岳陽樓','馮時行','宋','宋诗','song-poetry','','["\u6d1e\u5ead\u6e56", "\u5cb3\u9633\u697c"]','洞庭涵浸八百里，岳陽樓高跨湖尾。',112,'全唐诗/poet.song.112000.json','["洞庭涵浸八百里，岳陽樓高跨湖尾。", "天空地迥豁疏襟，有客臨風來徙倚。", "是時窮冬天氣昏，慘淡愁殺湘君魂。", "層欄半落煙氛外，浩蕩猶恐旋乾坤。", "異時清霄玉鑑白，空明月路飛仙客。", "明朝露華洗七澤，萬頃寒光天一色。", "眼中未見此境好，他日扁舟吾未老。"]'),
('abd7c42a-12fb-47c9-831f-e6b78fcbfdfc','遊君山值冰合不得進','馮時行','宋','宋诗','song-poetry','','["\u6d1e\u5ead\u6e56"]','東畧扶桑還掛席，朔雪顛風經赤壁。',96,'全唐诗/poet.song.112000.json','["東畧扶桑還掛席，朔雪顛風經赤壁。", "欲呼龍伯出珠宮，戲上君山吹玉笛。", "仙人未熟長生酒，故遣玄冰凍湖口。", "洞庭千里一鏡中，煙鬟黛抹空回首。", "丹經素書舊巖丘，長歌歸去吾不留。", "他年酒熟當勸客，鶴使相尋縉雲側。"]'),
('0994aec0-1d45-490b-a65f-4a08f16ebe1f','題張粹夫萬卷樓','馮時行','宋','宋诗','song-poetry','','[]','儒生讀書不貴書，枕頭閣脚醉夢餘。',102,'全唐诗/poet.song.112000.json','["儒生讀書不貴書，枕頭閣脚醉夢餘。", "反不若浮屠，寶貝爲函金作字。", "海龍扶出凌空虛，君今收拾一萬卷。", "置在高樓截雲漢，想當日月出沒間。", "玉軸牙籤互璀璨，我欲牽車駕黄犢。", "往發縑緗煥心目，論孟久荒緣老病，請君爲我刪嚴令。"]'),
('d0c0ad2c-63d5-4ec6-a3fb-2e8e0d7f9802','宴林簡州桃園','馮時行','宋','宋诗','song-poetry','','[]','樂昌溪東大江頭，脫木老屋風颼颼。',100,'全唐诗/poet.song.112000.json','["樂昌溪東大江頭，脫木老屋風颼颼。", "開門滿院種桃樹，桃花主人林簡州。", "明年二月爛照眼，簡州西川醉春晚。", "憑誰管領江上花，但寄玉醪三萬盞。", "爲君對花連日夜，翻杯作雨雨花下。", "使桃大如王母所種高參天，直使花氣連西川。"]'),
('5d3acae7-e402-4765-b20d-0fdbd6e21c87','送召客','馮時行','宋','宋诗','song-poetry','','[]','暮春送客朝明光，顛風吹花繞柂檣。',160,'全唐诗/poet.song.112000.json','["暮春送客朝明光，顛風吹花繞柂檣。", "大江吞天日出沒，赤心許國一葦航。", "平生夢躡螭龍尾，天門九重九萬里。", "一朝巨手開天關，丹極紫霄隨步履。", "兒輩端非五湖匹，國柄今歸謝安石。", "遥之別墅清晝長，笑拂楸枰行折屐。", "共傾東海洗乾坤，景仁况是名公孫。", "四郊多壘士之耻，富貴浮雲何足論。", "宦海十年風退鷁，我亦彈冠聽推檄。", "安能鬰鬰久居此，朔饑欲死心不死。"]'),
('109a11ec-cb4a-443b-88b6-2f93f56252f2','和張仁甫李花韵','馮時行','宋','宋诗','song-poetry','','[]','江頭誰家千樹李，影落清江徹江尾。',128,'全唐诗/poet.song.112000.json','["江頭誰家千樹李，影落清江徹江尾。", "風吹扁舟到花下，花間啁啾亦欣喜。", "瑶林成徑千步長，花光燭天天半香。", "恍如坐我羣玉府，飛瓊酌勸青霞觴。", "勝事此游難具列，照映肝腸盡明潔。", "老懷已戒語作綺，新詩向擬風回雪。", "東家西鄰詩更奇，一時共借花光輝。", "更須妙索留春句，無使花飛春告歸。"]'),
('edbcd2e4-1dbf-4c80-99ae-679a5e30e45e','李花已盡再用前韵末章專屬蒙景明資一笑也','馮時行','宋','宋诗','song-poetry','','[]','向來風前見桃李，今日紛紛落風尾。',128,'全唐诗/poet.song.112000.json','["向來風前見桃李，今日紛紛落風尾。", "老人於花亦何有，不用天公事嗔喜。", "漫天高跨風力長，更飛急雨湔餘香。", "雪兒歌底踏舞馬，燕子泥邊隨濫觴。", "明粧皎皎爭前列，觸手還羞疑不潔。", "芳菲已斷陽臺夢，只有消煩嚼冰雪。", "明年祇應花更奇，豈無方畧留春輝。", "欲作短章憑阿素，只待西隣之子歸。"]'),
('3b4b1c91-8ef8-47f4-a48d-0463f55dadfe','李彥澤紫雲洞','馮時行','宋','宋诗','song-poetry','','[]','玉帝侍臣紫雲翁，帝嗔謫居跨鼇峯。',120,'全唐诗/poet.song.112000.json','["玉帝侍臣紫雲翁，帝嗔謫居跨鼇峯。", "年齡瞬息反帝所，空有衣冠藏山中。", "山中草木俱不同，紫雲霏微氣鬰葱。", "風清月白巖穴空，翁猶被髮乘虬龍。", "來從南箕驅長風，人間奔趨爭追蹝。", "依稀可望不可從，披尋遺編三復重。", "舜庭絲匏間笙鐘，嗚呼翁兮終莫從，姑從遺編愈盲聾。"]'),
('2417b9d8-8253-4a11-985c-d85986867fd0','峽州楚塞樓','馮時行','宋','宋诗','song-poetry','','[]','東南上流蜀之門，領畧形勝斯樓存。',184,'全唐诗/poet.song.112000.json','["東南上流蜀之門，領畧形勝斯樓存。", "岷峩之西江發源，勢如建瓴注平原。", "出門頓息波濤喧，五溪七澤相吐吞。", "蜿蜒紆餘带城垣，山亦却立且踞蹲。", "排青疊翠來庭軒，座隅彷彿聞清猿。", "我來新律當正元，天地清夷日晏溫。", "主人延客開清樽，酒酣疏襟忽孤鶱。", "北望兩京手可捫，感時撫事銷客魂。", "比聞狂酋如封豚，灰飛煙滅華夷分。", "赤縣神州宜細論，翠華幾時驅育賁，歸挽天河洗乾坤。", "願見從來中國尊，老夫日拭雙瞳昏。"]'),
('c276562a-88cd-4eef-b91f-9a965a09ca4a','遊峨眉','馮時行','宋','宋诗','song-poetry','','[]','向來一紀登臨意，白髮頹齡才一至。',64,'全唐诗/poet.song.112000.json','["向來一紀登臨意，白髮頹齡才一至。", "阮哭窮途真可笑，孔小天下或如是。", "平生歷覽廓無礙，方稱老懷疏不緻。", "安能却粧住雲霄，更不婆娑下平地。"]'),
('5ef14e66-5683-440c-8977-2ebe3b232b06','杜如篪屢督烹茶仍作詩次其韵','馮時行','宋','宋诗','song-poetry','','[]','老寄餘生山水窟，寂無朝煙屈硉矹。',256,'全唐诗/poet.song.112000.json','["老寄餘生山水窟，寂無朝煙屈硉矹。", "客從何方問棲隠，無人譍門杖藜出。", "言間遺我翠玉餠，把玩芳香襲呼吸。", "便欲洗琖試水品，腸胃空枯恐稱屈。", "緘藏小篋掛東牖，惕若虬龍隨手入。", "雲濤雪浪有變化，扃鐍苞苴何鬰鬰。", "痛嘗七碗豈不願，待營一飽終無及。", "窮人談富如畫餠，浪說烹炮詫知識。", "真求大嚼薦茗飲，可笑詩人太癡絕。", "豈惟枵腹誤指染，更并麗句成乾沒。", "亦知且具衲子供，澆淋蔬筍供一啜。", "恐君肺腑出宮商，造物反怪太喧聒。", "又恐展轉夜不寐，深思危慮比孤孽。", "何如待我食萬錢，東閣大開玉醅潑。", "翠娥捧香沃煩膩，醉起一笑天地間。", "男兒蓋棺事始定，所不踐言有如日。"]'),
('7a95c59f-e03d-4c88-bc91-820b08fa897f','廣安朱義從爲渝上霜臺之客母夫人年八十餘極其孝養一日有三白鷺翔集中庭不去義從作翔鷺亭識其事縉雲子爲賦此詩','馮時行','宋','宋诗','song-poetry','','[]','振振鷺，鷺于飛。',120,'全唐诗/poet.song.112000.json','["振振鷺，鷺于飛。", "白華遺音詠潔白，故此翔鷺呈鮮儀。", "萱堂八十癯仙姿，無心更出風絮詞。", "夜入佛觀燈耿耿，晨翻貝葉多髮絲。", "郎君風標晉人上，芙蕖照映清漣漪。", "晨昏定省履聲細，鷺兮飛躍隨彩衣。", "吾聞擊石百獸舞，又聞上世巢可窺。", "余生眼明見異事，感今懷昔爲此詩。"]'),
('aef1fc59-2c21-41e2-8852-34c77ed4b1c0','山中宿小民家夜聞虎因有感','馮時行','宋','宋诗','song-poetry','','[]','虎叩門，山風裊裊吹黄昏。',60,'全唐诗/poet.song.112000.json','["虎叩門，山風裊裊吹黄昏。", "編蓬爲戶隣虎穴，敢於虎口寄浮生。", "干戈時有人相食，吏猛於虎角而翼。", "虎叩門，不敢入，使我愴惻長歎息。"]'),
('bfcaf88c-eed2-485f-9081-70ce51c50d17','正月二十日上山莊二月晦日歸不見花','馮時行','宋','宋诗','song-poetry','','[]','山巑岏，立屏幛。',56,'全唐诗/poet.song.112000.json','["山巑岏，立屏幛。", "山上無花不見春，下山花落空惆悵。", "嫣香空後芳草萌，芳草萋萋愁更生。", "子規啼血不見花，春又別我天之涯。"]'),
('512dd380-05da-4eac-828c-a447d996ff24','和張仲山寄酒','馮時行','宋','宋诗','song-poetry','','[]','兵厨盎盎孚盈缶，憐我十年青濮口。',144,'全唐诗/poet.song.112000.json','["兵厨盎盎孚盈缶，憐我十年青濮口。", "投醪分惠繼以詩，詩更分香過於酒。", "酒瓶詩卷墮我前，頓使幽棲添二友。", "朝吟直到屋翻日，夜醉不覺山銜斗。", "也知庭內無留難，掃除弊事如揮帚。", "龜陵千里數萬家，誰不高擎加額手。", "公餘退食多燕衎，一斗百篇困何有。", "餘波借與草木春，况是江頭釣魚叟。", "更煩遣騎日聯翩，暖熱縉雲先馬走。"]'),
('3c680a2a-6661-4331-9152-efe54cb2d4a4','夔帥范太尉生日','馮時行','宋','宋诗','song-poetry','','[]','秋空無雲倚太阿，天駟不受金盤陀。',98,'全唐诗/poet.song.112000.json','["秋空無雲倚太阿，天駟不受金盤陀。", "英姿傑氣狹宇宙，却立引手攀明河。", "已辦長纓三百尺，縛取胡雛寄飛馹。", "徐揮白羽掃龍庭，停驂戲勒燕然石。", "落落雄圖九萬里，白帝屈公朝夕耳。", "天使中興氣象自公還，還當與公金石年。"]'),
('bdf60bc3-df85-4c3a-a777-c6218c9a485d','恭州楊倅生日','馮時行','宋','宋诗','song-poetry','','[]','鳳龍虎豹無凡文，墨池太玄之裔孫。',96,'全唐诗/poet.song.112000.json','["鳳龍虎豹無凡文，墨池太玄之裔孫。", "至寶不琢粹璞具，猶有太古羲易淳。", "渝州別駕未足論，嘯歌已是騰清芬。", "一錢不輸縣官手，飽食長歌耕壠雲。", "生朝佳氣氤氳集，歡聲一境聽洋溢。", "願從黄童至白首，年年擊壤歌君壽。"]'),
('1b27a982-731f-4359-b716-48ccef30a8a6','劉守生日','馮時行','宋','宋诗','song-poetry','','[]','天清地浄行清秋，帝命吉祥驅蓐收。',160,'全唐诗/poet.song.112000.json','["天清地浄行清秋，帝命吉祥驅蓐收。", "九霄墜露濯仙骨，冰壺翠鑑塵不留。", "十年持節東西州，繡衣輝煌照遐陬。", "山之岷峨水之涪，兩川至今騰歌謳。", "渝城突兀大江頭，豈足滯公霄漢遊。", "鬰葱之山海上浮，上有仙人老浮丘。", "玉井蓮開花作舟，載公縹緲登瀛洲。", "瓊瑶之臺白玉樓，霞裾飄飄海上遊。", "仙人吹簫勸黄流，一觴不老仍不愁。", "始知仙凡隔塵土，人間衮衮真浮漚。"]'),
('d8ad5f54-6b36-492e-b802-6294f87ffb0c','常君挽詞','馮時行','宋','宋诗','song-poetry','','[]','龜城之山龍蟠崛，山下佳城何鬰鬰。',96,'全唐诗/poet.song.112000.json','["龜城之山龍蟠崛，山下佳城何鬰鬰。", "一抔黄土百年心，數字寒旌萬里骨。", "風愁雨悲春色死，生長何方葬於此。", "亂離溝壑半公卿，不得如君君有子。", "我生苦晚復異縣，平生不識先生面。", "但聞其見元祐時，傷今思古爲此歎。"]'),
('95ce22fd-a1e8-4a19-8e6b-67fd00d353db','石孝立挽詞','馮時行','宋','宋诗','song-poetry','','[]','斯人已矣舟移壑，惆悵九原誰可作。',96,'全唐诗/poet.song.112000.json','["斯人已矣舟移壑，惆悵九原誰可作。", "靈光長與孤月孤，幻化偶隨落葉落。", "人間好事平生有，留得芬香傳萬口。", "楊侯宅畔蜀江邊，霜立梅花醉哀酒。", "伯仲如林吾所愛，俯仰十年無一在。", "鬢邊日月去如飛，老懷不待秋風悲。"]'),
('8ddab156-669b-47ad-b8e9-6ad61799b825','題香積寺','馮時行','宋','宋诗','song-poetry','','[]','撥草詹風日，招提重訪尋。',48,'全唐诗/poet.song.112000.json','["撥草詹風日，招提重訪尋。", "雪如將路斷，雲實助山深。", "密印傳初祖，英風嗣少林。", "我來聊借榻，靜夜聽龍吟。"]'),
('258406ae-82a8-4e4b-a000-bba06ee60c74','天華寺亭二首  其一','馮時行','宋','宋诗','song-poetry','','[]','老去心如水，眼明猶愛山。',48,'全唐诗/poet.song.112000.json','["老去心如水，眼明猶愛山。", "偶來出己意，特爲破天慳。", "能使渺茫處，盡歸尋丈間。", "公餘成踐蹂，心事等雲閒。"]'),
('5b176561-e8cf-48ef-8f76-f349d949606a','天華寺亭二首  其二','馮時行','宋','宋诗','song-poetry','','[]','一亭開浩蕩，千載納幽閒。',48,'全唐诗/poet.song.112000.json','["一亭開浩蕩，千載納幽閒。", "日色射丹巘，秋姿凝翠鬟。", "人家屏上見，鷺點鏡中還。", "冷宦驚人眼，無妨飽看山。"]'),
('c50e58bf-65c6-4823-b057-60a730fcfb8c','遊東郊以園林無俗情爲韵得情字二首  其一','馮時行','宋','宋诗','song-poetry','','[]','野寺日欲落，晚林煙自生。',48,'全唐诗/poet.song.112000.json','["野寺日欲落，晚林煙自生。", "霞文明遠水，鴉點背孤城。", "酒盡無閒酌，茶粗得老烹。", "歸來喜不寐，濩落稱余情。"]'),
('b6ecf776-e0d3-4def-847f-5b2035122cea','遊東郊以園林無俗情爲韵得情字二首  其二','馮時行','宋','宋诗','song-poetry','','[]','散漫藤蘿外，飄然猿鶴情。',48,'全唐诗/poet.song.112000.json','["散漫藤蘿外，飄然猿鶴情。", "雲山如有舊，草木半無名。", "隔竹寺幡出，前村砧杵鳴。", "乾坤清絕地，猶覺是昇平。"]'),
('c3d7a72b-bb7b-4c1b-9675-d7d444f80c3e','詠雪','馮時行','宋','宋诗','song-poetry','','[]','疏木墮栖鳥，寒潭悲卧蛟。',48,'全唐诗/poet.song.112000.json','["疏木墮栖鳥，寒潭悲卧蛟。", "與松爲老伴，喚月結清交。", "簷滴冰爲浄，梅添玉作梢。", "豐年何以報，作頌紀南郊。"]'),
('49c9b9b1-8ce2-4a31-9fea-fd5a0b3965f6','阻雪','馮時行','宋','宋诗','song-poetry','','[]','朔風飄正急，客况老難禁。',48,'全唐诗/poet.song.112000.json','["朔風飄正急，客况老難禁。", "問路迷南北，携笻探淺深。", "地驚盈尺許，杯喜十分斟。", "梅蕊如相識，暗香何處尋。"]'),
('9a9cd0fd-fd98-4c87-a618-fe681413125c','寄張昭度','馮時行','宋','宋诗','song-poetry','','[]','知君多暇豫，山縣少追胥。',48,'全唐诗/poet.song.112000.json','["知君多暇豫，山縣少追胥。", "日晏未鳴鼓，夜分猶誦書。", "相思千里外，一見二年餘。", "錦水連三峽，時通雙鯉魚。"]'),
('ea9bb26d-4922-47d5-b391-0a9e0554d153','臘月二十八日','馮時行','宋','宋诗','song-poetry','','[]','晷景餘三日，憂愁盡一年。',48,'全唐诗/poet.song.112000.json','["晷景餘三日，憂愁盡一年。", "酒侵新歲熟，花待故枝妍。", "隣里多遺餽，庖厨有盛煙。", "擁爐風雪順，春意欲相先。"]'),
('6620a56a-986a-4733-a994-3ee0a87e4376','除夕','馮時行','宋','宋诗','song-poetry','','[]','峽裏江山暮，愁邊日月窮。',48,'全唐诗/poet.song.112000.json','["峽裏江山暮，愁邊日月窮。", "酒濃新不飲，春近舊多慵。", "歲事橫胸臆，年華入鬢蓬。", "明朝有王會，心與蜀江東。"]'),
('6769f0a6-9772-4950-a2b6-beb6e1a0b100','元日二首  其一','馮時行','宋','宋诗','song-poetry','','[]','穀旦休祥見，元朝氛祲開。',48,'全唐诗/poet.song.112000.json','["穀旦休祥見，元朝氛祲開。", "日車扶曉出，斗柄斡春回。", "致理歸廊廟，私憂尚草萊。", "太平豈無象，天意是胚胎。"]'),
('1c4f8720-027c-40a3-b627-1a2535503980','元日二首  其二','馮時行','宋','宋诗','song-poetry','','[]','日月新年節，乾坤舊觀還。',48,'全唐诗/poet.song.112000.json','["日月新年節，乾坤舊觀還。", "鬰葱浮曉霧，紫翠動晴山。", "御氣籠宮闕，朝班雜佩環。", "遥知王會散，喜色粲天顔。"]'),
('5950c53d-c639-428e-a3b6-3a5dea07012a','和何子應盛山一首','馮時行','宋','宋诗','song-poetry','','[]','徑掃風雲浄，爐薰山谷香。',48,'全唐诗/poet.song.112000.json','["徑掃風雲浄，爐薰山谷香。", "青葱環暗壁，金碧跨崇岡。", "小雨留歸旆，飛霞落酒觴。", "干戈遽如許，稅鞅更何妨。"]'),
('ae986e6a-ac5f-45bf-9dfd-ed294d004855','和何子應記所見','馮時行','宋','宋诗','song-poetry','','[]','公事有餘暇，披衣繞風林。',48,'全唐诗/poet.song.112000.json','["公事有餘暇，披衣繞風林。", "高吟起高興，閒事引閒心。", "未種淵明柳，方鳴子賤琴。", "幾多疏散意，矯首亂山深。"]'),
('cc12ca10-300d-4496-a377-30d71788c702','清明','馮時行','宋','宋诗','song-poetry','','[]','律歷調元氣，氛埃廓景風。',48,'全唐诗/poet.song.112000.json','["律歷調元氣，氛埃廓景風。", "清明歸在宥，憔悴得沖融。", "日御元來正，王春自昔同。", "野人看氣象，暫覺百憂空。"]'),
('2a02e207-0a06-4ce1-9d1c-eaac78f65be9','寓興','馮時行','宋','宋诗','song-poetry','','[]','乘軒知有負，啜菽苦無歡。',48,'全唐诗/poet.song.112000.json','["乘軒知有負，啜菽苦無歡。", "萬事等一夢，寸心當自安。", "荆卿甘度易，李愿喜歸盤。", "默坐發深想，春山猶夜寒。"]'),
('fbb3986d-7c6a-49d2-8bff-f9f6f197e1cf','彭山道中','馮時行','宋','宋诗','song-poetry','','[]','劫劫真無謂，遲遲再有行。',48,'全唐诗/poet.song.112000.json','["劫劫真無謂，遲遲再有行。", "斷雲峰出沒，殘照水分明。", "遠意誰能共，長亭空有情。", "從今離別夢，逐夜到江城。"]'),
('0b7118b4-c503-4ebd-bf49-d42c47fd3013','旅興寄張惠之','馮時行','宋','宋诗','song-poetry','','[]','始覺歸耕晚，從誰話此情。',48,'全唐诗/poet.song.112000.json','["始覺歸耕晚，從誰話此情。", "但能安食息，敢復計聲名。", "留滯煩書信，艱難愧友生。", "有懷悲不盡，歸鳥暮雲橫。"]'),
('2f1b015a-f69f-4b92-ad41-840679eb1138','舟中見月','馮時行','宋','宋诗','song-poetry','','[]','濮上今秋月，於人大有情。',48,'全唐诗/poet.song.112000.json','["濮上今秋月，於人大有情。", "銀盤隨水湧，素練截江橫。", "岸闊天光近，舡虛夜月明。", "寒光迷上下，萬里一心清。"]'),
('fad708de-5bfc-49a1-b474-5fda437cb53d','送友人兄弟赴省','馮時行','宋','宋诗','song-poetry','','[]','書劍一門去，由來得主盟。',48,'全唐诗/poet.song.112000.json','["書劍一門去，由來得主盟。", "峨冠雖合遝，再鼓已聾盲。", "風急鴒原起，雲高雁序橫。", "天衢在咫尺，去去任飛鳴。"]'),
('c8a411c9-5b30-4086-b8ae-9f6b5c639953','就得勝寨遣人入巫山買酒','馮時行','宋','宋诗','song-poetry','','[]','聞道巫山縣，秋深好白醪。',48,'全唐诗/poet.song.112000.json','["聞道巫山縣，秋深好白醪。", "形神須此物，觴詠本吾曹。", "馬杓勝鸚鵡，羊羹當蟹螯。", "暮寒催渴肺，徑欲賣青袍。"]'),
('eca5817d-27d6-4352-afec-1e154662a864','白雲安尉出戍至夔州','馮時行','宋','宋诗','song-poetry','','[]','戍鼓黄雲外，征夫白帝東。',48,'全唐诗/poet.song.112000.json','["戍鼓黄雲外，征夫白帝東。", "風林行嘯虎，雨夜颯哀鴻。", "路入山光靜，村含晚色空。", "嵐煙欺眼力，不見鹿皮翁。"]'),
('c4b61f8c-136a-43fd-ae6b-5a52e26b8af1','至日三首  其一','馮時行','宋','宋诗','song-poetry','','[]','太史書雲日，周家紀歷年。',48,'全唐诗/poet.song.112000.json','["太史書雲日，周家紀歷年。", "一樽供笑裏，五載客江邊。", "城暗催春雨，山連作雪天。", "功名驚過隙，節物自推遷。"]'),
('0974380b-479a-4d08-bc3b-1753584d3042','至日三首  其二','馮時行','宋','宋诗','song-poetry','','[]','至日寒無頼，今朝愁奈何。',48,'全唐诗/poet.song.112000.json','["至日寒無頼，今朝愁奈何。", "兩宮黄屋遠，二老白頭多。", "聖主今嘗膽，皇天忍薦瘥。", "乾坤爲回首，慷慨一悲歌。"]'),
('32461f0b-ca5b-428f-b51c-328436effe37','至日三首  其三','馮時行','宋','宋诗','song-poetry','','[]','令節仍長至，公家放小休。',48,'全唐诗/poet.song.112000.json','["令節仍長至，公家放小休。", "愁城開六府，醉眼見千憂。", "梅萼含春小，雲容带雨收。", "曦娥自來往，生理百年浮。"]'),
('b6374ffd-dbc8-4576-aa58-54908cf23cf0','遊寶蓮寺分韵得塵字','馮時行','宋','宋诗','song-poetry','','[]','路出青山近，招提更可人。',48,'全唐诗/poet.song.112000.json','["路出青山近，招提更可人。", "清心鐘磬響，遠跡簿書塵。", "晚日池邊迥，秋風杖履親。", "頻來一樽酒，不畏老僧嗔。"]'),
('dfc22558-1c91-4594-ae80-dca9f6de2066','楚甸江頭望雪晴二首  其一','馮時行','宋','宋诗','song-poetry','','[]','歲暮風欺客，天開日解圍。',48,'全唐诗/poet.song.112000.json','["歲暮風欺客，天開日解圍。", "雪消無奈白，雲細不禁飛。", "目盡江無盡，吾歸雁亦歸。", "曉來清徹骨，塵物污人衣。"]'),
('3f435fd1-4d3a-41e7-b9f1-0911e8bfc585','楚甸江頭望雪晴二首  其二','馮時行','宋','宋诗','song-poetry','','[]','晴天開澤國，江渚匝煙圍。',48,'全唐诗/poet.song.112000.json','["晴天開澤國，江渚匝煙圍。", "鷺靜蕭蕭立，梅孤默默飛。", "岸荒羣虎過，村迥一人歸。", "愁緒如相惱，帆收徑典衣。"]'),
('f77a52bf-131a-4e83-aa45-0ba420b9ea74','遊樂磧江中石洲','馮時行','宋','宋诗','song-poetry','','[]','石出杖藜穩，沙暄牽興長。',48,'全唐诗/poet.song.112000.json','["石出杖藜穩，沙暄牽興長。", "半江鷗鳥地，三峽水雲鄉。", "携客撐煙艇，開樽俯綠塘。", "便當從此去，煙雨釣滄浪。"]'),
('6b357c40-8378-4800-b1dd-2d05648fff4f','行遇小雨','馮時行','宋','宋诗','song-poetry','','[]','小雨暗兩岸，孤舟撐一篙。',48,'全唐诗/poet.song.112000.json','["小雨暗兩岸，孤舟撐一篙。", "清同寒鷺迥，愁與暝雲高。", "已判亂波色，時饒點鬢毛。", "三農有重賦，爲汝喜如膏。"]'),
('cd50e978-d351-43c8-81c7-75841a6e8b54','夔州撫屬陳行之座上作','馮時行','宋','宋诗','song-poetry','','[]','雲細不成雨，虛從萬里還。',48,'全唐诗/poet.song.112000.json','["雲細不成雨，虛從萬里還。", "卸帆逢故舊，把手話間關。", "酒濁消千慮，春新見一斑。", "便須開口笑，白髮不勝刪。"]'),
('a705e586-633e-4961-9f56-b20a6dd3cff9','至日讀莊子','馮時行','宋','宋诗','song-poetry','','["\u957f\u6c5f"]','世路頻時節，山城暗夕煙。',48,'全唐诗/poet.song.112000.json','["世路頻時節，山城暗夕煙。", "酒先回暖律，梅自斷殘年。", "日月長江水，功名小井天。", "如何割幽抱，更與問虛玄。"]'),
('84a56308-108d-4642-8345-3cdffd8ead85','謝景濬卿東州名士未曾傾蓋因僧悟策有詩寄余臭味不殊千里同契望風增感作詩寫懷一首寄謝','馮時行','宋','宋诗','song-poetry','','[]','客唱凌天路，僧傳到野亭。',48,'全唐诗/poet.song.112000.json','["客唱凌天路，僧傳到野亭。", "人間聞譽處，句裏識儀形。", "學道荒文律，嬰愁鈍性靈。", "只如老瞽史，音節尚能聽。"]'),
('65c9fd5d-a27b-47c6-9615-3b97ff8f1192','歲暮舟次荆州呈李堯俞','馮時行','宋','宋诗','song-poetry','','[]','肅霜聞渡雁，湖海發歸舡。',48,'全唐诗/poet.song.112000.json','["肅霜聞渡雁，湖海發歸舡。", "煙樹開吳澤，風帆盡楚天。", "經過成往事，信宿是明年。", "詩句隨元禮，雲山共一天。"]'),
('207d28e9-4878-46a6-9a8b-56525dd14fb2','舟中觀雪呈李堯俞二首  其一','馮時行','宋','宋诗','song-poetry','','[]','孤渚凝寒睇，斜風看亂飄。',48,'全唐诗/poet.song.112000.json','["孤渚凝寒睇，斜風看亂飄。", "已狂難自定，初泊不勝嬌。", "白向水邊斷，輕來衣上消。", "更愁清夢覺，篷底聽蕭蕭。"]'),
('29e891b4-7f38-4799-bffd-c083c662aacc','舟中觀雪呈李堯俞二首  其二','馮時行','宋','宋诗','song-poetry','','[]','密雪晚來急，扁舟江上看。',48,'全唐诗/poet.song.112000.json','["密雪晚來急，扁舟江上看。", "凍雲千頃白，對我一襟寒。", "屨冷深猶立，巾欹重更彈。", "家山想同夢，夜倚玉欄干。"]'),
('46a88b56-c862-4502-bd4b-0db5cd9f2689','自行在解維宿長安閘下回望天竺諸山依依在目微臣去國撫事感傷因成此詩','馮時行','宋','宋诗','song-poetry','','[]','歸來豈不好，去國意如何。',48,'全唐诗/poet.song.112000.json','["歸來豈不好，去國意如何。", "主聖憂思切，時危習俗訛。", "山高更回首，天闊阻悲歌。", "一寸丹誠地，餘生感憤多。"]'),
('2cc4d951-1742-4e4a-b9c9-9ab27a35f07e','再登岳陽樓','馮時行','宋','宋诗','song-poetry','','["\u5cb3\u9633\u697c"]','樓高臨迥渚，天闊上丹梯。',48,'全唐诗/poet.song.112000.json','["樓高臨迥渚，天闊上丹梯。", "雲盡樹不去，水平天更低。", "江湖分去住，吳楚亙東西。", "遐矚寬幽抱，愁多望轉迷。"]'),
('7434ea64-316a-4eb3-a6f2-576d1e844ce6','和楊團練元韵','馮時行','宋','宋诗','song-poetry','','[]','此生渾褦襶，秋鬢漸鬅鬙。',48,'全唐诗/poet.song.112000.json','["此生渾褦襶，秋鬢漸鬅鬙。", "跂德山徒仰，雄談壘更增。", "奇謀閒袖手，佳句老傳燈。", "起我棲遲意，寒鳩欲化鷹。"]'),
('059d9f00-87ac-4e0f-80f0-8326574ec7ce','同王公佩和老杜韵  其一','馮時行','宋','宋诗','song-poetry','','[]','新長篔簹竹，傍穿薜荔牆。',48,'全唐诗/poet.song.112000.json','["新長篔簹竹，傍穿薜荔牆。", "夜須邀月坐，晝不待風凉。", "剩放梢添綠，斜將籜抱香。", "幽居絕還往，相伴興何長。"]'),
('041bd1ff-8b2c-4fda-8482-22567d14b483','同王公佩和老杜韵  其二','馮時行','宋','宋诗','song-poetry','','[]','敝屋甫環堵，此君憂面牆。',48,'全唐诗/poet.song.112000.json','["敝屋甫環堵，此君憂面牆。", "當窗蔽寒綠，入坐薦清凉。", "客詠閟餘響，佛薰留散香。", "老成看氣骨，霜雪表靈長。"]'),
('c69fce0b-f8d8-4d12-96cd-154688e057ca','和丁利用韵','馮時行','宋','宋诗','song-poetry','','[]','末路初傾蓋，春風一繫舟。',48,'全唐诗/poet.song.112000.json','["末路初傾蓋，春風一繫舟。", "英姿森劍戟，餘論有春秋。", "時事朝暮別，年華日夜流。", "徒勞是州縣，東去勿遲留。"]'),
('f1fa1fa6-a86d-4e1b-bda8-bc089377f140','和何子應遊西山','馮時行','宋','宋诗','song-poetry','','[]','乘時休杖屨，勝槩洗塵凡。',48,'全唐诗/poet.song.112000.json','["乘時休杖屨，勝槩洗塵凡。", "屏障開蒼壁，龍蛇拔老杉。", "水明花並倒，山疊玉相攙。", "卜築公相可，吾當住翠巖。"]'),
('a208e884-53a9-46cd-bb70-1f1cb09984fe','又和子應遊萬州岑公洞','馮時行','宋','宋诗','song-poetry','','[]','泉細或疑雨，巖深微見天。',48,'全唐诗/poet.song.112000.json','["泉細或疑雨，巖深微見天。", "暫來如可老，長往不難仙。", "石髓層層落，松聲樹樹傳。", "欲歸重回首，明月傍船舷。"]'),
('afb36f0e-5352-42e8-858a-5e96e5d33904','題友人南北江山圖','馮時行','宋','宋诗','song-poetry','','[]','地廓秦山壯，天涵海甸寬。',48,'全唐诗/poet.song.112000.json','["地廓秦山壯，天涵海甸寬。", "十年經眼處，萬里入毫端。", "戶牖開千嶂，風煙老一竿。", "已無圭組累，圖畫不空看。"]'),
('468d8b2c-9ac1-41da-a5d6-b250ac35bec8','送涪守何常卿十六韵','馮時行','宋','宋诗','song-poetry','','[]','一時周屏翰，千載漢循良。',192,'全唐诗/poet.song.112000.json','["一時周屏翰，千載漢循良。", "寵渥分民社，疲羸頼紀綱。", "洪恩隨雨潤，令問與風翔。", "日月流年駛，江山別恨長。", "已聞談舊政，方改視新章。", "賤子千官底，曾依數仞牆。", "迂愚真濫吹，浩蕩實包荒。", "倦鳥棲林樾，哀鴻顧稻粱。", "一廛聯戶版，餘惠及耕桑。", "迨此徵黄速，還聞借寇忙。", "江雲引行旆，峽樹遠歸檣。", "亟欲承顔面，於焉寫肺腸。", "麥秋驅病馬，山雨絕橫塘。", "意去如飛鳥，身留類觸羊。", "登臨空悵望，竚立更淒涼。", "眷注期公久，趨瞻預可量。"]'),
('ebfdaf96-991a-45b4-a5f3-d79d14e25d51','西山一首','馮時行','宋','宋诗','song-poetry','','[]','有客徵清賞，携笻上翠微。',60,'全唐诗/poet.song.112000.json','["有客徵清賞，携笻上翠微。", "雨差肥水面，春恰染山衣。", "破綠苔迎屐，藏寒竹擁扉。", "雲融開別浦，天浄見孤飛。", "語響留舟壑，杯光艷落暉。"]'),
('e6966786-475e-4485-8ad4-1512ee7dc56e','和李工部月夜','馮時行','宋','宋诗','song-poetry','','[]','天地渾無滓，清光濯肺肝。',48,'全唐诗/poet.song.112000.json','["天地渾無滓，清光濯肺肝。", "倚風哦絕唱，想像見仙官。", "照我竹書冷，戀君銀鬢寒。", "家山想同夢，倚玉夜闌干。"]'),
('380bd3d8-add2-49ce-b23e-8ecd9c9cf717','題王與善隠軒','馮時行','宋','宋诗','song-poetry','','[]','苦節風塵際，甘心季孟間。',48,'全唐诗/poet.song.112000.json','["苦節風塵際，甘心季孟間。", "祿微幾飲水，眼冷只看山。", "江綠鷗千點，簷疏月半環。", "飽諳清浄趣，渾未覺天艱。"]'),
('63f7a4ac-0bfd-4ac7-b445-b25767ad714e','春日題相思寺','馮時行','宋','宋诗','song-poetry','','[]','繫艇依寒渚，扶筇上晚林。',48,'全唐诗/poet.song.112000.json','["繫艇依寒渚，扶筇上晚林。", "山山春已立，樹樹雨元深。", "掃葉移床坐，穿雲買酒斟。", "相思思底事，老大更無心。"]'),
('cf7ddb48-cee3-4ea3-afba-862375d15523','山居','馮時行','宋','宋诗','song-poetry','','[]','溪带三弓地，山開一蓋天。',180,'全唐诗/poet.song.112000.json','["溪带三弓地，山開一蓋天。", "茅簷低沒霧，藤路細迷懸。", "惡草翻新耨，獰彪突舊穿。", "爭雞喧腷膊，靜鷺立攣拳。", "翠著衣襟濕，嵐薰草樹鮮。", "老夫甘廢棄，末路寄沈綿。", "水出桃源俗，人來谷口賢。", "心期如水冷，世事絕風傳。", "瘠瘵高眠穩，疏慵入靜便。", "酒缸開半熟，茶餠索新煎。", "溫飽無餘事，安閒得剩年。", "勝遊欣此始，妄想置從前。", "出處非吾浪，乘除計亦全。", "况因心地靜，粗了佛家緣。", "零落餘生在，寧無火裏蓮。"]'),
('61d78064-36a6-4f82-80fc-162b76059768','送楊元老召赴闕','馮時行','宋','宋诗','song-poetry','','[]','羣心周道直，萬國舜門開。',240,'全唐诗/poet.song.112000.json','["羣心周道直，萬國舜門開。", "咫尺清虛地，精微擇異材。", "光輝生錦里，合沓上蘭臺。", "霄漢橫高翥，風雲接大來。", "龜龍紛秘奧，奎壁煥昭回。", "碧海浮城闕，丹梯近斗魁。", "由來陞密勿，此地實胚胎。", "早晚龍淵躍，從容衮職陪。", "斯文歸黼藻，吾道久塵埃。", "漢武威懷遠，周宣正化恢。", "治源先簡儉，國本厚封培。", "造膝心終啟，前籌力竟回。", "正宜須弼亮，豈獨藉淹該。", "疇昔先登際，聲名亦壯哉。", "追風先蹙踏，戢翼更徘徊。", "巨寶應難價，殊姿肯自媒。", "中天懸日月，萬里忽風雷。", "戮力銘鍾鼎，餘波及草萊。", "故人元勃窣，晚節更摧頹。", "料想憐枯肺，吹噓助酒杯。"]'),
('6352d4e0-c56a-4fd6-9421-757d2abf0406','送張仁甫見何少卿續郎中二首  其一','馮時行','宋','宋诗','song-poetry','','[]','并州天下脊，人物見遺英。',48,'全唐诗/poet.song.112000.json','["并州天下脊，人物見遺英。", "亂復歸何處，貧甘送此君。", "天高卿月滿，雲靜使星明。", "二老恩波闊，扶衰强一行。"]'),
('6db7d63c-b0a9-41ff-8971-5f1bb8729964','送張仁甫見何少卿續郎中二首  其二','馮時行','宋','宋诗','song-poetry','','[]','水驛風煙暝，江郊茅葦秋。',48,'全唐诗/poet.song.112000.json','["水驛風煙暝，江郊茅葦秋。", "不關窮易老，自是客多愁。", "自倚連城價，終艱一飽謀。", "向非天下士，强項敢輕投。"]'),
('c40c5d85-de9e-42b7-b5f9-926a47d37111','月夜','馮時行','宋','宋诗','song-poetry','','[]','秋立雨新霽，氣清雲自消。',48,'全唐诗/poet.song.112000.json','["秋立雨新霽，氣清雲自消。", "地空銀海闊，天浄玉丸跳。", "把硯承明露，扶兒看碧霄。", "病禁淒冷得，不惜到明朝。"]'),
('67c2c0df-cd78-40a0-8ce3-6b31f25b17b6','遊峨眉十一首  其一','馮時行','宋','宋诗','song-poetry','','[]','聞說最佳處，深藏疊嶂間。',48,'全唐诗/poet.song.112000.json','["聞說最佳處，深藏疊嶂間。", "只須一兩屐，更入數重山。", "架竹深猶渡，垂藤險可攀。", "林泉未厭客，風雨不教還。"]'),
('758685e1-ad2a-4d97-b8d6-1cc779e46bf2','遊峨眉十一首  其二','馮時行','宋','宋诗','song-poetry','','[]','薄宦非初志，幽棲有宿期。',48,'全唐诗/poet.song.112000.json','["薄宦非初志，幽棲有宿期。", "勝遊宜數數，老境已垂垂。", "山好無時見，雲閒逐處隨。", "誅茅或未可，細路有人知。"]'),
('91b76593-3a37-446b-94ec-dc26c6670216','遊峨眉十一首  其三','馮時行','宋','宋诗','song-poetry','','[]','蜀公愛山水，無不到牛心。',48,'全唐诗/poet.song.112000.json','["蜀公愛山水，無不到牛心。", "歲久無從問，詩亡不可尋。", "雲堂環碧嶂，溪路擘青岑。", "從僻須回杖，窮探不厭深。"]'),
('a53c7fff-4dd0-476a-bb52-90f6556d6114','遊峨眉十一首  其四','馮時行','宋','宋诗','song-poetry','','[]','絕嶺人人到，空迴亦大誇。',48,'全唐诗/poet.song.112000.json','["絕嶺人人到，空迴亦大誇。", "至人觀實相，凡眼眩空花。", "有障猶隨牒，無心已出家。", "普賢吾日月，歸屐候晴霞。"]'),
('3a2bad60-679c-4844-a5b2-02e9e64398b3','遊峨眉十一首  其五','馮時行','宋','宋诗','song-poetry','','[]','緬想如天遠，由來路不賒。',48,'全唐诗/poet.song.112000.json','["緬想如天遠，由來路不賒。", "快穿靈運屐，徑造普賢家。", "仰睇雲霄遠，回觀錦繡華。", "老難持浄戒，細細酌流霞。"]'),
('34adc634-ab01-4fe7-a5e6-1ab5980ade2f','遊峨眉十一首  其六','馮時行','宋','宋诗','song-poetry','','[]','萬山皆拱揖，蹲俯若臣隣。',48,'全唐诗/poet.song.112000.json','["萬山皆拱揖，蹲俯若臣隣。", "初到最高處，誰爲第一人。", "自驚渾俗骨，或湧半天身。", "初夏猶深雪，難忘數飲醇。"]'),
('1862128a-077a-41c6-8e84-dd38d8850877','遊峨眉十一首  其七','馮時行','宋','宋诗','song-poetry','','[]','豈但山儲秀，年多樹亦靈。',48,'全唐诗/poet.song.112000.json','["豈但山儲秀，年多樹亦靈。", "華夷供靜矚，參井入危經。", "幽討真殊絕，神光却渺冥。", "正當存不議，聊使俗迷醒。"]'),
('a3aaaf7f-339c-4553-8654-fa5036d53e3f','遊峨眉十一首  其八','馮時行','宋','宋诗','song-poetry','','[]','巖巒皆創見，草木半無名。',48,'全唐诗/poet.song.112000.json','["巖巒皆創見，草木半無名。", "翠削山山玉，光摇樹樹瓊。", "嶺雲隨客袂，谷響答僧行。", "清絕渾無寐，空山月正明。"]'),
('48bab903-cf08-4fec-a0ba-c1959568ffc2','遊峨眉十一首  其九','馮時行','宋','宋诗','song-poetry','','[]','攙天元有路，絕俗更無村。',48,'全唐诗/poet.song.112000.json','["攙天元有路，絕俗更無村。", "孤眺臨崖觜，危升挽木根。", "渺茫均遠邇，倏忽變明昏。", "佛現驚搜句，巖前萬口喧。"]'),
('b3e81291-7de0-4d63-8e6b-a2dc7897cf5d','遊峨眉十一首  其一○','馮時行','宋','宋诗','song-poetry','','[]','佛已歸無跡，吾當反自崖。',48,'全唐诗/poet.song.112000.json','["佛已歸無跡，吾當反自崖。", "肺腸蠲墜露，衣佩結明霞。", "陶令難忘酒，龐公亦有家。", "下山人借問，姑射咤南華。"]'),
('c0293baf-1697-4aa0-9188-9b568959eea2','遊峨眉十一首  其一一','馮時行','宋','宋诗','song-poetry','','[]','雖知仙可學，酒盞喚淵明。',48,'全唐诗/poet.song.112000.json','["雖知仙可學，酒盞喚淵明。", "未遂山中隠，聊爲地上行。", "留人垂雨意，送客走泉聲。", "初上乘危慣，歸途更不驚。"]'),
('2624e96a-95ee-4177-aac6-391ae0cd9bef','雲安下巖二首  其一','馮時行','宋','宋诗','song-poetry','','[]','繫纜江沙靜，杖藜巖谷春。',48,'全唐诗/poet.song.112000.json','["繫纜江沙靜，杖藜巖谷春。", "花依竹色好，草入漲痕新。", "占笋苔初破，嘗梅客遽顰。", "篙師勿槌鼓，幽興苦留人。"]'),
('67525aa4-15ff-4708-8ba9-3a518c60952a','雲安下巖二首  其二','馮時行','宋','宋诗','song-poetry','','[]','曩遊成斷夢，再至是陳人。',48,'全唐诗/poet.song.112000.json','["曩遊成斷夢，再至是陳人。", "攬景追前跡，尋詩拂舊塵。", "孤松難破凍，細草易生春。", "晴日江天好，凭欄愁更新。"]'),
('13ae25e1-92b9-452e-a146-28a932883461','題梵音水野亭','馮時行','宋','宋诗','song-poetry','','[]','三宿離桑下，棲遲向一年。',48,'全唐诗/poet.song.112000.json','["三宿離桑下，棲遲向一年。", "無來元謾爾，欲去也淒然。", "峽路梅隨馬，吳江柳繫船。", "此生無再到，題字寄山泉。"]'),
('276f5cf4-201c-49d9-98e3-4f0484dc07db','題黄氏所居','馮時行','宋','宋诗','song-poetry','','[]','環翠五六里，深藏三四家。',48,'全唐诗/poet.song.112000.json','["環翠五六里，深藏三四家。", "風高鳴雁序，春暖茁蘭芽。", "門巷分楠直，溪流带竹斜。", "我來風雪曉，倚杖看梅花。"]'),
('f30ff0f7-c922-48bd-8c06-a21a17bb6984','遊雲泉寺','馮時行','宋','宋诗','song-poetry','','[]','人日訪山寺，春風能借溫。',48,'全唐诗/poet.song.112000.json','["人日訪山寺，春風能借溫。", "柳橋通野水，柏徑隠重門。", "泉竇來何處，梅花別有村。", "從容尋後約，假榻卧雲根。"]'),
('2ff837c1-d7fd-474f-9c68-aec5d5d39cb1','假守蓬州視事二十日以臺章罷黜行至溫湯作此以寄同僚二十韵','馮時行','宋','宋诗','song-poetry','','[]','聯事春將半，去官春未歸。',240,'全唐诗/poet.song.112000.json','["聯事春將半，去官春未歸。", "儒冠真蹭蹬，祖席有光輝。", "罷遣親刀筆，勾牽坐釣磯。", "同寮多俊彥，投老失親依。", "坐席丘無煖，扁舟蠡亦肥。", "泉聲清夢寐，山色浄裳衣。", "竹杖隨時拄，山杯信手揮。", "荷天將土苴，爲我易煙霏。", "州縣徒勞耳，簞瓢殆庶幾。", "不糜公廩粟，元長故山薇。", "白髮心猶壯，丹途計益非。", "人生今殄瘁，世路只歔欷。", "苦潦人將溺，思援手病痱。", "道孤誰歎息，迹蹇共嘲譏。", "去矣猶迴首，憂之欲奮飛。", "古今難骨鯁，風俗易脂韋。", "深峽真浮海，溫泉當浴沂。", "空山猿擇木，豐草馬辭鞿。", "已遂孤雲遠，猶通一徑微。", "年年如問信，深覓薜蘿扉。"]'),
('8baacf74-2b70-44a1-8d7e-e0d701d47b48','答郭師聖','馮時行','宋','宋诗','song-poetry','','[]','問訊煩書札，情親語味長。',48,'全唐诗/poet.song.112000.json','["問訊煩書札，情親語味長。", "是非元自定，得失已兼忘。", "洗手分僧飯，清心炷佛香。", "窮城不假給，何似水雲鄉。"]'),
('76524271-aa7b-4ef8-9035-b0846a57c617','石漕生辰','馮時行','宋','宋诗','song-poetry','','[]','夢斷熊羆夜，祥呈饋鯉初。',96,'全唐诗/poet.song.112000.json','["夢斷熊羆夜，祥呈饋鯉初。", "固應賢有後，誰謂慶無餘。", "爲國家相似，憂民子不如。", "符分四郡虎，金佩十年魚。", "未補三公衮，聊分八使車。", "權衡公選格，陵阜富軍儲。", "閥閲名猶在，朝廷席已虛。", "稱觴勤祝頌，二十考中書。"]'),
('cab4f3a8-583c-4a38-8d4b-703c8ad0f586','張公升挽詩','馮時行','宋','宋诗','song-poetry','','[]','掃地綠覆牖，撥醅香繞牆。',48,'全唐诗/poet.song.112000.json','["掃地綠覆牖，撥醅香繞牆。", "是非閒處少，日月醉中長。", "薤滴悲歌露，柯寒落葉霜。", "百年成底事，宿草任蒼茫。"]'),
('a29fd2cb-132f-45c9-b1a1-79606358e733','中秋探韵坤字','馮時行','宋','宋诗','song-poetry','','[]','山雨連秋懶出門，嬋娟佳節更堪論。',64,'全唐诗/poet.song.112000.json','["山雨連秋懶出門，嬋娟佳節更堪論。", "一年有限天知已，萬里無雲月返魂。", "淡影參差收海岳，清光浮動洗乾坤。", "擬憑樽酒相酬答，遮莫沈沈下別村。"]'),
('1f41db3d-952b-4363-8e3b-fdb90cc81ace','秋日即事','馮時行','宋','宋诗','song-poetry','','[]','人情節物自相關，强不悲秋亦恐艱。',64,'全唐诗/poet.song.112000.json','["人情節物自相關，强不悲秋亦恐艱。", "漸老身危生理索，憑高眼遠暮天寒。", "樹能長嘯風前聽，山亦多愁雨裏看。", "陶寫無他仗詩句，雁聲砧杵倚欄干。"]'),
('65bb2892-05ea-4614-9da2-2b1920815cd5','秋夜書事','馮時行','宋','宋诗','song-poetry','','[]','燈暗文書隔縠羅，寒欹竹枕倦吟哦。',64,'全唐诗/poet.song.112000.json','["燈暗文書隔縠羅，寒欹竹枕倦吟哦。", "本來無事消魂得，作意撩人奈雨何。", "二十五聲秋點冷，百千萬緒客愁多。", "海山寂寞應如此，琴自無弦一放歌。"]'),
('c1e93b7b-6382-4719-9610-db18330372d2','和郭信可秋夜有懷','馮時行','宋','宋诗','song-poetry','','[]','又是山寒水綠秋，年華冉冉鬢邊流。',64,'全唐诗/poet.song.112000.json','["又是山寒水綠秋，年華冉冉鬢邊流。", "一聲孤雁人千里，三點寒更月半樓。", "宦海浮生成底事，騷人徹骨是長愁。", "天空地迥淒涼夜，一曲商歌一掉頭。"]'),
('2133c0ba-2ab7-4177-abb0-a82c1c463b70','十七日夜月色尤佳與韋去非東亭小酌','馮時行','宋','宋诗','song-poetry','','[]','秋來瑶海浴嬋娟，天上人間又一年。',64,'全唐诗/poet.song.112000.json','["秋來瑶海浴嬋娟，天上人間又一年。", "有酒何妨三夜看，無雲尚見九分圓。", "樓臺迥憶仙遊眼，村落遥思禁曙煙。", "斗柄銜山風露冷，歸來清絕不成眠。"]'),
('639eca15-ae43-41a4-ae2e-30de0ddf69c4','食笋','馮時行','宋','宋诗','song-poetry','','[]','錦籜初開玉色鮮，烹苞葅脯盡稱賢。',64,'全唐诗/poet.song.112000.json','["錦籜初開玉色鮮，烹苞葅脯盡稱賢。", "絕能加飯非無補，浪說冰脾苦不便。", "一日偶無慵下箸，四時都有不論錢。", "寒儒氣味都休問，準擬凌風作瘦仙。"]'),
('91dbd8cf-9421-41bc-b9e4-788fe3be6ff6','送孫履道','馮時行','宋','宋诗','song-poetry','','[]','平生心印久相傳，出處窮通豈偶然。',64,'全唐诗/poet.song.112000.json','["平生心印久相傳，出處窮通豈偶然。", "且把新詩斟別酒，莫將離恨惱衰年。", "步兵未必非奇士，太白惟知是謫仙。", "待我休官彭澤去，約君同老白雲邊。"]'),
('685538da-5204-43bf-8a5f-cbd5f11294f1','上知己','馮時行','宋','宋诗','song-poetry','','[]','十年宦海塵埃客，文墨於人有底功。',64,'全唐诗/poet.song.112000.json','["十年宦海塵埃客，文墨於人有底功。", "天遠寧知心匪石，官卑不許氣如虹。", "唐雖未老行將老，衍不應窮究竟窮。", "何日得君天上去，收雲拾雨借長風。"]'),
('ba244d5e-1446-4035-90cb-f9dec30afc16','寄越州張子文待制二首  其一','馮時行','宋','宋诗','song-poetry','','[]','霜清玉潔紫微人，海水羣飛蹭蹬頻。',64,'全唐诗/poet.song.112000.json','["霜清玉潔紫微人，海水羣飛蹭蹬頻。", "首尾七年歸剪拂，東西萬里隔聲塵。", "酒杯强遣愁中趣，藥裹長隨健裏身。", "天遠征鴻飛不到，登高極目更傷神。"]'),
('75f305cf-80b6-4c61-84d9-a5955db443c2','寄越州張子文待制二首  其二','馮時行','宋','宋诗','song-poetry','','[]','風塵綿邈想懷家，爲報平安向海涯。',64,'全唐诗/poet.song.112000.json','["風塵綿邈想懷家，爲報平安向海涯。", "壻舊能詩鳴曉雁，兒初弄筆抹秋鴉。", "陶張蹇石真心腹，王蔡韋侯比輔車。", "更有梁山何小隠，要乘春漲別金華。"]'),
('c2d34459-5e9a-4dc3-93b7-9dc1d33c44d9','盧秀才家食梨','馮時行','宋','宋诗','song-poetry','','[]','屢款盧仙貢玉堂，谷梨霜飽每分香。',64,'全唐诗/poet.song.112000.json','["屢款盧仙貢玉堂，谷梨霜飽每分香。", "冰圓咀液凉疏齒，金醴吞甘浣熱腸。", "誤誚斧斤訛魯簡，駭聽名字笑吳娘。", "好同火棗供嘉品，端比蟠桃味更長。"]'),
('b08d5e44-274f-4e5a-9cf6-a3fc63c9bf02','溪上望居人有感','馮時行','宋','宋诗','song-poetry','','[]','溪上居人三兩家，竹籬斜插倚蒹葭。',64,'全唐诗/poet.song.112000.json','["溪上居人三兩家，竹籬斜插倚蒹葭。", "清流日暖魚飛浪，靜渚輕煙鳥印沙。", "鱠落霜刀分綵縷，酒傾玉碗泛瓊花。", "因思故國園林約，默數歸期定不賒。"]'),
('cca89cc6-a236-45b7-887e-9913112048a9','感事詠菊','馮時行','宋','宋诗','song-poetry','','[]','寒花冷艷爲誰發，霜露泠泠祇汝侵。',64,'全唐诗/poet.song.112000.json','["寒花冷艷爲誰發，霜露泠泠祇汝侵。", "弱質向人如有託，清香絕世本無心。", "會逢仙老收靈藥，不用騷人費苦吟。", "十載豈無陶靖節，東籬蕭索待知音。"]'),
('de39ae99-e705-47fb-acca-067cb9abc5c3','詩呈監試','馮時行','宋','宋诗','song-poetry','','[]','筆陣詞鋒已破堅，深深簾幕度微煙。',64,'全唐诗/poet.song.112000.json','["筆陣詞鋒已破堅，深深簾幕度微煙。", "紛袍幸免催詩雨，堆案何堪造榜天。", "走馬共知難看錦，得魚自笑已忘筌。", "芙蓉豈待春風力，偶失知音勿斷絃。"]'),
('8a0be0ea-8986-4611-8afa-f90957bec7b2','和食笋二首  其一','馮時行','宋','宋诗','song-poetry','','[]','敢將蔬笋擬甘鮮，清瘦肥癡定孰賢。',64,'全唐诗/poet.song.112000.json','["敢將蔬笋擬甘鮮，清瘦肥癡定孰賢。", "氣味比僧從淡薄，支離似鶴要輕便。", "未隨煙客登山屐，且輟江神飲馬錢。", "一歲可能三百把，骨青髓綠配松仙。"]'),
('d6e6c0b9-8e8d-4a82-826f-80cb4352781f','和食笋二首  其二','馮時行','宋','宋诗','song-poetry','','[]','麞牙鴨脚色相鮮，更遣逢迎酒聖賢。',64,'全唐诗/poet.song.112000.json','["麞牙鴨脚色相鮮，更遣逢迎酒聖賢。", "齊魯大邦應自美，煙霞清興豈相便。", "風神肯慢吹成竹，市老能教省直錢。", "早晚蕭然文字飲，何須喚作地行仙。"]'),
('9335d093-3a4e-4ca9-a79c-b5dc754eb7f8','早行','馮時行','宋','宋诗','song-poetry','','[]','馬入寒林驚宿鴉，羸僮呵手怯霜華。',64,'全唐诗/poet.song.112000.json','["馬入寒林驚宿鴉，羸僮呵手怯霜華。", "已經殘月路數里，知過安眠人幾家。", "嚦嚦曉烏天外唱，疏疏煙樹嶺頭斜。", "前程自謂明時近，不用孜孜苦歎嗟。"]'),
('de926981-89a3-4bfd-93cd-1412a0f95d04','新居鑿井飲之味殊清勝因成一首','馮時行','宋','宋诗','song-poetry','','[]','丹砂黄菊莫年須，清浄玄功世恐無。',64,'全唐诗/poet.song.112000.json','["丹砂黄菊莫年須，清浄玄功世恐無。", "千里長源開地脈，數篙寒影落金樞。", "蟄龍雨氣通滄海，丹鳳秋風老碧梧。", "事業正應歸鼎飪，更分清韵入冰壺。"]'),
('8f9df08a-ea2d-44ad-acf8-6d4876eb4fde','曉行得江字','馮時行','宋','宋诗','song-poetry','','[]','晴色招人步曉江，牙牙瘦石水淙淙。',64,'全唐诗/poet.song.112000.json','["晴色招人步曉江，牙牙瘦石水淙淙。", "斷雲作片元隨伴，白鳥無羣不著雙。", "浄渚鏡磨涵崛屼，飛濤雲湧過艂艭。", "煙蓑雨笠吾將老，富貴心慚苦未降。"]'),
('9eb87feb-9463-4e4d-b804-613b1ef4aa51','客丹稜天慶觀夜坐','馮時行','宋','宋诗','song-poetry','','[]','家山千里秋風客，搔首夜深寒雨窗。',64,'全唐诗/poet.song.112000.json','["家山千里秋風客，搔首夜深寒雨窗。", "萬古興亡心一寸，孤燈明滅影成雙。", "鬢邊日月如飛鳥，眼底塵埃擬漲江。", "高枕欲眠眠不穩，曉鍾迢遞發清撞。"]'),
('0f72ab70-cd8d-4bd6-82e3-0789d4d191c5','苦雨','馮時行','宋','宋诗','song-poetry','','[]','噎鳩喚雨惱秋魂，唾手牋天恨少文。',64,'全唐诗/poet.song.112000.json','["噎鳩喚雨惱秋魂，唾手牋天恨少文。", "捲去行雲宜有主，放行飛海恐成羣。", "濛濛遮眼尋山遠，點點送愁緣竹聞。", "神女工夫遽如許，可能匝地洗妖氛。"]'),
('7b8e38ed-0777-4903-be59-d795141814f7','清明','馮時行','宋','宋诗','song-poetry','','[]','寶勒香輪簇柳陰，宦遊清味獨沈吟。',64,'全唐诗/poet.song.112000.json','["寶勒香輪簇柳陰，宦遊清味獨沈吟。", "野雲未散山頭暗，春水初生岸脚深。", "萬里松濤寒食淚，十年萍梗故園心。", "狂風又捲殘紅去，飛落誰家無處尋。"]'),
('9fda863d-9a34-4774-ad47-160f4416e63a','思歸','馮時行','宋','宋诗','song-poetry','','[]','安用區區五斗爲，竹籬茅屋喚人歸。',64,'全唐诗/poet.song.112000.json','["安用區區五斗爲，竹籬茅屋喚人歸。", "閉門高卧不通客，倚樹長吟懶繫衣。", "秋稻水乾還築圃，春蠶桑盡欲鳴機。", "山雲野樹吾家物，身瘦何妨道自肥。"]'),
('daaee02e-c2d7-458f-9abb-708323799327','和王祖文','馮時行','宋','宋诗','song-poetry','','[]','河東河北塞煙長，誰作今年一葦航。',64,'全唐诗/poet.song.112000.json','["河東河北塞煙長，誰作今年一葦航。", "已見五龍思自奮，似聞兩虎却相傷。", "麟臺君有青雲路，蝸舍吾其白首郎。", "憂國憂家連夢寐，端知不復有他腸。"]'),
('a8a76fc5-070c-405c-8026-d56ed2f1e479','贈李西臺','馮時行','宋','宋诗','song-poetry','','[]','瀟湘濃碧浸青天，千里人家接楚田。',64,'全唐诗/poet.song.112000.json','["瀟湘濃碧浸青天，千里人家接楚田。", "惜別正當歸雁後，相思無奈落花前。", "江樓閒上雲藏樹，野渡初迴月滿船。", "看著行春驅五馬，絲絲垂柳拂長鞭。"]'),
('25b3d075-c805-4e95-b207-d79d5bb39a02','索友人賡和','馮時行','宋','宋诗','song-poetry','','[]','詩債遲遲不見還，只緣草賦動天顔。',64,'全唐诗/poet.song.112000.json','["詩債遲遲不見還，只緣草賦動天顔。", "一揮可但難加點，三復何消更索斑。", "餘力自知過我輩，新篇不合是君慳。", "風流來往無多日，肯與吾曹作兩班。"]'),
('e7bb6ff2-a70f-4fe2-bdea-96e9f4711d0c','和陳舜弼中秋有感三首  其一','馮時行','宋','宋诗','song-poetry','','[]','宦海浮沈久倦遊，一聲雲雁一襟秋。',64,'全唐诗/poet.song.112000.json','["宦海浮沈久倦遊，一聲雲雁一襟秋。", "只今楚客多愁思，况是潘郎已白頭。", "何處有山堪寄老，此時無月亦登樓。", "寸心或是孤雲起，浩蕩天涯不可收。"]'),
('a1a27582-e268-4dd8-b036-e7b382294df0','和陳舜弼中秋有感三首  其二','馮時行','宋','宋诗','song-poetry','','[]','相別相逢總是天，朅來醉月又經年。',64,'全唐诗/poet.song.112000.json','["相別相逢總是天，朅來醉月又經年。", "君歸已買三山馬，我去仍求一水船。", "貧富勿論俱是夢，雨暘休問苦無田。", "中秋已過重陽近，頻向離筵醉拍肩。"]'),
('a9d89275-3593-4cb9-8540-f3e1716e31b0','和陳舜弼中秋有感三首  其三','馮時行','宋','宋诗','song-poetry','','[]','人間八九不如意，獨坐蕭蕭愁絕時。',64,'全唐诗/poet.song.112000.json','["人間八九不如意，獨坐蕭蕭愁絕時。", "空有此心誰領會，知余明月是襟期。", "婆娑寒影不知老，呼吸清光能療饑。", "今夕不妨休見面，旱苗須雨一深犂。"]'),
('1b2a3200-55a8-4ea4-af23-c8a11761cab7','送王公佩之瀘','馮時行','宋','宋诗','song-poetry','','[]','炎薰五月只須臾，底事書生亦渡瀘。',64,'全唐诗/poet.song.112000.json','["炎薰五月只須臾，底事書生亦渡瀘。", "午影風凉槐繫馬，曉岑雲白杖挑壺。", "見聞幽谷鶑遷木，氣類朝陽鳳集梧。", "見說阿房曾有賦，聲名速爲詫東都。"]'),
('5ba6d138-e2a7-4cde-87a2-39995f3cca22','送馮貫道赴行在二首  其一','馮時行','宋','宋诗','song-poetry','','[]','路入丹霄起柂初，峽山晴色曙煙疏。',64,'全唐诗/poet.song.112000.json','["路入丹霄起柂初，峽山晴色曙煙疏。", "海深南斗臨天闊，江合西川直帝居。", "禁漏深寒參佩玉，御爐香暖散衣裾。", "遥知三接承恩罷，日影參差轉玉除。"]'),
('c2cbf137-8a8d-49f6-9dbb-1558f5f3b419','送馮貫道赴行在二首  其二','馮時行','宋','宋诗','song-poetry','','[]','儒雅風流總不如，烝髦久合下旌車。',64,'全唐诗/poet.song.112000.json','["儒雅風流總不如，烝髦久合下旌車。", "黄堂報政瓜初及，宣室傾賢席已虛。", "楚樹迎船春去盡，吳蓮傍槳雨收餘。", "留連物色題詩裏，健步傳呼有峻除。"]'),
('ddf4ea6d-48a7-4d02-8a45-d7f19ec55f50','雨中書事','馮時行','宋','宋诗','song-poetry','','[]','昨夜風吹茅葦紛，今朝急雨洗崖痕。',64,'全唐诗/poet.song.112000.json','["昨夜風吹茅葦紛，今朝急雨洗崖痕。", "山山霞沒江喧枕，樹樹鳩鳴雲到門。", "隠几真心開暝照，繙書老膝痹危蹲。", "山居染得疏慵病，無復功名皓首論。"]'),
('d47e390a-cc5e-4d35-a1d4-ecec0b775bdd','謝杜合州送酒','馮時行','宋','宋诗','song-poetry','','[]','浦樹江雲晚杜門，史君書札問深村。',64,'全唐诗/poet.song.112000.json','["浦樹江雲晚杜門，史君書札問深村。", "憂愁徹骨妨詩律，賦詠開荒得酒樽。", "病肺可能供痛飲，濡唇亦足荷深恩。", "呼兒擎出隨藤杖，洗盞開嘗坐竹根。"]'),
('89ac1bf3-d8a1-43fb-9811-a55902fb30cc','眉僧曉岑僕未之識也持鉢求施既辭以貧則願丐一詩詩未暇作而三至門知嗜好可喜也因書長句四韵以贈','馮時行','宋','宋诗','song-poetry','','[]','門前剝啄遣兒譍，客是平生不識僧。',64,'全唐诗/poet.song.112000.json','["門前剝啄遣兒譍，客是平生不識僧。", "檀施咄嗟貧未可，詞場馳逐老猶能。", "識凌風月收孤思，乞與雲山伴曲肱。", "我亦從來慚綺語，休將此段擬傳燈。"]'),
('43172b8f-3a42-4092-be60-24a7b1f43423','和劉仲廉新年春望二首  其一','馮時行','宋','宋诗','song-poetry','','[]','年於鬢髮最相干，又作新正一再看。',64,'全唐诗/poet.song.112000.json','["年於鬢髮最相干，又作新正一再看。", "懶共燕泥烘午霽，吟隨鶑樹澀朝寒。", "餘生已分千人後，燥吻猶須百榼乾。", "愁絕向來飛舄伴，蕭然形影若爲歡。"]'),
('035bcae7-6506-49b7-a2a0-60cf1243dfd5','和劉仲廉新年春望二首  其二','馮時行','宋','宋诗','song-poetry','','[]','闢掠閒愁自不干，因春成老亦看看。',64,'全唐诗/poet.song.112000.json','["闢掠閒愁自不干，因春成老亦看看。", "花枝本自能時樣，燕子從前有歲寒。", "酒著酡顔衰似健，杖扶沙步雨猶乾。", "杜門何似頻還往，藉綠簪紅趁逐歡。"]'),
('75f4aeed-e0eb-4c89-8dc0-c1ad576892e4','送張卿赴西路憲','馮時行','宋','宋诗','song-poetry','','[]','不容巴國戀深仁，使節朝馳詔墨新。',64,'全唐诗/poet.song.112000.json','["不容巴國戀深仁，使節朝馳詔墨新。", "山水兩川奇勝地，典刑三晉老成人。", "使星正自臨東井，卿月元來照紫宸。", "自是皋陶多邁種，歸毘舜德詠臣隣。"]'),
('e8ab592d-1448-4a8b-8b80-70c406c8a9d2','九日邀郭信可登龍鶴山','馮時行','宋','宋诗','song-poetry','','[]','已脫青衫付酒家，請君含笑岸烏紗。',64,'全唐诗/poet.song.112000.json','["已脫青衫付酒家，請君含笑岸烏紗。", "百年行見星星髮，一醉須還歲歲花。", "令甲許人休吏卒，峯巒邀客上煙霞。", "龍山故事依然在，莫把風流讓孟嘉。"]'),
('64505f6c-1f47-45a1-a1b8-8dfe82efba29','冬至有感','馮時行','宋','宋诗','song-poetry','','[]','蕭辰俛仰及嚴冬，白髮空云是至公。',64,'全唐诗/poet.song.112000.json','["蕭辰俛仰及嚴冬，白髮空云是至公。", "造雪不成天本恕，喚梅未醒句無功。", "可能人事無消長，只待天時有變通。", "節物相關愁似醉，一庭霜葉一窗風。"]'),
('f9bd73bc-338f-48d8-8311-62fec43792a5','南至即事','馮時行','宋','宋诗','song-poetry','','[]','愛惜清秋預恐貧，豈堪時序過來頻。',64,'全唐诗/poet.song.112000.json','["愛惜清秋預恐貧，豈堪時序過來頻。", "待梅沽酒無多日，隔臘看春只並隣。", "俗薄連牆成異縣，時難佳節是蕭辰。", "望雲還卜中興日，濺淚乾坤一小臣。"]'),
('d56b33ad-916b-4d2e-9f2b-7193ce4b12a9','梅花','馮時行','宋','宋诗','song-poetry','','[]','正是園林花木衰，冰姿玉潔出疏籬。',64,'全唐诗/poet.song.112000.json','["正是園林花木衰，冰姿玉潔出疏籬。", "月中瘦影道傍見，江上寒香人不知。", "時節驚心非故物，簿書滿眼欠新詩。", "碧雲暮合關山遠，擬折瓊英寄所思。"]'),
('62c6c10a-fded-481d-b135-6a56d6ab3ca4','落梅','馮時行','宋','宋诗','song-poetry','','[]','不禁清瘦怯風霜，遠信先憑驛使將。',64,'全唐诗/poet.song.112000.json','["不禁清瘦怯風霜，遠信先憑驛使將。", "樓上笛聲吹舊曲，鑑中人面學新粧。", "飄零院宇仍多思，點綴簾櫳亦自香。", "留與春風共流轉，憑誰試與祝東皇。"]'),
('e685612b-d40c-484d-87c5-2fe422866015','酴醿','馮時行','宋','宋诗','song-poetry','','[]','萬仙同駕碧雲翔，容與人間散異香。',64,'全唐诗/poet.song.112000.json','["萬仙同駕碧雲翔，容與人間散異香。", "梅似前賢長隔世，酒真同氣莫相忘。", "流鶑夢斷驚風雨，落月魂銷映雪霜。", "春暖日長無一事，飛花片片倚胡床。"]'),
('df824ba4-e3ad-46b2-8cb4-cd7aef076fd1','和向文叔見寄','馮時行','宋','宋诗','song-poetry','','[]','煙雲浩蕩五湖身，老向風塵學問津。',64,'全唐诗/poet.song.112000.json','["煙雲浩蕩五湖身，老向風塵學問津。", "白髮只應無奈若，青衫定是可憐人。", "草侵吟枕依依夢，花傍愁襟故故春。", "江上負暄樵牧晚，素書千里慰蕭辰。"]'),
('1e336f1a-adad-498c-9408-948988824e7c','縉雲寺','馮時行','宋','宋诗','song-poetry','','[]','借問禪林景若何，半天樓殿冠嵯峨。',64,'全唐诗/poet.song.112000.json','["借問禪林景若何，半天樓殿冠嵯峨。", "莫言暑氣此中少，自是清風高處多。", "岌岌九峯晴有霧，瀰瀰一水遠無波。", "我來遊覽便歸去，不必吟成證道歌。"]'),
('798e80d3-de7d-4c03-81e6-0a9a70d473ff','謝陳舜弼送丹荔','馮時行','宋','宋诗','song-poetry','','[]','驪珠三百照傾箱，一一都全味色香。',64,'全唐诗/poet.song.112000.json','["驪珠三百照傾箱，一一都全味色香。", "道遠鶴觴齊騎驛，雨多龍伯護津梁。", "蠲煩已笑冰無味，過眼仍同玉有光。", "報貺無他空覓句，更慚詩骨謝凌霜。"]'),
('b3307809-a289-48fd-b6fa-0bcb16264ca5','寓棲隠僧舍讀書','馮時行','宋','宋诗','song-poetry','','[]','茅竹無錢結翠霞，歸來棲止梵王家。',64,'全唐诗/poet.song.112000.json','["茅竹無錢結翠霞，歸來棲止梵王家。", "夜窗聽雨翻書葉，曉研凌霜注井花。", "已隔朱樓安管鑰，獨尋碧磵問津涯。", "蘆簾紙帳門如水，兀坐蒲團事不賒。"]'),
('aea6cb5f-d091-4fc3-bb62-de449f5bddbb','過鐵山驛','馮時行','宋','宋诗','song-poetry','','[]','來時趁作世情遊，歸去淒涼遣客愁。',64,'全唐诗/poet.song.112000.json','["來時趁作世情遊，歸去淒涼遣客愁。", "萬事世間多反復，一生此地幾春秋。", "天寒樹老葉全脫，水落岸高溪不流。", "行路崎嶇縱難料，江湖付與一孤舟。"]'),
('e58b0a85-aa9c-44ed-85f7-7f8a758cafd7','清富軒','馮時行','宋','宋诗','song-poetry','','[]','道高清識自超殊，白璧黄金視若無。',64,'全唐诗/poet.song.112000.json','["道高清識自超殊，白璧黄金視若無。", "坐側擁書皆是寶，望中森木盡爲奴。", "朱簾畫棟皆成俗，綠水青山可與娛。", "日有輕肥尋訪去，每教留戀過殘鋪。"]'),
('a601e358-bb3e-47bb-abbf-49c741cdfbb4','題蔡雲叟山居','馮時行','宋','宋诗','song-poetry','','[]','茅屋依雲晚未收，一門山色倚寒流。',64,'全唐诗/poet.song.112000.json','["茅屋依雲晚未收，一門山色倚寒流。", "戲簷黄雀驚彈劍，飲水鳥猿看放鈎。", "醉卧落霞斜枕手，高吟晚日更昂頭。", "朝廷莫問安邊策，人在深山笑五侯。"]'),
('01fdd4f5-5bf0-4661-8062-48f6b7a5495a','送常德翁知縣','馮時行','宋','宋诗','song-poetry','','[]','山多豺虎水蛟黿，萬里歸來只舊官。',64,'全唐诗/poet.song.112000.json','["山多豺虎水蛟黿，萬里歸來只舊官。", "莫問蒼生待君起，須知白髮見親難。", "高蹤已逐飛鴻去，凡眼休將退鷁看。", "得句驚人須寄我，時時要看老波瀾。"]'),
('e987406e-fd20-45a6-93a8-1d8121fed544','寒食夜坐','馮時行','宋','宋诗','song-poetry','','[]','雨餘虛廡靜前墀，坐到空江月上時。',64,'全唐诗/poet.song.112000.json','["雨餘虛廡靜前墀，坐到空江月上時。", "馬嚼青芻喧夜寂，人圍綠幕夢歸期。", "一年已是逢寒食，千里誰能慰客思。", "留宿春城愁落寞，杏花明日更離披。"]'),
('03d184fa-fa8c-46b3-8ad8-fb03a8d03b0c','將之瀘南','馮時行','宋','宋诗','song-poetry','','[]','幾年落魄劍南州，重入蠻鄉覓舊遊。',64,'全唐诗/poet.song.112000.json','["幾年落魄劍南州，重入蠻鄉覓舊遊。", "十驛出城難夙駕，一生浪跡愧虛舟。", "家留異縣懷親老，夢繞滄洲恐鬢秋。", "白馬鳴寒如可問，此身端復謝沈浮。"]'),
('f9063a18-176c-48e4-8db8-ce09ed090317','村居','馮時行','宋','宋诗','song-poetry','','[]','飛蛾故故撲燈光，風雨蕭蕭打紙窗。',64,'全唐诗/poet.song.112000.json','["飛蛾故故撲燈光，風雨蕭蕭打紙窗。", "人爲官方搔白首，虎來村落渡清江。", "猿啼冷日誰家夢，故國愁牽幾曲腸。", "籬菊何曾憂戰伐，夜添寒蕊趁重陽。"]'),
('401c3591-2220-4a79-ab88-5128a7c6e879','送同年朱元直監稅  其一','馮時行','宋','宋诗','song-poetry','','[]','會計牛羊道益光，幽蘭不佩亦芳香。',64,'全唐诗/poet.song.112000.json','["會計牛羊道益光，幽蘭不佩亦芳香。", "前郎未必辭官小，我輩惟知作法凉。", "客抱只消潘鬢白，俸囊無奈朔身長。", "要知別後相思地，獨上西山下夕陽。"]'),
('d00a060f-f813-4520-850e-124127f1e3b1','送同年朱元直監稅  其二','馮時行','宋','宋诗','song-poetry','','[]','秋風可擬借年光，曉覺新篘潑鼻香。',64,'全唐诗/poet.song.112000.json','["秋風可擬借年光，曉覺新篘潑鼻香。", "黄菊丹萸元嫵媚，敗荷衰柳自淒涼。", "山纔入眼身尤健，事不關心日便長。", "欲把酒藤凌翠嶠，醉餘起舞送重陽。"]'),
('8ec9559e-a854-4801-b4b4-81dc42d86d85','送同年朱元直監稅  其三','馮時行','宋','宋诗','song-poetry','','[]','池上千巖入曉光，無花草木自吹香。',64,'全唐诗/poet.song.112000.json','["池上千巖入曉光，無花草木自吹香。", "眼隨天霽山山見，心與秋清事事凉。", "長嘯響驚龍壑靜，微吟思入雁雲長。", "未須摇落增悲慨，新報王師復洛陽。"]'),
('82365498-a54a-4b71-bbc1-531126374d0a','謝韓秀才送松栽四首  其一','馮時行','宋','宋诗','song-poetry','','[]','新拓藤蘿住翠巒，移根千本到雲端。',64,'全唐诗/poet.song.112000.json','["新拓藤蘿住翠巒，移根千本到雲端。", "初乘雨露迎春種，便作雲霄蔽日看。", "巖穴從今增氣象，茯苓可擬救衰殘。", "知君有意憐棲隠，更約堅身待歲寒。"]'),
('4645e43c-7f06-4bde-a3cc-f3d23a643d64','謝韓秀才送松栽四首  其二','馮時行','宋','宋诗','song-poetry','','[]','鬰葱待得覆巖巒，愛護關心豈一端。',64,'全唐诗/poet.song.112000.json','["鬰葱待得覆巖巒，愛護關心豈一端。", "已恐旱乾支水繞，更防牛馬倩人看。", "何當倚杖聽蕭瑟，便欲從渠號懶殘。", "物色最宜清浄觀，列仙癯瘦不言寒。"]'),
('175898ae-6421-44e7-b52b-ef28a49875f1','謝韓秀才送松栽四首  其三','馮時行','宋','宋诗','song-poetry','','[]','已將疏懶寄雲巒，人世於今有萬端。',64,'全唐诗/poet.song.112000.json','["已將疏懶寄雲巒，人世於今有萬端。", "整頓林泉宜急急，上還簪綬亦看看。", "移根遠带前山澗，荷鍤行衝小雨殘。", "急爾成林十年後，颼颼爲作暑天寒。"]'),
('04d8166f-93e2-40f1-bd98-7647ca59cc93','謝韓秀才送松栽四首  其四','馮時行','宋','宋诗','song-poetry','','[]','餐松食柏老巖巒，藥餌從今可問端。',64,'全唐诗/poet.song.112000.json','["餐松食柏老巖巒，藥餌從今可問端。", "髮白顔蒼無復懼，骨青髓綠後來看。", "色隨春焙茶煙碧，凉入晨烹竈火殘。", "自是本來山澤相，故煩天遣伴淒寒。"]'),
('8245c56a-8048-46af-99b3-9d0bbb393996','代簡寄壁山諸友慈洞硯','馮時行','宋','宋诗','song-poetry','','[]','聞道諸郎長似林，臨池已遣學山陰。',64,'全唐诗/poet.song.112000.json','["聞道諸郎長似林，臨池已遣學山陰。", "信傳鴻翼兼雙硯，物比鵝毛表寸心。", "書札總無緣懶病，襟懷堪寄有孤吟。", "歸裝準擬隨春色，歲酒須留待細斟。"]'),
('c4d27db1-189c-4e0c-839e-a11ef5c7ae83','春久不雨','馮時行','宋','宋诗','song-poetry','','[]','老將百指寄耕田，雨不霑春重慨然。',64,'全唐诗/poet.song.112000.json','["老將百指寄耕田，雨不霑春重慨然。", "雲染夕曛成返照，霧隨山色化輕煙。", "王官掃廩徵豐歲，野史濡毫記有年。", "咄爾虬龍須早起，莫將乖懶滯重淵。"]'),
('4cfadc7f-f3a9-4582-9de2-43c0f88a10fd','春和譚曦晉仲見惠之什晉仲夔人隠居歸之城下簞食瓢飲有可樂者','馮時行','宋','宋诗','song-poetry','','[]','大隠休誇渾俗塵，由來空谷有幽人。',64,'全唐诗/poet.song.112000.json','["大隠休誇渾俗塵，由來空谷有幽人。", "只無憂患催垂白，何必功名掛汗青。", "我已退非金馬客，君宜上應少微星。", "卜隣有意誅茅切，竹杖交頭到夢屏。"]'),
('80dbff71-c898-4c94-959d-2ec1536a7e24','和史濟川見贈','馮時行','宋','宋诗','song-poetry','','[]','歲晚扁舟雪霰邊，蕭疏與君俱可憐。',64,'全唐诗/poet.song.112000.json','["歲晚扁舟雪霰邊，蕭疏與君俱可憐。", "向來共厄黄楊閏，別後相逢白髮年。", "覓句剩煩梅作興，攻愁直縱酒稱賢。", "故人一笑誠希闊，得失休論布幔天。"]'),
('f8a68e0a-35b5-4601-8e48-5c7f79e9fda4','和李堯俞郎中西歸有感','馮時行','宋','宋诗','song-poetry','','[]','去留出處勿相關，煉得心丹已九還。',64,'全唐诗/poet.song.112000.json','["去留出處勿相關，煉得心丹已九還。", "自有文章爲鼓吹，只將廊廟等雲山。", "百年有酒堪留念，萬事無心忘駐顔。", "郎署分符舊名姓，安知不在覆盂間。"]'),
('70330c29-b6f0-449c-b54f-cc2facdb13ff','和李堯俞韵','馮時行','宋','宋诗','song-poetry','','[]','海頭歸到峽江濱，新歲殘年只並隣。',64,'全唐诗/poet.song.112000.json','["海頭歸到峽江濱，新歲殘年只並隣。", "梅自多情工惱客，月如知己輒親人。", "江山縱肯容吾老，猿鶴應嫌不自珍。", "從此扁舟須駕閣，名教魯史續書麟。"]'),
('34b0fc05-35a3-4cfa-b58f-5827b1c6be9f','雪中用黄太史韵','馮時行','宋','宋诗','song-poetry','','[]','密雪誰人巧擬鹽，初飛仍带雨廉纖。',64,'全唐诗/poet.song.112000.json','["密雪誰人巧擬鹽，初飛仍带雨廉纖。", "夜吹玉笛滿浮酒，曉看遥山高捲簾。", "方積銀杯翻過馬，欲銷冰筯插疏簷。", "不堪時傍潘安鬢，華髮朝來覺驟添。"]'),
('68393f8a-c9f8-43b1-8c56-24ca1e36a2fc','題瀘南石𥒁灘','馮時行','宋','宋诗','song-poetry','','[]','雲間依約起樓臺，江上遥觀眼豁開。',64,'全唐诗/poet.song.112000.json','["雲間依約起樓臺，江上遥觀眼豁開。", "初謂僧房有鐘磬，那知人戶半蒿萊。", "一生夢幻本如此，過眼浮雲安在哉。", "獨倚斜陽弔今古，亂鴉飛處一舟回。"]'),
('a5f58e59-8ba2-4420-b18b-31d4816c9251','有感','馮時行','宋','宋诗','song-poetry','','[]','俛首趨時獨自嫌，年來壯膽尚相淹。',64,'全唐诗/poet.song.112000.json','["俛首趨時獨自嫌，年來壯膽尚相淹。", "神鋒不及錐頭利，花蜜翻虧蔗尾甜。", "萬里水雲閒有約，一床墳籍靜無厭。", "明珠自得非他得，懶更驪腮著手拈。"]'),
('3aefd185-cc31-46be-b7f0-9302bb84bf6c','登西樓二首  其一','馮時行','宋','宋诗','song-poetry','','[]','林際虹霓掛晚晴，西樓無事翠烟橫。',64,'全唐诗/poet.song.112000.json','["林際虹霓掛晚晴，西樓無事翠烟橫。", "荷花半落水風遠，桂子欲飄山月明。", "黄卷久忘塵世事，白雲猶動故園情。", "無端最是城頭角，頻作淒涼塞上聲。"]'),
('3834da17-b1d1-4590-a264-d6e869a8ebeb','登西樓二首  其二','馮時行','宋','宋诗','song-poetry','','[]','年來雙目厭紛華，獨上西樓日欲斜。',64,'全唐诗/poet.song.112000.json','["年來雙目厭紛華，獨上西樓日欲斜。", "幽鳥有情啼苦竹，畫船無事艤荷花。", "吳天半出雲中樹，越嶺初橫雨後霞。", "惆悵倚欄人去後，一竿明月屬漁家。"]'),
('7f801087-5de6-4caf-a4d4-9c9bfdbbcbd7','謝馮貫道惠小舟','馮時行','宋','宋诗','song-poetry','','[]','先生憐我欲歸休，爲我添錢買小舟。',64,'全唐诗/poet.song.112000.json','["先生憐我欲歸休，爲我添錢買小舟。", "老去尚餘州縣業，見來便起江湖秋。", "有名如合稱聱叟，無夢焉能賣直鈎。", "他日相隨鷗鳥外，短篷烟雨醉懞頭。"]'),
('4dc9b190-9806-446e-bdb8-60ccd0eb5610','到墊江先作詩寄郝令君蒙老','馮時行','宋','宋诗','song-poetry','','[]','盛家山前古雀籬，寒烟冷雨別君時。',64,'全唐诗/poet.song.112000.json','["盛家山前古雀籬，寒烟冷雨別君時。", "後來空作相逢夢，此處端成一笑期。", "已聽歌謠增喜樂，未聞謦咳祇飛馳。", "急須倒屣迎徐孺，一榻高懸更爲誰。"]'),
('0307e271-b440-460a-9531-13cbc08c383b','和楊良卿韵新自興元歸見貽二首  其一','馮時行','宋','宋诗','song-poetry','','[]','飽聽玉帳報平安，猿鶴關心又乞閒。',64,'全唐诗/poet.song.112000.json','["飽聽玉帳報平安，猿鶴關心又乞閒。", "再理十年君杖屨，來分一半我雲山。", "歌能著意傾愁斛，酒解將紅染病顔。", "老去世情銷未盡，尚希東閣管窺斑。"]'),
('b5afbbbe-2fd3-4113-8652-40cefc07393e','和楊良卿韵新自興元歸見貽二首  其二','馮時行','宋','宋诗','song-poetry','','[]','人間平地有危機，歸去應先未辱時。',64,'全唐诗/poet.song.112000.json','["人間平地有危機，歸去應先未辱時。", "少著青衫元自懶，老簪華髮更何疑。", "向曾汩沒痕猶在，尚此廉纖愧自知。", "惟有冥鴻心一寸，從今寤寐考槃詩。"]'),
('9b4671f1-d5c4-4767-b297-129107bed1fc','登岳陽樓','馮時行','宋','宋诗','song-poetry','','["\u5cb3\u9633\u697c"]','湖面層收雨露開，浪聲千里急奔雷。',64,'全唐诗/poet.song.112000.json','["湖面層收雨露開，浪聲千里急奔雷。", "草迎雲夢秋光去，帆带衡陽曉色來。", "帝子不歸林葉下，楚魂堪弔暮鴻哀。", "羈遊到此偏增感，况悼長沙放逐才。"]'),
('d5f6d892-7db3-4627-a110-00e965e97fd0','送何子應二首  其一','馮時行','宋','宋诗','song-poetry','','[]','送客江頭水漸生，客愁無那亦相纓。',64,'全唐诗/poet.song.112000.json','["送客江頭水漸生，客愁無那亦相纓。", "一離夔子真成別，欲過岑公且勿行。", "小舞清歌元有興，綠楊青草正關情。", "背人歸去春無頼，未害開懷鬭酒兵。"]'),
('a23ec962-3f69-46c5-add1-70e8b838bb14','送何子應二首  其二','馮時行','宋','宋诗','song-poetry','','[]','功名本自屬諸生，誰向滄浪便濯纓。',64,'全唐诗/poet.song.112000.json','["功名本自屬諸生，誰向滄浪便濯纓。", "枕上日高惟我懶，船頭風飽看君行。", "眼前歷歷幾經手，意外悠悠久繫情。", "待得封侯應有日，胸中况貯萬奇兵。"]'),
('65ed692f-4b6e-4cac-9b45-82b60fd6225e','謝益仲惠黄雞苦笋新茶三物書意勤渠欲索鄙製仍首讚僕之談詠頗窺玄窟以詩謝之','馮時行','宋','宋诗','song-poetry','','[]','明月山中謝惠連，遠將何物餉柴門。',64,'全唐诗/poet.song.112000.json','["明月山中謝惠連，遠將何物餉柴門。", "仙歸碧落雞遺種，龍入丹淵竹有孫。", "欲索風騷供詠味，仍分雪乳滌蒙昏。", "殷勤雅意知何報，待把禪宗與細論。"]'),
('2d5f1f95-989b-458d-91e9-760fa78caa10','送同年楊元直持憲節湖南二首  其一','馮時行','宋','宋诗','song-poetry','','[]','天闊風高旆纛輕，江清沙白映揚舲。',64,'全唐诗/poet.song.112000.json','["天闊風高旆纛輕，江清沙白映揚舲。", "西岷峻極開文紀，南斗昭垂並使星。", "已見帆頭湖水白，猶看柂尾蜀山青。", "祇應直上裁天詔，楚甸風烟暫一經。"]'),
('bf13bc0b-d3e3-4cfe-a0c6-5100751a0046','送同年楊元直持憲節湖南二首  其二','馮時行','宋','宋诗','song-poetry','','[]','猶記瓊林插賜花，雲霄翮斷進塗賒。',64,'全唐诗/poet.song.112000.json','["猶記瓊林插賜花，雲霄翮斷進塗賒。", "形歸靜定幾生柳，道叩虛無類煮沙。", "曉落秋風驚白髮，病瞻南極記丹砂。", "願分九鼎刀圭力，留得殘年老種瓜。"]'),
('79bf26c3-be8b-4f2a-8518-409258e03616','答杜如箎','馮時行','宋','宋诗','song-poetry','','[]','迂疏百試百無長，身世從教墮渺茫。',64,'全唐诗/poet.song.112000.json','["迂疏百試百無長，身世從教墮渺茫。", "老得雲山真不惡，拙憑草樹更深藏。", "三杯且共逢迎酒，一瓣誰薰知見香。", "便肯經年繫舟檝，如君惠好實難忘。"]'),
('483c15a9-14f8-4c23-a3b1-7308ae24e2f1','見張魏公二首  其一','馮時行','宋','宋诗','song-poetry','','[]','危機易蹈退難安，進退如公地最寬。',64,'全唐诗/poet.song.112000.json','["危機易蹈退難安，進退如公地最寬。", "憂國憂家雙鬢白，通天通地一心丹。", "久虛海宇蒼生望，專結庭幃綵綬歡。", "終始哀榮情罔極，誰云忠孝兩全難。"]'),
('f2ee5cff-8d5f-43aa-abaa-2d96736bc83f','見張魏公二首  其二','馮時行','宋','宋诗','song-poetry','','[]','四海於今望治安，當頭退避也應難。',64,'全唐诗/poet.song.112000.json','["四海於今望治安，當頭退避也應難。", "是非歷歷開新聽，變化紛紛入靜觀。", "孰把後圖歌寤枕，再將前事倚危欄。", "重拈今古看奇特，幸記塵冠久不彈。"]'),
('1cbbd9d4-2b67-4d43-919c-1df59bda1fbb','宿石洞峽','馮時行','宋','宋诗','song-poetry','','[]','五十七年來往處，扁舟幾繫亂雲邊。',64,'全唐诗/poet.song.112000.json','["五十七年來往處，扁舟幾繫亂雲邊。", "江山寂寂渾無恙，鬢髮絲絲也可憐。", "水背黄牛吞七澤，杯翻白鶴過羣仙。", "差池世故渾如此，底事長歌亦浩然。"]'),
('823ca9b7-31c5-4398-9d85-970b06213fa0','送王子善移江津酒官一首','馮時行','宋','宋诗','song-poetry','','[]','相看相別意何如，見事蜂生正要渠。',64,'全唐诗/poet.song.112000.json','["相看相別意何如，見事蜂生正要渠。", "挽袖一杯山月上，凝眸十里峽風徐。", "衣冠苗裔烟塵際，京洛風流咳唾餘。", "自此清愁欺老得，逢君重見爲驅除。"]'),
('557f477a-719e-4ca4-9d6c-e45a45de2b4b','二月將半雨過花盛開二首  其一','馮時行','宋','宋诗','song-poetry','','[]','一年青春日無幾，二月小雨花齊開。',64,'全唐诗/poet.song.112000.json','["一年青春日無幾，二月小雨花齊開。", "底事我禁愁思得，可能不近酒杯來。", "山青樹樹明於纈，江遠村村爛作堆。", "老罷興來須抖擻，自吟詩句自相催。"]'),
('c3dea2f2-38d6-4656-a56f-ec0d140e59d0','二月將半雨過花盛開二首  其二','馮時行','宋','宋诗','song-poetry','','[]','最憐半見或不見，更惜欲開猶未開。',64,'全唐诗/poet.song.112000.json','["最憐半見或不見，更惜欲開猶未開。", "樹遠祇疑隨水去，枝低還似傍人來。", "不堪小蕊樽前落，可忍殘紅砌下堆。", "著盡工夫春自去，不須風雨惡相催。"]'),
('8ce82211-015c-4d5f-ac30-e6ef2383e943','鄂州南樓其下爲黄鶴樓故基','馮時行','宋','宋诗','song-poetry','','[]','今日南樓獨上時，西風無復片雲飛。',64,'全唐诗/poet.song.112000.json','["今日南樓獨上時，西風無復片雲飛。", "天連江水去不盡，雲傍遠山閒自歸。", "鸚鵡巧言終掇禍，麒麟高舉亦知幾。", "詩翁仙子今何在，徙倚欄干送落暉。"]'),
('6c0c13b6-5311-40f1-948e-0af47b654bd3','郭信可索雲溪詩懶未能作戲成此寄以自解','馮時行','宋','宋诗','song-poetry','','[]','疏疏翠竹浄江沙，遠寄新詩特地誇。',64,'全唐诗/poet.song.112000.json','["疏疏翠竹浄江沙，遠寄新詩特地誇。", "月徑剩教添鬢雪，雲溪日放長苔花。", "也知一决君無勇，豈是狂吟我欲賒。", "琴鶴今朝隨小隠，詩篇明日寄烟霞。"]'),
('26206e8d-5b54-4c33-b93c-4cb740c3c39e','題村居','馮時行','宋','宋诗','song-poetry','','[]','荆棘叢中少避鋒，歸來袖手十春冬。',64,'全唐诗/poet.song.112000.json','["荆棘叢中少避鋒，歸來袖手十春冬。", "茅簷去市遠更遠，樵路入山重復重。", "雲與好閒長作伴，虎知聞道亦相容。", "濁醪寄釀枯松腹，夜醉南山最上峯。"]'),
('1c2325e9-23ff-4e75-808a-e62f5fd3b4fa','遊白鶴山','馮時行','宋','宋诗','song-poetry','','[]','草樹烟雲滿眼秋，長河橫嶺共悠悠。',64,'全唐诗/poet.song.112000.json','["草樹烟雲滿眼秋，長河橫嶺共悠悠。", "覓歸未得登臨怯，與世相違俯仰愁。", "萬里音書無過雁，百年心事倚危樓。", "西風早晚催征馭，却向青衣江上遊。"]'),
('b26dcd68-94a7-47ab-864d-2fc96610aff8','日望冉雄飛之來久不聞近耗因成鄙句以見翹然之思','馮時行','宋','宋诗','song-poetry','','[]','緩轡微吟自不催，看山下馬想徘徊。',64,'全唐诗/poet.song.112000.json','["緩轡微吟自不催，看山下馬想徘徊。", "陽春白雪久不聽，日暮碧雲殊未來。", "已戒兒童篘熟酒，更勤風雪化新梅。", "雲間飛舄何時下，抑鬰孤懷遲一開。"]'),
('950e0375-e186-46a4-8e4e-ab9d6be3e744','和蔡伯世韵二首  其一','馮時行','宋','宋诗','song-poetry','','["\u957f\u6c5f"]','鉅璞希音未易知，芒鞋竹杖祇相宜。',64,'全唐诗/poet.song.112000.json','["鉅璞希音未易知，芒鞋竹杖祇相宜。", "還收北伐六奇計，歸作東遊五勝詩。", "千里雲山通夢想，十年笑語隔心期。", "擬憑浩蕩長江水，日落烟寒寄所思。"]'),
('3e06530e-4cf0-4be9-aed8-1622d7919a31','和蔡伯世韵二首  其二','馮時行','宋','宋诗','song-poetry','','[]','中郎風調世間無，敢謂明時德不孤。',64,'全唐诗/poet.song.112000.json','["中郎風調世間無，敢謂明時德不孤。", "掃地焚香詩得計，曲肱飲水道如愚。", "寄書只說遊山好，臨老都緣學佛癯。", "白帝一來真漫浪，時人無用便題輿。"]'),
('eac84998-bcaa-4325-8be6-6a32893d649a','題毛祖房屋壁','馮時行','宋','宋诗','song-poetry','','[]','卜築縉雲山下村，縉雲山色青滿門。',64,'全唐诗/poet.song.112000.json','["卜築縉雲山下村，縉雲山色青滿門。", "承當春色花成段，領略朋簪酒滿樽。", "盡去機關馴虎豹，略推愷悌赦雞豚。", "要知餘慶須彌遠，堂上森然見子孫。"]'),
('4c49b66c-7402-47b7-86ba-a8386d2048af','牟元禮挽章','馮時行','宋','宋诗','song-poetry','','[]','淚注瓊瑰事可傷，白衣回首白雲鄉。',128,'全唐诗/poet.song.112000.json','["淚注瓊瑰事可傷，白衣回首白雲鄉。", "兩三遺冊新詩在，四十餘年素業荒。", "學海驟乾千頃浪，儒林舊剪一枝芳。", "風流未寄三題草，光焰誰家萬丈長。", "不作人間金榜客，應爲天上玉樓章。", "詼諧未見車公口，錦繡應無李白腸。", "幽鳥空啼疏竹徑，青燈愁見舊梧堂。", "就中有事空堪恨，誰問雙親兩鬢霜。"]'),
('bcbdbbf7-0864-408b-aace-5f8240ea3b51','萬州','馮時行','宋','宋诗','song-poetry','','[]','銀珠絡髻繡衣裳，家住江南山後鄉。',32,'全唐诗/poet.song.112000.json','["銀珠絡髻繡衣裳，家住江南山後鄉。", "聞道君侯重行樂，相將腰鼓迓年光。"]'),
('8580dd98-5934-456f-960e-da7ed1b73219','題三峰','馮時行','宋','宋诗','song-poetry','','[]','古院無人僧作佛，碧潭有水魚化龍。',32,'全唐诗/poet.song.112000.json','["古院無人僧作佛，碧潭有水魚化龍。", "當年矩諾小遊戲，一石擊碎成三峰。"]'),
('dd8c0c14-6774-4b58-9951-bd4c85586d75','烏棲曲','馮時行','宋','宋诗','song-poetry','','[]','黄河吹風暗平川，東流之水清且瀾。',64,'全唐诗/poet.song.112000.json','["黄河吹風暗平川，東流之水清且瀾。", "明月不如長年好，照我離離滿秋前。", "明年此夜月還明，我是荆江雲水人。", "勸君莫唱烏棲曲，千古悲凉鬼神哭。"]'),
('2c9e629d-50d1-4c40-ad9a-20ef12def754','寄題龐宮使提舉山齋二絕  其一','馮時行','宋','宋诗','song-poetry','','[]','才及中年便買山，山中何事可怡顔。',32,'全唐诗/poet.song.112000.json','["才及中年便買山，山中何事可怡顔。", "當時白傅登臨眼，物色渾歸几案間。"]'),
('0590513b-09e3-45ef-a53e-931511db0956','寄題龐宮使提舉山齋二絕  其二','馮時行','宋','宋诗','song-poetry','','[]','白衣蒼狗變浮雲，過眼紛紛不可論。',32,'全唐诗/poet.song.112000.json','["白衣蒼狗變浮雲，過眼紛紛不可論。", "晚歲逢迎真耐久，青山相對兩忘言。"]'),
('85647fb1-4738-43e3-84d0-deee59181a4e','鈴齋','馮時行','宋','宋诗','song-poetry','','[]','亂離固多事，賢哲有要領。',72,'全唐诗/poet.song.112000.json','["亂離固多事，賢哲有要領。", "一切本仁義，條教日月炳。", "邦民用不犯，閉閣自非省。", "猶能肖蓋公，使我醉清浄。", "春風花滿門，午夢日轉影。", "先已戒鈴下，吏至無輒請。"]'),
('38d1c93e-8a2b-49d0-9220-b999c1c5c8ef','梅臺','馮時行','宋','宋诗','song-poetry','','[]','緬懷清絕姿，風流似居士。',24,'全唐诗/poet.song.112000.json','["緬懷清絕姿，風流似居士。", "固宜命斯臺，俗子視桃李。"]'),
('c7d5e30c-f50c-41f7-b76d-0aecc9dfb294','贈何山人','馮時行','宋','宋诗','song-poetry','','[]','又聞科詔下諸州，舉袂成帷盡俊遊。',32,'全唐诗/poet.song.112000.json','["又聞科詔下諸州，舉袂成帷盡俊遊。", "汝去爲吾推甲乙，千人誰是釣鼇鈎。"]'),
('20ce28e5-1063-483d-9619-5e81b3700e59','落花十絕  其一','馮時行','宋','宋诗','song-poetry','','[]','枝頭日日候韶妍，百舌聲中又隔年。',32,'全唐诗/poet.song.112000.json','["枝頭日日候韶妍，百舌聲中又隔年。", "莫道山翁無思緒，見人踏著便悽然。"]'),
('d0215387-92f2-4635-90d3-90a4a81cb0f4','落花十絕  其二','馮時行','宋','宋诗','song-poetry','','[]','著花著酒苦相留，嗔雨嗔風畢竟休。',32,'全唐诗/poet.song.112000.json','["著花著酒苦相留，嗔雨嗔風畢竟休。", "有態游揚元嫵媚，無心點綴亦風流。"]'),
('5c4a1215-20f0-44e1-81a6-eb6359e00186','落花十絕  其三','馮時行','宋','宋诗','song-poetry','','[]','萬翠千紅錦一張，春秋何處不芬芳。',32,'全唐诗/poet.song.112000.json','["萬翠千紅錦一張，春秋何處不芬芳。", "誰教無頼狂風雨，收作年華入鬢霜。"]'),
('3aaae8c3-9e16-4d22-a90e-3ab3efe13323','落花十絕  其四','馮時行','宋','宋诗','song-poetry','','[]','老來著意惜餘年，時世那堪急似弦。',32,'全唐诗/poet.song.112000.json','["老來著意惜餘年，時世那堪急似弦。", "敵面被春將一歲，又隨風葉去翩翩。"]'),
('71f37bcf-6946-4fb5-a674-7bd77e5b95ed','落花十絕  其五','馮時行','宋','宋诗','song-poetry','','[]','惱教衰病倩人扶，掩得疏慵倒酒壺。',32,'全唐诗/poet.song.112000.json','["惱教衰病倩人扶，掩得疏慵倒酒壺。", "半濕垂垂粘醉帽，全輕冉冉上吟鬚。"]'),
('81341803-9c71-45df-8099-d7a91727d49c','落花十絕  其六','馮時行','宋','宋诗','song-poetry','','[]','半去還來繞舊叢，半隨胡蝶便西東。',32,'全唐诗/poet.song.112000.json','["半去還來繞舊叢，半隨胡蝶便西東。", "從交滿地無人掃，快意甘心薄倖風。"]'),
('0bc7d2c4-e361-496b-afc8-4603bc11863e','落花十絕  其七','馮時行','宋','宋诗','song-poetry','','[]','即看簇簇鬭鮮妍，忽作漫天也可憐。',32,'全唐诗/poet.song.112000.json','["即看簇簇鬭鮮妍，忽作漫天也可憐。", "隨雨隨風知有恨，恨無人著買春錢。"]'),
('531b47c4-7dbd-465e-bfe9-06eaa95a8710','落花十絕  其八','馮時行','宋','宋诗','song-poetry','','[]','幽棲竹路滿蒼苔，花擁柴扉午未開。',32,'全唐诗/poet.song.112000.json','["幽棲竹路滿蒼苔，花擁柴扉午未開。", "可是春風料理得，時吹一片過窗來。"]'),
('b4081e65-2658-4922-ad6c-4fdd42f8dfcf','落花十絕  其九','馮時行','宋','宋诗','song-poetry','','[]','瘦笻隨意步晴沙，困卧江頭野老家。',32,'全唐诗/poet.song.112000.json','["瘦笻隨意步晴沙，困卧江頭野老家。", "桃李盈門春寂寂，鶑驚睡覺一床花。"]'),
('4820302b-5ba4-42d7-9381-e92e814935d6','落花十絕  其一○','馮時行','宋','宋诗','song-poetry','','[]','朝來酌酒尚芳菲，醉眼醒時已覺稀。',32,'全唐诗/poet.song.112000.json','["朝來酌酒尚芳菲，醉眼醒時已覺稀。", "苦妬妖饒鶑拂下，解憐飄泊燕銜歸。"]'),
('2734e2c4-8b73-4f46-b42c-8c87b0430ba5','題綦母氏孝友堂詩','馮時行','宋','宋诗','song-poetry','','[]','高堂麗丹雘，燕衎謝迫隘。',168,'全唐诗/poet.song.112000.json','["高堂麗丹雘，燕衎謝迫隘。", "揭名屏物色，所取一何邁。", "艱難丕平後，南陔日廢壞。", "借鋤記父恩，紾臂飽兄嘬。", "惟君肖古先，學識洞源派。", "尊承天倫重，愧赧絕纖芥。", "遥遥曾閔心，千載知勉勵。", "雍穆粹閨閫，里閈消螫蠆。", "培植誕嘉種，芟藴殄莠稗。", "善積慶自餘，福履可不卦。", "斯堂寄丹抱，永煥曾玄戒。", "白華粲堂下，紫荆老不殺。", "吁嗟嗣芳烈，世世勿剪拜。", "感激自成詩，謾往致壁疥。"]'),
('4dc5c1f3-f43e-4968-86e9-a2b40c0d4c58','稽古堂詩爲曹應祥題','馮時行','宋','宋诗','song-poetry','','[]','稽古堂前雨半天，濛濛山色思依然。',32,'全唐诗/poet.song.112000.json','["稽古堂前雨半天，濛濛山色思依然。", "幾多心事催霜鬢，零落梅花又一年。"]'),
('c645bf71-8e25-4100-8bd8-49e8cd7407cd','學古堂爲毛應叔題','馮時行','宋','宋诗','song-poetry','','[]','昔人性嗜古，服用皆古先。',264,'全唐诗/poet.song.112000.json','["昔人性嗜古，服用皆古先。", "有虞作漆器，弊碗歷世傳。", "貨貲以得之，其費溢萬千。", "孔席伯夷杖，乾沒乃復然。", "家貧遂行乞，猶丐九府錢。", "此語雖詼嘲，義理茲可研。", "學古學其心，其用則蹄筌。", "軒轅騎蒼龍，舜入九嶷巔。", "古意已寥廓，如酒醨其元。", "君生萬世下，劫火經幾燃。", "作堂表佳目，意與開闢連。", "譬如引猨臂，踶跂摸蒼天。", "雖則如上說，膠談豈稱賢。", "今人亦古人，面目等媸妍。", "饑食寒而衣，天地靡變遷。", "澆風揚末塵，胡爲莫洗濺。", "忘機使神守，抱朴貴純全。", "六籍燦日星，泓泓聖賢淵。", "滑浄一几案，羲皇列吾前。", "薰染庶可久，膏肓儻其痊。", "聞君憙事者，有子鸞鳳騫。", "作詩助鼓譟，吾徒俱勉旃。"]'),
('cd56bd4d-baa6-49f3-b1ae-d1b9880d1311','雲巖','馮時行','宋','宋诗','song-poetry','','[]','樅陽之陽羌廬峰，千巖萬壑雲濛濛。',176,'全唐诗/poet.song.112000.json','["樅陽之陽羌廬峰，千巖萬壑雲濛濛。", "仙人往往遊其中，安期羨門喬與松。", "天或使之爲扃封，咫尺象外不可通。", "我昔杖履秋將窮，洞宮蕭森還遽匆。", "至今魂夢江南東，聞君斸石蒼崖穹。", "下燕衆客幽襟同，君真庶幾羌俗翁。", "作詩疾驅勤僕僮，斬薙薈蔚煩祝融。", "木章竹箇羣巔空，要使恢廓無蔽蒙。", "指麾八極呼雲風，坐與九江爭俊雄。", "當有騎鶴來遐沖，與君論道如崆峒。", "去之勿疑求大功，慎勿顧此杉楠楓。"]'),
('76aa0a45-f3d2-413d-b3e0-3678b554d4ba','中巖','馮時行','宋','宋诗','song-poetry','','[]','曠絕無人境，超然乃真遊。',96,'全唐诗/poet.song.112000.json','["曠絕無人境，超然乃真遊。", "如何許世俗，踏破蒼苔幽。", "我知大士心，月印千江秋。", "示迹蓋偶爾，雨罷雲亦收。", "層巒擁肺腑，修幹騫龍虬。", "巉巖近恐墜，窈窕翠欲流。", "標指諒非月，索劍寧刻舟。", "倚杖聽松風，聊爲信宿留。"]'),
('ebe7f222-3132-4867-b7b4-0e68d190c1a2','題漢初東巖','馮時行','宋','宋诗','song-poetry','','[]','疏官寂寂解行衣，脫木蕭蕭立翠微。',32,'全唐诗/poet.song.112000.json','["疏官寂寂解行衣，脫木蕭蕭立翠微。", "江带暝煙隨意曲，鳥翻落日向人歸。"]'),
('bcb6ebbe-5279-447f-a139-d89a7b0c4784','涪州北巖','馮時行','宋','宋诗','song-poetry','','[]','晴著春江鏡樣光，扁舟來炷佛前香。',32,'全唐诗/poet.song.112000.json','["晴著春江鏡樣光，扁舟來炷佛前香。", "山從幽處亭亭綠，日倚閑邊故故長。"]'),
('7e9297aa-d3de-4e2c-aa30-2525c53a9ea6','留題雲頂','馮時行','宋','宋诗','song-poetry','','[]','山如虬龍來，渴飲金淵水。',192,'全唐诗/poet.song.112000.json','["山如虬龍來，渴飲金淵水。", "水竭欲飛去，驤首振鱗尾。", "壯哉老頭陀，奮迅咄使止。", "左手攬其角，右手持其耳。", "壓以大蘭若，宛轉不得起。", "跏趺盤石上，頤指役萬鬼。", "至今五百載，金碧半天倚。", "檀施走兩川，澆鉢日萬指。", "我來過其下，柴車爲一柅。", "周覽三歎息，仰止百拜跪。", "憑高撫浩蕩，霜天浄無滓。", "幽懷散百慮，老眼卷千里。", "因知大力量，建立乃如此。", "德大無小試，器薄戒遠使。", "不聞力扛鼎，但見橛撼螘。", "感彼上人者，不覺淚盈眥。"]'),
('860ac947-8510-4d5b-88e7-b2da834e09bd','茶嶺','馮時行','宋','宋诗','song-poetry','','[]','翠嶺依然在，芳根久已陳。',24,'全唐诗/poet.song.112000.json','["翠嶺依然在，芳根久已陳。", "山靈如感舊，亦合厭荆榛。"]'),
('f82b4819-f0d7-485f-a3c8-3fe4cca641f4','出郊題瀼東人家屋壁  其一','馮時行','宋','宋诗','song-poetry','','[]','入座山如屏障，卷簾風滿衣襟。',28,'全唐诗/poet.song.112000.json','["入座山如屏障，卷簾風滿衣襟。", "正是梅花時候，怡融恰似春深。"]'),
('032b9590-2b75-4e2c-ad66-9cb6ba5154d9','出郊題瀼東人家屋壁  其二','馮時行','宋','宋诗','song-poetry','','[]','風引晴雲度去，臘催殘葉飛來。',28,'全唐诗/poet.song.112000.json','["風引晴雲度去，臘催殘葉飛來。", "短景餘寒幾日，安排都放花開。"]'),
('aaefd1db-6c82-4031-aa71-d0d2efc30796','梅林分韵得梅字','馮時行','宋','宋诗','song-poetry','','[]','霜朝馬蹄無纖埃，錦城城西江之隈。',152,'全唐诗/poet.song.112000.json','["霜朝馬蹄無纖埃，錦城城西江之隈。", "金蘭合沓俱朋來，白沙鱗鱗江水洄。", "梅花傍江高崔嵬，人言猶是王建栽。", "豪華過眼浮雲哉，飛英送香來酒杯。", "酒酣疾呼竹籬開，走尋屋角如龍梅。", "梅龍雖多此其魁，睡龍屈盤肘承胲。", "風皴雨散封蒼苔，孫枝迸出誰胚胎。", "天公撫摩春爲回，慎勿變化隨風雷，年年開花照尊罍。", "我欲結茅買芋煨，與梅周旋送衰頹。"]'),
('e9fd928f-e512-4cdf-befa-6b29178ec0a5','雙飛橋','馮時行','宋','宋诗','song-poetry','','[]','巨木架長虹，橫跨驚湍上。',48,'全唐诗/poet.song.112000.json','["巨木架長虹，橫跨驚湍上。", "有如排世難，出力貴用壯。", "行人知寶地，非此欲何嚮。", "因懷濟川功，作詩鑱絕嶂。"]'),
('22e8c58e-e7ee-4993-a34b-a2d6e1a6fe04','甘寧廟','馮時行','宋','宋诗','song-poetry','','[]','豪傑自不羣，俗眼蓋盲瞽。',48,'全唐诗/poet.song.112000.json','["豪傑自不羣，俗眼蓋盲瞽。", "劉表既不識，那復論黄祖。", "翻然脫羈銜，渡江得英主。", "垂手立功勳，雄名詫千古。"]'),
('8f76792b-73f8-4e21-99ff-9678cf3b6c72','伏虎寺','馮時行','宋','宋诗','song-poetry','','[]','良友百年新，芳遊十日共。',48,'全唐诗/poet.song.112000.json','["良友百年新，芳遊十日共。", "蒼壁聯躋攀，清湍競揮弄。", "雲來萬壑平，風過千山動。", "奇處合中分，歸作平生夢。"]'),
('da5ce4d8-dc61-4c49-8027-ec8d265fd982','句  其一','馮時行','宋','宋诗','song-poetry','','[]','妾身在代不如意，漢中胡中俱斷腸。',16,'全唐诗/poet.song.112000.json','["妾身在代不如意，漢中胡中俱斷腸。"]'),
('2552d3c5-6dd4-4945-a84d-c9474763d4f9','句  其二','馮時行','宋','宋诗','song-poetry','','[]','兒童便讀山中記，老大纔登記裏山。',16,'全唐诗/poet.song.112000.json','["兒童便讀山中記，老大纔登記裏山。"]'),
('750b3425-e14e-486a-a0a9-048afc299020','句','陳舜弼','宋','宋诗','song-poetry','','[]','憂貧仍閔雨。',6,'全唐诗/poet.song.112000.json','["憂貧仍閔雨。"]'),
('de656ccb-28b6-47f1-9325-c68bfc6bca2e','梅林分韵得今字','楊凱','宋','宋诗','song-poetry','','[]','蘭亭久陳迹，脩竹空自陰。',144,'全唐诗/poet.song.112000.json','["蘭亭久陳迹，脩竹空自陰。", "龍山亦淒涼，鮮花誰與簪。", "英遊曠千載，盛事新梅林。", "四海馮黎州，未妨鐵石心。", "提携到諸子，遍賞江之潯。", "亭亭姑射仙，玉立何森森。", "謝氏六君子，對飲香滿襟。", "西郊訪老龍，奇怪尤可欽。", "宛然如先生，高卧歲月侵。", "從茲飽薰風，佳實共鼎鬵。", "正味悅天下，妙用無古今。", "去去好著鞭，江南春已深。"]'),
('659ba95d-2d7b-4876-9689-3e89b83c0765','梅林分韵得彭字','于格','宋','宋诗','song-poetry','','[]','庭柯卧蒼龍，閲世如聃彭。',108,'全唐诗/poet.song.112000.json','["庭柯卧蒼龍，閲世如聃彭。", "朔風破檀蕊，零落滋玉英。", "江空人響絕，影落千丈清。", "今代文章籙，縉雲主齊盟。", "躍馬覘春色，觴客江上亭。", "三嗅韵勝華，霜霰飽曾經。", "及時剝其實，可用佐大烹。", "幸因輶軒使，錫貢充廣庭。", "王明儻予燭，和羹登簋鉶。"]'),
('d7f17d2e-0265-4024-8032-15ee7fbfd555','梅林分韵得舊字','杜謹言','宋','宋诗','song-poetry','','[]','竹村喜紆徐，江雲迷昏晝。',72,'全唐诗/poet.song.112000.json','["竹村喜紆徐，江雲迷昏晝。", "踟躕馬上語，嫩寒入衣袖。", "天公惜梅花，破臘開未就。", "端待使君來，春風本依舊。", "一樽既相屬，勿辭作詩瘦。", "明年用和羹，請爲使君壽。"]'),
('34d23510-bba1-4e98-86a8-ee9c87f8a957','梅林分韵得愛字','呂及之','宋','宋诗','song-poetry','','[]','去城十里南郊外，突兀老梅餘十輩。',128,'全唐诗/poet.song.112000.json','["去城十里南郊外，突兀老梅餘十輩。", "玉雪爲骨冰爲魂，氣象不與凡木對。", "我來窮冬煙雨晦，把酒從公對公酹。", "人言此實升廟堂，埋沒荒村今幾歲。", "清芳不爲無人改，捐棄何妨本根在。", "瑰章妙語今得公，國色天香真有待。", "歸路從公巾倒戴，俗物污人非所愛。", "我公行向日邊歸，此段風流入圖繪。"]'),
('4044e9e7-9d3c-46e2-b757-c5669171442c','梅林分韵得陶字','楊大光','宋','宋诗','song-poetry','','[]','蟠根寄荒絕，擢幹空椮蕭。',168,'全唐诗/poet.song.112000.json','["蟠根寄荒絕，擢幹空椮蕭。", "鄉來聞妙語，翦拂到兒曹。", "垂老猶叵堪，開落幾徒勞。", "不謂動杖屨，惠然排蓬蒿。", "尚能領諸生，相就醉澂醪。", "真頼旁輝映，併覺標韵高。", "酒闌興未已，分韵看揮毫。", "籍湜俱可人，冥搜爭過褒。", "乃知天地間，一等爲賢豪。", "橫飛與陸沉，亦各繫所遭。", "再煩起窮邊，國柄行當操。", "盡期如此花，曉夕幸甄陶。", "得備和羹用，寧不出伊皋。", "百年幾春風，勿令心忉忉。"]'),
('09699adf-05e0-46aa-804c-f92bfe7c3929','馮先生訪梅於成都西郊同游十五人分韵哦詩而積不與翊日先生分僧字屬積作之','張積','宋','宋诗','song-poetry','','[]','春回九地陽潛升，南枝破臘如酥凝。',224,'全唐诗/poet.song.112000.json','["春回九地陽潛升，南枝破臘如酥凝。", "疏籬度香竹稍短，寒沙倒影溪流澄。", "魁然老株忽駭目，雪鱗矯矯雙龍騰。", "天公一叱困仆地，掀髯弄爪高曲肱。", "長林望斷千百株，奮首直欲青雲凌。", "黎州太守和羹手，十里往看車呼登。", "西江破曉郊路浄，合簪者誰金蘭朋。", "歡笑藉草飛大白，行厨載酒多於澠。", "風花飄摇落杯面，漱齒澆胸如嚼冰。", "湘流之清峴山瘦，千古邂逅一笑興。", "却踏東風急回首，侵夜霜月寒生稜。", "入門未坐亟相詫，曰今見之生未曾。", "成都勝事多四蜀，我欲問津雲水僧。", "先生功成早丐身，未老重來醉倚籐。"]'),
('cff9900a-9243-4117-b75e-6e23b032754c','梅林分韵得作字','呂商隠','宋','宋诗','song-poetry','','[]','一樹知獨秀，十里方出郭。',156,'全唐诗/poet.song.112000.json','["一樹知獨秀，十里方出郭。", "江流浩清冷，露氣凝淒薄。", "胡爲此行色，疲馬外踴躍。", "玄冥正擅令，植物困摇落。", "喜見南北枝，粲然秀冰壑。", "千林色輝映，百畝香旁礴。", "首破春風荒，獨傲清雪虐。", "坐令芳信傳，芬菲到羣萼。", "如一君子信，茹連俱有託。", "相期飲此意，浩蕩放杯酌。", "更應護攀折，嘉實須若若。", "終收調鼎功，傅巖真可作。", "持問縉雲老，一尊笑相酢。"]'),
('5a110d0d-8743-4855-9395-422be15d28ae','偈頌六十首  其一','釋曇華','宋','宋诗','song-poetry','','[]','大道只在目前，要且目前難覩。',28,'全唐诗/poet.song.112000.json','["大道只在目前，要且目前難覩。", "欲識大道真體，不離聲色言語。"]'),
('b81d639d-e71e-47a1-9318-68c325458193','偈頌六十首  其二','釋曇華','宋','宋诗','song-poetry','','[]','九年面壁，壞却東土兒孫。',24,'全唐诗/poet.song.112000.json','["九年面壁，壞却東土兒孫。", "隻履西歸，鈍置黄面老子。"]'),
('deb6b1c1-aa42-4f28-9df2-0e44b58d80eb','偈頌六十首  其三','釋曇華','宋','宋诗','song-poetry','','[]','黄蘗老婆，大愚饒舌。',73,'全唐诗/poet.song.112000.json','["黄蘗老婆，大愚饒舌。", "佛法無多子，正眼瞎馿滅。", "妙嚴突出拄杖，三人證龜成鼈。", "拄杖子，善甄別。", "硬却脊梁，莫教漏泄。", "觀音菩薩將錢買胡餠，放下却是一塊生鐵。"]'),
('defe8055-a318-481c-99c0-a3a58a10c966','偈頌六十首  其四','釋曇華','宋','宋诗','song-poetry','','[]','大丈夫，須猛烈。',110,'全唐诗/poet.song.112000.json','["大丈夫，須猛烈。", "打破從前伎倆，直下斬釘截鐵。", "拈却佛祖機，拔却繫馿橛。", "豈不見睦州爲人太親切，拶得雲門脚折。", "後來兒孫不辨端倪，却向推門處辨別。", "若也恁麽參禪，馿年未得休歇。", "妙嚴不惜眉毛，與你當頭拈出。", "南贍部洲人，常在北鬰單越。"]'),
('038ec3fd-1c1a-4f0c-bc2f-6034813c75fb','偈頌六十首  其五','釋曇華','宋','宋诗','song-poetry','','[]','簸箕有唇，米跳不出，天下衲僧赤肐𩪸。',34,'全唐诗/poet.song.112000.json','["簸箕有唇，米跳不出，天下衲僧赤肐𩪸。", "更須撥轉上頭關，十方世界黑似漆。"]'),
('15d445f4-7c02-443f-a5eb-9cb9f180b6e1','偈頌六十首  其六','釋曇華','宋','宋诗','song-poetry','','[]','百草頭上，罷却干戈。',48,'全唐诗/poet.song.112000.json','["百草頭上，罷却干戈。", "萬仞峰前，縱橫遊戲。", "暗嗟魯祖面壁，一味祇貪瞌睡。", "翻笑睦州見僧，與我提一桶水。"]'),
('719395ee-5f05-42cd-a13a-807ef76a8d53','偈頌六十首  其七','釋曇華','宋','宋诗','song-poetry','','[]','九九九，釋迦老子不知有。',45,'全唐诗/poet.song.112000.json','["九九九，釋迦老子不知有。", "翻轉面皮，伸出毛手，握金剛鎚碎窠臼。", "突出無位真人，一一面南看北斗。"]'),
('9f1c53d6-7e5f-4a08-ae75-c4e52dc8deb3','偈頌六十首  其八','釋曇華','宋','宋诗','song-poetry','','[]','千溪水冷，萬壑雲寒。',58,'全唐诗/poet.song.112000.json','["千溪水冷，萬壑雲寒。", "無位真人乾屎橛，金剛寶劒破牢關。", "多年曆日最靈驗，百尺竿頭子細看。", "瞎却眼，啞却口，無孔鐵鎚成隊走。"]'),
('9b40aae9-9479-44dc-adbb-5555cb890964','偈頌六十首  其九','釋曇華','宋','宋诗','song-poetry','','[]','雲門露，猛如虎。',58,'全唐诗/poet.song.112000.json','["雲門露，猛如虎。", "達磨師，不是祖。", "豈不見鹽官老須彌爲槌，虛空爲鼓。", "又不見禾山老解打鼓。", "休莽鹵，甜瓜徹蒂甜，苦瓠連根苦。"]'),
('97a904bf-1d76-4fd6-aaae-0eec5d7ff9a5','偈頌六十首  其一○','釋曇華','宋','宋诗','song-poetry','','[]','少室峰前，漆桶話墮。',20,'全唐诗/poet.song.112000.json','["少室峰前，漆桶話墮。", "曹溪路上，賺殺闍梨。"]'),
('a3fdad0c-0d8a-4c3a-8d16-f81e9f85d000','偈頌六十首  其一一','釋曇華','宋','宋诗','song-poetry','','[]','德章老瞎禿，從來沒滋味。',36,'全唐诗/poet.song.112000.json','["德章老瞎禿，從來沒滋味。", "拈得口，失却鼻。", "三更二點唱巴歌，無端驚起梵王睡。"]'),
('5993de31-0633-4884-810e-40a1f1d917e2','偈頌六十首  其一二','釋曇華','宋','宋诗','song-poetry','','[]','虛空爲鼓，須彌爲槌。',20,'全唐诗/poet.song.112000.json','["虛空爲鼓，須彌爲槌。", "要打便打，莫問是誰。"]'),
('c8d819ca-67ed-4f3a-a5f8-30c3dfc89d20','偈頌六十首  其一三','釋曇華','宋','宋诗','song-poetry','','[]','始從鹿野苑，終至跋提河。',24,'全唐诗/poet.song.112000.json','["始從鹿野苑，終至跋提河。", "用盡自己心，笑破他人口。"]'),
('332b4a59-c2ba-436b-b27a-1a682be85114','偈頌六十首  其一四','釋曇華','宋','宋诗','song-poetry','','[]','文殊據虎頭，山僧取虎尾。',24,'全唐诗/poet.song.112000.json','["文殊據虎頭，山僧取虎尾。", "中間諸菩薩，隨列生歡喜。"]'),
('9e85dff5-3c9f-4d37-8957-dab1713a9bcc','偈頌六十首  其一五','釋曇華','宋','宋诗','song-poetry','','[]','蜻蜓許是好蜻蜓，飛來飛去不曾停。',34,'全唐诗/poet.song.112000.json','["蜻蜓許是好蜻蜓，飛來飛去不曾停。", "被我捉來摘却兩邊翼，恰似一枚大鐵釘。"]'),
('566aa427-9990-46a2-ae19-08c6aa9a96fe','偈頌六十首  其一六','釋曇華','宋','宋诗','song-poetry','','[]','藥山道頭，雲巖知尾。',24,'全唐诗/poet.song.112000.json','["藥山道頭，雲巖知尾。", "雖然頭尾相稱，要且不知羞耻。"]'),
('aacb47db-0281-4703-a58c-6f89532a21ab','偈頌六十首  其一七','釋曇華','宋','宋诗','song-poetry','','[]','天清地寧，時康道泰。',24,'全唐诗/poet.song.112000.json','["天清地寧，時康道泰。", "摩醯正眼洞明，肘後靈符光彩。"]'),
('c0c537c3-e4c6-42c2-8a90-7c001659ec5f','偈頌六十首  其一八','釋曇華','宋','宋诗','song-poetry','','[]','現成公案，百匝千重。',40,'全唐诗/poet.song.112000.json','["現成公案，百匝千重。", "峻如嶮崖，平如鏡面。", "執之失度，必入邪路。", "放之自然，體無去住。"]'),
('1465f951-cf1d-46c7-9028-336b8c58ed14','偈頌六十首  其一九','釋曇華','宋','宋诗','song-poetry','','[]','雪子落紛紛，烏盆變白盆。',24,'全唐诗/poet.song.112000.json','["雪子落紛紛，烏盆變白盆。", "忽然日頭出，依舊是烏盆。"]'),
('e1683299-3ee9-44be-941b-f12b962d1e46','偈頌六十首  其二○','釋曇華','宋','宋诗','song-poetry','','[]','若作一句商量，喫粥喫飯阿誰不會。',33,'全唐诗/poet.song.112000.json','["若作一句商量，喫粥喫飯阿誰不會。", "不作一句商量，屎坑裏蟲子笑殺闍梨。"]'),
('ee609e7b-28fb-4302-af54-c34e0e01d615','偈頌六十首  其二一','釋曇華','宋','宋诗','song-poetry','','[]','跛脚雲門言打殺，達之居士示全身。',32,'全唐诗/poet.song.112000.json','["跛脚雲門言打殺，達之居士示全身。", "當陽出格無多子，報佛深恩只兩人。"]'),
('78df69c5-484a-4abf-8f5f-c148243d7796','偈頌六十首  其二二','釋曇華','宋','宋诗','song-poetry','','[]','去時冒雨連宵去，回來带水又拖泥。',32,'全唐诗/poet.song.112000.json','["去時冒雨連宵去，回來带水又拖泥。", "自怪一生無定力，尋常多被業風吹。"]'),
('74fb9fb5-7dd1-4beb-b16a-b99ff324b3d4','偈頌六十首  其二三','釋曇華','宋','宋诗','song-poetry','','[]','心自本來心，本心非有法。',24,'全唐诗/poet.song.112000.json','["心自本來心，本心非有法。", "有法有本心，非心非本法。"]'),
('d50b52d7-4851-4948-b11b-0c1f29f51d14','偈頌六十首  其二四','釋曇華','宋','宋诗','song-poetry','','[]','五月五日端午節，好事當陽難掩塞。',52,'全唐诗/poet.song.112000.json','["五月五日端午節，好事當陽難掩塞。", "歸宗突出拄杖頭，閑神野鬼俱消滅。", "俱消滅，砌下寒泉忽倒流，嶺上白雲不敢白。"]'),
('dff5afc4-da51-415e-89b5-c28220bd4ba4','偈頌六十首  其二五','釋曇華','宋','宋诗','song-poetry','','[]','彌勒真彌勒，分身千百億。',24,'全唐诗/poet.song.112000.json','["彌勒真彌勒，分身千百億。", "時時示時人，時人俱不識。"]'),
('5d1f99b2-f21b-48a0-865b-d03800e3a033','偈頌六十首  其二六','釋曇華','宋','宋诗','song-poetry','','[]','佛祖正印，衲僧藞苴。',30,'全唐诗/poet.song.112000.json','["佛祖正印，衲僧藞苴。", "有眼如盲，有口如啞。", "更問如何，可知禮也。"]'),
('f7803ea9-06d4-4d65-88d6-6b6bd38b72b2','偈頌六十首  其二七','釋曇華','宋','宋诗','song-poetry','','[]','苦苦，苦中苦，樂中苦，誰道黄金如糞土。',35,'全唐诗/poet.song.112000.json','["苦苦，苦中苦，樂中苦，誰道黄金如糞土。", "象骨老師曾輥毬，秘魔扠下捉老鼠。"]'),
('a2afad87-69bd-4a8a-a453-0ca777f33d7b','偈頌六十首  其二八','釋曇華','宋','宋诗','song-poetry','','["\u5e90\u5c71"]','大道無方所，從容寰海間。',24,'全唐诗/poet.song.112000.json','["大道無方所，從容寰海間。", "幾思歸隠處，安樂在廬山。"]'),
('52e3baa6-44eb-47a9-a15f-c28c5a89391a','偈頌六十首  其二九','釋曇華','宋','宋诗','song-poetry','','[]','黄面老人乾屎橛，參隨一火爛泥團。',64,'全唐诗/poet.song.112000.json','["黄面老人乾屎橛，參隨一火爛泥團。", "心肝腸胃皆條直，蔬飯茶花照膽寒。", "佛法雖然未夢見，神通却許入雲端。", "應須痛念歸宗寺，時復持盂下翠巒。"]'),
('6b8b2ca8-5950-4bbd-ac57-0f2a511745e1','偈頌六十首  其三○','釋曇華','宋','宋诗','song-poetry','','[]','識得橙子，周匝有餘。',48,'全唐诗/poet.song.112000.json','["識得橙子，周匝有餘。", "識得橙子，天地懸殊。", "若向周匝有餘處會，理上偏枯。", "若向天地懸殊處會，事上偏枯。"]'),
('879be2d2-60de-4f41-96c1-720d817495b3','偈頌六十首  其三一','釋曇華','宋','宋诗','song-poetry','','[]','金錫罷游留靠壁，草鞋乾曬待秋風。',64,'全唐诗/poet.song.112000.json','["金錫罷游留靠壁，草鞋乾曬待秋風。", "且那長夏深思省，看是平生有底功。", "真實行藏宜保惜，虛頭伎倆疾銷鎔。", "老僧豈是多饒舌，要與諸人氣味同。"]'),
('27167d57-0261-4297-b275-437412031bda','偈頌六十首  其三二','釋曇華','宋','宋诗','song-poetry','','[]','古來爲法老尊宿，荷衆曾無有倦時。',64,'全唐诗/poet.song.112000.json','["古來爲法老尊宿，荷衆曾無有倦時。", "况是年來衰落甚，動爲多與行相違。", "應須痛念平生事，著意披襟善護持。", "顆粒果能無滲漏，少林初不隔毫釐。"]'),
('c5b38f1b-2edc-460f-9be9-c4f0ef59512c','偈頌六十首  其三三','釋曇華','宋','宋诗','song-poetry','','[]','西天四七，唐土二三。',60,'全唐诗/poet.song.112000.json','["西天四七，唐土二三。", "盡向者裏釘樁摇櫓，新東林爲你諸人解纜放船。", "未說超宗異目，若得齊眉共矚。", "亦可明窗下安排，未免欄腮摑出。"]'),
('1cbcb322-076a-4e14-8371-214fe6178b0c','偈頌六十首  其三四','釋曇華','宋','宋诗','song-poetry','','[]','心佛及衆生，笑而還復喜。',56,'全唐诗/poet.song.112000.json','["心佛及衆生，笑而還復喜。", "笑喜本無根，緇素誠有旨。", "千古萬古人，幾箇識道理。", "道理深，何處尋。", "海枯終見底，人死不知心。"]'),
('c546b748-a6ea-4b98-b29a-82dcb16403af','偈頌六十首  其三五','釋曇華','宋','宋诗','song-poetry','','[]','雲門不負者僧來問，未免落在陷阱中。',36,'全唐诗/poet.song.112000.json','["雲門不負者僧來問，未免落在陷阱中。", "是你諸人若向者裏會得，許你高步毗盧頂。"]'),
('fbc5f906-1bb3-4aff-9d8e-ee1ced6de449','偈頌六十首  其三六','釋曇華','宋','宋诗','song-poetry','','[]','一呼善來，鬚髮自落。',30,'全唐诗/poet.song.112000.json','["一呼善來，鬚髮自落。", "積累既多，無處安著。", "普請大衆，把火燒却。"]'),
('93834203-2b49-4177-8ff2-8d5a217e9f34','偈頌六十首  其三七','釋曇華','宋','宋诗','song-poetry','','[]','元正啟祚，更無回互。',60,'全唐诗/poet.song.112000.json','["元正啟祚，更無回互。", "萬物咸新，截鐵斬釘。", "應時納祜，跳出窠臼。", "孟春猶寒，言端語端。", "知事頭首，各各希有。", "雲堂大衆，雍容鄭重。"]'),
('af5364f2-5c31-47aa-b639-f2490d659c0f','偈頌六十首  其三八','釋曇華','宋','宋诗','song-poetry','','[]','世人住處我不住，世人行處我不行。',32,'全唐诗/poet.song.112000.json','["世人住處我不住，世人行處我不行。", "不是與人難共住，大都緇素要分明。"]'),
('34ece156-f45d-40fa-b158-f2acdcf6b750','偈頌六十首  其三九','釋曇華','宋','宋诗','song-poetry','','[]','思是聞之本，聞是思之用。',28,'全唐诗/poet.song.112000.json','["思是聞之本，聞是思之用。", "青原白家三盞酒，喫了猶道未沾脣。"]'),
('a5423d5e-cc1e-40dc-9285-b94ab32f279d','偈頌六十首  其四○','釋曇華','宋','宋诗','song-poetry','','[]','道遠乎哉，觸事而真，善因招惡果。',32,'全唐诗/poet.song.112000.json','["道遠乎哉，觸事而真，善因招惡果。", "聖遠乎哉，體之即神，刻糞作旃檀。"]'),
('e3d607f4-38b0-4c90-bf7b-c0aa4500c479','偈頌六十首  其四一','釋曇華','宋','宋诗','song-poetry','','[]','趙州喫茶，我也怕他。',36,'全唐诗/poet.song.112000.json','["趙州喫茶，我也怕他。", "若非債主，便是冤家。", "倚牆靠壁成群隊，不知誰解辨龍蛇。"]'),
('5992c6b0-3546-4e98-b8be-0f99ee3fe904','偈頌六十首  其四二','釋曇華','宋','宋诗','song-poetry','','[]','天上無雙日，閻浮一至尊。',24,'全唐诗/poet.song.112000.json','["天上無雙日，閻浮一至尊。", "萬年松不老，聖壽等乾坤。"]'),
('7804c9c7-3fc7-40d8-82f0-3cc6b4466657','偈頌六十首  其四三','釋曇華','宋','宋诗','song-poetry','','[]','去年無此雪，今年有此雪。',50,'全唐诗/poet.song.112000.json','["去年無此雪，今年有此雪。", "人皆怨此雪，不見元宵燈與月。", "莫怨雪，自是時人無辨別。", "堪辨別，一片清光倚寥泬。"]'),
('1276d46f-2cd7-4586-8745-5a7e262f7c8a','偈頌六十首  其四四','釋曇華','宋','宋诗','song-poetry','','[]','一莖兩莖斜，其意毒如蛇。',48,'全唐诗/poet.song.112000.json','["一莖兩莖斜，其意毒如蛇。", "三莖四莖曲，無疑入地獄。", "言下若知非，心空及第歸。", "堪笑蔣山老，無端入荒草。"]'),
('d89d15f1-4b28-412c-a7a7-9155e494a3ab','偈頌六十首  其四五','釋曇華','宋','宋诗','song-poetry','','[]','一二三四五，五四三二一。',76,'全唐诗/poet.song.112000.json','["一二三四五，五四三二一。", "從頭點檢來，笑殺維摩詰。", "带累李胡子，噴水髭鬚濕。", "灑浄已周圓，次念波羅蜜。", "蔣山恁麽道，千古誰人識。", "識不識，何處覓，堪與叢林爲軌則。"]'),
('85a7b66c-94a7-49a1-90c7-103f93f8b64d','偈頌六十首  其四六','釋曇華','宋','宋诗','song-poetry','','[]','泥多佛大，水長船高。',26,'全唐诗/poet.song.112000.json','["泥多佛大，水長船高。", "直饒說得道理分明，也須親到一遭。"]'),
('37e68c9e-a08c-44a9-971d-316820ce4115','偈頌六十首  其四七','釋曇華','宋','宋诗','song-poetry','','[]','千說萬說，不如親見。',59,'全唐诗/poet.song.112000.json','["千說萬說，不如親見。", "把手共行，略通一線。", "打破漆桶，何曾見面。", "阿耨多羅三藐三菩提，也是靈驗。", "蔣山恁麽做頌，馿年也未夢見。"]'),
('00e4a3aa-4bd9-4c8b-b1e1-f10b68e12d16','偈頌六十首  其四八','釋曇華','宋','宋诗','song-poetry','','[]','金佛不度爐，木佛不度火。',60,'全唐诗/poet.song.112000.json','["金佛不度爐，木佛不度火。", "泥佛不度水，真佛屋裏坐。", "萬牛挽不迴，千箇與萬箇。", "好事積如山，祇緣輕放過。", "不放過今日，鍾山甘話墮。"]'),
('3822af62-7f3e-4913-a145-c54aa42d8c0c','偈頌六十首  其四九','釋曇華','宋','宋诗','song-poetry','','[]','師子吼，無畏說，百獸聞之皆腦裂。',32,'全唐诗/poet.song.112000.json','["師子吼，無畏說，百獸聞之皆腦裂。", "香象奔波失却威，龍天寂聽生欣悅。"]'),
('6123b874-28f8-4775-847e-873b9b0f14bc','偈頌六十首  其五○','釋曇華','宋','宋诗','song-poetry','','[]','千年田，八百主。',142,'全唐诗/poet.song.112000.json','["千年田，八百主。", "甜瓜徹蒂甜，苦瓠連根苦。", "君不見禾山解打鼓，又不見採菊東籬下，千山萬山疊疊高門戶。", "又不見光孝僧堂六七間，日日普請搬泥土。", "又不見臨濟主中賓賓中主，二三四七面相覩。", "報禪流莫莽鹵聞，普請歡喜攙先去。", "去去實不去，途中好善爲。", "來來實不來，路上莫虧危。", "又不見主中主，箇箇衲僧氣如虎。"]'),
('b89f6d45-0d72-4438-b555-c93c94ad4cfa','偈頌六十首  其五一','釋曇華','宋','宋诗','song-poetry','','[]','去年十一月，笑別下鍾阜。',156,'全唐诗/poet.song.112000.json','["去年十一月，笑別下鍾阜。", "今年九月中，行見朝天路。", "去住既無心，動靜非取與。", "平生安樂法，此意同誰語。", "四明昔嘗到，諸剎皆可數。", "山川氣象雄，麟鳳棲遲處。", "今思昔日遊，歲月二紀許。", "豈謂臨晚景，侯伯重相顧。", "開緘讀來書，丁寧見毫楮。", "姑蘇二千石，眼高照天宇。", "我昔昧平生，今見開心腑。", "欣然樂與行，方鳴集衆鼓。", "先師未了底，今日應須去。"]'),
('4069ead0-a5f9-4242-a53b-891696b2f85b','偈頌六十首  其五二','釋曇華','宋','宋诗','song-poetry','','[]','禪禪，更不相煎。',76,'全唐诗/poet.song.112000.json','["禪禪，更不相煎。", "坐底自坐，眠底自眠。", "大家安樂，無法可傳。", "禪禪，曹洞五位，臨濟三玄。", "大年三十夜，脚踏地，頭頂天。", "禪禪，不直半文錢。", "海枯終見底，人死脚皮穿。"]'),
('ce1d97b9-9840-4f48-938b-8fff4660a3ae','偈頌六十首  其五三','釋曇華','宋','宋诗','song-poetry','','[]','四月初八佛生日，天下叢林皆浴佛。',224,'全唐诗/poet.song.112000.json','["四月初八佛生日，天下叢林皆浴佛。", "佛身充滿太虛空，何處更有虛空覓。", "見前僧俗等金軀，長短方圓皆顯赫。", "放光動地二六時，從本至今無間隔。", "今有檀越女弟子，劉氏同男王承直。", "曠大劫來植善根，所行真實如菩薩。", "當知功德福無涯，回向癸未誕生日。", "唯願歲君嚮此誠，諸天星曜同昭格。", "資持劉氏從此去，壽同趙州百二十。", "更祈不盡大功勳，保男察判官崇極。", "子子孫孫福祿昌，無量福田咸併集。", "此月十四往臨安，龍天當護爲般挈。", "三江九堰聰明神，稽首歸依助英傑。", "全家既達九重城，母子忻懽仰天力。"]'),
('15bd90e3-3ca2-447a-b69e-41d2b26ed865','偈頌六十首  其五四','釋曇華','宋','宋诗','song-poetry','','[]','一棒一條痕，一摑一手血。',80,'全唐诗/poet.song.112000.json','["一棒一條痕，一摑一手血。", "臨濟老瞎馿，至今猶未瞥。", "須彌頂上浪拍天，大洋海水無一滴。", "偉哉本色人，頂門亞三隻。", "辨龍蛇百草頭，擒虎兕一毫力。", "穿大地人鼻孔，坐斷衲僧摇舌。"]'),
('d1563f7e-e168-4bfb-9c16-3deef8daa931','偈頌六十首  其五五','釋曇華','宋','宋诗','song-poetry','','[]','五月五日端午節，天童爲汝開真訣。',82,'全唐诗/poet.song.112000.json','["五月五日端午節，天童爲汝開真訣。", "驅釋迦，逐彌勒。", "佛病祖病毛病頓清凉，魍魎邪神俱殄滅。", "相從唯喜本色人，非我同流誰與別。", "拄杖子，非列挈。", "公心一字更無說，千古萬古休饒舌。"]'),
('7e821c33-49f4-4b3e-aa79-f7e871ffbf48','偈頌六十首  其五六','釋曇華','宋','宋诗','song-poetry','','[]','青蘿夤緣直上寒松之頂，白雲澹濘出沒太虛之中。',38,'全唐诗/poet.song.112000.json','["青蘿夤緣直上寒松之頂，白雲澹濘出沒太虛之中。", "狗子尾巴書梵字，野狐窟宅梵王宮。"]'),
('a4d3bd11-6bdd-40f6-80bb-edf89d8e43fa','頌古十首  其一','釋曇華','宋','宋诗','song-poetry','','[]','草木無端拈出來，更加註脚放癡獃。',32,'全唐诗/poet.song.112000.json','["草木無端拈出來，更加註脚放癡獃。", "西天此土誰知己，夜半優曇火裏開。"]'),
('a9525622-c3f8-4c24-a055-ad054878a3f2','頌古十首  其二','釋曇華','宋','宋诗','song-poetry','','[]','金色頭陀忽破顔，看來也是管窺斑。',32,'全唐诗/poet.song.112000.json','["金色頭陀忽破顔，看來也是管窺斑。", "當時若得回頭早，免見兒孫墮黑山。"]'),
('0bc39485-e96b-42d4-a264-08399beda8be','頌古十首  其三','釋曇華','宋','宋诗','song-poetry','','[]','出得出不得，滿面是埃塵。',28,'全唐诗/poet.song.112000.json','["出得出不得，滿面是埃塵。", "愁人莫向愁人說，說向愁人愁殺人。"]'),
('7b3a360e-bc18-4993-a1fe-e996dd40e941','頌古十首  其四','釋曇華','宋','宋诗','song-poetry','','[]','鑿開荒徑造浮圖，往復商量價不孤。',32,'全唐诗/poet.song.112000.json','["鑿開荒徑造浮圖，往復商量價不孤。", "無限落華隨水去，夕陽春色滿江湖。"]'),
('e12ef95b-a841-4c7a-8b07-12618fd1c080','頌古十首  其五','釋曇華','宋','宋诗','song-poetry','','[]','急水灘頭下釣時，錦鱗紅尾尚遲疑。',32,'全唐诗/poet.song.112000.json','["急水灘頭下釣時，錦鱗紅尾尚遲疑。", "驀然跳出洪波裏，攫霧拏雲宇宙低。"]'),
('7142460a-9a9b-433f-864c-001f2c2e00c0','頌古十首  其六','釋曇華','宋','宋诗','song-poetry','','[]','大海波濤湧，千江水逆流。',24,'全唐诗/poet.song.112000.json','["大海波濤湧，千江水逆流。", "龍王宮殿裏，不見一人遊。"]'),
('a9dbe03e-face-48ea-9e83-972741f10676','頌古十首  其七','釋曇華','宋','宋诗','song-poetry','','[]','背衆喫油糍，對人誇好手。',24,'全唐诗/poet.song.112000.json','["背衆喫油糍，對人誇好手。", "潦倒不識羞，抵死揚家醜。"]'),
('dd068bb1-57d4-4e26-b19f-e343dc7834b7','頌古十首  其八','釋曇華','宋','宋诗','song-poetry','','[]','故園春色在枝頭，惱亂春風卒未休。',32,'全唐诗/poet.song.112000.json','["故園春色在枝頭，惱亂春風卒未休。", "無事晚來江上望，三三兩兩釣魚舟。"]'),
('45a712c0-ab15-466b-889c-7a837335d6f5','頌古十首  其九','釋曇華','宋','宋诗','song-poetry','','[]','丹霞寒燒木佛，院主因禍得福。',28,'全唐诗/poet.song.112000.json','["丹霞寒燒木佛，院主因禍得福。", "可憐杜撰巡官，祇管胡卜亂卜。"]'),
('ebc5ef60-02fd-4850-ac2c-3241ef05bc1b','頌古十首  其一○','釋曇華','宋','宋诗','song-poetry','','[]','苦瓠連根苦，甜瓜徹蒂甜。',24,'全唐诗/poet.song.112000.json','["苦瓠連根苦，甜瓜徹蒂甜。", "兩般滋味惡，中後入黄泉。"]'),
('d22aa4b4-925d-4e75-a49b-00aa59acb652','贊睦州和尚','釋曇華','宋','宋诗','song-poetry','','[]','稽首金容癩狗師，一生快活沒人知。',64,'全唐诗/poet.song.112000.json','["稽首金容癩狗師，一生快活沒人知。", "平田淺草翻身處，合水和泥換步時。", "垂手未施三寸刃，破關先下頂門槌。", "寥寥萬古誰堪對，唯有嘉禾跛脚兒。"]'),
('9a6516f5-4061-48ff-b798-a0b99dda496b','嚴教授畫臨濟請贊','釋曇華','宋','宋诗','song-poetry','','[]','喝下忽雷驚，聲前休領略。',48,'全唐诗/poet.song.112000.json','["喝下忽雷驚，聲前休領略。", "當鋒嚙鏃時，蹉過第一著。", "不在壁立處，豈向平地泊。", "野水白連天，秋空飛一鶚。"]'),
('8580e169-5882-40f1-882f-83848cf6082d','滿禪人畫臨濟像請贊','釋曇華','宋','宋诗','song-poetry','','[]','臨濟禿，無眼目，討便宜兮不知足。',48,'全唐诗/poet.song.112000.json','["臨濟禿，無眼目，討便宜兮不知足。", "高懸羊頭賣狗肉，秤頭斤兩惜如玉。", "胸中更有一般毒，天下無人敢輕觸。"]'),
('87853de6-ab14-4964-9b20-0230d52567ba','卞禪人畫布袋和尚求贊','釋曇華','宋','宋诗','song-poetry','','[]','人謂是彌勒，且喜沒交涉。',44,'全唐诗/poet.song.112000.json','["人謂是彌勒，且喜沒交涉。", "拖箇破布袋，到處納敗闕。", "祇有一味長，子細爲君說。", "是什麽，乾屎橛。"]'),
('6357f476-45a5-4189-93f3-b9883140137a','贊三將軍','釋曇華','宋','宋诗','song-poetry','','[]','家在歸宗寺後山，洞中春色異人間。',32,'全唐诗/poet.song.112000.json','["家在歸宗寺後山，洞中春色異人間。", "祇因親受靈山記，長與歸宗把要關。"]'),
('2214de41-e868-4346-8897-80f9997b963b','贊大慧禪師','釋曇華','宋','宋诗','song-poetry','','[]','人天之師，佛祖榜樣。',68,'全唐诗/poet.song.112000.json','["人天之師，佛祖榜樣。", "頂𩕳一著，匙挑不上。", "俾臨濟價增十倍，起圓悟更無伎倆。", "小姪如此贊揚，老胡决定有望。", "三十年後脫空話行，也是一番性懆起謗。"]'),
('f20f5cdf-7df3-4859-84b8-7b6dfec9c2ce','贊虎丘先師','釋曇華','宋','宋诗','song-poetry','','[]','老漢從來無禪，一味心中含毒。',56,'全唐诗/poet.song.112000.json','["老漢從來無禪，一味心中含毒。", "此毒時復現前，渾家大小不穆。", "異口同音呪詛，至今活陷地獄。", "一名臨濟正宗，一名叢林瞎禿。"]'),
('b2be583d-389f-4666-85d0-7dd5067f65ac','贊佛眼叔祖雪堂和尚侍立','釋曇華','宋','宋诗','song-poetry','','[]','正法眼藏，瞎馿邊滅。',36,'全唐诗/poet.song.112000.json','["正法眼藏，瞎馿邊滅。", "父行子隨，了無途轍。", "老禪已是錯針錐，添得應庵亂饒舌。"]'),
('d6c5d0fd-47f9-4d8a-97b9-4dac5ab3d3c8','贊此庵元和尚二首  其一','釋曇華','宋','宋诗','song-poetry','','[]','佛祖生冤家，人天不喜見。',38,'全唐诗/poet.song.112000.json','["佛祖生冤家，人天不喜見。", "忒殺聱頭，却通一線。", "劈胸拳下破牢關，大用機輪轆轆轉。"]'),
('771ff4a0-2f53-498e-a78d-3023dc18affa','贊此庵元和尚二首  其二','釋曇華','宋','宋诗','song-poetry','','[]','十分畫得相似，祇有一處誵訛。',28,'全唐诗/poet.song.112000.json','["十分畫得相似，祇有一處誵訛。", "佛祖檢點不出，從教平地干戈。"]'),
('70110321-7aae-4d83-a04a-a2d607f4c26e','贊李知府朝議','釋曇華','宋','宋诗','song-poetry','','[]','人言公死，我言公在。',22,'全唐诗/poet.song.112000.json','["人言公死，我言公在。", "在在在何處，清風動天籟。"]'),
('b915251e-f18f-422d-aaaf-8a921abca4e6','贊程宗古承務','釋曇華','宋','宋诗','song-poetry','','[]','龐居士悟心於馬駒言下，裴相國得大用於黄蘗棒頭。',107,'全唐诗/poet.song.112000.json','["龐居士悟心於馬駒言下，裴相國得大用於黄蘗棒頭。", "雖相去數百年間，其金聲玉振聯環不斷。", "彼時有此二大老光明烜赫，此時有宗古先生仁義禮信。", "根於心而能以此心確然履踐，佛祖大解脫門誠不讓耳。", "白雲山月未足爲齊，寒檜青松堪同大節。"]'),
('79bd0dab-56bf-44f8-bdf2-20745cda2cf1','烏巨山逵長老命立首座持師頂相請贊','釋曇華','宋','宋诗','song-poetry','','[]','煙林風姿，山岳氣宇。',60,'全唐诗/poet.song.112000.json','["煙林風姿，山岳氣宇。", "坐看春回，行無伴侶。", "不圖成佛，豈欲作祖。", "一句掀翻，萬機罔措。", "更提柱杖，擊塗毒鼓。", "立禪持歸，分付烏巨。"]'),
('4c0c6311-9f23-412e-8603-aa4158da3049','積善普長老請贊','釋曇華','宋','宋诗','song-poetry','','[]','天台南，石橋北，觀音寺裏有彌勒。',32,'全唐诗/poet.song.112000.json','["天台南，石橋北，觀音寺裏有彌勒。", "頂門瞎却摩醯眼，肘後風雷轟霹靂。"]'),
('ffee979e-0311-4de0-a76d-18e2df7e3574','表微首座請贊','釋曇華','宋','宋诗','song-poetry','','[]','左捺膝，右握拳。',46,'全唐诗/poet.song.112000.json','["左捺膝，右握拳。", "槌瞎正法眼，打破葛藤禪。", "奮迅西河爪距，踢出楊岐金圈。", "祇憑箇一著，今古有人傳。"]'),
('a5a97968-e658-47d9-8038-dc576a290ac4','禪人寫真請贊  其一','釋曇華','宋','宋诗','song-poetry','','[]','形枯豈是持齋叟，貌古還非入定僧。',32,'全唐诗/poet.song.112000.json','["形枯豈是持齋叟，貌古還非入定僧。", "馬又不成馿不是，當頭一著得人憎。"]'),
('d953fc28-73c8-4b48-8a38-8cdbe574cbd3','禪人寫真請贊  其二','釋曇華','宋','宋诗','song-poetry','','[]','法中之魔，僧中之賊。',58,'全唐诗/poet.song.112000.json','["法中之魔，僧中之賊。", "盜佛祖寶刀，斷衲僧命脈。", "貧窮者示之無價寶珠，富貴者令之破家散宅。", "不是平地上干戈，且非孤峻處標格。"]'),
('f5edb585-6cee-42f9-acb1-a4c4e26de1ff','禪人寫真請贊  其三','釋曇華','宋','宋诗','song-poetry','','[]','者漢初無罪過，祇是頭匾眼大。',43,'全唐诗/poet.song.112000.json','["者漢初無罪過，祇是頭匾眼大。", "雖然肚裏醒醒，開口便先話墮。", "如斯出世爲人，恰似大蟲看水磨。"]'),
('809ab232-06ba-418f-b006-05a934b09017','禪人寫真請贊  其四','釋曇華','宋','宋诗','song-poetry','','[]','豎拂拄拂，全機出沒。',53,'全唐诗/poet.song.112000.json','["豎拂拄拂，全機出沒。", "一喝耳聾三日，叢林至今狼藉。", "屈屈，且道是馬祖屈，百丈屈，歸宗屈。", "宗一侍者，但恁麽拈出。"]'),
('8643f1c2-b281-4021-8c2c-ed2e17e08dff','禪人寫真請贊  其五','釋曇華','宋','宋诗','song-poetry','','[]','魯祖偏工面壁，秘魔動便擎杈。',56,'全唐诗/poet.song.112000.json','["魯祖偏工面壁，秘魔動便擎杈。", "唯有歸宗長老，一味撒土撒沙。", "三箇上牢漆桶，不知那箇堪誇。", "諸方檢點得出，也是勾賊破家。"]'),
('fb3c561d-20ff-4b3a-86bf-dfdb58cd652d','禪人寫真請贊  其六','釋曇華','宋','宋诗','song-poetry','','[]','波濤千尺冷颼颼，誰向滄溟泛逆流。',32,'全唐诗/poet.song.112000.json','["波濤千尺冷颼颼，誰向滄溟泛逆流。", "唯有渠儂諳水脈，卷舒出沒任遨遊。"]'),
('0c1e3542-8a55-4c08-8830-38f842b9695e','禪人寫真請贊  其七','釋曇華','宋','宋诗','song-poetry','','[]','九年面壁成迂曲，三頓親承愈見賒。',32,'全唐诗/poet.song.112000.json','["九年面壁成迂曲，三頓親承愈見賒。", "併蕩那伽大機手，不知誰可繼生涯。"]'),
('ca731f48-d93f-4e19-b40c-7d0a7c159cec','禪人寫真請贊  其八','釋曇華','宋','宋诗','song-poetry','','[]','拭眼堂前，臨濟正令。',20,'全唐诗/poet.song.112000.json','["拭眼堂前，臨濟正令。", "且行一半，拈佛祖病。"]'),
('d3c11d23-d0da-4bb2-bef2-39f12cdce2d9','禪人寫真請贊  其九','釋曇華','宋','宋诗','song-poetry','','[]','江上青山千萬疊，水邊茅屋兩三間。',32,'全唐诗/poet.song.112000.json','["江上青山千萬疊，水邊茅屋兩三間。", "朝來無限扁舟過，何似渠儂把釣竿。"]'),
('1efc3f7d-59e8-438c-a0c7-8123e218a2bf','禪人寫真請贊  其一○','釋曇華','宋','宋诗','song-poetry','','[]','茅屋紫霄下，良田石鏡邊。',76,'全唐诗/poet.song.112000.json','["茅屋紫霄下，良田石鏡邊。", "此生隨分過，不用買山錢。", "這般惡比丘，何人敢近傍。", "恣焚三毒火，力起無根謗。", "破除少室窠巢，併蕩衲僧見障。", "聞者見者攢眉，應是無人瞻仰。"]'),
('0011e093-e093-4730-ac2e-483fe0415e61','禪人寫真請贊  其一一','釋曇華','宋','宋诗','song-poetry','','[]','身心一如，身外無餘。',77,'全唐诗/poet.song.112000.json','["身心一如，身外無餘。", "不願成佛，亦非凡夫。", "甘作上牢漆桶，無心計較錙銖。", "萬古銀山鐵壁，更沒者也之乎。", "是則活埋老僧，不是則打殺曇慧。", "暗透兩重牢關，烈焰不藏蚊蚋。"]'),
('39dfc42d-a200-48ba-a1f9-6239cc6c4373','禪人寫真請贊  其一二','釋曇華','宋','宋诗','song-poetry','','[]','元是黄梅村裏僧，生來自笑百無能。',32,'全唐诗/poet.song.112000.json','["元是黄梅村裏僧，生來自笑百無能。", "一瓶一鉢隨緣住，孰謂而今繼祖燈。"]'),
('1abb7b6e-fe28-4b9a-8482-265165885662','平江虞祖道寫頂相求贊','釋曇華','宋','宋诗','song-poetry','','[]','枯松下，盤陀上，獨坐大方，橫按拄杖。',48,'全唐诗/poet.song.112000.json','["枯松下，盤陀上，獨坐大方，橫按拄杖。", "謂是應庵，無恁相狀。", "謂非應庵，誰肯歸向。", "分付祖道，試自定當。"]'),
('7cc40c24-d503-46c7-8a19-b0518dd1c288','徐伯壽求贊','釋曇華','宋','宋诗','song-poetry','','[]','大海波濤闊，千峰氣象雄。',48,'全唐诗/poet.song.112000.json','["大海波濤闊，千峰氣象雄。", "當頭俱坐斷，直下展家風。", "一喝分賓主，三玄辨正宗。", "其餘都莫問，今古有盲聾。"]'),
('7d588bd9-aaf3-4a93-8c20-427f23b039d8','如道人求贊','釋曇華','宋','宋诗','song-poetry','','[]','江上青山疊疊來，屋頭松竹手親栽。',32,'全唐诗/poet.song.112000.json','["江上青山疊疊來，屋頭松竹手親栽。", "柴門盡日無人到，時見窗前雲作堆。"]'),
('462b3eb0-e844-4fdb-acf5-b0f88c51c484','蓮道人自寫像求贊','釋曇華','宋','宋诗','song-poetry','','[]','凌行婆，蓮道者。',38,'全唐诗/poet.song.112000.json','["凌行婆，蓮道者。", "一箇患聾，一箇患啞。", "聾者善聽，啞者能話。", "堪笑堪悲，可知禮也。"]'),
('84a9a9a2-f941-466a-b0e3-dd11596cf530','吉彬老二姪女繡普賢菩薩求贊','釋曇華','宋','宋诗','song-poetry','','[]','吳門吉彬老，壽年可及百。',180,'全唐诗/poet.song.112000.json','["吳門吉彬老，壽年可及百。", "骨目清且癯，施爲有標格。", "行步快如風，談笑氣不乏。", "窮之無他術，一味好佛法。", "每親善知識，言下究生殺。", "家有二姪女，貞姿迥超拔。", "自幼不茹葷，晨昏常燕默。", "從容定中起，痛念十使結。", "顯塵劫大願，運針發五色。", "幻普賢妙身，應現四菩薩。", "等十方虛空，皎若揭日月。", "大哉白象王，羣狐悉彌滅。", "當知妙殊勝，豈在別處設。", "若從自己求，猶如病作熱。", "如是名正觀，不爾是邪說。"]'),
('cbb8cb31-380b-4009-a3c3-0c125d09cee9','和宮使李侍郎頌送入莞山庵','釋曇華','宋','宋诗','song-poetry','','[]','此山已是勝天台，峰頂寥寥正眼開。',32,'全唐诗/poet.song.112000.json','["此山已是勝天台，峰頂寥寥正眼開。", "無限水雲難湊泊，却容掃地相公來。"]'),
('139e2f10-4d34-4b48-ad43-98243e139ae2','題陳參議中大大隠圖','釋曇華','宋','宋诗','song-poetry','','[]','荷鋤居士隠雲莊，竹屋茅堂瞰小江。',32,'全唐诗/poet.song.112000.json','["荷鋤居士隠雲莊，竹屋茅堂瞰小江。", "祇這逍遥是知己，人間天上更無雙。"]');
